insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('01428161-e6ec-5a59-b68e-2d0d5a35c935', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-06-06', '18:40:00', null, '通常 / 先週の引き続きをやりたいが、説明するだけだとダメなので、リストの使い方のチュートリアルを見せて使い方を再度学ぶ', '様子：目標はリストの管理、変数を使う、メッセージを送る ただ、大貴くんの場合はここに行き着くまでに意気消沈しそうだったので、まずはリストのチュートリアルを見せて使い方（リストのタブを間違えないなど）を学んでもらいました。 大貴くんの問題点としては、半角と全角数字が間違えてしまうこと バグがあった場合に自分で答えを導き出すのが苦手 ただし自分でわかってはいることなので、一緒にバグを探してあげることで本人が納得してくれるんだと思っています。', null, 'タイピング: 様子：点数も安定しているので今後は長文の方に挑戦してもらいたい
盛り上がり: 今日はすこし真面目モードになってしまいましたが、来週は完成まで近づけていきたいと思います。そこまでいけば、本人ももっと楽しくできるのかなと思っています。'),
  ('9198cf31-b54e-5082-a27c-87975333e3b7', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-04-22', '17:30:00', null, '通常 / 「さあ踊ろう」で、前回やりたがっていた「残像を残しながら移動する」の解説または基本操作コース09ジャンピングゲーム', '前回持ち越した件の続きと、新しいゲーム作成を選ばせたところ、新しいものを作りたいとのことで、基本操作コース09に進みました。（前回の課題は簡単なクローンを使用するので、クローンを取り扱う際に振り返ってみても良いかと…） 新しいスプライトが気に入ったようで色々試していましたが、声をかけたら短時間で切り替えてコード作成に移ることができました。（以前は「もうちょっと待って」がもっと長かったです） スプライトの初期位置を座標で設定することと、コスチュームの変更にはだいぶ慣れてきました。 ジャンプで「繰り返し」を使う意味を聞いてきたので、繰り返しを使わずに同じ高さまで移動させるのを試してもらったところ、動きの違いを見て納得していました。 障害物スプライトの出現をランダムにしたいということで、自分から乱数を使って試していました！ （「表示する」ブロックの位置は再検討してみても良いかも？？） 繰り返しや条件分岐の中に入れるブロックが整理しきれていないようなので、細分化の導入として、「繰り返したい動作」「条件にあてはまったときに実行したい動作」を書き出して考えさせてみてもよいかと思います。', '「すべてを止める」ブロックの位置がおかしいためゲームが動かなくなっているので、次回は上記の書き出しから始めて見直しをし、スコアの作成に取りかかりたいところです。', 'タイピング: 1172 正誤率93.2% 最近は順調にスコアを伸ばしています！
盛り上がり: ゲームが単調になるとつまらないから、と、乱数を使った発想は良かったです！ 新しいスプライトを「かわいい！」と喜んでいました。 「障害物が端に触れたら隠す」というところは、自分で考えて作成していました。'),
  ('25f9ed0d-b7f2-528c-9547-bf03e62aab75', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-05-30', '18:40:00', null, '通常 / 先週からの続き！完成に近づける！', '様子：がちゃがちゃのアレンジ アレンジの内容：質問リストを作る、答えが当たったらお金がゲットできる、お金を使ってガチャガチャを回すことができる 苦労している点：演算を使いながら、答えの判定をする部分でとても悩んでいた。 ここで問題なのが、「イベント」の使い方。 答えているのに次の問題にいかない、背景が変わった後に質問のリストが出て欲しいのに出ないなど イベントの使い方＝リレーションの問題がどうしてもまとまっていない様子です。 また、どうコードを書いたらいいのか＞＞今まで自分がやったことがない、もしくは例を見たことがないことに関して、頭の中で考えるだけになってしまって、自信がなくなってしまうという状態が続きました。 ただ、今日は楽しくなくてもどうやったら自分で答えを導き出せるのか？を考えて欲しかったので、 「混乱したら紙に書くという習慣をつけようね」と伝えておきました。', null, 'タイピング: 様子：はじめてやるタイピングなので意気揚々とやっていましたが、私が思うに彼には簡単な部類だったと思います。結構早く終わってしまった感じもあるので。'),
  ('e8a8f833-63dc-5322-a481-4698e8adf312', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-04-15', '17:30:00', null, '通常 / 前回までの記録で「以前よりは、自分で試して、動く動かないをやってくれるようになりました。ただ、わからなくなると暴走ぎみになるので、今やっていることと以前やったことを行き来するような感じで思い出してもらいながら、今後も学習すると良いかと思いす。（ナホ）」とあるので。 少し間があいたので、本人の前回画面を見ながら「前回はピンポン作ったよね～、この時、「もし〇〇なら」のブロックの使い方を習得したよね～と、で、この時「もし〇〇なら」のブロックの中に、乱数も使えたね」いう程度の復習にしておこう。↓↓ピンポンゲームの単元のポイントは「もし〇〇なら」で調べるコードを使うということなので。ここの復習。 ・簡単に復習したら、次の単元いっちゃいましょう。 ・「さあ、踊ろう」か「ジャンピング」、両方見せてやりたい方を選択してもらおう。 それぞれの目標は以下です。', '物語を作ろうで触れた箇所も複数あったため、復習と新規の勉強を兼ねることを説明して取り組みました。 相変わらずスプライトの編集にこだわりすぎて時間を取られることもありましたが、以前よりも適当なところで切り替えができるようになった印象でした。 メッセージを使用したリレーションや繰り返しなどはしっかり覚えていて、自力で作成できました。 スクラッチのゲームで、スプライトが残像を残して動く箇所を真似したがったため、まずはその動きの基礎を、ということでペンツールを学習しました。', '残像がのこったままではなく、少しずつ小さくなって消えるような感じにしたいとのこと、こちらでも調べておきます。', 'タイピング: スコア：1045 正誤率93.2% うまくいかないとすぐにキャンセルする癖がだいぶなくなり、最後まで取り組めるようになってきました。正誤率をほめたら嬉しそうにしていました。
盛り上がり: 久しぶりの教室でモチベーションが上がっていたのか、本人の成長かはわかりませんが、行き詰まっても投げ出すことがありませんでした。早業でタブを閉じることもなく、時間いっぱいしっかりと取り組めていました！
備考: 車ゲームでけいとくんと盛り上がっていました。とうきくんに作品を見せたりゲームの説明をしたりと、面倒を見ようとする姿勢が見られました！'),
  ('b189d2c8-d768-5ba9-8f92-34160980ff18', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-05-23', '18:40:00', null, '通常 / アルスパーク/ガチャガチャ1の続きから', '様子：質問の表示の仕方を一緒にやりました（やまと）。 ▶︎リストの使い方を、アルスパークhttps://app.arspark.jp/contents/13181のタイピング練習（５０音編）をみて理解したような様子でしたが、独特の使い方に慣れるまで大変そうでした（青木） 変数に乱数を設定して、質問の表示と答えの判定のときに同じ乱数を使う必要があることを説明しました。とても難しい内容でしたが、こちらの方を見てしっかり話を聞いてくれました。「かつ」と「または」の違いに混乱してしまうことがあるようです。 変数の設定と質問の表示まで終わりました。答えの判定は来週以降です。', null, 'タイピング: 様子：人差し指以外の指があまり使えていなくて残念でした。キーの配置はなんとなく覚えているようでした。'),
  ('b5eb6424-17f8-50d3-a859-6d999283b391', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-10', '18:40:00', null, '通常 / 検定2級の練習問題 時間が余ったら前回の作成の続き', '途中まではスラスラと作成していましたが、ロケットの上昇が思うようにいかなくなったあたりで集中力が切れたようでした。 乱数を使って足し算のクイズを出すところは、ゆまちゃんが何度かクイズゲームで扱ったところなので上手にできていました。 ロケットの上昇あたりのネスト構造で混乱したようでした。 ロケットがうまく上昇しないまま、時間切れとなりました。', '検定が途中なので、再確認をしたいです。 問題文をブロックに置きかえることはできていますが、順序に勝手にアレンジをかけていたりするので、文章を確実に読んで忠実に置きかえることを意識してやり直したら、できるのではないかと…', 'タイピング: 東方タイピング
盛り上がり: クイズの演算式や変数の作成、やや複雑なセリフの表示なども、迷いなくできていて、これまで作成してきた経験が活かせていました！ 一方で、自分が見たムービーの記憶でできそうなところは、問題文の読み込みが足りずに順序が適当だったり読み飛ばしがあったりというケアレスミスが見られました。'),
  ('99cfbabe-5d31-5643-a8c3-f811fb0cba40', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '6d82582b-9fef-5e62-991e-1e08d8fa4818', '2022-05-16', '18:40:00', null, '通常 / クラゲゲームhttps://app.arspark.jp/projects/10326/editor 見せたのち、本人がやりたいかどうか？今までの応用', '様子：取り組むものにかなり悩んでいましたが、ガチャガチャに取り組むことになりました。 「質問に答えて稼いだお金をつかってガチャガチャをしたい」とのことでした！ 「もし」を使ったときに「ずっと」を忘れていましたが、すぐに自分でミスに気付いて訂正できたので良かったです。 「質問をランダムに表示したい」という本人の希望があったので、いろいろと試してみました。はじめに配列を使って挑戦してみましたが、試行錯誤がまだ必要そうです。定義や変数と乱数をうまく組み合わせるといいかもしれません。 次回は、質問をうまくランダムに表示させたいです。（和） 全体的に自分がやりたいことをゲームにする方がだいきくんにとってはBetterだと今日のクラスで実感しました。基本的には頭の中でコードは出来上がっているので、紙に落とし込む作業がいつ自分にとって必要になるのか？がわかる日がくればいいなぁと思います。（青木）', null, 'タイピング: 様子：人差し指以外の指があまり使えていなくて残念でした。キーの配置はなんとなく覚えているようでした。
盛り上がり: 集中して前向きに取り組めていたのでよかったと思います。'),
  ('cd1d4608-1a9a-53d4-a694-66c3d39c8b6c', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-05-09', '18:40:00', null, '通常 / 射的ゲーム（簡単Ver）', '様子：全体的に今までやってきたことを思い出すまで時間がかかる？ 細分化はやりたくない様子だったので、実際にキーボードを先に動かしてやってもらうことにしました ▶︎ここは今後少し根気良くどうして細分化が必要なのか？を小出しに教えていくべきかなとは思いますがめんどくさがり屋さんなので、実際に手を動かしながらの方がいいのかな・・でもそうするとコードがめちゃくちゃになるので、どうしたもんか・・・ ボールが上下に動く＞＞左右に跳ね返ると同じだよ〜というまでどうしたらいいか？を迷ってしまう 弾が出る＞＞座標を使用するもなかなか思い出せない', '続きから', 'タイピング: どうしても難しいタイピングを避ける傾向がある。プログラミングでもそうだけどめんどくさいことを避けてる感じ。
盛り上がり: 思い出せば、できるという自信があって良かったと思います。'),
  ('142b5269-18fe-51c7-a2b0-e6931685e06f', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-03', '18:40:00', null, '通常 / 【Prg】38 トランポリンゲームを作ろう！https://app.arspark.jp/contents/13762 作成 本人がやりたがったら、アルスパーク、アクションゲーム_移動とジャンプ 完成版ステージアップ【LR】https://app.arspark.jp/contents/2953 を自分なりにアレンジする続き', '候補のトランポリンゲームは楽しんでいましたが、以前から気になっていたふくわらいを自分で作ってみたいとのことで、お絵描きの時間を決めた上でふくらわい作成をしました。 終了15分前で半ば強引にコード作成にうつりました。輪郭のスプライトに必要な初期設定（座標、最背面など）と、目のスプライトに必要な設定（複数必要なため何をすればいいのか←クローンをいくつ作成するか）などを考えてもらい、コード作成いたしました', null, 'タイピング: 準2級を出していました。
盛り上がり: お絵描きはとても緻密できれいな絵を描いていました。それをスプライトにして並べた時も満足そうでした。 コード作成にかける時間が少なくなっているので、今回の作品をもう少しゲーム仕様にできないか考えてもらえるとよいかと…。 見たゲームの細分化はできていますが、アウトプットするときがわりと大雑把になっている気がします。そのせいで作成に時間がかかり、トランポリンのようなコードをたくさん使用しているものは面倒になっている可能性もあるかと。 単元別ドリルに取り組むか、現在作成中の作品のゲーム仕様を細分化で考えてもらい、小さい単位で作成していくのもありかと思われます。'),
  ('e773bf3b-9aa7-5ad8-8218-91ef99866e55', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-04-25', '18:40:00', null, '通常 / 〇ちょっと飽きが見えてる感じ？がするので。ここまで順調にきたから、彼はしばらくフリーダムにしてもいいかもね？ 前回のマミさんの記録にも書いてありますが、検定をやるという約束があったっぽいけど。実は好きなゲームを作りたい？感じ？ 自由制作でもいいかもね。その際、いくつか、大貴君にとって手ごたえありそうなゲームを3つぐらいアルスパークから選んでおいて、今日はこの中で好きなの作っていいよーの路線にしようか。 (前回の記録↓↓) 次回は検定をやってみる、とのことでしたが、好きなゲームを作りたいという気持ちも強いようでした。', '様子：自分でゲームを作るか、検定をやるか？を聞いたところ、自分のゲームを作るのに細分化を書くのがいやだということで、結局検定へ。 全ての問題に対してきちんと言葉を理解し、ひっかけにもひっかからずよくできていたと思います。20分ほどで出来上がりましたと言われたのでアレンジしてみよう！とはなしたところ、「どのアレンジを加えたらいいか迷ってできなかった」と言っていました。それでも全問正解していたので余裕で４級は受かるかなと思っています。', 'もう一個検定違うやつをやるといいかな。特に〜へ向かう、行くの問題がいいのだけど〜', 'タイピング: 様子：最初からココアのタイピングがやりたいと話していたのですが、運？よくサイトにアクセスできないという不具合があり、Playgramの方で練習してもらいました（だいきくんはこっちで全然大丈夫なので最初からこちらを提案していたのでよかったです）タイピングの速さも格段にあがり、本人が心配しているほどではないと思います。難しいことをやるのが好きではない（失敗が嫌いなんだと思います。）
盛り上がり: 意外にも満足げに検定をしていたのである意味ハードルがあるような感じだといいのかな？'),
  ('e0329a1c-53c8-5504-8dab-28fd6f1ab962', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-05-13', '18:40:00', null, '通常 / アルスパーク、アクションゲーム_移動とジャンプ 完成版ステージアップ【LR】https://app.arspark.jp/contents/2953 を自分なりにアレンジする続き', '前週と同様アレンジの作業。 ひとまずキャラクターを出せたのはいいが、動きに関しては未定だったようなのでどんなことができたらいいか？を紙に書くところから。大体は書けたのでそこから作業となると、スプライトの動きを作るところから入るよりも、見た目を重視するようで１〜２つぐらいのスプライトの色や形を変化させることだけで終わってしまった。やりながら「こうかな？」「こうしようかな？」の考える部分はとてもよいものの、中だるみのような感じも見受けられたので、メリハリをつけて今後はできたらいいのだけど・・と思い。 ただ、スライムのキャラクターが単純に横に移動する感じにするのではなく上から”落ちる”ような動作をさせたいと話していて、今まで使ったことがないコードの動きもやりたいという意欲があるので、大きな心で見守り続ける方が彼女にはあっているのかも。', null, 'タイピング: ４級、スコアは横ばい
盛り上がり: ①それぞれのスプライトのキャラクターの色の変化を場面場面で変えようというクリエイティビティーがある ②こういう動きがあったらいいなという動きの発想が出てきた（←今までにはない発言）ということはある程度自分ができるという自信があって、かつ多分これだったらできるかもしれないという可能性を信じてくれるようになったのかな？'),
  ('c184f7d5-ce7d-5912-8dc8-1bb9c52567c7', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-05-06', '18:40:00', null, '通常 / 自分が好きなゲームを見つけて細分化してみる', 'まずは、自分のやりたいことをスプライトを入れながら考えてみてくれました。このゲームをアレンジすると決めるまでおしゃべりしながらになってしまいましたが、ある程度自分が作りたい物が決まっている（自分がやりたいのとレベル感を推し量っている）ので、来週も同じようにやってもらいたいと思っています。', null, '盛り上がり: 本物のマリオのようにスターに当たったら、マリオが点滅する、無敵になる クリボーと同じようなキャラクターを進出させる コインを拾ったらボーナスアップ ↑以上のようなアレンジをしたいと話していました。'),
  ('e37b3aa7-86d4-5b53-9cf0-e3c5fbc620ea', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'f3bb6393-f24e-5dfd-a9d3-03590f567292', '2022-04-18', '18:40:00', null, '通常 / 検定問題４級', '様子：検定問題を提示したものの、「今日は自分のゲームを作りたい気分」とのことで、前回に引き続きキャッチゲームのアレンジに取り組みました。 色々な点数のりんごをたくさん作っては削除する、を繰り返していましたが、その中でもだいきくんが気に入った？スプライトをいくつか残してゲームを作り込んでいくことはできました。作っては削除、というスプライトも多かったですが、ゲームバランスを考えての削除がほとんどという点では、ゲームを彼なりに考えているのではないかと思われます。 演算式の等号と不等号の使い方を学習しました。 しぶしぶながら、ゲームオーバーの動きを作ってくれました。', '次回は検定をやってみる、とのことでしたが、好きなゲームを作りたいという気持ちも強いようでした。', 'タイピング: 様子：今日はあまり気分ではなかったようで、ココアタイピングを少しした後、マイタイピングを開いてはみたものの、キーボードをガチャガチャして（止めました…）「また今度やる」となりました。
盛り上がり: 親子コンテストに出る！とのことです。 いろいろなスプライトを作っては試しながら、ゲームがどのくらいでクリアできるのか、ゲームバランスを見ている点は良かったと思います。'),
  ('a9ad981b-b4f5-5c7b-b5a4-a4a12cf832a4', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-04-22', '18:40:00', null, '通常 / 前回のゲームの続き、バスが動く→スペースキーが離れたらバスの動きが止まる、を完成させる', '前回は背景画面が動いているように見せるためにはどうしたらいいか？で止まっていました&バス停に止めるというのを単純に触れたら〜でいいのかもう一度検証しようねというところで止まっていました。 そこから続きをおこなっていて、まず背景画像は「応用のジャンプゲーム」で芝生が動いているやつを活用しようかとはなしたのですが、背景全体が動くとかなり難しいということに発見したので、道路だけ動かすことに。 そのためには背景から、道路を切り離して作らないといけないので、私と一緒にどう切り取って作成するか？また座標の位置も芝生と同じ数字を書くと微妙に違ったので、多少そこは数字の調整を一緒にしました。 また私から提案で、バス停に触れたら止まる〜のがゲームのゴールでもOKだけど、もしバス停の前で止まってしまった場合に距離は知りたくない？（電車でGOのゲームと同じで停留所よりも前に停車をすると後何キロと出るので）演算を使うことにしました。 ここで問題なのは考え方ですが、単純にバス停の座標からバスが止まった座標分引けばいいだけ。 でも「バス停のX座標」というコードが見つからない。 このバス停の座標というのは、バスというスプライトを選んでいれば「X座標」というコードがすなわち「バス停のX座標」ということを、まっちゃんにも聞いて解決しました。 私も勉強になったことではありますが、選んだスプライトの中の「X座標、Y座標」のみのコードはそのスプライトの〜座標を意味することをゆまちゃんがどれだけ理解してくれたか？が今回のレッスンの中で気になった部分でした。 その他、演算の使い方、変数の使い方に関しては問題なく、演算を使う使い方をさらに強化することでゆまちゃんの想像力がさらに発揮されるのでは？と思いました。', '次回は、演算の＞、＜と距離の測り方や重さの測り方、スプライトの中にある単純コードを使ったゲーム系？をやってみたいけど・・', '盛り上がり: 道路を切り取る際に、細かく移動しているように見せる、ことを意識していた→細部にこだわることや美意識の観点がすばらしい！'),
  ('39d090ce-ff0b-585a-9f23-4dd4d2389d0d', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-04-11', '18:40:00', null, '通常 / 火曜日だったので３週空いているので、最初にちょこっとジャンピングでやったことおさらいするといいかもね。 次回「キャッチゲーム」やるという話しになっていたよう(*^^)v 順調だね。 今週から月曜の6:00スタートなので、最初の動線要検討だね。中島頭数に入れて段取り。 キャッチゲームをやる', '様子：概ね今までの授業を覚えている様子で、「りんごは、座標でしょ〜、あのコードだよね？」 とどのコードを使えばいいかが理解できている様子。 ボウルのコード 👇やり方2つをおさらい ①〜のボタンが押されたら ▶︎何歩動く ②もし〜がなら ▶︎X座標を動かす ①と②だと格段にボウルの動く速度が変わって見えるので、どちらのやり方でもいいけどもどちらがゲーム性として面白いかを確認 全部を繋げてコードを書いても干渉しないことを自分でわかっていて ①Y座標が-170の場合の時と②ボウルに触れたらの時とで書き分けていた アレンジとして、大好きな乱数を入れたり、15度回すを入れて動きが多くあるようにみせながらゲームを難しくしていることにチャレンジ。', '次回は、今回のゲームの応用をおこなうか・・もしくは飽きるタイプなので違うゲームにするか・・・ その場合射的が一番同じ路線なのでいいのだけど、〜に行く、向かうというコードを教えることになるため、違う目的になってしまいそうな・・・', 'タイピング: 様子：ステージ３までクリア ほとんどクリアしているものの、熱中がすごいので（クリアしたいという意欲）ステージ３まで続けてやってもらいました。一通り３文字の単語は問題なく打てる様子です。ただこどもタイピングなどに移ったときに（以前）途端に嫌がるので3文字のタイピング以上を今後どのタイミングで行うか？を見極めてあげたいと思います。
盛り上がり: もう一つりんごを用意し、得点を変更 アレンジを加えて早く出現させるようにした 変数を使うことに抵抗がなく、かつ自分でそれを上手に使える 👆全体的に、自分はこのゲームを作れるという自信がある💛'),
  ('27d14102-4009-5064-bd6c-803429221530', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-04-15', '18:40:00', null, '通常 / 先月の記録を以下にコピーしました。やや教え方に軌道修正が必要と思いました。 本当に、ゆまちゃんは細分化がきちんとできているのか？ 基本はしっかりできていると思います。但し、「現時点のレベルで」ということになっていないか、再度授業設計してあげたいですね。 成長するために、今より少し難しい事にチャレンジしなくてはなりませんが。 本人のコードをみると、オリジナルとかなり違いますよね。まだ途中なのかな？ でも、途中だとしたら、２週連続で作ったわりに、簡単なコードでしか作っていないので？？？？と思いましたm「できるコードしか使っていない」現象になっていないか？ 途中なのかなあ？ 今週やるとしたら、間が空いたのでサッカーゲームはモチベーションがあがらないか？ サッカーゲームの難しいところと、単元のツボは「減速・加速」です。 今週やるとしたら以下のページを参考に、バスが止まる、加速するという単純な動きをゼロから考えて作ってみましょうか？ https://futabazemi.net/scratch/accel-decel/ まずは、最近のゆまちゃんの様子、教えてもらえますか？', 'まず初めに、サッカーゲームの内容をおさらいした。どこがおかしいのか？今途中なのか？などを話したのち変数の使い方をおさらいしました。その上で加速、減速のバスを動かして、一緒にバス停に停車させるということと、背景を動かして、バスが走っているように見せるところまでを考えてやってみました。 本当は、バス停に近くなったら減速しバス停に泊まるようにしたかったのですが、そこができなかったので、次回までに私の方でどうやるかを実証してみたいと思います。', '次回は、ひとまず同じことをおこなうか？もしくはサッカーの単元にもどって、同じコードを使ってゴールまで完成してもらうか？などもう一度新鮮な気持ちでやってもらいたいと思います。', 'タイピング: 何回か、 自分のパソコンでタイピングを行い、クラッシュしてしまって止まったりした。 なので3回ぐらい試したため、スコアが低めにでてしまった。ただ、本人が打ち疲れしただけなのでそこまでは心配してないです。なにより準２級なので。
盛り上がり: バス停まで行ったら止まるという工夫を、バス停の前に線を作ってみたらどうか？など自分でいろいろと考えてくれたゆまちゃん。一緒に話しながら考えることで、これはどうだろう？こうしたらどうか？など試行錯誤してくれ、楽しく授業をやってくれました。'),
  ('f6aa5a71-b07e-519f-84d1-ad2f39277947', '36b32225-ef6e-58f8-add5-c3bfbcfffc48', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-06-03', '17:30:00', null, '通常 / だいきくんのリスト作品の動きと、アルスパークのリスト作品を見せてから、リストを使った作品を作ってみる。', '今回はリストをチュートリアルでやってもらった。（３０分）使い方に関しては問題ない様子。 ただアレンジとなるとちょっと及び腰になっていた。 自分の人生のゲームリストをつかって、アレンジしてみたら？ →あんまり乗り気ではない様子。 ただし、なほがいうよりも由紀先生が言う方が、僕の人生というゲームに活用してくれそうではあったので、来週はそこをするか、もしくはシューティングゲームをおこなうかのどちらか・', null, null),
  ('280e36a2-f377-5eed-8000-f780ee0c165b', '36b32225-ef6e-58f8-add5-c3bfbcfffc48', null, '51f93219-e30b-5494-98c9-4ecd93a17aaf', '2022-05-27', '17:30:00', null, '通常', '作り途中だったゲーム(いい家を探すゲーム？)を進めました。 ドット絵メーカー(https://neutralx0.net/tools/dot3/)を使って背景の絵を作り、その後プロローグの途中(終わりまでできたかも？)まで作り、そこで集中が切れたため終わりにしました。(18:20頃) どんなゲームを作りたいのかいまいち分からなかったので進めながらどんなゲームを作りたいのか聞こうと考えていましたが、思ったより進めることが出来ませんでした。', null, 'タイピング: ホームポジションを意識して集中してやっていました。'),
  ('10fbdba1-6514-502f-b17b-7c0d94d261fe', '36b32225-ef6e-58f8-add5-c3bfbcfffc48', null, '2863fe3b-74f5-59ec-b388-06ad4a82b75c', '2022-05-20', '17:30:00', null, '通常 / 前回のゲームの続き、敵をどうするか？の部分を考える', null, null, null),
  ('13afba75-af4e-5376-b66b-bb242c774963', '36b32225-ef6e-58f8-add5-c3bfbcfffc48', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-05-13', '17:30:00', null, '通常 / キャラクターの動きなど 定義を使ってみては', '定義については参考にした作品によって、使ったり使わなかったりとのことだったので、見やすくわかりやすいように、コードが冗長になっているところを定義を使って整理してみることを勧めました。 当初は「なんでそんなことをする必要があるの？」という反応でしたが、はるとくんが参考にしている作品の中でも、見やすくてアレンジしやすいものとそうでないものがあるのでは？と尋ねると大きく共感してくれました。 いずれ自分の作品を公開したいという希望を強く持っていたので、はるとくんの作品を参考にしたい、という子がいたときに、「これをアレンジしてみたい」と思われるようなコードを書いてみたらという提案に乗ってきてくれました。 「オレンジボム」で定義ブロックの復習ができたようなので、「今最も完成させたい作品」という「0531」を見直していきました。 定義ブロックを適宜使用すること、クローンの弾の動きをスムーズにすることを目標に取り組みました。 コンテストを意識し、「対戦」または「協力プレイ」ができるように改造していきたいそうです。', null, 'タイピング: 自分から「やってもやらなくてもどちらでもいい」と言ってきたので、プレイグラムのれんしゅうにチャレンジしてもらいました。
盛り上がり: 自分の作品を公開した時、たくさんの人に見てもらいたい、という目標により、コードを見やすく書こうという意思を強く持ってくれました！'),
  ('28f3606c-f052-5d28-b297-647d23605978', '36b32225-ef6e-58f8-add5-c3bfbcfffc48', null, '761a91b5-63ed-547d-8524-e06abcc55967', '2022-04-22', '17:30:00', null, '通常', '初めは今まで作ったものはやりたくないという感じで新しいものを作っていましたが途中ゆきさんが話して、インベーダーゲームのようなゲームを開いてくれました。そのゲームを作るうえで細分化が必要なのですが、はるとくんは細分化をしたことがなかったので「射撃ゲーム＿初級」を使って細分化の練習をしました。 だいぶ細かく細分化できており、インベーダーゲームにも応用できるかと思います。', '今回の細分化を生かしてインベーダーゲームの敵を作る。', '盛り上がり: とても集中して細分化に取り組んでいました。'),
  ('347e1894-a11a-5e0d-b5e5-40b7a2a26995', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-16', '17:30:00', null, '通常 / すごろくのマス画面の作成', '・サイコロを振る説明を音声合成で作成しました。 ・人生ゲーム https://scratch.mit.edu/projects/266107310/ を参考に、マス目を作成しました。', null, 'タイピング: 承太郎君に勝ちたい！とがんばっていました。
盛り上がり: ・マス目のネタに八王子を入れることで盛り上がりました。 ・サイコロを振る説明のところは、よくできていました！ゆきちゃんも、音声合成を使えて楽しそうでした。'),
  ('44c14dfe-5236-5a46-8a66-800a08823891', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '7a070d72-6bb3-5410-8e94-56f390092259', '2022-06-16', '17:30:00', null, '通常 / 自由作品作成', '前回作ったイラストを使って動きのコードを作りました。正しくコードを作れているのに不安なのか何度か消して作り直したりして、時間がかかてしまいました。 本人が現状コードを作る意欲が無くって「コードは下さんが作る」少し身勝手な言動が多かったです。若干授業中も遊びや音楽の選曲に気が取られてしまい、少し心配です。 ジャンプを作るコードでは、なんとなくは作りたいものは頭の中にあるけど具体的にどのコードで構成されていたがあやふやだったので、前にせい君が作ったジャンプゲームを振り返って、やりました。ジャンプの間隔を前のものよりスムーズに動かすように調整できていたのがよかったです。', 'また背景を書くのにドット絵を使いたいらしいです。', 'タイピング: 人差し指だけでタイピングが多いが、速度は速くなっている
盛り上がり: 最後の新しい話の真剣にみていました。'),
  ('e8143c34-01b2-579e-9d6c-6d6eeb4daba6', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-06-16', '17:30:00', null, '通常 / コンテスト用のプログラムを進める。敵を踏んづけるプログラムを作る。', '自分がプログラムにのめりこむことに気づけてきたようです。 「終わりそうにもないからそこまではやらない」と線引きすることが出来ていました。 ジャンプの判定を座標で制御しようとしていましたが、うまくいかなかったので、主人公の色を一部変えて再度プログラムすることにしました。ジャンプ制御の際、x座標とy座標間違えて少し混乱しました。 「敵が主人公に上から当たられたとき」の判定を考えました。 何を考えてもうまくいかず（色判定、y座標、上と下から挟んで条件を狭めるなど）、本人が思い当たる悪影響を与えていそうなコードを一緒に確認しました。 クローンが悪影響を及ぼしていることが分かったので、「クローンがない状態で」うまく作動するようにしました。その次にクローンを戻したところ、うまく作動しました。下から当たっても上から当たっても、敵は消えてしまいます。色判定を加えれば、上からの衝突に限定できると思いますが、最後は本人に任せました。あとで考えるようです。 キャラクターが敵にあたってしまったときの判定を追加してくれました。うまく下に落ちる様子をプログラムできていました。', '決めてはいませんが、本人が「サボテン追加したい」と言っていました。', 'タイピング: ベストスコアでした。両手を使って集中して取り組めていたので良かったです。
盛り上がり: ゆきちゃんと話しつつ、楽しく進められました。敵がうまく消えたときはとても嬉しそうでした！'),
  ('780c22ab-9c7e-5d46-a6e6-5c838b7f7d0d', 'b2246586-4496-52f9-a825-be2488a00a31', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-16', '17:30:00', null, '通常 / 検定4級問題', '・こちらが用意していた検定4級のおいかけっこゲームは、やったことがあるとのことだったので、サメと魚の追いかけっこゲームの問題を渡しました。 ・「はじめの設定」などは質問もなく、きちんとできていました。 ・個々の動きになると、問題を読んだ時点では「わからない」モードになっていましたが、普段よく作っているゲームのおばさんの動き、とヒントを与えたら、自力で作成できました！ ・「すべてを止める」と「スプライトの他のスクリプトを止める」の違いを学習しました。', null, '盛り上がり: ・普段作っているゲームの経験がしっかりといきていて、本人も嬉しそうでした。 ・問題の最後までしっかり取り組むことができました！'),
  ('b6593ba7-8b9e-5548-8e48-ad708a165dbe', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-06-16', '16:30:00', null, '通常 / ゲーム性アップ。コードの整理', '前回やったことを忘れてしまっていたようでした。 ゲームの大枠自体はどうやら完成だったようです。 コードが乱立していて見づらかったので「きれいにする」を伝えました。使わなかったブロックも一目瞭然でとても気に入ってくれたようです。 メッセージの送り方、動かし方も正確にプログラムできていました。 発車時刻のコントロールに苦心していました。 難しく考えすぎて、制御の部分のブロックが複雑になっていたようです。もう一度見直し、シンプルなものに書き換えました。演算ブロックはまだ苦手なようです。 自分で高尾山に行って、ケーブルカーのリアルを録音してきてくれたので、ダウンロード、編集、追加をしました。 かなり細かく調整していました。こだわりがあるみたいです！！！', null, 'タイピング: ミスタイプ率も10%程でとてもよかったです！上位28%でした！
盛り上がり: 自分が録音してきた音楽が実際にプログラムに入り、かなり嬉しそうでした！！！'),
  ('96440363-6baf-5904-b3e2-7cf81e82ddc1', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2022-06-09', '16:30:00', null, '通常 / 前回の続き。点数の入れ方を考える。 ゲーム性を高めたい。', '前回ゲームのおおよその内容は完成しましたが、スコアの入れ方のゲーム性が低かった（扉を操作しない方が点数が高かった）ので指摘しました。本人はあまり気づいていなかったようです。 改善の仕方が思いつけなかったので、加点を提案しました。 修正してくれましたが、またも扉を操作しない方が点数が高い優しい仕様になっていたので、際どいところにボーナスポイントがあるから面白いことを伝え、再び考えてもらいました。 電車の発車の様子をプログラムし、さらに時間制限を設けることになったようです。 出発のプログラムの座標は何回も試して微調整していました。 乗客が足りないので来週追加するそうです。今後の展望もしっかりしていそうです。', null, 'タイピング: 久しぶりに挑戦してもらいました。得点が前回やったときから上がっていたので良かったです！準2級合格レベルでした！PlayGramの方が好きみたいです。
盛り上がり: 話しかけてくれる機会が増えて嬉しいです。'),
  ('55345167-fd6d-5040-a0e3-9bf437bdb0c1', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2022-06-02', '16:30:00', null, '通常 / 余裕があればストーリー構成をきいてみる 前回のケーブルカーの続き', 'ちょうどいいタイミングでドアを閉めるプログラムに今日は挑戦しました。 乗客のうごくスピード、位置にこだわりがあるようで、何回も丁寧に確認してプログラムしていました。 1回目にプログラムが発動したのち、2回目は動かないようにしたいという相談がありました。 一緒に何分か悩んだのち、変数を使うことを提案しました！もう少し説明しようとしましたが、ピンときたようですぐに手を動かし始めてくれました。うまく動かせていたのでとても良かったです。 点数の入れ方にもう少し工夫をした方がいいかもしれないです。来週までにポイントを入れる新しい方法を考えてくるようにお願いしました！', null, 'タイピング: 正答率はそこまで高くありませんでしたが、両手を使って集中して取り組めていたので良かったです。
盛り上がり: 自分が作ったプログラムについて丁寧に説明してくれました！'),
  ('00902db0-00c4-58fd-97e1-c88e0f381a0b', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2022-05-26', '17:30:00', null, '通常 / 前回考えた内容のゲームをはじめから作成', '前回難しい場面のコードを一通り考えたので、今回は初めから作り始めました。 最初に使うスプライトを選択しました。ボタンは自分で書いていましたが、ケーブルカーの絵はイラストACから取り込みました。 扉があいたときの様子も表現するため、ケーブルカーを加工して扉が閉まっている状態と開いている状態の2つを表現していました。丁寧に画像を編集できていたて良かったです！ 今日はプログラムとして「ドアを開ける動作」を作りました。扉が開くのにかかる時間を細かく調整してくれたようです。開閉も座標をコントロールしてくれました。とても滑らかに動かせていました。', null, 'タイピング: ミスが多いように見えますが、間違えたことに気づかずそのまま打ち続けてしまっていることが原因なようです。左手がとくにホームポジションを意識できていて良かったです。
盛り上がり: 虫をキャッチして見事退治してくれました！'),
  ('9b94ee81-7c75-51ee-8918-6791036d7ed5', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2022-05-19', '16:30:00', null, '通常', '「高尾山ケーブルを動かす」と言っていました！ 考えてくれたゲームの内容が不完全だったので、こちらから質問して徐々にゲーム内容を固めていきました。プレイヤーが車掌になり、乗客のために扉の開閉をコントロールするゲームだそうです。 ゲームの内容で「乗客が挟まらず、いい感じのタイミングで扉をしめたら得点が入る」というのがありました。プログラムが難しくなりそうだったので、今日はここだけ取り出して考えてみました。20分ほど時間をとって私も一緒に考えました。 スムーズで自然な扉の開閉が再現されていたので驚きました。「中にはいったときにすぐ閉じると点数が入る」だと、プログラムの仕方に困っているようでした。なので、逆に「入っている途中に扉に挟まれたら減点する」という考え方を提案しました。 扉にずっと当たっていると点数が減り続けてしまう問題が生じました。色で判別＆点数を引いたあとある程度時間をおく という工夫をしてうまくプログラムを動かすことができました。 このプログラムは完成しました。来週からは本題に入ってもいいのではないかと思います。スプライトも決める必要があります！', null, 'タイピング: 正解率は94%でした。集中してタイピングできていたので良かったです。
盛り上がり: 約20分間プログラムを考えている間とても集中していました。'),
  ('990f530a-9eb2-5efd-8f33-68b8969b6971', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2022-05-12', '16:30:00', null, '通常 / まゆねこのクローン振り返り 自由作成(テーマ・方向性の整理)', 'クローンを使ったマユネコの復習をしました。前回は未完で終わったのですが、授業後に自分で直してくれたようです。どう直したかは忘れてしまったようです。 時間についてのプログラムが背景にプログラムされていました！前の話がしっかり伝わっていました！良かったです。 自由作成についての話をしました。本人には全くアイデアがなかったので、テーマを伝えました。さらにテーマから連想するといろんな内容につながるという話もしました。モチーフは「電車」みたいです。 アイデア出しについての私の提案があまりよくなかったようです。考えにつまずいてしまう場面がありました。 まみさんのアドバイスを受けてからは、検索ワードの内容が幅広く具体的にピンポイントになったのでとても良かったです。マインドマップを使って考えるのが良いのかもしれません。', '予定ではありませんが、1週間の間にアイデアを考えてくるようにお願いしました。', 'タイピング: はじめの方に続けてミスタイプをしてしまったので、ミスタイプ率は20%と高かったですが、タイプの速さは高かったです！
盛り上がり: 本人曰く、アイデアだしはかなり苦手。
備考: 思考方法に苦戦しているように見えたので、マインドマップの作成を冒頭だけ一緒にやってみました。 取り扱いたいテーマは「電車」、その中でも特に興味があるのは「車掌の業務」、さらに「乗車中の業務」を取り扱ってみたいと進めていました。職業調べなどでも調べたことがあるそうなので、これまで調べたこと、遊んできたゲームなどから、ひいろくんが考える業務の効率化などを考えてみてもいいのでは… （おおはら）'),
  ('5e9b927f-b3c2-556d-bb13-90cc8e275ecb', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2022-04-28', '16:30:00', null, '通常 / 細分化の練習 「～へ向ける＆〇歩あるかす」と「〇秒で～～行く」の使い方 時間に余裕があれば、先週の振り返り（クローン）', '細分化は正確に書けていました。ゴールするのにかなり苦戦していましたが、細分化の表に記載するため繰り返し挑戦してくれたようです。 あるくんの動かし方で悩んでいました。「〇秒で～へ行く」と「～へ向ける」を併用して工夫してくれましたが、納得のいく動き方ができていないようでした。向けるが使えているのが良いと伝えると、「〇歩」を追加してきれいにプログラムしてくれました。「～へ行く」と「～へ向ける＆歩かす」の違いがなんとなく伝わったようです。 黒色で跳ね返るところで困っていました。いろいろな考え方を試してくれていました。正解のプログラムをしてくれていましたが、歩数を戻すところでミスがあり（-2歩のところを-1歩にしていた）うまくいっていなかったようです。注意力を上げていきたいです。 時間があったのでマユネコに挑戦しました！（細分化はしませんでした） クローンの使い方はなんとなく覚えてくれていたようです。ランダムな場所に出現させるところは問題なくできていました。 試して繰り返し挙動を確認してくれていました。 ゲームが終わったときに最初の状態に戻らないと困っていました。いくつか方法を紹介しました。時間が少なく、完成に至りませんでした。クローンの挙動自体はできています！', null, 'タイピング: 正答率96%!!速さは2.3タイプ/秒でかなり早かったです！
盛り上がり: 初めてゴールについたとき「着いた！！」と報告してくれました！嬉しそうでした！ そうたろうくんとまみさんのお話にちょっと参加してました。慣れてきてくれたのかな？ メッセージやファイルの名前、喋る内容をいつも面白くしてくれます。'),
  ('deb09a0d-3a8f-5f94-a8f5-5573b1ae5ece', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2022-04-21', '16:30:00', null, '通常 / プログラムの整理の仕方 「ビルのすき間」を通してクローンにふれる', '前回完成した射的ゲームのプログラムの、ブロックの置き方についてアドバイスをしました。ゲーム全体に関するプログラムは背景の方においた方がいいのでは、と提案しましたが、イマイチ本人の心に響いていない印象でした。繰り返し伝えていく必要があると思います。 「ビルのすき間をぬけよう」を作りかた動画をみつつ作成してもらいました。動画をほぼ進めることなく進めていました。動きがはやい！ 終えてプログラムが完成したあと、クローンを使って新しい作品を作ってもらおうとしましたが、アイデアもなく、イマイチ理解が進んでいなかったようなので、「DKアート うずまき作品」を見せて、これに似たものを作ってもらうようにリクエストしました。 いろいろ自分でいじってもらったものの、見本のようにはうまく作れていなかったので、考え方を一緒に整理しました。「中心にいるのが本体でクローンが動いてる」ということを確認し、この状況をたとえると「砲台が回って球が出てるよね」とまでいくと、スムーズに手を動かして作ることができました。その後、自分なりに見た目に関するコードを足して楽しんでいました。', null, 'タイピング: 様子：ミスタイプ率が14%ほどでした。ホームポジションからずれてしまっているのでもったいないので、ホームポジションについての話をしました。
盛り上がり: 考えを整理するときにかなり真剣に取り組んでいました！'),
  ('6da6cf4d-c954-5446-8be6-eae7954789a5', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, null, '2022-04-15', '16:30:00', null, '振替え / 射的ゲーム応用にチャレンジ 検定の2級を受けたいという目標もあるので、いろいろなパターンのゲームを見て作れるようになる', '昨日作成の射的ゲームを、説明しながら見せてくれました。本人なりに満足できた出来のようです。 昨日のゲームをさらに進化させるか、新しいゲームに挑戦するか選んでもらったところ、新しいほうがやりたいとのことで、応用にチャレンジ。 ゲームで遊んでから細分化をしました。3つの変数の設定にも着目できました。背景の動きなど、細かいところもよく見ています。 「○○キーが押されたとき」と、「ずっと～もし○○キーが押されたなら」の違いを説明しました。 ほぼ自力で完成させることができましたが、「～まで待つ」「もし～なら」の使い分けに多少迷うことがあります。 ゲームの構成を把握するのはよくできていて、本人もどちらかというと得意とのこと。 乱数や変数は問題なさそうです。風船の出現タイミングも乱数でアレンジしていました。 ゲーム自体は動いていますが、変数定義の位置がスマートでないところがありました。最後に急いで完成させたせいかと思われます。', '今回のコードを見直して、微妙な箇所を修正できたら新しい課題に取り組む予定です。', 'タイピング: 5分間は疲れたようでしたが、正答率85%で終えたのはすばらしい！ タイピングはよくできていますが、検定としてはあまり興味はないそうです。
盛り上がり: 「ちょっと難しかった」との感想でしたが、時間内にゲームとして完成させることができました！ 背景のグラデーションが変化しているところ、風船ゲットのスプライトが点滅しているところなど、よく気づいて設定できていました！ ゲームの内容や構成を把握するのが得意？と問いかけたら、少し嬉しそうにしていました。'),
  ('7717b172-64cb-5f73-a67f-652866a03c2e', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, null, '2022-04-14', '16:30:00', null, '通常 / 今年度からブラッシュアップの内容をするのを楽しみにしている面もあるので、今週射的ゲームでこれまでの復習をしたうえで、問題なければ来週から少しずつブラッシュアップの内容に入っていくことを伝え、モチベーションを維持させる方向で…', 'まず今年度は「クローンとか定義に挑戦するよ」ということを伝えました。まだ自分ではさわったことがないようでした。 射的の細分化に挑戦してもらいました。細かく丁寧に伝わりやすく書かれていたので素晴らしかったです。 途中、玉が発射された後銃の位置に戻ったもののそのまま留まらず、困っていました。ピンポンゲームのパドルを引き合いにだし、マウスのx座標だけではなくて「ｘもy座標も一緒にする必要がある」ことを伝えました。 「～ではない」を使うことに慣れている様子でした。また、見本では残ってしまっていた端についた玉もきちんと見えなくなっていて、細かくプログラムできていました。 的のプログラムについても、残り時間が少ない中で必要なブロックを的確にもってきてくれました。乱数の使う位置が見本と違ったため、見本とひいろくんのプログラムの考え方の違いを説明しました。なんとなく分かってくれたようで良かったです。', null, 'タイピング: 左手がホームポジションからちょっとずれてるのが気になりますが、かなり早くタイピングできてると思います。（正答率：90％）
盛り上がり: ばったの目の位置について話題になりました。'),
  ('439778a5-9f03-57a1-a7b4-f14df4c9a640', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, null, '2022-06-09', '17:30:00', null, '休み', null, null, null),
  ('b63b61fc-ef6b-5dbf-994b-09517d3abebf', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-06-02', '17:30:00', null, '通常 / オリジナル作品の続き 混乱したら紙に書き出す ドット絵', '今日は、主に場面転換と敵と挙動のコードを作りました。 場面転換のコードは、転換中に主人公のスプライトを止まるようにしたいとことでした。最初は悩んでいましたが、変数を使って転換中のオンオフ作るといいよとアドバイスをしたところ、スムーズにできていました。また、場面転換を起こす条件は「端に触れる」ではなく「座標」を使ってほかのバグが起こらないようにしていたのがよかったです。 敵のスプライトは、乱数で不規則に移動するのは良かったです。残影が残るようスムーズな動きに工夫されていました。 全体的に、何か不具合が見つかっても自分で修正できることが多かったです。 来週は、敵を上から踏んだ時と、横からあたった時で違う動作をつけてたいといっていました。', null, 'タイピング: スコアもよくスムーズにできていました。
盛り上がり: 敵のイラストは主人公の丸い形と対照的に四角くなっているのはかっこよかったです。'),
  ('b8eef84d-4183-5459-8d60-35cfaef703c2', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '5cfbd637-17cd-5e1f-9521-1dae0dcfd527', '2022-06-09', '17:30:00', null, '通常 / オリジナル作品 全体の内容相談、コース作成、アイテム', 'すごろくゲームにするそうです。出た目や着いたマスでイベント・ハプニングが起きるそうです。 すごろくの目を出すのに、コスチュームがランダムに出で、サイコロの目をスプライトが言うプログラムを作りました。 もしのときにずっとを使うのを忘れてしまうようです。もしの中身のプログラムに気を取られてしまうようです。 スペースキーを押して再びサイコロが止まるようにするために、すこし複雑なプログラムになりました。プログラムの読み方について共有できたので良かったです。 スプライトに変数を喋らすときに、「～と～」を使うと言葉と変数を同時に話せることを紹介しました。', null, 'タイピング: 両手を使ってプログラムできていました！早いのですが、ホームポジションが意識できていないので、声をかけていきたいです。
盛り上がり: 来週はマス目を作れたらいいなと話しました。 明日から移動教室みたいです！！楽しみにしてました！'),
  ('fd778d2d-cf36-5868-b432-7e6601cfd87d', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-26', '17:30:00', null, '通常 / コンテスト作品作成 ゲームの世界観を意識しながら 細分化など', 'うまくいかないときに自分でブロックを外して検証できていたので良かったです。（やまと） 「または」を使ってくれました。何を「または」にいれるのかを筋道立てて考えられていたのでよかったです。かなり学校でも使っているそうです（やまと） これまで既存のキャラクターを使うことが多かったため、最初はキャラクターをどうしていいかわからないと言っていました。 ゆきちゃんが丸だけで描いたキャラクターを気に入って、同様に自分で描いてからは作成に意欲が出たのか、集中して取り組んでいました。 クローンを使って残像を残して進む自キャラクターと、道中にあるブロックの作成までができていました。 ブロックのスプライトを複製で増やすと、「スプライトに触れた」判定をするための演算式が「または」でつながって長くなるのが面倒とのこと、色判定などほかの手段も提案して検討してもらっても良いかもしれないです。', null, '盛り上がり: 学校で作成していたものを見ながら説明してくれました。初めてオリジナルキャラクターを作成して、嬉しそうでした！
備考: 最近少し遅れることが多いです。お母さんのお仕事の都合で、お迎えが遅いようです。 学校でかなり作成しているらしく、できれば並行して進めたいとのことでした。'),
  ('3fbb1596-ba06-5e5b-b9a6-2b2c67ca7c49', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-02', '17:30:00', null, '通常 / オリジナル作品 コース作成、アイテム、オープニング画面？', 'ゲームのオープニング画面を作成しました。 座標や回転などを駆使して、楽しいタイトル画面を作成していました。 イメージがはっきりしているので、少しだけ紙にかいたあとは、自分で色々試しながら作成できていました。', null, 'タイピング: 学校でランキングを競っているとのことで、3回ほど練習していました。お得1230円でした。
盛り上がり: ムービーのようなもののイメージはとてもしっかりしているゆきちゃんなので、黙々と自分のイメージを形にできていました！
備考: 学校で【再共有】Sling Drift/スリングドリフト ✧日本語版✧https://scratch.mit.edu/projects/619837622/editor/が流行っているそうです。'),
  ('9801b538-48bd-5144-820a-fd1c4610e266', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-19', '17:30:00', null, '通常 / コンテスト作品作成 方向性が決まっていなかった場合は、ゆきちゃんと話しながら、作りたい仕様（対戦、ストーリー、育成など）を話し合わせても 先生と二人で作り込まず、お互いの作品を見ながらブラッシュアップしていきたい', 'ゆきちゃん同様、作りたいゲームがありすぎて悩みましたが、ゆきちゃんとは違うものを作りたいということで、プラットフォーム系のものを作成することになりました。 マリオのように、背景が変わっていくようなゲームを作りたいそうです。', null, '盛り上がり: 久しぶりだったせいもあるのか、作りたものがありすぎてたまらない！といった感じでした。 アイディアは頭の中でできているそうなので、次回以降それをアウトプットしていければというところです。
備考: 「音ゲー [極ノ深淵] Ver.2.0」https://scratch.mit.edu/projects/577015874/と最後まで悩んでいました。 「ドラえもんのお約束」https://scratch.mit.edu/projects/413188727/で遊んでいました。クラスで流行っているそうです。'),
  ('233da02d-7cbf-5250-8929-bf7ec8f588e7', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-05-26', '17:30:00', null, '通常 / コンテスト作品作成 レースゲーム作成 DKゲーム氷の上のレース参考', 'レース系のゲームを作るために、上下に動かすコースに提案しましたが、参考にしているマリオカートのゲームのようにコースを曲げて動かしたいといっていました。なので、次回までのできるだけそのゲームを解析をして、伝えられたらいいと思う。 動かすキャラクターを作りました。左右に動くときに目の方向も変わる工夫もとてもよかったです。2pの方を色も鮮やかに変えてかわいかったです。 動きのコードを作るときも最初は、イベントの〇が押されたときのコードを使って作ろうとしていましたが、前までにやったもしの条件を使った方法でヒントを与えたら、スムーズに作ることができました。 次回は、コースつくりとアイテムなどを作っていけたらいいと思います。', null, 'タイピング: 先週よりもさらにスコアが伸びて、知事クラスになっていました。
盛り上がり: 承太郎くんがキャラ作りに悩んでいた時に、話し合ってアイデアを出してくれました。 スプライトが左右に動くときの動きをもう少し変えたいとのことで、目の動きを提案したらとても喜んで作成していました。（大原） コスチュームを色違いでたくさん作ったので、最初に色を選べるようなオープニングを作ってみたいそうです。（大原）'),
  ('027992ab-dd8c-513a-a5d3-f1d43f102470', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-19', '17:30:00', null, '通常 / コンテスト作品作成 方向性が決まっていなかった場合は、承太郎君と話しながら、作りたい仕様（対戦、ストーリー、育成など）を話し合わせても 先生と二人で作り込まず、お互いの作品を見ながらブラッシュアップしていきたい', '承太郎君と話しながら、最初は「音ゲー [極ノ深淵] Ver.2.0」https://scratch.mit.edu/projects/577015874/を作りたがっていましたが、曲の著作権の説明をしたところ、音楽系は諦めていました。 カート系のゲームを作りたいとのことで、自分のキャラクターとアイテムについて、細分化を始めたところです。 コースの背景やアイテムを八王子に関連付けられないか、検討していました。', 'Scratchで作成した分を、保存しないでタブを閉じてしまったようで復元できなかったため、次回はアルスパークに素材をインポートしておいてから始めさせたいです。', 'タイピング: 先週よりもスコアも打鍵スピードも上がって頑張っていました。同じものやり続けて慣れがあるかもしれないので、ほかのタイピングもしてもいいかも。
盛り上がり: もともとゲームのアレンジからの発想が得意なので、どんなゲームを作りたいかを考えてからゆきちゃんの世界観をお話にしていくよう促したら、ゲームの方向性がみえてきたようでした。
備考: 「マリオカート8デラックス」https://scratch.mit.edu/projects/244287057/を参考にしています。 承太郎君と、「ドラえもんのお約束」https://scratch.mit.edu/projects/413188727/で遊んでいました。クラスで流行っているそうです。'),
  ('0699439c-c75f-54d5-ace2-dc4200dde5f8', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, null, '2022-05-12', '17:30:00', null, '休み', null, null, null),
  ('d0aa45ec-02f5-57b9-9d35-9bb6d958c437', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-04-28', '17:30:00', null, '通常 / 星取りゲームのアレンジ', '犬が星を全部取ってロケットに向かう時の、犬の動作と大きさを変えるコードを追加しました。手が止まることがなく、スムーズに行っていました。 このコードを作った後、星が表示されないバグが発生しました。バグ解消のために、本人自身考えても行き詰っていたので、次のことを指摘しました。星の出現する場所が端に触れてしまい、端に触れると隠すコードがダブっていてうまくいきませんでした。本人が星の出現する座標を勝手に変えていたことが原因だったのかと思いました。 星が取れなかったときのメッセージが上手く作用しないバグも発生しました。一緒に考えても解らなかったので、発動条件となる「端に触れたら」から座標の位置で判別するように提案してあげました。だが、その位置の条件を不等号では＝でやってしまい、上手くいきませんでした。最後の最後でヒント上げて、なんとか修正することができました。得点とかの不等号の使い方がまだわかっていないのかと思いました。', null, 'タイピング: 正答率は高いが、左手をあまり使わず、右手だけ売っている場面がありました。
盛り上がり: 上手くいかなくなった時、まさきくんのゲームで気晴らしすることができました。'),
  ('febfb202-528a-52ac-a3bf-f9bf816973f9', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, 'a7e5839c-3699-5447-b96d-16e04b073a59', '2022-05-12', '17:30:00', null, '通常 / 基本操作コース10 キャッチゲーム きりのいいところで自由作成', 'コインを上端にランダムで配置する際に、乱数のコードを持ってくることはできたが、ひだ端から右端まで、どうやってやるか悩んでいた。まみさんの助けもあって、スプライトの実際にその場所まで持っていて座標の位置を確認することで解決できた。 落ちる動きのコードを作る際に、何秒で移動するコードを使わないように提案したとところ、落ちるってことは何が変わっているか問いただしたら、自ら手を進めて適するコードを作れた。 自由製作でテーマを決める際に思った以上に悩んでしまった。テーマからマインドマップで連想させていくことで、アイディアを広げることはできた。広げていく際に、自分の実体験から引き出していくのもいい感じだった。', null, 'タイピング: 前回よりもスコアをよりよくなっていた。指使いは右手はバランスよく使えていたが、人差し指に頼りがちの場面があった。
盛り上がり: ゼロから作っていく際に参考例を見せたらハードルがさがったみたいで、考えがよく出てきた。'),
  ('4adfcfb0-3a4e-56ac-aa9b-74b2ec88f730', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '5cfbd637-17cd-5e1f-9521-1dae0dcfd527', '2022-04-28', '17:30:00', null, '通常 / 基本操作コース09 ジャンピングゲーム応用 一覧表の応用アレンジをクイズ形式で ①プラスの弾とマイナスの弾をランダムに出す ②スコアではなくメートルを競うパターンにする ③背景の動き ④衝撃を受けた雰囲気', '①乱数を使うことはすぐに思いつけた様子でしたが、乱数をどこで使えばいいのかに困っている様子でした。「〇秒待ってから発射させたらどうか」と提案したところうまくプログラムすることができました。スプライトの非表示・表示についても正確にブロックを置けていました。 ②秒速がわからないとプログラムしにくいと思ったので、「１秒で1m進む」というようにこちらからリクエストしました。「ずっと」を置いたあと、プログラムが止まったときにカウントも同時に止まるのかについて自分で考えられていました。 ③自分で考えるのは難しく残り時間も少なかったので、見本のコードを見せ、コードの意味を説明してもらいました。同じスプライトが2コあること、2コ動くことで背景が動いているように見えることを説明してくれました。左に行き切ったのち、右に戻ることも一緒に確認できました。 ④アレンジの内容に迷っていましたが、隣の人のアドバイスを参考にしたりコスチュームを変えたりして考えてくれました。こける挙動にしてくれました！タイミングもばっちりでした！', null, 'タイピング: 正答率、スコアともに高かったです！小指が使えるようにアドバイスをしました！
盛り上がり: 集中して取り組めていました！ ・隣にいたせいくんと情報共有する場面もありました！'),
  ('59c6bcfe-53bc-5889-826d-89ed8607e534', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2022-04-21', '17:30:00', null, '通常 / 星とりゲームに挑戦する（変数に注意） アレンジを楽しむ', '前回、うまく星がカウントされなかった事象を改善しました。ブロックでスプライト名を選択するときに、存在するはずのないスプライトの名前を使っていたので指摘しました。また星のカウントが適切に動かないこともあり、かなり一緒に考えました。 複雑な動作も筋道を立ててプログラムできていたので良かったです。 自分でプログラムのミスを見つけるとき、「数撃ちゃあたる戦法」で偶然にそのミスが改善されてしまうこともあるので気を付ける必要があると感じました。「他の人のプログラムを見て指摘する」みたいな練習をする必要があるかなと思いました。 犬がロケットにいくプログラム、ロケットが上に行くプログラムも作成しました。ロケットの回転こそありませんでしたが、犬が消えたり自然に動かしたりができていたのでとてもよかったです！', 'アレンジの続きをする予定です！（拡張機能とかも使うと面白いかも）', 'タイピング: ホームポジションからずれてしまっていたのが気になりました。正答率は高かったのですが、今後も少し注意していきたいと思います。
盛り上がり: 集中して取り組めていたのでよかったです！とくに後半は楽しそうにやってくれました！'),
  ('feef3712-0a0e-5e0a-8fd5-2f11c722f7e8', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '226b66a2-5b98-5f7c-ab61-7de9f495d62d', '2022-04-21', '17:30:00', null, '通常 / 基本操作コース09 ジャンピングゲーム応用', 'あたるとゲームオーバーになるビームと、ポイントをゲットできるビームを作成していました。自分がやりたいアレンジの形が明確で、しっかりと説明してくれました。 得点を下げるときに「もし」のところに「ずっと」を使うのを忘れ、困っていました。何かブロックが足りない旨を伝えるとすぐに気づいてくれたので良かったです！ 学校で友達が使っているのを見てやってみたかったという音声合成を使って、ゲームオーバーのときの音声を作成していました。 キーによってジャンプの高さを変えたり、ゲーム開始時に操作説明を出したりと、工夫が見られました。', null, 'タイピング: 左手が苦手なようですが、じょうたろうくんと楽しそうにやっていました！'),
  ('0f9c2330-db9c-59e7-91dd-301943383293', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2022-04-19', '17:30:00', null, '振替え / 「～まで待つ」/「~ずっと」「～もしならば」の使い方を再確認 （時間があれば）細分化に挑戦', '前回の続きのキャッチゲームクリア画面の作成をしました。前回うまく画面が表示されず終わったのですが、自分なりに考えて（「～まで繰り返す」を応用！）成功することができました。メッセージを使ってくれたのですが、タイムラグがその分発生してしまうことも説明し、見本の方法も紹介しました。 星取りゲームの細分化をしました。「犬が取り逃したらプログラムが止まる」など、細部が抜けている部分がありましたが、自分がプレイしている中での操作やモノの動きなどはしっかり描かれていました。抜けている部分は、自分がプログラマーになっているつもりで想像力を働かせる必要があるかもしれません。 犬、星の動きともに問題なく進みました。集中力がとても高かったです。 獲得した星のカウントがうまくいきませんでした。時間もなかったので次回に持ち越しです。', '星の動きのカウントがうまくいきませんでした。次回の授業でまた挑戦しようと伝えました！', 'タイピング: ミス率は7％、1.9タイプ/sでした。左手があまり積極的に使えていないので、こちらから声をかける必要があると感じました。
盛り上がり: 星とりゲーム作成中の集中力がすごかったです。声をかけるタイミングをうかがうほどでした。'),
  ('9f7023db-c14c-5a0b-9531-bd1415ab38ad', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-04-14', '17:30:00', null, '通常 / 前回「基本操作コースⅡ08さあ、踊ろう オリジナル作品を作ろう で、いろいろなスキルの理解がかなり深まっているということなので。 今日からスムーズに新しい単元、「③基本操作コース＿09 ジャンピングゲーム」いきましょうか。 その際、可能な範囲で細分化させてみてください。どれぐらい細分化できるかみていきましょう。もし、できなかったら、一緒に話をしながら細分化の方法をイメージできるように併走してあげてください。', '長いストーリーやゲームを作ることを目標としているため、細分化の必要性もよく理解して取り組んでくれました。 初めて用紙を使った細分化をしてもらいましたが、よく書けていました。 日本語で書いてくれたので、この動きをするためにはどういうコードを使っているかとの問いかけに対し、 しっかりとScratch上の動きで書くこともできていました。 これまでの経験がきちんと生きていて、テキストを進める前に、最初の座標の指定やスクリプトを止めるコードを 自分から作成できていました。 テキスト内容に関しては、ほぼ自力で完成させていました。', 'ジャンピングゲームのアレンジをしてみたいそうです！', 'タイピング: 正誤率94.5％
盛り上がり: 検定の合格証書を喜んでいました！3級にももちろん挑戦する！とのこと。 ジャンピングゲームのアレンジとして、マリオのようなゲームを作りたいとのこと、 スプライトをいくつか吟味していました。上から踏んだらつぶれるようなスプライトも 作ってみたいとのこと。 Scratchで検索したイカゲームで遊びながら、「こういうのも自分で作れそう」と盛り上がっていいました！
備考: 今年度もじょうたろうくんと同じクラスだそうです。'),
  ('c90e87bd-ebd6-580a-8d93-8982dfcb77c9', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, null, '2022-04-14', '17:30:00', null, '休み', null, null, null),
  ('9e8084ed-3deb-5e77-8ff2-65286f6f1a00', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-06-09', '17:30:00', null, '通常 / 自作スプライトの取り込み オリジナル作品の作成', '上のゲームを参考に、ドット絵のゲームで主人公が自由にジャンプや左右に動けて、右から出ていって左から入ってくるステージ移動もしたいそうです。県や斧を使って敵を倒したり、体力もあってダメージも食らうようにすると構成していました。 ただ、今の構成のままだと元のゲームのパクリになるので、本人は嫌だと言っていますがアレンジもう少し考えてきてと伝えておきました。 描くイラストは細部まで色遣いをこだわっていて集中して取り組めていました。 剣や水のイラストは独自の配色をしていてよかったです。 来週からはコードを組み立てていけると思います。', null, 'タイピング: 1つ1つ画面とキーボードを確認しながら、アルファベット打ててスコアも上がっていけました。今後、ひらがな1文字ずつ素早く打てたらいいなと思ってます。
盛り上がり: ゆきちゃんが悩んでいた時、伝えた上げたり、まさきくんがうるさいときに注意をしたりしてよく回りを見えていました。'),
  ('46e0d532-ad5b-5432-9cb3-c245f21b00a1', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2022-06-02', '17:30:00', null, '通常 / 前回の続き（ストーリーを足す） 新しい作品を考える（ドット絵に挑戦してみるのも良い！）', '新作のゲームに挑戦することになりました。本人もかなり意気込んでいました。 スプライト作成のため、8bitを使いました。 まず自分なりにネコを描いてくれていましたが、途中で見本を見つつスプライトを描く方にシフトしました。既存のものを編集して作るそうです。 長時間プレイをしてるとマグマが上がってくるような構想です。 途中、自分のやりたいことが実力と照らし合わせたときに実現可能なのか心配で質問をくれましたが、一緒に頑張ろうと声をかけました！ たくさんのスプライトを作ってくれたので、来週までに具体的にどのようなストーリーのあるゲームを作るのか考えてくるようにお願いしました。 描いたスプライトは色の濃淡さまでこだわっていてすごかったです。(下迫田)', null, 'タイピング: 人差し指が多めのタイピングでしたが、集中して取り組めていたした。
盛り上がり: とても集中してスプライトを描いてくれました！'),
  ('8ba9c7e1-19a3-5fff-9a32-762f93bdfdcc', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, null, '2022-05-26', '17:30:00', null, '休み', null, null, null),
  ('91524f07-c3a5-5c09-817e-25ade273209d', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2022-05-19', '17:30:00', null, '通常 / 前回から作っているゲームの続き（レベルアップさせる）', '前回の続きをしました【何秒後かに扉を出す】と【じゃまものの追加】をしました。 【何秒後かに扉を出す】：出現したあとにすぐに消えてしまい困っているようでしたが、自分で「ずっと」の使い方に間違いがあることに気づき直せていました！ 「もし」と「ずっと」の併用もしっかりできていました。 【じゃまものの追加】使うスプライトにもこだわっていました。既存のスプライトのサイズや色をアレンジして使うのが得意なようです。 こちらが質問するとよりアイデアが出てくるようでした。質問から独自のアイデアが出て、実際に作品に取り入れられていました。 扉につくと、ゲームがすべて止まる設計になっていて良かったです。 じゃまもののナイフを回転して弾を防ぐのがいいアイデアと思いました。最後になって、たくさん増えてて驚いたが。', null, 'タイピング: 両手を使って集中して取り組めていたので良かったです！
盛り上がり: 最後に進捗発表会をしたときに披露してとても楽しそうでした！ 高評価をもらえたのも嬉しかったようです！ 複製してゲームを難しくするのが面白かったようです。'),
  ('9876094a-c7fa-59d2-94a1-7ef97c9eb90a', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-09', '16:30:00', null, '通常 / オリジナル作品 続き 海の中でサメが登場してからのアルくんとアルごんの動き 今後の展開を考えながらゲームを入れるかストーリーを続けるか相談', 'サメが出てきたあと、アルごんを自分で動かしてサメから逃げるゲームを作成していました。 座標はよく覚えていて、○○キーが押されたときの後は、正確な座標と数値を自分で入力できていました。 矢印キーでスプライトが動くようにしました。「もし○○キーが押されたなら」を一つ作成して複製することを学習しました。4つのキーについて作成したら、自分から「ずっと」を持ってくることができていました。', 'コンテスト作品はゲームが作りたいとのこと、ベースは射的ゲーム＿応用だそうです。 風船の代わりに鳥をゲットしたいそうです。 余裕があれば、自宅でもゲームの内容について少し話してきてもらうようお母さんにお伝えしました。', 'タイピング: かわべの竹林第三話クリア！ かなり慣れてきて、「こいつよわ！」と言いながら取り組んでいました。 アルファベットのタイピングはだいぶスムーズになりましたが、たまに出てくるローマ字入力は同じ文字が連続で出ない分、難しそうでした。それでも、今日のステージをこなしていくうちに、みるみる上達していました！ 「i」「l」の見分けに少しとまどっていました。 文字の形の覚えは早く、大文字との違いがわからなかった小文字も一度教えると大体できるようになっていました。
盛り上がり: タイピングの上達が実感できてきたようで、とても楽しそうに時間前から取り組んでいました。 座標についてはほぼできています。本人も得意げに説明してくれました。'),
  ('d0328722-31fc-5d61-9dad-c3f7eb1f69a7', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-05-12', '17:30:00', null, '通常 / きりがいいので、自由作成から（コンテストとは伝えず） 簡単な設計書を書いてみる', '自分でイチから作るのは好きなようです！「デスゲー作る！」と意気込んでいました！ 計画書はスプライトを作ってから製作したいようです。イメージがわくそうです。 計画書はあまり積極的にはかけず、こちらから質問してから書いてもらうことが多かったです。 「おいかける」という事象をプログラムするのに苦労していました。実際に追いかける場面をイメージしてもらって、「追いかける人の方に体をむけてから」「歩く」の2点を確認しました。少し時間はかかりましたが、自分でプログラムすることができたので良かったです！ 「もし」を使うときに「ずっと」を忘れてしまうことがありました。 あるごんの動きがカクカクしていたので、プログラムに再び挑戦してもらいました。最初は分からない様子でしたが、他にもあるごんの動きを制御する方法があったことを伝えると、完成させることができました。今までスプライトの動きの違いに注目したことはなかったようです。 来週にもしたいアレンジが頭の中にはある（ゲームクリアの演出など）ようですが、計画書に書くことはできませんでした。', null, 'タイピング: 時間はかかりましたが、正誤率が高かったです！1年前からタイピング速度が約2倍になっていました！
盛り上がり: イチからプログラムしてイチからゲームを作るのはかなり好きなようです！ Ctrl+CとCtrl+Vを教えました！何も言わず使うと「教えて！！」と頼まれました。'),
  ('6d46f628-999a-5951-9031-ba98e75ce3d0', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-02', '16:30:00', null, '通常 / オリジナル作品 続き', '前回までは〇秒待つが気に入っていましたが、それだけでは話の流れが制御しきれないことに気づいたらしく、今日はメッセージを多用していました。 海の中に入った時の動きをゆっくりしたり、向きを変えたりと、こだわりをもってスプライトを動かしていました。 コスチュームを繰り返してサメの口がパクパクするコードなどは、自力で作成できていました！', '海の中でサメが登場してからのアルくんとアルごんの動きを作成予定です。', 'タイピング: 復習がしたいとのことで、たいぴんぐ道場をしてからかわべの竹林ステージ2に進みました。 新しいキーが出ると焦りますが、ステージの間にどんどん覚えていっていました。 かわべの竹林第二話をクリアしました！
盛り上がり: タイピングは練習するたびにキーを覚えてスコアが上がるのが楽しいようで、一生懸命取り組んでいました。 ただ、手がまだ小さいのでホームポジションに指を置いておくのは厳しそうです…。 今日はようやく新しいキャラクターを登場させることができたので、嬉しそうでした。 途中から登場するスプライトの表示非表示などはよく覚えてできていて、そこを褒めると「このくらい当たり前でしょ！」と得意そうでした。'),
  ('f3921a5e-fd7e-547e-9ab1-7f178cb8efb9', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-04-28', '17:30:00', null, '通常 / 座標の使い方を復習する 見た目の変え方のタイミングを考える 星の動きをキャッチゲームの復習をしつつ考える', '星の動きとゲームクリアをプログラムしました。 星の動きは「キャッチゲーム」のコードを参考にして作成していました。途中、y座標の設定にミスがあり星が落ちてこない現象がありましたが、自分で探して原因を究明できていたので良かったです。 星の数をかぞえる方法がなかなか思い浮かばなかった（今まで主に変数を得点として考えていたようです）ので、変数を使ってカウントをすることを提案しました。「星の数=20」だとうまく働かないことを覚えていてくれて、不等号をしっかりと使いこなせていたのでとても良かったです。 ゲームクリア時は見本では宇宙船に行くのですが、音声合成を使いたかったようなので、犬に「ゲームクリア―」と喋らすことにしました。「星の動きも止めてほしい」というリクエストにもこたえてくれました。 ゲーム自体のプログラムはほぼ終わった印象です。', null, 'タイピング: しっかり取り組めていました！ミスタッチはまだ多いようです。
盛り上がり: となりのゆきちゃんと情報交換（せいくんがアドバイスしたり、音声合成について聞いたり）をしていました！ 集中して取り組めていました！'),
  ('33533cff-264e-5402-b925-cfb785b43403', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-26', '16:30:00', null, '通常 / オリジナル作品 続き 場面が海中にかわってから 秒数での切り替えとメッセージや背景での切り替えの使い分け', '座標を使った画面内の細かい動きと、コスチュームのアレンジをしました。', '引き続きストーリーの先を作成していく予定です。', 'タイピング: たいぴんぐ道場で練習してみました。丁寧に指使いを覚えようとしています。 前回クリアできなかったかわべの竹林の最終ステージをクリアできました！
盛り上がり: 一つ進めては、毎回丁寧にチェックをして動きが自然になるように確かめていました。 作りたいストーリーができているので、それをスムーズに表現できるよう自分なりに試行錯誤して進めることができていました。 タイピング中段の人差し指、中指はだいぶ覚えてきて、とても楽しそうに取り組んでいました！
備考: 運動会は6月4日だそうです。 今度の週末はキャンプに行って、マス釣りをするそうです！'),
  ('6f143ada-d704-5ad3-bc2e-0b58a5bb718d', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-19', '16:30:00', null, '通常 / オリジナル作品 続き ボールの動き', '背景の変更と条件分岐、コスチュームの変更、メッセージの送受信、座標の指定、角度による向きの指定など、自分で覚えていて、試行錯誤しながらも想定した動きを作成することができていました。 初めて「最前面」を教えました。「これこれ！」と喜んでいました。', '場面が海中に変わってからのストーリーを作ります。○秒待つを使ってストーリーを組み立てていくのが好きなようですが、そろそろ会話が多くなってきたので、適宜メッセージの使用も提案していきます。(メッセージの使い方自体はそうちゃんも理解していて使用もしています)', 'タイピング: 初めてタイピングにチャレンジしました。かわべの竹林ステージ3はクリアできませんでしたが、とても楽しいとのこと。 毎回少しずつ練習することを目標にしました！
盛り上がり: タイピングはとても楽しかったようです。 一度教えたことは基本的に身についていて、活用することができているのがすばらしい！'),
  ('d8d6ae59-4f4d-528b-ba6e-985ebe772323', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-12', '16:30:00', null, '通常 / 「③基本操作コース＿08 さあ踊ろう」またはドリル、後半自由作成 「さあ、踊ろう」の内容は、「物語を作ろう」でもいくつか取り上げたので、オリジナル作品作成にハマらなければ短時間で終了するかと…', '棒人間を並べて楽しい作品を作っていました。 コスチュームの切り替え、繰り返しなどは良く覚えてできていました。 オリジナル作品を作ろう、と持ち掛けたところ、生き生きとストーリーを語ってくれました。 ストーリーの流れは私が記述しましたが、私の手元を見て嬉しそうに一緒に読んでいました。 ストーリーの内容としては、「スポーツ」「対戦」「未知の敵との闘い」あたりが当てはまりそうです。', 'アルファベットはわかるとのことで、ココアタイピングを始めてみます。 ボールが海の向こうにとんでいって小さくなるところから作成します。', '盛り上がり: ストーリーを考えることが好きなので、とても楽しそうに取り組んでいました！ 行動のきっかけを細かく秒で設定するのが好きなようです。'),
  ('fe4da5b6-7054-52ec-96a6-927ffb0b2e0e', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-04-28', '16:30:00', null, '通常 / 「③基本操作コース＿07 ピンポンゲーム」ゲームクリア作成 演算式、ドリルに挑戦', '足し算を例にして=の説明をしました。=の演算式の使い方は納得できたようでした。 ゲームクリアしたらボールがゴールに移動して止まる、というアイディアを形にすることができました！ 「かち」スプライトを表示したらボールをゴールに動かしたい、ということで、以前の「雪合戦」作品で使ったものを思い出すよう促したところ、メッセージを使うことを思い出して作成ができました。 ピンポンゲームが完成したところで残り20分だったので、ファイルの一覧表を見せながら「今までこんなにたくさんのことを勉強したので、どのくらい覚えているか試してみよう」と声掛けをしてみました。初めは「テストみたいで緊張する」と及び腰でしたが、今までそうちゃんができていたことだよ、と実際の問題を見せたら、「これならやってもいい」とチャレンジしてくれました。 問題を音読してもらってから作成、という手順で進めました。「向き」の初回で説明を入れましたが、それ以外はノーヒントでクリアできました！1問クリアするごとにスタンプを押したら喜んで、時間いっぱい使って4問目まで進めました。', null, '盛り上がり: 自分のアイディアを、これまで習ったことを活用して形にすることができました！お母さんにゲームをしてもらえて嬉しそうでした！ 2ケタ＋2ケタの算数ができます。 ドリルはやってみたら「クリア」がはっきりしていること、スタンプがもらえることでモチベーションが上がっていました。 定期的に取り組んでいけるかと思われます。単元ごとに小さなシールなどがあると目標になるかも…'),
  ('d4508be2-52f1-50af-b3b6-1b75bd37297c', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-04-21', '16:30:00', null, '通常 / 前回の見直し 新しいことを覚えてまた続きに戻ることを了承するようなら「③基本操作コース＿07 ピンポンゲーム」', '最初は「難しそう」と躊躇していましたが、「できる！」と説得して始めました。 ゲームに必要なスプライトは自分で理解して準備することができました。 パドルの操作はどうしてもキーボードでやりたいとのことで、そちらで作成しました。 「もし～なら」を使うというのは自分で見つけられました！「ずっと」を使う必要があることも、自分から言い出していました。 分度器を見せて、角度の説明をしました。さすがに乱数の部分は今日は飛ばし、「170度まわす」で設定しました。 ゲームオーバーについてはこちらが問いかける前に「もし棒にさわったらゲームを止める」と言い出し、自分で作成できました。 スコアをつけるタイミングについては自分で条件を付けて、ゴールポストのスプライトを通ったら、と作成していました。 変数についてもすぐに理解し、「スコアを1ずつ増やす」「スコアを0にする」ブロックも自分で見つけて自力で作成していました。 最初にゲームをプレイした時点で、頭の中である程度の細分化はできていたようで、「スコアが5になったらクリアにするのはどうすればいい？」と自分から質問してきました。 体験のしょうたくんにゲームを説明する時間をとったため、ゲームクリアについては次回になりました。', '演算式を使ってゲームクリアの作成をする予定です。', '盛り上がり: とにかく勘が鋭いです！変数について説明しただけで的確にコードを作成したのは驚きました。
備考: ポケットに入っていたポケモンのプラスチックのカード？について説明してくれました。 背景に使った体育館と、みなみ野小学校の体育館について一生懸命説明してくれました。 図書室で借りた「おしりたんてい」の本を読んでいるそうです。'),
  ('fd65fb8c-5a66-524e-abaa-094d4c455d69', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-04-11', '16:30:00', null, '通常 / 前回まで「物語を作ろう」やってたので、 まずは、前回までの復習 その後、以下のいずれかな？両方提示して、好きな方やってもらおうか。 ①物語りを作ろうの応用は↓↓以下です。 ②次の単元に進む「③基本操作コース＿07 ピンポンゲーム」', '前回の作品の続きを作りたいという希望により、話をふくらませていった。 メッセージの送受信、コスチュームの切り替えや歩いている動き、背景の切り替えによる イベントの実行などを学びました。 先のストーリーを話しながら自分の中で整理して、コードに置きかえるという作業が自然にできています！ 新しいスプライトを自分で描き始めたところ、とても熱中して立ち上がって描いていました。 全体の流れによって、「〇秒待つ」「メッセージを送る」を自主的に使い分けていました。 スプライトの向きにもこだわっていて、コスチュームを切り替えれば向きを変えられるよね、と質問してきたので、コスチュームの複製と反転のやり方を教えました。コードで向きを変える方法も、折を見て教えていければと思います。', 'このストーリーは、そうたろうくんの中ではまだまだ続くようなのですが、時間を区切って少しテキストを進めても良いかとは思います。「物語を作ろう」の応用内容はほぼできていて、新しく教えたこともどんどん吸収できているようなので…。', '盛り上がり: 自分の思いついたストーリーをスプライトが演じてくれるのがとても嬉しそうで、お母さんにも照れたり甘えたりしながら見せていました。
備考: ポケモンのアルセウスが好きだそう こっそりと、ポケットに入れていた箱のマジックを見せてくれました。'),
  ('8eca069f-e2ed-55a2-a062-03114a1cc14e', 'b2246586-4496-52f9-a825-be2488a00a31', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-09', '17:30:00', null, '通常 / 新しいゲームの製作に挑戦する ランダムワープの迷路', 'いつもの、敵キャラクターから逃げながらスコアがたまるまで特定のスプライトに触れる、というゲームを作成していました。 スコアが1000点になったら新しいスプライトを4つ出す、10000点になったらすべてを止める、という動作を、演算式やメッセージを使って作成することができました。 演算式の不等号の向きが違い、ゲームがスタートと同時に止まる仕様になっていたときは、Scratchの不具合だと勘違いして癇癪をおこしかけていましたが、不等号の説明をしたらすぐに納得して作成しなおしていました。', null, '盛り上がり: 使えるコードが増えてきたことは楽しそうでした。 癇癪をおこしかけても、説明を受け入れておさめることができていました。'),
  ('87a30001-431f-597d-9016-7920f9e3381a', 'b2246586-4496-52f9-a825-be2488a00a31', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-02', '17:30:00', null, '通常 / 新しいゲームの製作に挑戦する ランダムワープの迷路', '以前作りかけていたジャンプゲームのようなものを作るとのことで、自分でテキストを見ながら作成していました。 ジャンプが真上ではなく斜めに跳ぶようにしたいとのことだったので、真上に跳ぶのはy座標だということを確認したら、自分からx座標を同時に変えることを思いついていました。 ジャンプが思い通りにできたら満足したようで、その後は「完成まで見ないで」と言いながら、背景やコスチュームがスペースキーで変わっていく作品を作っていました。', null, '盛り上がり: 作品の発表会をとても楽しみにしていました。'),
  ('9b80e1f5-63fd-5116-9513-7b1b9f2d4027', 'b2246586-4496-52f9-a825-be2488a00a31', null, '5cfbd637-17cd-5e1f-9521-1dae0dcfd527', '2022-05-26', '17:30:00', null, '通常', 'もしを使うときに「ずっと」を忘れがちなようです。 点数を制御してゲームを動かすのが好きなようです。 屋根の上に腰かけている男の人を作っていました。置いた場所が絶妙で、本当にこしかけているみたいに見えました！うまい！ 「やることがない」とのことだったので、まゆねこ（追いかけられる人気者）のコスチュームをアレンジしてもらいました。 コスチュームの見せ方もよかったです。こちらの提案も取り入れてくれることもありました。 モザイクの使い方について質問されました。「見た目」の欄にありそうだということは見当がついていたようです。 途中、気分が下向くこともありましたが、自ら手を動かす場面がとても多かったです。画面がにぎやかな面白いゲームを作ってくれました。 ピンポンが最上面にでてきているのが少し残念です。 本人がそろそろ飽きてくるころ合いかもしれないので、新しいゲームを提案してみたいです。', null, '盛り上がり: 最後の報告会でも楽しそうな様子でした！'),
  ('64860869-7d02-5aea-81a6-00f565d84ec3', 'b2246586-4496-52f9-a825-be2488a00a31', null, '5cfbd637-17cd-5e1f-9521-1dae0dcfd527', '2022-05-19', '17:30:00', null, '通常', 'いろいろ話していく中で、ピンポンダッシュを作ることになりました「見つかったら家主に怒られる」という設定も自分から出てきて良かったです。 タイピングも表を見ながらならできる様子。 表現したいこととプログラムのブロックで表現できる内容が一致しないことがある。 スコアの値によってプログラムを分けるために、演算とスコアの使い方について説明しました。 こちらが喋りすぎるといっぱいいっぱいになってしまうようなので、注意が必要だと思いました。 スコアの変数を作るとき、ただスコアを1ずつ増やすコードだけを入れるのはでなく、2秒待つのコードも自ら入れることができてよかったです。 逃げ回って時にも音を入れてほしいと提案したところ、素直に受け入れて手伝うことなく作っていました。', null, '盛り上がり: 作りたいコードを先生に聞いたり、ファイルを持ってきたりして作っていたので、特に創作意欲がたかかった。 発表会のときもとても楽しくプレイしてもらったので喜んでいた。'),
  ('d0cad08d-81a0-5408-8efa-4a63fcb1398c', 'b2246586-4496-52f9-a825-be2488a00a31', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-05-12', '17:30:00', null, '通常', '前回作成していた脱出ゲーム？で遊んでいたので、コンテストの課題の一つである「対戦ゲーム」へのアレンジを勧めてみました。 すぐにプレイアブルスプライトを複製してくれたので、判別がつくようにしてほしい、こちらも他のキーで動くようにしてほしいと伝えたところ、色をかえたり操作するキーを変えたりと、自分で更新できていました。 別のゲームを作成していたときに、地球が燃える様子をうまくコスチュームを使って表現することができていました。見た目を変えるのは得意なのかもしれません！（和） 提案：授業の最初にドリルなどからやってほしい動きもしくはコードを見せてあげて、このコードを使ってゲームを作るようにするのはどうでしょうか。コードの選択肢が増えたら、まさきくんのオリジナルティあふれる作品に拍車がかかると思う。', null, '盛り上がり: 二人で遊べるゲームができたことは、とても嬉しそうでした。'),
  ('135dc867-18a6-5a25-8268-00f9c74c088f', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, 'c4085d7a-5e93-5712-b8bc-4a5e6caaf6ba', '2022-04-21', '17:30:00', null, '通常 / 細分化の練習 「滑らかな動き」と変数を復習する', '最初、星取りゲームを少し遊んでもらってから先週行った細分化を基に、犬の動きからから作り始めました。 犬を左右に動かすとき、動く方向に向きが変わってなかったので、元のゲームはどうなっていたか問いかけたら、向きが変わっていることは認知できていた。 左に向けるとき、-90度に向けてー10歩動かすようにしてしまい、そこの理解に手こずっていた。「前」と「後ろ」を使って説明するのが良いかもしれない。繰り返して練習する必要がある。 左に向けるときに、回転してしまうことを指摘したが「左右のみに回転する」のブロックを覚えてくれていなかった。一度使ったことを説明したが、自信なさげだった。 スプライトが左右に動くときに、前作からコードを変えてくれたので滑らかに動かすことが出来るようになっていた！！ 最後に、星の動きを作ってもらおうとしていたが、集中力が切れてたので、前のかごのゲームを見て進めなかった。星の動きも前に作ったプログラムを参考に作ってもらいたいと思う。', null, 'タイピング: ひとつひとつキーを確認しながらやって疲れ切っていました。タイピングが短いやつがいいかもしれない。
盛り上がり: 始まる前ににゃんこ大戦争をやりすぎてつかれていた。 前半は、自らコードを作って、上手くいかないところも修正はできていた。'),
  ('99a13f5c-5f13-5ec9-8984-e1acefb8d17b', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '5cfbd637-17cd-5e1f-9521-1dae0dcfd527', '2022-04-14', '17:30:00', null, '通常 / 前回まで 「キャッチゲーム 04・06(スコア以外) 」 次回「次回はスコアの表示、クリア画面の作成・プログラムに挑戦したいです。今日はとても集中して取り組めていました！この調子で頑張りたいです。 」とあるが。様子をみて、休み明けなので、新しい事の方がいいかも？ キャッチゲームだと、承太郎君と同じ単元なので、応用に行ってもいいかもね。 キャッチゲームの目的は ▶制御処理「★★」「もし●●●」を演算と組み合わせることができる ▶関数「★」「もし〇〇なら」というブロック内に，＞＜＝などを用いて条件を設定できる これがマスターできていそうだったら、キャッチゲームの応用やりましょう。 ⇒キャッチゲームの応用は「【Prg】初級 星とりゲームを作ろう！」です。 ⇒最初に細分化させてみて。 あるいは、少し飽きがきているようだったら「射的」を取り組んでもいいかもしれない。好きそうなので。', 'スコアは全く問題なくプログラムできていました！ クリア画面の作成で躓きました。スコアを使ってコントロールするという発想はできていたのですが、＝≧≦の使い分けが難しかったようです。また、「もし」を使うときに、「ずっと」を併用するのを忘れがちなようです。声を掛けたらすぐに気づいてくれました。 難しいキャッチゲームの細分化に挑戦しました。初めての細分化でした。最初に言葉でいくつか説明してもらいましたが、ばっちりでした。見本を示した後、細分化の意図や目的を少し説明して書いてもらいました。書きにくい様子でしたが、こちらが知りたい内容を問いかけると記入してくれました。初めてでしたが、十分に取り組めたと思います。 落ちてくる星の細分化がまだ終わっていません。', null, 'タイピング: 集中して取り組めていました！両手使えていたのですごい！！
盛り上がり: 裏技ctrl+Zを教えました！！ニヤニヤしてました！ 推しマフィンの話をしました。バナナが好きなようです。'),
  ('99a65328-a9be-5820-aa09-c63405e17704', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-16', '16:30:00', null, '通常 / コンテスト用作品の作成開始 ベースは射的ゲーム_応用', '・コンテスト用の作品を作り始めました。 ・魚が海の中を泳いできて、ジャンプしたときに撃つゲームにしたいそです。 ・2種類の魚のスプライトと海のスプライトを作成しました。', 'さかなの動きのコード作成の予定です。', 'タイピング: こだまの森第一話をやりました。下段のキーも良く打てています。左手は特に、指使い通りに打っていました。
盛り上がり: ・自分の中のイメージがしっかりあるようで、嬉しそうに作品の設定を決めていました！'),
  ('60505cd8-3ea5-597a-ae35-33dbeadc652f', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-14', '17:30:00', null, '通常 / コンテスト作品作成開始', '・親子プログラミング大会のホームページを見せて、どのような作品を作りたいかを考えました。 ・どんなゲームにしたいかを決めて紙に書いてから、スプライトの作成に入りました。', '・細かい作り込みはこれからなので、世界観を考えてきてもらい、それに沿ってゲームやストーリーを作成していく予定です。', 'タイピング: 安定してゴールド級を出しています。
盛り上がり: ・どんなゲームにしたいのか、ある程度の構想はあるとのことで、熱心に作成を進めていました。'),
  ('c31bff68-eeef-57c3-9543-834aaf093806', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-14', '16:30:00', null, '通常 / 基本操作コース08 さあ踊ろう または マリオ？', 'マリオのゲームを人が作った作品を真似て自分で作りたがったが、Scratchのマリオは難しすぎて断念。似たゲームとマリオがジャンプするという点で、基本操作コースのジャンピングを作ることに。ひよこをドット絵の男の子にして開始。 →座標の概念が曖昧。「習った、知っている」とは言うが、座標を指定するブロックを用意しても数値をいじる概念がない。座標が数値で変わるという点を説明したが、理解があいまいな様子が見られる。 →次回、座標を数値で指定して動かく単元を、再度みっちりやった方がよさそう。 →入力のスキルがもう少し必要。アルファベットがわかっていないので、次回、タイピングの基本の様子を見てあげてレベルアップさせてあげたいです。 →また、基本、マウスで操作することをしばらく徹底したい。', '以前やった事を忘れがちなので、次回から、前半に少し復習の時間を設けた方がいいね。', 'タイピング: 第2ステージを3つクリアしましたが、早くマリオのプログラミングに入りたくて気もそぞろでした。
盛り上がり: 大ヒントを与えてではあったものの、自分で「マイナス入れるのか」「大正解！」となった時はうれしそうでした。'),
  ('c31d9e2a-bffe-59bc-b827-fe90f4e3d284', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '66e39e2a-e1cf-5364-b72d-b454b7e45768', '2022-06-13', '17:30:00', null, '通常 / 追跡ゲームの作成', '・追跡ゲームかピンポンゲームを両方見せて遊ばせて、どちらかを作るか聞いたが、悩みに悩んでいたので、こちらで追跡ゲームの方を選んで作りました。よ ・まずキャラの動きのコードをつくりました。十字キーで動かすのは前の物語でやったが、正解のコードまで思い出すのに時間がかかてしましたした。そのコードの作り方があるのは覚えていたが、具体的にどうゆうものか曖昧でした。 ・そのあとは、スプライトの絵の方にこだわって、手が上下に揺れて泳いでいる風になっているのは良いアイデアでした。ただ、こだわりすぎて時間をかけすぎてしまうところがあるのでこちらで切りよく切り上げた方がいいと思う。', '追跡ゲームの作成', 'タイピング: 本人的には今日はタイピングは悪かったと言ってましたが、スコアも正答率も上がって成長が見られました。'),
  ('40c2bab7-8060-531e-b28c-25cedda23d7f', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-06-13', '17:30:00', null, '通常 / ３週にわたって書いていたガチャポンのコードを最後まで完成させる', '終始、メッセージを送る、受け取るのリレーションが苦手な様子。スプライトが増えれば増えるほどコードが増えていくので、リレーションがどうなっているのか？を確認しなければバグになるということを繰り返ししていました。途中「バグを見つけるのは俺の仕事じゃない」と言ったので、それは、自分の作品なんだからちゃんと探してコードを書き直すことも仕事のうちなんだよ〜と伝えておきました。', '来週は検定の問題をやる', 'タイピング: レベル３が全部おわるまでやってもらいました、できるのにココアにするってことはある意味自信がない現れかな？とも思ったので最後までやってもらうことに意味があるかなと思い、最後まで根気強くやってもらいました。
盛り上がり: いちおう、自分でもリレーションがどうつながっているのか？は分かってくれている様子。'),
  ('bdc2a7e9-d251-56ac-953e-b0c0b82c20e4', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-06-13', '16:30:00', null, '通常 / 追跡ゲーム', '最後のレベルアップ、背景が変わるを残し終了。概ね向きや変数を使うやり方をマスターしたように感じます。次はリレーションが始まっていくので、それまでにもう少し追跡ゲームを深く掘り下げてもいいかなぁと思います。', '次回は最後まで進んで、アレンジを行っても良いかも', 'タイピング: レベル２を完全にクリア（キーボードの中段が全て終わった様子）段々とタイピングできる回数が増えてきて、本人も自信がついてきた様子
盛り上がり: よく理解をしている様子です。基本的にはやってみる→間違ったら聞いてみて、どうすればいいのか？を聞く姿勢があり、修正された点に関しては、「あぁそうすればいいのか！」という理解がありました。'),
  ('af5726d8-f82d-5aef-b949-8b5d104ceee9', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-06-13', '16:30:00', null, '通常 / コンテント作品作成、日程予定確認', 'コンテスト作品作成＆予定確認 ・最初にコンテストの予定確認をしました。見直しの期間を含めると、完成までに時間をかけてられないことが認識してもらいました。1次審査は書類審査なのでざっくりと作品を作る方針で進めました。 ・作業としては、チュートリアルの最終確認のテキスト作りまで進めました。若干テキストの文字が背景との相性が悪く見えずらい感じだったので後で直すように伝えました。 ・「次へ」のボタンで触れると小さくなる挙動が、ボタンの境目だと拡大縮小が繰り返してしまうバグが少し気になったのでそこも直していくべき点です。 ・来週は、ゲーム本編を作れるので大枠を埋めながら進めるようにしたいです。', null, 'タイピング: 遅れてきたのでなし
盛り上がり: オウスケ君がはるちゃんの作品を見て、丁寧な進み方ですごく関心していました。'),
  ('d3f143ef-ca42-52dd-b3fd-d8cd9a311a11', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-06-13', '17:30:00', null, '通常 / ピンポンゲームを完成させる', 'ピンポンゲームを全部行いました、ここでも向きが出てくるのでおうすけくんにとってはとても良い勉強になったのでは？と思っています。 ただ、コードを書く時に半角数字に数字を直すのを忘れたり、演算を使う際に＝や大なり小なりの向きをきちんと確認しない癖があるので、落ち着いてコードを書いて欲しいと思います。', '次回はコンテストのじゅんび？', 'タイピング: 腕試しで今回は３級になった様子
盛り上がり: 自分なりにスプライトをアレンジしたり、音を変更したりすることや、ゲームの面白さを追求したりすることができました！'),
  ('060134f9-840a-5e50-a939-ec40c605e841', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-06-13', null, null, '通常 / 検定2級に挑戦！', '2級の検定問題に挑戦しました。 取り組んでいる最中は深く考えすぎてしまうこともなく、順調にプログラム作成が進んでいるように見えました。1度声をかけてみたものの、本人的にも難しすぎる訳ではなかったようです。 変数とその他の言葉を組み合わせて表示させる方法を忘れてしまっていたようで、「～と～」をうまく使えていませんでした。再度使い方を伝えると、論理的に組み立ててプログラムできたのでとても良かったです。 その後ゲームで遊んでみましたが、点数がうまく加点されていなかったので、正解と照らし合わせて確認しようとしたところ、時間となってしまいました。 来週は、①検定のプログラムの確認 ②前回挑戦したトランポリンの挙動の確認 を行う予定です。', '「検定のプログラムを正解と照らし合わせて確認」はやりたいです。', '時間帯: その他
タイピング: 姿勢よく取り組めていました。
盛り上がり: 「きれいにする」を伝えたところ、ニヤニヤしていました！！知らなかったようです。'),
  ('9beb2245-52dc-5391-9a3d-c5edc5999e27', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-06-13', '17:30:00', null, '通常 / コンテスト作品の続き', '前回から続いている、案内人の言葉の入力の続きをしました。得意ではないにもかかわらず、ひとつひとつ丁寧に取り組んでるのがとても良かったです。 ローマ字表をほとんど見ることなく頑張っています。 メモ機能からアルスパークへのコピペで手間取る場面がありました。マウスでコピペを説明しました。ショートカットは扱いにくかったようです。 ステージ1の案内人が話すプログラムが完成しました。次回からはまちがい探しのプログラムの作成に移るようです。まちがい探しのスプライトを編集していました。', null, 'タイピング: 集中して取り組んでいて素晴らしかったです。ゲームの仕様にイライラしてしまう場面もありました。
盛り上がり: 学校がいそがしく少し疲れているようすでしたが、集中して頑張ってくれていました！'),
  ('dc6719f6-b738-5f82-8a9f-2970840cabdf', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-06-13', '17:30:00', null, '通常 / コンテストの作品の考案or検定に挑戦(4級)', 'ゲーム内容の考案とスプライトの作成に取り組みました。前回作った自分の作品が気にいっているようで、前回の作品をアレンジ＆ストーリーを付け加えることになりました。 ストーリーの構成にかなり悩みましたが、こちらからいくつか案を出すと、それらを踏み台にオリジナルのストーリーを考えてくれました。 ゲーム性は前回作ったものと変わりませんが、前後に新たにストーリーが加わるイメージです。 コスチュームは全て完成しました！', null, 'タイピング: ホームポジションを意識して取り組めていました！
盛り上がり: とってもかわいいコスチュームを作ってくれました！'),
  ('75ad2270-9a13-50d7-8f65-f03a2f69aa92', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-06-10', '18:40:00', null, '振替え / 追跡ゲームのバグを修正とドリルでどこまで理解ができているかを測る', '追跡ゲームのバグ修正（詳細はこちらhttps://app.arspark.jp/projects/12383/editor コメント欄を参照ください）とドリルレベル３ ３１〜３７まで', 'ピンポンゲーム', 'タイピング: 99.07 ％ 正誤率 概ね悪くない
盛り上がり: 今日は苦手な向きにずっとチャレンジしていたため、相当疲れた様子。 ただ向きをきちんと理解をしておかないと次のピンポンゲームの時に困ってしまうので、向きの理解をするにはとても良かったかと思います。'),
  ('812f3e28-21cc-592d-941b-4f16f9952829', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-06-06', '16:30:00', null, '通常 / 基本操作コース 世界を創造しようのアレンジ', '『宇宙を題材』にして自分なりの物語を作ることができた、場面を変えることやきちんとしたストーリーがあるものにできているので、良いかと思います。 コードも長く描けるようになり、どこが間違っているかを自分でも理解できている様子でした。', '追跡ゲームを行う', 'タイピング: 場面２までクリアできた、だんだんとFGHJの列は覚えることができている様子です。
盛り上がり: 細部までこだわることがとても良い点だと思います。'),
  ('2e51e252-610a-51b8-811c-95c7f6d9e36b', '36b32225-ef6e-58f8-add5-c3bfbcfffc48', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2022-06-11', '17:30:00', null, '通常 / 作品をすすめる', '何をどう初めていいかわからないと言ってたので、順番にシーンの洗い出しをした。 スタートのイラストを自分でする作って、雰囲気あってよ 良い仕上がりと思う。 仕事シーンで書類の山を越えるジャンプゲームというアイデアを出してくれて。面白いなぁと思いました。', '宿題でアルスのレッスンの。ガチャをやってくるようにー伝え。ガチャの方法を取り入れてスタート画面を次回作成します。', 'タイピング: 苦手苦手と言いながら。最後までやっていました。ー
盛り上がり: ちょっと眠そうでしたが、全体スケジュールを確認できたのと納得してたのでやる気にはなっています。'),
  ('aff511ec-c4f3-56c5-8579-5c6b144f22bf', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, null, '2022-06-09', '18:40:00', null, '振替え', null, null, null),
  ('769e4e24-47ac-518f-8a11-430d953dec5d', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2022-06-06', '17:30:00', null, '通常 / いろいろ', null, null, 'タイピング: 難しいわ'),
  ('99baa98a-ae58-5736-8475-11a684d8221b', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '86cccbf6-175d-5339-b610-5b304c281f00', '2022-06-06', '16:30:00', null, '通常 / 先週の続き。 どうかな。次のステップは何かリストやるか？ 定義をやるか。', null, null, 'タイピング: いいね'),
  ('b5a1f8f8-a43b-5ca0-bdf0-08fa9d4331ab', '36b32225-ef6e-58f8-add5-c3bfbcfffc48', null, '4024e439-731f-5595-aca0-a451dc395367', '2022-06-05', '17:30:00', null, '通常 / 間が空いたので、最近の様子を確認して次のステップを本人とも話す', '射撃ゲーム＿初級 https://app.arspark.jp/contents/11309 様子：初めは今まで作ったものはやりたくないという感じで新しいものを作っていましたが途中ゆきさんが話して、インベーダーゲームのようなゲームを開いてくれました。そのゲームを作るうえで細分化が必要なのですが、はるとくんは細分化をしたことがなかったので「射撃ゲーム＿初級」を使って細分化の練習をしました。 だいぶ細かく細分化できており、インベーダーゲームにも応用できるかと思います。', null, 'タイピング: なし'),
  ('f049fa51-55ab-50ff-80ff-723973bb315f', '36b32225-ef6e-58f8-add5-c3bfbcfffc48', null, '4024e439-731f-5595-aca0-a451dc395367', '2022-04-15', '17:30:00', null, '休み', null, null, '備考: 0'),
  ('acccb8f5-5f82-5236-a46a-ecdd9a0c08c7', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-06-05', '16:30:00', null, '通常 / 先週の射的ゲームの玉の動きを完成させる ～の方へ向かう動きを確実に定着させるために、検定4級の「かえるの花びらのり」にチャレンジするか、射的ゲームの応用にチャレンジするかをゲームを見せて本人に決めさせる。', 'テスト', null, 'タイピング: テスト
盛り上がり: つと
備考: テスト'),
  ('5a228e7f-6687-5082-85ad-baced42f1db8', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-04-11', '16:30:00', null, '通常 / 間が空いたので、ウォームアップかねて楽しくゲーム制作がいいかね？ サレンがちょうどよいレベルであったという「射的ゲーム」が良いのでは？ ↓↓写真参照／右の「きょうざいやさん」が作った射的は同じ５年生の作品ということで、まずは簡単なコードで射的を作り、次に高度なゲーム（ナホちゃんが作った方）にチャレンジという流れがいいのでは？？ その際に、「最初に難しい方も両方見せてゴールを確認してから、簡単なのを始める」という流れがGOODです。 最初に簡単な方で細分化させてみよう！ 細分化と復習！', '難しいゲームと簡単なゲームの両方をみてもらいましたその後、簡単なゲームをまず細分化しました。細分化は難なくおわりました！スプライトも面白い独自性のあるものを選んでくれました！的を動かすのが大変でした。「⚪︎秒で〜に動く」を使うことが発案できず、少し時間がかかりました。 乱数を「⚪︎秒」と「座標」の2箇所に使うことで、よりランダムに動く的を作ってくれました！ 玉の動きがまだ終わっていません！', null, '盛り上がり: 久々でしたが集中して取り組んでくれました！
備考: 0'),
  ('33ed9be0-56ad-54b7-bfd2-98679b2212ca', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-25', null, null, '通常 / 検定練習', '今回は、特に悩み止まることがなくスムーズに解けたそうです。確認をしても1つだけの間違えでほぼ完ぺきでした。修正箇所が間違っていたので、なぜその場合だと、上手くできないのか深く考えてもらいました。そのバグを探るのに時間はかかりましたが、しっかり答えることが出来ました。', null, '時間帯: その他'),
  ('958a62fe-1932-59ed-a45d-b0ebffa53128', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-22', null, null, '通常 / 自由制作', 'コマンドRPG風ゲームで今回はそれぞれの剣や杖のモーションを使っていました。属性とかによって変化する仕組みになっていて工夫が出ていました。コマンドボタンも作っていったので 次回はこれらを繋ぎ合わせるといいかも', null, '時間帯: その他'),
  ('852f915d-269c-5289-96ce-aad87c0f6912', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-06-22', null, null, '通常 / 親子大会の作品作り', '散らかっていたスプライトや背景などを整理してやりたいものを確認しました。元から語ったバイクで追い掛け回すコードを活かしてタコをリンゴキャッチ風のものにしていくことを決めました。途中から出してきたサメのスプライトも邪魔者として利用できることもいいねてきな話もしました。次回は散らかっているスコアの変数をまとめてあげるといいと思います。', null, '時間帯: その他
タイピング: よくやっていました'),
  ('235fe8db-34c5-587b-82e4-c01d7ebfce2b', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-21', '17:30:00', null, '通常 / 親子大会ビギナーズ部門「ふうせんをわろう」 上位を狙うつもりでアレンジを頑張ろう', '周りに気が散ってしまうようで、作成のスピードはゆっくりでした。サッカーの出現場所をランダムに変えるときに変数を使う！という考えがでてきて良かったです。一方でプログラムの方法はまだ慣れないようなので、かなりサポートをしました。制御のブロックがあると考えるときに少し混乱するようですが、少しサポートすると理解できるようです。 点数を入れるところまで（音はまだ）やりました。できる範囲でアレンジ要素を入れつつプログラムを進めています。', null, null),
  ('f423a9a5-1dea-570b-a720-7ca3d31cd15d', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-21', '17:30:00', null, '通常 / 親子大会オリジナル作品 オープニング 予期せずしないタイミングで消えていきバグが発生していました。その際、原因を起こしているコードまでは把握できていましたが、その修正方法がわからず、作業が終わってしまいました。', 'オープニングのバグですが、アルスパークで見たり本人が動かしているところを確認したりしましたが、バグが分かりませんでした。本人からも特になかったので解決したのかな？と感じています。途中、メッセージがうまく機能していないプログラムがありましたが、メッセージが送られる場所をたどり解決することができました。扉についた時のクルクル回る演出も面白いです。集中して取り組めました。', null, null),
  ('7c528757-5b0b-52b1-9965-e825d725423f', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-21', '17:30:00', null, '通常 / いろいろな形を描こう https://app.arstudio.fun/contents/21750 リスト番号の5→指定した正n角形をかく、できたら6以降、できあがりを見せて、自分でコードを作れるか', '授業時間前に「遊んでいた矢印キーを動かすと、そこが頭となって後ろについた竜がくねくね動く」という作品がどうしても気になったそうで、作ることになりました。（作成前にオリジナル作品の中身を確認しましたが、理解でそうなプログラムだったので作りました）図形も進めましたが興味がなさそうでした。スプライトの最初の位置の設定に四苦八苦していましたが、一度作り終えた後は変数を変えて動きの変化を見たり（前のスプライトに追従する速さが変わる）、プログラムの仕組みを確認したりしました。楽しそうで良かったです。', null, null),
  ('bbec2b3c-5fb0-53d1-aa90-0ca4e0ed34e7', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-21', null, null, '通常 / 親子大会オリジナル作品 たてスクロールのやり方の確認', 'たてスクロールの方法を共有しようと思いましたが、自分なりにやることが決まっていた様子で、今回は伝えませんでした。前半は自分で取り組んでいましたが、後半とらくんと一緒にアイデアカードを引きました。思いついたことがある様子で、スプライトを描き始めました。まだ描いている途中のようです。', null, '時間帯: その他'),
  ('2aa12068-f712-5ea8-8588-caafa9a1677b', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-21', null, null, '通常 / U16大会作品作成 テーマを考えながらアレンジしていけるよう促して', '前半は考えつつプログラムしつつ順調なように感じました。後半でアイデアに詰まっていたので、とらくんとカードを使って一緒に考えました。3枚引いて考えてもらったのですが、すぐに3枚のカードを使ってストーリーを考えることができていて素晴らしかったです。何回やってもできていたのでかなり得意なようです。いくつかアイデアが思い浮かんだそうなので良かったです。', null, '時間帯: その他'),
  ('1e8da2b1-2ce3-5e0f-97ac-0b7a1ff9add1', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-28', null, null, '通常 / 検定4級 または親子大会オリジナル作品 本人のモチベーション次第で コンテストの入賞を目指すには、「何を作りたいか」をはっきりさせなければいけないことをわかってもらった上で、どちらにチャレンジするか決めさせても。', '最初は親子大会のオリジナル作品の作成を進めていましたが、あまりアイデアがでてこず詰まっていたので、本人から「検定やりたい」という申し出があったので検定に取り組みました。親子大会のストーリーの部分や作成したい具体的なものを引き出せるように話してみたのですが、少し難しかったようです。 検定は、見たものがうまく再現できないため自分で考えてプログラムをしてしまう、文章が慣れないため困る、「～まで繰り返す」のブロックの使い方を忘れてしまう、などうまくいかない面もありましたが、大枠は理解できていました。あんまり嫌そうでもないので、練習を積めば大丈夫そうな気がします。', null, '時間帯: その他'),
  ('325246ef-87f1-5e15-9f2a-95069fb139d5', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-06-21', null, null, '通常 / U16大会作品作成 作成したいものについて、ある程度の細分化が必要かも。漠然とした全体像からだと作成が難しいので、そのあたりを意識させて。', '前半は前回iPadを使って描いていたお城の絵を編集していました。かなりきれいに書けている様子です。後半は作品のテーマ、ストーリー構成について話し合いました。前回大会の受賞作品一覧のpdfは見たようですがなかなか内容が定まらなかったので、カードを引いて考えることにしました。', null, '時間帯: その他'),
  ('9afb81f2-ebc5-5324-84e2-6309876569e9', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-06-22', null, null, '通常 / 大会作品制作', '現在作成している大会作品は、以前に作っていたシューティングゲームを応用して作っていくようです。現在考えている構想としては、PvPのゲームにしていくようでそれぞれの機体にビームとバリアをつけることでゲームとしての面白さを引き上げようとしていました。本人としては、作品制作には乗る乗らないの波があるようで集中している時とそうでない時の差が激しかった印象です。そのため、次回は集中する時間を伸ばしていけるように本人のアイディアをどんどん出していきたいと思っています。', null, '時間帯: その他
盛り上がり: 作品の中で自分のアイディアを試しているときは楽しそうに作っていました。'),
  ('37d6f52a-2b7b-5dbb-b98e-b6db7cdd2e44', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-06-29', null, null, '通常 / 大会作品制作', '大会作品ではリストを使ってクイズを出していく作品を作っていきました。クイズを出題するまでの部分は完成しているようでしたので、残りの部分としてクイズの内容と正解不正解の演出などを詰めていくことができれば完成まで持っていけそうです。時間的にも余裕があるので、本人の思いついたことや疑問に思っていることをどんどん作品に取り入れていくことで、さらに個性を出したものに仕上げていくことができそうです。', null, '時間帯: その他
盛り上がり: クイズにどんな問題を入れようかネットで検索しながら吟味していました。'),
  ('f864c043-295f-5aee-8fa0-873e82677c59', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-06-29', '16:30:00', null, '通常 / Excel練習', '今回は、Excelの中でも表を本格的に作成していました。セルの結合や表の線引きなど、実際に使用していく上でもそれなりに使っていく技術をやっていきました。内容としてはシンプルなものが多かったため、動画を見ながらスラスラと問題を解いていくことができていました。この調子で次回も問題を解いていき、どんどん進めていきたいところです。', null, '盛り上がり: 問題をスラスラと解けて気持ちよさそうでした。'),
  ('295523fa-6ee9-5b78-b613-a93063052642', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-06-29', '17:30:00', null, '通常 / 大会作品制作', '前回で風船割ゲームの基本部分は完成したため、今回からアレンジ部分へと入っていきました。内容が風船割ゲームの部分をかなり変えてしまっているため、本人の独創性は多く取り入れることができていますが、ビギナー部門に提出する場合には少し難しくなってくるかもしれません。本人もこのままアレンジを続けて作品を完成させたい様子なので、オリジナル部門への提出を考えてもいいかもしれません。次回聞いてみてどちらにするか決定してみても良いかもしれません。', null, 'タイピング: 確実に打っていきました。
盛り上がり: アレンジをとにかく入れて自分の作りたいものを作っていくことができて楽しそうでした。'),
  ('18c1a82e-a11d-5b4e-989d-0a835b32817b', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-06-29', '17:30:00', null, '通常 / 検定問題３級 応用問題２', '問題はスラスラと解くことができており、時間にも余裕がある様子でした。アレンジ部分は手をつけていなかったので、次回から挑戦していきたいです。答え合わせでは、不等号の違いやブロックの入れ違いなどケアレスミスがいくつかある程度で、大まかな部分は合っていました。そのため、問題文とコードの照らし合わせと見直しをおこなっていくこと。そして、時間に余裕があるためもう少しゆっくり解答して行っても良いかもしれません。そういったミスがなくなれば満点も余裕で取れると思います。', null, '盛り上がり: 自身のミスに気づき、次はどうすればいいのかを考えていました。'),
  ('fa83d251-e8d5-551f-b0c0-dccb6c08dc59', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, null, '2024-06-29', null, null, '休み（未対象）', null, null, '時間帯: その他
備考: 当日連絡なし'),
  ('d8853690-d612-525f-a261-a70eef77499e', '28d52d6e-7571-5090-a2d9-492c997b719e', null, null, '2024-06-29', null, null, '休み（未対象）', null, null, '時間帯: その他
備考: 体調不良のため当日欠席連絡'),
  ('c492141b-d9dd-5dcf-b8b3-40d5268cf328', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-06-29', null, null, '振替 / 大会作品制作', '前回の続きから作成していきました。今回はキャラクターが選択画面で動いたり攻撃をしないように修正をしたり、投擲アイテムの挙動の修正をおこなっていきました。全体的に新しいものを入れたというよりはデバッグ作業よりの内容となりました。本人もゲームの動きに関してはかなり拘っているようで、疑問に思った部分はすぐに修正に取り掛かっていました。今回でバトル部分のほとんどが完成したため、次回からは残りの部分とバトル以外の部分についてアレンジを加えていく予定です。', null, '時間帯: その他
盛り上がり: 作品のクオリティが着実に上がっており、喜んでいました。'),
  ('c1c7b225-afd0-5071-964d-5248bff1525a', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-29', null, null, '通常 / 親子大会の製作', '作りたい内容はわかっていて一緒に整理もしましたが、やる気が出るまでに少し時間がかかりました。同じ意味のコードが重複している部分があったせいでバグが出ましたが、コード全体をよく見るように促すと重なっている部分を消せました。また、テストプレイをしたときに、止まるはずの動きが止まらないことに気づき、「このスクリプトを止める」を足して自己解決できていました。PvPのアイデアも一度考えていたようですが、変更して1人用のゲームとして作成を続けたいとのことです。', null, '時間帯: その他'),
  ('7b5fbfde-c92f-5577-a550-8143238a6021', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-06-29', '16:30:00', null, '通常 / Excel練習', '今回は表とグラフの作成をおこなっていきました。今までと同様に動画を見ながら学習していき、練習問題にて確認をおこなっていました。それほど難しい要素はなく詰まることなく最後まで解き終えることができていました。Excelをやっている際や終わったとに、pythonやjavascriptなど他の言語をやりたいともいっていたので、授業に余裕のある際にはそちらもmonacaなどでやってみるのもいいかもしれません。本人の理解度が高いため、Excelの問題はすぐに解き終えることができると思います。', null, '盛り上がり: 最後まで完璧に解くことができていました。'),
  ('f3a1f1d0-cc2a-5367-ae91-d25ab59e927b', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-29', null, null, '通常 / 親子大会のオリジナル作品を作成する', '授業時間になったらすぐに、先週まで作成していた部分の最終調整をしていました。 問題数問に正解すると、画面がスイーツでいっぱいになるという、可愛らしい作品ができていました。 なつめちゃんは満足そうにしていましたが、プレイ時間がとても短いため、もう少し作品をふくらませてみようと提案しました。 出てくるキャラクターの犬やスイーツからストーリーを考えられないかと提案したところ、どちらもブレストカードで引いたお題のため、自分の中では特にストーリーはなかった、と混乱していたため、ゲームのステージを増やす提案をしたところ、そちらをやってみたい、とのことで取りかかっていました。 使用する絵のテイストを変えたくないとのことで、前々回に和先生と見つけた画像サイトを探していました。（ベクターシェルフ https://vectorshelf.com/） 問題を出す犬のスプライトを複製して使おうとしたところ、リストへの追加が重なってしまって動きがおかしくなったため、複製した場合の重複するコードに注意して、とりあえずコードをイベントブロックからはなして動作確認をするなど、なつめちゃんなりに工夫をしていました。', '問題は家で考えてくるとのことだったので、2ステージ目以降を作成してゲームのボリュームをアップする予定', '時間帯: その他
盛り上がり: 背景も含め、全体的に可愛らしくファンシーな仕上がりになってきているのが嬉しそうでした。 問題が面白く、こちらがプレイして解答に悩んでいるのを見て、少し楽しそうにしていました。'),
  ('271212e8-5fd3-58c1-9db3-d5445dbdbb0c', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-06-29', '16:30:00', null, '通常 / 大会作品制作', '前回の続きから作成していきました。ステージ上に自身の思い浮かべたさまざまなものを置いていたため、非常に独創的なデザインとなりました。しかし、本人としては置いただけで満足しているようなので、できればおいたものを動かしたりして動きを取り入れていきたいところです。そのため、次回の授業ではそういった背景となっている素材などを動かして作品に動きをより多く取り入れていきたいです。作業中はやりたいことをやれていたようでとても楽しそうに作ることができていました。', null, '盛り上がり: 楽しみながら作ることができて、モチベーションを高く保っていました。'),
  ('3845a533-0323-5f32-a92e-78beb0d1f3e7', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-29', null, null, '通常 / 親子大会作成', '前回出たバグは家で考えたが分からなかったとのことで、一緒に原因を整理しました。その際、スプライトごとに紙に書いて細分化をしていきました。原因は「このスプライトを押す」ブロックはクローンには反応しないということだとわかりました。代わりの方法を考えようと促したところ「マウスが押された」と「マウスのポインターに触れた」を使うという方法を思いつき、それでうまくいきました。 バグは直ったので、どのようにルール説明・出題をするのかを考えてもらいました。ルール説明の文章の最初の方は書けたので、残りは家で書いてきて、教室では難しいコード部分をやりたいと計画だてることができました。', null, '時間帯: その他
盛り上がり: 入賞する確率を少しでも上げようとスプライトの名前などの細部にこだわろうとしていました。熱意を感じますが、それで完成しなかったら入賞しようがないので、一度ざっくり完成させてから細かい修正をすることを勧めました。'),
  ('5f66e597-256d-55cc-9760-c433a4fb56b7', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-06-29', null, null, '通常 / プログラミング検定対策をする', '検定のお知らせを見せながら、今後の予定について話しました。11月の検定は、ちょうど期末試験や推薦入試と重なるかもしれないので、できれば早めに検定を受けてしまいたいとのことでした。今回3級、2級のW受験にするかどうか、家で相談してくるよう促しました。 検定3級問題は、アレンジまでしっかりやっても時間に余裕があり、本人も、これまで解いてきた3級の問題は特に困ったこともなかった、との感想でした。 授業の残り時間がちょうど30分だったので、試しに2級をできるところまでやってみるか聞いたところ、やるやる！という感じですぐに取りかかっていました。 2級も30分で終わらせ、今回の問題で知らないブロックは「りんごとばなな」だけだったとのこと、これも、自分で推測できて解けたとのことでした。 問題の修正のところでのコードの書き方が慣れていなくて、一部足りないコードがありましたが、そこも問題を見直して自己解決できていました。', '2級検定問題①を予告しています', '時間帯: その他
盛り上がり: 検定対策が続いているため、気晴らしに他のことをやる提案もしましたが、問題文を読んで何かを作るのは嫌いじゃない、とのこと、早めに上位の級を取ってしまいたいという本人の希望もあり、検定2回分のチャレンジとなりましたが、楽しんで取り組めているようでした。 最後のバグつぶしまで、楽しそうにやっていました。
備考: こちらの授業後に塾の予定が入ったそうで、授業時間の10分前倒しを希望してきました。Comiruのノートに記載済みです。'),
  ('d49ed41f-7e10-5f2e-9696-d61601b2c900', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-06-29', null, null, '通常 / 検定練習', '今回は２級問題をやっていきました。時間に余裕を持ってスラスラと解き終えることができ、解答も間違うことなく満点で終えることができていました。その後はプログラミング大会の要項や予選のパワーポイントの概要などを見ていまいた。予選に関しては、今までに何回かパワーポイントを使っての資料作成をおこなったことがあるようなので、それなりに自信があるようでした。次回は検定問題を終わらせて大会作品の制作に取り掛かりたいようなので、より早く終えることができるかもしれません。', null, '時間帯: その他
盛り上がり: ミスなく解き終えることができて喜んでいました。'),
  ('2cf9837b-aa6e-56ce-97a2-c2fb46dbd69a', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-29', null, null, '通常 / 手順通りに作成を進める', '同じコードを使いまわせるところは複製したりして、サクサクと進んでいけました。前回のように大量の数値が出てくるところにまた出くわして嫌になりかけましたが、複製すればそんなに大変ではないことに気づかせてあげると、集中を保ったまま比較的短時間で切り抜けました。今回もメリハリをつけて最初の30分間頑張りました。', null, '時間帯: その他
盛り上がり: のあくんと同じテーブルだと互いにちょっかいをかけたりすることもたまにありましたが、「そうするならテーブルを離すよ」というと2人とも集中モードに戻ってくれました。'),
  ('b297f99c-451d-5ae8-a9cb-04928093a572', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-06-29', null, null, '通常 / 親子大会作成', '前回はゲームの詳細が思いつかず苦戦したようでしたが、この一週間で考えがまとまったようでした。迷子のヒヨコが周りの自然を調べて親を見つけるという謎解き風のゲームを作ることに決めました。ゲームの序盤はセリフやメッセージなど作成しやすい部分が多く、手を動かし続けることができました。', null, '時間帯: その他
盛り上がり: 落ち着いた様子で進められていました。'),
  ('7f2ff335-8000-5402-905e-0f8e97de0a9a', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-01', '16:30:00', null, '通常 / 親子大会作品作り', '前回リストを導入したことから、今回は既存のコードの整理を行いました。リストにより不要になった部分を見極めて、見やすいコードに作っていきました。番数毎に異なる動きをするコードについては、どのように表現したら区別をできるか考えてもらいました。ここで、番数の変数で=条件を作ればいいのですが、リストという概念が混ざりこんできて、少し戸惑っていました。本質は変わらないから「問題番号」の変数を導入した意味を再度家訓しながら作っていきました。1かっしょ出来たらほかの問題も同じように対応できてました。次回は問題数を増やして織基の続きの動きを作っていきたいです。', null, null),
  ('d015a100-89d1-5a77-907e-e92fd8dc3953', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-01', '17:30:00', null, '通常 / 親子大会作品作り', '親と考えてきて、スプラ的お掃除ゲームを作りたいそうです。敵がごみを巻き散らかして、その投げ跡がペイントされ、こちらは掃除するように動き色を塗り替えていくゲームです。今回は、イラストとそれぞれの大雑把な動きを作っていきました。ペンの使い方は学校で習ったそうで、スムーズに使えていました。移動をしながら動いていくもきれいにできていました。次回は、実際のゲームみたいなインクの飛び跳ねを同様に表現しているか考えてい来るそうです。', null, 'タイピング: スコア伸びてました'),
  ('d8cc5ace-99b0-5c8c-b3ce-0fdc662869e4', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-01', '16:30:00', null, '通常 / さあ踊ろう・音をつくろう →基本事項＆スタンプで埋める！', '前回よりも少し集中力が上がった気がします！スタンプを使うときには考えに詰まってしまって退屈そうでしたが、後半の音楽は楽しく取り組むことができました。制御のブロックは比較的使うことができていました。またBGMの流し方や楽器の音の鳴らし方を自分の知っているブロックを使って表現することができていました！！ リズムについてはあまり興味がなさそうなのですが、ぜひやってもらいたいです。', null, 'タイピング: 集中力を欠くためスキップ'),
  ('0d36ca1d-2ee9-5679-aacf-8447f4494aee', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-01', '16:30:00', null, '通常 / さあ踊ろう・音をつくろう →基本事項＆スタンプで埋める！', '前回よりも少し集中力が上がった気がします！がくくんよりも早く始めて呼びかけていたので良かったです。スタンプを使うときには「右に動いて押す」というイメージが理解できて、自分で「〇歩動かす」のブロックを使うことができていました。ドラムを鳴らす、リズムを作るときには自分の発想というよりはテキストに沿って進めていきました。せいぎょのブロックがすぐに出てこず、「〇回繰り返す」があまり使えていないので今後の課題です。', null, 'タイピング: 集中力を欠くためスキップ'),
  ('13eef0de-d273-599c-ac3a-f39cc4429717', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-01', '17:30:00', null, '通常 / 親子大会作品', '前回発生したバグは今日見てみても直し傾向が見られなかったので、別のものを作っていきました。新しいものでは、左右で選択していくゲームみたいで、片方を押したら、両方消える表現に苦戦していました。ここで、あまり使われていない「まで待つ」の有効性を知ってもらいました。また、押したら最後まですすでしまうことも長押し対策の作品を思い出してもらいました。使えそうな気づきがあれば、自分で治せていくので良い動きです。', null, null),
  ('2f67c19e-ca50-54cf-921d-b0e0f764d9ff', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-01', '17:30:00', null, '通常 / 初回。レベルチェックと基本事項 名前を動かす', 'マウスは初めて使うようでした。アルスパークの画面をみたときからその操作性についての質問や、複数のスプライトがあるときの操作方法について質問してくれました。好奇心があり、自分が分からないことが何かをよく理解できているように感じました。 また自分がすることにきちんと物語性があり、（焼きおにぎり、太陽、ビーチなど）作りたい動きをイメージしてプログラムを動かしているような気がしました。「はまっちゃいそう～～寝ないでやっちゃいそう～～」と言っていました。 アレンジ作品の材料集めを最後にやりました。作りたいイメージを考えてくるように伝えたのですが、「直前に思いつくタイプだから」と言っていました。その日の気分で決まるのかもしれません。 クラスにScratchがすごい得意な男の子がいるようです。テニスを5年くらい続けているそうです。面白いものが好きで、「見るとなぜかクスっと笑えるもの」が好きだそうです。', null, 'タイピング: すみません。すっかり忘れていて飛ばしてしまいました。 タイピングはしっかり自分でできていました！'),
  ('70bec5bb-8a81-542b-a815-dda6b0f9e47f', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-01', '17:30:00', null, '通常 / 自由製作、またはmonaca', '自由製作をしました！大会に作品提出をするか聞いたのですが、あまり興味がないようです。すぐに首を横に振っていたのでむしろ嫌なのかもしれません。 プログラム自体は集中してよく頑張っていました！制御が重なる難しい部分も（詳細は把握できていませんが）考えながら手を動かせていたので良かったです。', null, null),
  ('1f4eb8c4-4d65-5fe0-9467-867d737ca20d', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-08', '16:30:00', null, '通常 / 親子大会作品作り', '前回でコードの整理が片付いたので、本番想定の問題数に増やしました。それぞれの問題に対して動きをそれぞれの動きをつけて、1連の流れはできました。そして、OPと途中のサポートも付け加えられていて、アイデアが飛んでいました。この辺りは黙々と一人でできていました。なので、途中の機織りのイラストを頑張って作ってみました。ひろとくんにはまだ立体作図が苦手だったので、とても喜んでくれました。質の貢献になりました。', null, '盛り上がり: 大方一通りの流れが完成できそうなので、集中で来ていました。'),
  ('e95c8df4-961d-57ac-ba26-e05b783ba157', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-08', '17:30:00', null, '通常 / 自由作品', '前回に引き続き自分のプログラムを作成していました！初めに放送の部分を作るといっていたのですが、最後に見せてもらったときには鍵がないと操作できないような仕組みを作っていました！本当に鍵がないと操作できないのかは分からないそうですが、鍵穴が回転する仕組みまで綺麗に作れていました！', null, null),
  ('d128e665-270b-5400-975a-85ee3dd87857', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-08', '17:30:00', null, '通常 / 親子大会作品作り', '右左ゲームに変えてから、途中途中でバグの発生がしていたのでそこを直していきました。選んだものを最後に並べるはずが、すべて表示されないバグに対しては、こちらが軽めのヒントを与えると、そこから自走して形になるものができていたので、構想力はかなりついて行けたと思います。どうしてもうまくいかないものに対しては全く別のものを作り替える転換の速さも潔くていいと感じました。もう1回あればきれいに完成はできると思います。', null, null),
  ('02fc6e7e-ee94-5e8b-a4d6-bf3f78cb7895', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-08', '17:30:00', null, '通常 / 名前を動かそうオリジナル作品', '名前を一列に並べ、スペースキーを押すたびに右側へ移動し、端に触れたら反対に動かすような仕組みを作りました。考え方の大筋は良かったのですが、反対側に触れたときに角度を反対にするところで苦戦しました。前回は全く触れなかった条件分岐と演算のブロックを使って解決しました。考え方はなんとなくわかった様子です。 また次のアレンジとして棒人間のコスチュームが文字に当たったときに変わるようにしました。文字のプログラムの考え方を応用して大筋を自分でよく考えられていました！またメッセージの考え方を紹介し、他のスプライトも同時にコスチュームが変わるようにしました。本人的には「完成かな？」と言っていました。', null, 'タイピング: 簡単と普通の両方にとりくんでもらいましたが、長文を打つのは苦手そうなので今後は簡単をメインでやりたいそうです。'),
  ('506db1ae-f340-5d5a-a4e6-7e06f0af6035', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-08', '16:30:00', null, '通常 / サメから逃げろ！ 作品を完成させる', 'チュートリアルを見ずに進めました。逃げる方をプログラムに任せ、追いかける方を自分でプログラムしていました。逃げる方のプログラムはできていたので、矢印キーで動かすプログラムを作成しました。角度の後、「〇歩動かす」のブロックを思い出すことができていました。また、隠すを作ったあと、表示の方法も声をかけると思い出せたようです。アレンジとして「食べられた」と言わせることができました！ 後半の方は少し疲れていましたが、アレンジまで取り組むことができました！', null, null),
  ('c36ba4ea-cecc-5bce-a878-b8daec9d56ee', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-08', '16:30:00', null, '通常 / サメから逃げろ！ 作品を完成させる', '「どこかへ行く」を使って追いかけるスプライトを作成できました！「〇秒で」がついているブロックを使ったときに感動していました。矢印キーを使ってプログラムするところで苦戦しました。角度の話はすぐに理解できていましたが、その後の動かすブロックがすぐに思いつかなかったようです。見本通りだと動きがカクついてしまうことが気になっていたので、アレンジとして「もし～なら」を使ったコードを紹介しました！少し難しかったようですが、完成した動きはかなり気に入ったようです。 食べられたときの隠すと表示するのプログラムはスムーズにできました！ 楽しく取り組めました！', null, '盛り上がり: 家でタイピングの練習をしているそうです！'),
  ('7875081b-a38a-5add-90af-11186c733398', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-01', '17:30:00', null, '通常 / 親子大会作品作り', 'インクの飛び散り方をどのように作っているかすくっらちから見てくるようにしたが、しっかりとコスチュームを変化させてスタンプとして使っていることがわかりました。そこで、今回は、使いたい動きの基礎を作っていきました。ボムでは、こちらが何も教えずに自分で作れていました。お掃除ロボは、何秒たったら爆発する」はなかなか考えるには難しいコードでした。そこはこちらが、その仕組みを教えて、そこにペンや向きなど自ら調節できていました。今週もあるそうなので、次に向けてアイデアを考えてすぐできるようにしました。作り始めた遅いので', null, null),
  ('177cf307-f7df-52aa-acb5-c58aec5e4198', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-07-02', '16:30:00', null, '通常 / 大会作品制作', '今回も親子大会の作品制作をしていきました。アクションゲームの障害物の作成からキャラクターデザインまで様々なことをおこなっていきました。ステージ部分に関しては、ゲームをより面白くできるようい障害物の配置をとてもこだわっていました。特に、グラフィック部分のずれが気になっていたようで、そこに関しては特に慎重に調整を行っていました。キャラクターに関しては可愛いものがいいということで、フリー素材のカモを参考として模写をすることでキャラクターデザインを作っていました。作成にはとても集中しており、何回いも描き直して試行錯誤していました。出来上がったものは、後日アルスタジオに導入できるようにしてもらって取り入れていくようです。', null, 'タイピング: 集中して取り組めていました。
盛り上がり: 絵を描いている際に、どうすれば似せることができるか相談しながら描いていました。'),
  ('72c5cce6-61d9-57b6-81ce-95a1d57527c9', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-07-02', '16:30:00', null, '通常 / 大会作品制作', '大会作品として脱出ゲームを製作しているので、今回は謎部分とマルチエンディングにしたいということで複数のエンディングを作成していきました。謎解きとしては、アレンジ対象の脱出ゲームのように背景の椅子などをタッチすると変数が変わって特定の数値になった際に、特定のボタンを押すと脱出できるというものを作っていきました。さらに、そこから特定の行動を起こすと別のエンディングにいけるという方向で作っていきました。今後は音を入れていきたいようで、BGMや何かを押した際に音を追加していきたいようです。', null, 'タイピング: しっかりとタイピングできていました。
盛り上がり: マルチエンディングを取り入れることができて喜んでいました。'),
  ('34cce248-57e1-55ae-b305-91c56390b37f', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-07-09', '16:30:00', null, '通常 / 親子大会の作品作成', 'オリジナル作品については、時折さらちゃんの作品を見ておしゃべりしたりしながら、楽しそうに作成していました。 検定の申し込み用紙を見せながら意向を聞いたところ、勉強していないので月末に受けるのが不安だとのことでした。大会の作品はひとまず完成しているため、検定の準備をしたいという本人の意向により、2級の問題のうち、取りかかりやすい応用課題1を解きました。 時間内に完成はしたので、次回答え合わせともう一問への挑戦をし、7月受検か8月受検か決めたいです。', null, 'タイピング: 楽しそうにタイピングしていました'),
  ('9cfc8a8d-0e6b-5a51-a6ef-2e6b3cf812a6', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-07-09', '16:30:00', null, '通常 / 自発的に学習する', '私が担当するのが久しぶりだったことを利用して、「最近どう？」と声掛けをし、コンテストへの参加意思なども聞いてみました。何かを作りたいという気持ちはあるけれど、コンテストに出す気分ではないとのことだったので、コンテストに参加したくないという気持ちは尊重するし、別に問題もない、と伝えると、少しほっとしたようでした。 今は何を作っているのか、敢えて聞いてみたところ、タコのゲームを見せてくれながら、「本当はこっちがやりたい」といちごの反乱を見せてきたので、数回プレイしてから「自分ならどうするか」を考えてみるよう促しました。 少し一人の時間を作ってから、この作品を通して学習したいこと、アレンジしたいところを話し合い、「一度でEndにならないように体力を作成する」「弾の動きを変えるために、定義や変数、クローンのコードを重点的に見直す」ことを決めました。 コスチュームの編集に時間をかけることもありましたが、ぐちゃぐちゃと何かを描くのではなく、角度や向きをよく見て編集していたので、敢えて静止したりせずに好きにやらせておきました。 ちゃんとした質問があるなら隣に行く、というのを2回ほど繰り返したら、隣に来てほしいのか、コード上の質問を考えて呼んでくるようになりました。 時折、元のゲームで遊ぶこともありましたが、今日はすぐ後ろに女の子や下級生がいたせいもあるのか、一度も椅子からずり落ちることなく、真面目にPCに向かっていました。 思うような動きにならなかったときに、メインのコードから飛ぶ定義のコードなども、順番通りに丁寧に見直しているところは感心しました。', '体力コードの完成を目指す。やる気があれば、新しいスキル獲得として、体力ゲージをやっても良いかも。', 'タイピング: タイピングは面倒と言ったり、こちらが勧めてもスルーすることもあったのですが、今日は周りが寿司打で盛り上がっている雰囲気を感じたのか、自分から「寿司打やる」と検索して、真面目に取り組んでいました。
盛り上がり: 自分で納得した目標をたてたためか、他の生徒がいたためか、最近の中ではきちんと授業が受けられていたと思います。 帰るときも、ちょっと満足げな感じでした。'),
  ('c0083bb6-7318-5c19-b1ad-04c8e9a8d36f', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-07-11', '16:30:00', null, '通常 / 親子大会オリジナル作品の作成、リストへのテキストからの読み込み', '保護者都合で、20分ほど遅れて来室しました。疲れたと言いつつ、やる気は満々で、本を3冊抱えてきました。 保護者の方から、あらかじめ問題をテキストで送ってもらっていたのですが、到着するなり「クイズの問題を変えたい！」となったので、少し入力時間のロスがありました。 算数問題のテキストからの読み込みをやりましたが、操作自体はすぐに覚えることができました。 最初に出てくる画面から、好きな問題の家をクリックすると鐘が鳴って出題画面に移動するコードを、メッセージを駆使して頑張って作成していました。 コードを書くスプライトや背景を間違えて少し混乱することもありましたが、落ち着いて考えさせるとすぐに納得できていました。（ちょっとせっかちなこともあり…） 出題までの流れは思う通りにできたようで、満足気でした。', 'リストを使った出題と正誤判定の作成', '盛り上がり: 今回のアイディアは気に入っているようで、毎回楽しそうに作成しています。 良冶くん、虎太朗くん、塁くんともだいぶ馴染んできて、たまに作品を見せ合ったり、飴に群がったりと楽しそうにしています。今日は三浦そうたくんに話しかけたりもしていました。'),
  ('07746fe5-ea46-5ac3-b2d4-8c588b9e4202', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-11', '16:30:00', null, '通常 / 親子大会作品作り', '今日ははっきり言うと進んでいません。ほぼ、背景の冷蔵庫をインラストを集めて作成しているだけな感じでした。元から方針が決まっていなかったので、作っている最中、食材をたくさん作っていたので、料理でもするのか尋ねたが、難しいからやんないとと答えてきました。終盤になって冷蔵庫が完成すると、そのあとのプランは何も考えていなかったので、こちら側から、背景をたくさんあることから探し物ゲームを決めました。これなら脱出ゲームの仕組みを応用できてすぐにできると思います。次回からコードメインで作るようお願いします。', 'イラスト追加にはまりすぎるので、控え目にするようお願いします。', null),
  ('6bf18995-c3e6-55ec-87b3-fe6036d97a4b', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-07-11', '17:30:00', null, '通常 / 基本操作の習得', '遊んでもらったあと、細分化された動きをアルスタジオで見せながら進めていきました。見た動きを自分で言語化することができたので、それに対応するブロックを新しく教えていきました。x座標とy座標など少し難しい内容は理解するのに少し時間がかかりましたが、紙に書いて整理してあげると覚えられたようでした。全体的に興味をもってやってくれたのもあり、最後の方で一通り完成させることができました。', null, 'タイピング: 前回やったタイピングはあまり記憶が残っていなかったようでしたが、自分のペースでア行とカ行を打つことができました。
盛り上がり: もともと人見知りらしいですが、今回は教室にも慣れてきたようでたくさん喋ってくれました。「このゲームは止まっているだけでクリアできてしまう」と言って、完成したらアレンジをしたいという様子でした。お迎えについてきた弟さんに遊んでもらって嬉しそうでした。'),
  ('b84a7c6b-5404-5575-b0f0-0a0c920a4a9b', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-11', '16:30:00', null, '通常 / 親子大会作品作り', '今回は、打った後のボールの挙動を作っていきました。スペースキーとazxキーの押すボタンで飛んでいく方向が変わるのが面白いアイデアです。飛んでいく距離も、乱数になっていてゲーム性が増していました。ただ、現状のままだと、ボールの当たり判定が激ムズです。ある程度、バットの大きくしないと、タイミングが合わせずらいです。スイングの挙動的にバットが上下で届かない場所もあるので、降る前に振る場所を選択するのもいいかと思います。あと、現状のもしの二段の判定だとあまりにも瞬間の判定すぎるので、そこをもう少し改良できればいいと思う 後半は、全然集中両区がなかったので、次回上記のことをおすすめします。', null, null),
  ('1e8dfe25-0d40-5402-b27a-97d62480fb14', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-11', '17:30:00', null, '振替 / 親子大会作品作り', '今回は、武器を増加背ました。その際に、最初に選択できるようにしたいそうなので、選択の仕組みを教えました。日と下りの流れを教えると他の同類の部分は頼らずにできていました。前回お掃除ロボの挙動がおかしかったので、クールタイムの仕組みも含めて作りました。変数の使ったやり方でかなり納得いっていました。 次回まで、少しあくので、ほかの武器の増加を家でやってくるそうです。', '勝敗判定の仕組みをつくる https://scratch.mit.edu/projects/169328907/editor/ こいつのスプライト23の仕組みを参考に', null),
  ('935d02f7-12c0-5845-bc16-1dbe72f38875', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-07-11', '17:30:00', null, '通常 / U16大会作品の作成', '前回はScratchで公開されているテトリスを参考に作成していいたようなのですが、真似して途中まで作成したものの、次にどこを編集したらよいかわからず、完全に手が止まっていました。コンテストに出すものである以上、誰かの作品のコピーではいけないこと、必ず相応のアレンジをしなければいけないこと、アレンジをするためには元のコードがわかっていなければいけないことなどを話し、作成手順の説明がある「ビンゴおじさん」の作品を見せてみました。実際にプレイすると、しゅうくんが実装したい機能のいくつかがない、との感想でしたが、そこを作り込むと別のゲームになるということで俄然やる気になり、こっちで一から作ってみる！となりました。 まずは手順の通りに作ってみる、ということで、「ステージを作る」の項を最後まで作成できました。 最後に実行したらステージが出来上がるはずが、ブロックが左端に寄ってしまうというバグが出てしまい、心残り、という感じで帰っていきました。 なお、上記のバグはしもさんとこうくんが授業後に解決してくれました。 -110+((番号を12で割った余り)*20)を(-110+((番号を12で割った余り))*20と書いてしまっていたことが原因でした。', 'コードの修正をしてから、「ミノを落下させる」以降の作成', 'タイピング: ものすごい速さでタイピングしていました。次回のタイピングコンテストも気になっているようで、実施予定時期を聞いてきました。
盛り上がり: コードが多い！などとぼやくこともありましたが、基本的には理解できる範囲のコードだったこともあってか、熱心に作成していました。 アレンジ大賞の賞品のスピーカーを、とても喜んで受け取っていました！'),
  ('9d284951-41c5-5261-8298-168164c1e1c7', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-07-11', '16:30:00', null, '通常 / 親子大会作成', '少し時間がかかりぎみだったので、残り3回であることを伝えてざっくり計画を立ててもらいました。新しいステージを作ったあと、最終回は全体を整えるということも考慮していました。今作っているステージ1で「すべての荷物を集めたらお給料をもらえる」という処理がまだできていなかったので、そこからやりました。どうやって作ればいいか分からないと相談されたので、アレンジ大賞の謎解きでも使った「～済み」という変数を使えばいいというヒントを出すと、試行錯誤しながらもきちんと作れました。', null, '盛り上がり: ストーリーは頭の中で組み立てられているようでした。'),
  ('5436d277-87a0-56f8-8a93-15f4daac62f4', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-07-11', '16:30:00', null, '通常 / 親子大会作成', '最初はスクラッチのゲームに夢中で始めてくれませんでしたが、先生のパソコンから「るいくんこんなの作ってたよね～」と作品を見せて思い出させるとなんとかスイッチを入れてくれました。前回で手順書を見ながらゲームとして成立させられたのでアレンジを進めました。アイデアがなかなか思いつかなかったので、ゲームが終わる条件を変えてみることを勧めると、最初寝ているゴリラが起きたらゲーム終了という案を思いつきました。えみちゃんがやっていたように、ゴリラのフリー素材をダウンロードして使いたいと言ったので、方法を教えると覚えて何枚か保存できました。何秒かたったらゴリラのコスチュームが変わって起きるところまで作れました。', null, null),
  ('a95cdc87-b719-5a25-8b1c-63922e921e71', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2024-07-12', '18:40:00', null, '通常 / ごめん、みてない', '作りたいイメージはあるものの、いかんせん、まだ習って間もないので。何をどうしていいか、手が進まない様子。ウロウロとお兄さんたちの画面をのぞきにいく雰囲気でした。 私が隣に座り、作品の構想を聞いていった。 現時点で、風船割りのアレンジで、「グー」と「ピストルの弾」が出てくるところまでアレンジは完成。 ・会話をしていくと、その次のアイデアがドンドンでてきてしまう。 ・私が紙に書きながら整理したことを熱心に見て。「このステップは～」と、一緒に細分化っぽく考えられるところが素晴らしい ・全体図をみて「朝陽君、まだ習って２ヶ月ぐらいじゃん、これ全部、できそうかな？」と投げかけると、できそうもないと納得。相談して「ここまで作ろう」というラインを決めた ・カルバート五条、キャッシー、などキャラクター設定が面白い ・大会に提出するところまで、自由にできるところまでやってもらおう！', '大会提出が終わったら。基礎からやろう、と説明。ファイルを見せて、「お兄さんたちは、これだけのいっぱいやって、スキルがたくさんで、スキルたくさんだと朝陽君の考えた作品を作れるようになる」と説明。 このスキルアップが必要、ということを、大会提出後にも丁寧に説明が必要だと思う。 自由制作が非常に好きな感じなので。低学年でもあるので、何度も繰り返し伝える必要があるかも。', '盛り上がり: ゲームの全体を考えられたのが満足そうで。楽しそうでした。 まだ低学年なので、先生と一緒に会話しながらの時間が必要そう。'),
  ('dc351707-9ca7-5249-a539-987273504004', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-07-13', '17:30:00', null, '通常 / 検定２級 応用問題２', '今回は、２級の応用問題２を解いていきました。順調にプログラムを作成していき、つまることなく最後まで書いていました。プログラムがうまく動作していないと悩んでいましたが、全角と半角を間違えていたようで修正したところ無事動くようになりました。それ以外の箇所では特に間違えている箇所は見られなかったため、そういった小さなミスを気をつけていくことができれば、満点も十分狙えると思います。アレンジ部分に関しては、今回は手をつけることができていなかったため、次回以降ではその部分も確認していきたいです。', null, null),
  ('63f5662c-d269-5794-a667-ac8c6c55eb04', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-07-13', '16:30:00', null, '通常 / Excel練習', '今回も検定対策としてExcelをやっていきました。内容としては主に、グラフや図形を取り入れたり変更したりといった内容でした。動画を見ながら着実に行っていたため、スラスラと解き進めることができていました。この調子で次々に進めていくことができれば、余裕を持って本番に挑めると思います。完成したExcelのデータをどのようにして持って帰るか悩んでいたため、USBを忘れないように言ったほうが良いかもしれません。', null, null),
  ('4f5fbeb7-1f6b-5d62-ab9d-7a86e3d393c2', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-07-13', null, null, '通常 / 親子大会作成', 'クイズの問題と答え、そして問題のテーマになっている食べ物のイラストを集めていきました。画像の保存について操作方法を教えるなどはありましたが、基本的には自力で作業を進めていきました。クイズ全体の挙動を確認する予定でしたが、最後まで作業に追われ確認は持ち越しになりました。クイズに正解するほど食べ物がたくさん出てくるというコンセプトは伝わってきました。', null, '時間帯: その他
盛り上がり: やりたいことは思い浮かんでいてそれを実現するために淡々と頑張っていました。'),
  ('a93f4d18-0853-5245-a8be-0b3c63b4c49c', '0047fb11-a84a-5592-8c39-5a16c20eb10e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-13', null, null, '通常 / 「ではない」「まで待つ」の活用を覚えよう', '前回から3週間も空いたので、復習から入りました。角度の反射や変数についてはよく覚えていましたが、まで待つの条件にはあまり理科で来ていませんでした。そこで、まで待つをフル活用したレース順位ゲームを作りました。まずは、ノーヒントでどこまで作れるか試してみたら、もしを使い長押しでも動いてしまう状態でした。そこで、連打の動きについて細分化するように考えてもらいました。こちらの誘導で、押して離すの動作がわけられることがわかりました。そのとき、「ではない」のコードを使いましたが、初めて使うようでした。 順位の付け方も考えてもらったが、変数を使うヒントを出してもなかなか悩んでいたので、前回のスコアの付け方を振りかったところ、変数で変えるべきタイミングにコードを作ることができました。 親子大会について話しましたが、すぐには作れるものはなく、今はスキルアップの方がよいのことでしたので、今回は見送りました。', null, '時間帯: その他
盛り上がり: ふだんは文字お越しを音声とつけてやるのを作っているらしいです。'),
  ('94d4ecef-e9fa-53eb-9957-6fda0591dfec', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-07-13', null, null, '通常 / 大会作品制作', '前回の続きから大会作品を制作していきました。今回は、キャラクターが出す爆弾の挙動や効果音などについて制作および修正を行っていきました。プレイヤー１と２で爆弾の発射される距離が異なるため、一度コードを見直して修正を行っていきました。その際に、自分自身で間違いに気づくことができていました。次に、爆弾に効果音を入れる際には、自分のオリジナリティを出そうとどの効果音にするかかなり悩んでいました。最終的には納得のいくものが見つかったようです。次回で、爆弾の残ったバグ修正とBGMを入れて作品は完成となるため、頑張っていきたいところです。', null, '時間帯: その他
盛り上がり: バグを自分自身で発見および修正することができて喜んでいました。'),
  ('d6ec6e53-c511-5f39-84e6-9ad9b41b9047', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-07-13', '16:30:00', null, '通常 / オリジナルゲーム制作', '前回から作っていたオリジナルゲームであるRPG風ゲームの制作をしていきました。操作キャラクターと敵キャラクターの挙動や、技の名前などを考案していました。その他にも、特定の攻撃に対しての反応やUIの作成など様々なことへ挑戦していました。自分自身のアイディアや、やってみたいことをとにかく取り入れているような作品なので、とても楽しそうに作っていました。今後どういった内容を取り入れていくかも予め決めているようなので、制作にはより精が出てきそうです。', null, '盛り上がり: オリジナル作品を楽しそうに制作していました。'),
  ('ecae4a0d-6e62-5a9e-b6c2-688e6b72311f', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-13', null, null, '通常 / 作品作り', '基本的は、自立して進んでいるので、コードの表現が思いつかないで悩んでいるときは、補助してあげました。そこで、プレイヤーが拾った球をぷれやーの周りをまわる仕組みを作りたいそうだったので、三角関数を使ったものを教えてあげました。ちひろくんは学校ではまだ三角比を習ったばっかだったが、存在は知っていたので、スムーズに理解できました。「探す」で見本のコードがあったので、理解が早くそこから自分の領域へすぐに取り込めていました。', null, '時間帯: その他'),
  ('8868e557-4ce1-555b-b7e1-8f36b48dba7f', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-07-13', null, null, '通常 / 親子大会作成', 'アイデアは浮かんでいるがやり方を考えるのが難しいという感じだったのでヒントを出しつつ進めました。「y座標を変えると上に飛んでいく」「コスチュームを番号で指定する」などの基本要素は手順書の中で扱っていて、それを応用するとやりたいアレンジができるので、「その動きはここでやったよね～」と復習を促しました。すると内容を思い出してうまく作れました。 その後、10点と20点で違う演出をつけたいとのことだったのでやってもらいましたが、10点の処理と20点の処理が頭の中でごっちゃになってしまいました。そこで「プログラムは上から下の方に順番に実行される」ことを強調したうえで、旗を押してからの流れを時系列で整理しました。そうするときちんと理解してコードを組めました。', null, '時間帯: その他
盛り上がり: アイデアを話しているとき楽しげでした。'),
  ('23062b5b-6c65-5a85-80d5-a767246539fa', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-13', '17:30:00', null, '通常 / 親子大会作り', '分子を判定する仕組みを作っていきました。自分でも手探りで作っていったので、思いついた仕組みではゆうとくんにはなかなか難しいものになってしまいました。自分が考えている最中は背景や音を考えて持っていたので時間は無駄にはしていません。あくまで、今回作ったものは暫定的なので、あとできれいにできるところはきれいにして、ゆうと君用に上げときます。それを次回に3分子と4分子を作っていったらいいと思います。', '追記分子の判定の仕組みを自分が作った「しもさんの見本」で公開しました。その中のコードを参考にしながら教えてみてください。細かくコメントを入れたので', '盛り上がり: 姿勢を正そうね'),
  ('a5ea849a-56cf-5c02-8ba7-a8e934c8db89', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-16', '16:30:00', null, '通常 / いちごの反乱のアレンジ', '前回までつくったところを見せてもらいました！状況を進める部分のスクリプトをきれいに整理してプログラムできていました。本人の希望で「8」「9」「10」の状況をアレンジとして作成しました。親がクローンを作る部分、クローンを動かす部分と分けて説明しました。ランダムにクローンを置くところ、動かし方も理解しながら取り組めました。クローンの部分で「～でなければ」を使う理由が少し難しい様子でした。 スプライトのコスチュームを変えるとき、（プログラムが少し複雑にも関わらず）適切な場所にコスチュームの設定をプログラムすることができていました！', '続きをまだ取り組みたいようです！', 'タイピング: 普通に挑戦していましたが、ちょっと難しかったようです。
盛り上がり: 八ヶ岳にいく話を教えてくれました！かなり楽しみなようです！'),
  ('a71a5911-8c21-5163-9cbd-7cec02b81692', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-16', '17:30:00', null, '振替 / 大会作品', '前回作ったところまでプレイさせてもらいました。くまちゃんがうまく小さくなって隠れていて、よく工夫されていました。 のこり時間を意識してもらいつつ、お金を取られる部分とバイトの部分のプログラムを作成しました。バイトは最低でも1つ作りたいそうです。 盗られる部分：大きさをうまくコントロールしつつ、コスチュームにもこだわりつつ丁寧に進められました。前を横切る盗人もうまく動かせていました。 盗む部分は最後までおわりましたが、バイトはできませんでした...最後まで終わるか心配ですが、やりたいことはしっかりあるようなので、集中してプログラムに取り組んでもらいたいです。', null, null),
  ('85200bbd-42d5-5716-8513-0008088b0713', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-07-16', '16:30:00', null, '通常 / 締切を意識して完成までの見通しを立てる', 'オープニングの動きを何度か調整しながら丁寧に確認していました。 オープニングが完成したら、ゲーム部分を作りながら検証する際にオープニング部分のコードを外していたのには、さらちゃんの「慣れ」を感じました。 ゲーム部分の動きの参考が欲しいとのことだったので、アクションゲーム_移動とジャンプ 完成版ステージアップ【LR】を見せました。熱心にコードを見て、色のところを変えたりしていましたが、ジャンプの時と横移動の時の「色に触れたら」の意味がよくわからなかったようで、自己判断で省いてうまく動かない所がありました。元のスプライトの色を見せ、実際に動かして、どことどこが「触れた」判定をされているかを確認させたところ、納得したようでした。 元のゲームが背景でステージを変えているところをスプライトのコスチュームにしていたため、少し迷うところがありました。さらちゃんの作品的に、ステージ番号で管理した方がやりやすそうだったため、ここを次回、説明してから取り組んでほしいです。', '和先生に引継ぎ済み、ステージによっての向きや出発座標に注目させてあげてください。', 'タイピング: 楽しそうに取り組めていました
盛り上がり: さらちゃんが描いたカモがかわいく動くようになったのが、嬉しそうでした。 疲れたのか、途中でだるそうな様子も見せていましたが、カモが動くようになったのと、賞金5万円に盛り上がり、バスの時間ギリギリまでよくがんばっていました。'),
  ('d9f58041-688b-5d17-ac10-a226f37ce853', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-07-12', '17:30:00', null, '通常 / 自由作成', '親子大会には出さないという意思があったので、以前やったDKアートの花火の応用をしました。花火と同様に、クローンを作って色々な場所に配置する自由作品を作っていきました。この仕組みで今流行りの曲のMVが再現できることに気付くとそれをやっていました。親子大会に今日作ったアニメーションも使えるかもと伝えましたが、やはり乗り気ではなかったようです。', null, null),
  ('bae0663f-2b41-55ac-ad3e-3f3b7ac26a2c', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-07-12', '17:30:00', null, '通常 / 親子大会作成', 'ふうせんをわろうのアレンジをやりました。クリアの文字を英語で書きたいということで、頑張って書き写していました。30点以上でクリアにするという処理がわからなかったそうですが、算数で不等号は習ったそうなので「どっちが大きいかな？」などと問いかけると仕組みを理解しました。BGMやクリア音なども自分で曲を選んでつけることができました。', null, '盛り上がり: 進捗ができるたびに見せてきてくれました。'),
  ('56d7dfa0-3527-5423-90df-f3fdb2bcc9e5', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-07-12', '17:30:00', null, '通常 / 親子大会作成', 'ふうせんをわろうのアレンジを進めました。ゲームクリアの処理で少し混乱していたので不等号というヒントを出すとできました。また、クリア時に桜の花が降ってくる演出をやりたいとのことでどうすればいいのか迷っていましたが、x座標とy座標の知識を整理するとキャッチゲームなどの内容を思い出して作れました。「クリア」という文字を直線で描いてみたりもして見た目に面白い作品になっています。', null, null),
  ('8bb589aa-7d7b-51f1-b932-2e4d12071d9e', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-07-12', '18:40:00', null, '通常 / U16大会作成', '中学生大会の製作を今日から始めました。アイデアが浮かばないというので、過去の入賞作品やアルスタジオのゲームを参考にするよう勧めると色々見ていましたが、ピンとくるものはなさそうでした。ただ、その流れで自分のスタジオ(今まで作った作品)を見ると、昔のコンテストで出したコイン工場のゲームが出てきて、これの続編を作ろうということに決めました。まずは見た目を改善するということで、ベルトコンベアがうまく回っているような動きを作りました。', null, '盛り上がり: スイッチが入ると本領発揮していました。'),
  ('2f931bde-7d0d-5ad7-aee5-300ec685ca21', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-07-12', '18:40:00', null, '通常 / U16作成', '中学生大会はアレンジ大賞で優勝したスマブラを改良して出すことに決めていて、黙々と製作を進めていました。まずは自分で考えたしゃがみモーションを作るところまでいきました。全体的な計画についても少し会話し、キャラごとに違う性能をつけられたら面白いねなどと話しました。', null, '盛り上がり: 通常レッスンのあと教室に残ってオンラインもやるとのことで長時間でしたが頑張っていました。'),
  ('8df55695-beab-5223-8965-0fd79406e150', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-07-13', null, null, '通常 / インベーダーゲーム作成', '今日の中盤で手順書の部分を全て完成させ、晴れてアレンジに入ることができました。家で描いてきた自作のキャラを写真に撮ってスプライトとして使いました。また、世界観を追求したいようで「フリーのBGMを検索したい」と言ったので操作方法を教えるときちんと聞いて覚えました。これまでに手順書で集中力を培ったからか作成から脱線することはなく、1時間ほぼ休憩を挟まず作成を続けられました。', null, '時間帯: その他
盛り上がり: 約束通りやりきった達成感というよりはアレンジをしたい気持ちの方が大きかったようです。'),
  ('61ab5be5-6ef1-5b32-8453-a50547ca7504', '28d52d6e-7571-5090-a2d9-492c997b719e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-07-13', null, null, '通常 / 親子大会作成', '八王子名物が書かれた風船を撃つと得点、それ以外のものが書かれた風船を撃つと失点とするなど、ルールをしっかり考えていました。作りたい動きは言語化できるが作り方がわからないというので、少しずつヒントを出しながら進めていきました。針を撃つ動きは一見複雑でしたが、「まずどの方向を向く？そのあとどう動く？いつまで動く？」と順番に問いかけていきました。するとシンプルなブロックを組み合わせればいいと納得して作ることができました。「ふうせんをわろう」と「八王子名物」を組み合わせたやすのりくんの作品はビギナーとオリジナルのどちらにも出せるので、どちらにするか考えてくるように伝えました。', null, '時間帯: その他
盛り上がり: やはり賞金が欲しいことがモチベーションになっていました。賞金の取りやすさや額も出す部門の判断材料になりそうでした。'),
  ('24dac3ee-67c3-59c9-abde-bb70e14c4b6c', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-07-18', '17:30:00', null, '通常 / U16大会作品制作', '前回の続きからテトリスのプログラムを作って行きました。今回は、ミノの落下や左右移動などミノの動きに関する部分について作成して行きました。手順書を見ながら作成して行きましたが、ブロックの数がかなり多いため終わりが見えない作成に苦しんでいました。時間の最後には、ミノのデザインをしていく部分に入って行ったため、今までよりも気持ちが楽になって作れていたようでした。今回で全体の４割ほどが完成したため、次次回にて作品の完成を目指して行きたいところです。大会締切までは時間があるため、アレンジなどにも多く時間をさけそうです。', null, '盛り上がり: コードが一区切りついた際には進んでいることを実感して喜んでいました。'),
  ('850dc73f-3f1a-5770-b4a7-bac2037737ee', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-07-18', '17:30:00', null, '通常 / U16大会作品制作', '今回は、今まで作成していたものではなく、新たな大会作品の制作に取り掛かっていました。ゲーム内容としては、ゲージが上下に動き続けている中で一定の範囲内にある時に止めるというものでした。シンプルで遊んだことのある方も多いゲームのため、作成難易度自体はそれほど高くないため、すぐに完成させることができると思います。反対に、アレンジ部分に関してはかなりの工夫が必要となってくる可能性が高いため、その部分でいかに差をつけられるかが鍵となってきそうです。', null, null),
  ('96b07f35-29d7-59c7-946e-f7a48a847051', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-07-18', '16:30:00', null, '通常 / 大会作品制作', '前回の続きから大会作品制作を行なっていきました。作りたい内容をどんどん付け足して行ったり、素材の選定に時間をかけてしまったりと作業の進行がいまいち進んでいないのが現状であるため、可能であれば家でも作ってきてほしいと伝えました。作品の内容は本人の個性的な面が表れており、非常に素晴らしいものとなっているため、部分的に削ってでも大会には間に合わせて行きたいです。', null, null),
  ('e3df07d8-73c1-5b0d-83a3-91bc91bd1c71', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-07-18', '16:30:00', null, '通常 / 大会作品制作', '作品を続きから制作してきました。今回の序盤で作品作りは完成したため、桃太郎タイピングをおこなったり、別のゲームを遊んだりして行きました。提出フォーム用の紙への記入は抵抗があるようで、特に作品の説明部分に関してはかなり嫌がっておりました。結果として、最初の１行もかけていない状態なので、次回来た時に提出フォームを完成させて行きたいと考えています。', null, 'タイピング: しっかりと打てていました。'),
  ('af45eb8f-2284-5135-b1bd-57620f18046f', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-07-18', '16:30:00', null, '通常 / 親子大会作品の完成をめざす', 'やりたいことをきちんと決めてきたようで、授業開始直後に声をかけたら、「今は問題の部屋の入れ替え部分を作っているから自分でできる、大丈夫！」と熱心に進めていました。 場面がかわるときに背景を指定する際、背景名がデフォルトのままで英語を読むのに手間取っていたため、自分はもちろん、審査する人が見やすいように背景名を変えることを勧めたところ、とても納得したようで、素直に書き換えをしていました。 新しいリストを読み込んだ後のコード作成にまだ慣れていないようで、自主的に質問にきましたが、最初に作ったコードを複製して書きかえるべき場所がわかると、あとは一人で黙々と作業ができていました。', null, '盛り上がり: 今回の作品は、勉強になるし面白いから自信がある！と、満足げに語っていました。 作品のエンディングやアピールポイントを考えてくる！と、元気に帰っていきました。'),
  ('f8ad024a-a8d7-537f-9524-fb6554dd88fd', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-07-12', '16:30:00', null, '通常 / 基本的なスキルを学ぶ', '本人の希望で、ピンポンゲームの課題に入りました。最初に完成品で遊んだところ、すっかり気分が盛り上がって、そこのコードを見て覚えて、すぐにそのまま作成しようとするので、敢えて声をかけて手を止めさせ、一つ一つの動きと対応するコードを意識させるようにしました。りょうまくんも、気は急いていたものの、話しかけられるのは嫌ではないようで、素直に手を止めてこちらの話を聞き、質問もよく考えて答えようとしていました。 ↑x座標をマウスのx座標とする意味、パドルにボールが触れた時のコードで〇秒待つを入れる意味など、その都度よく考えて答えることができていました。 一通りゲームが動くようになると、やや集中力が途切れて、前回やって面白かったらしいビデオモーションのブロックをいじってみたりもしていましたが、考える時間、手を動かす時間、息抜きで興味のあるところをいじる時間と、一通りのバランスはとれていたように思います。', null, '盛り上がり: ピンポンゲームはずっと作りたかったようで、とても楽しそうに、やや前のめり気味に取り組んでいました。'),
  ('e8404d19-1486-5d36-b9d0-900c913389f8', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-07-12', '17:30:00', null, '通常 / 親子大会作品の作成', '作りたいことが頭の中にあるようで、基本的には黙々と集中して作業していました。 とはいえ、声をかけられるのは嬉しいようで、声掛けをするたびに、今はここを作っている、と楽しそうに説明をしてくれていました。 使用している変数の「変数」と「DENRYOKU」が、変数名のせいか、混同して使っているところがありました。最終的には自分で気づいて直していましたが、もしかしたらまだ、同様の間違いがあるかもしれません。 コードの書き方や画面の構成など、晴くんとしてはかなり成長してきていますが、バグ探しで焦ってくると、ものすごい速さでブロックを外したり捨てたり複製したりして、画面上のブロックが重なって余計に混乱を招いていることもありました。ただ、そこで投げ出さずに我に返って、「ブロックが重なっちゃった」などと言いながらもとに戻しているところは、成長に伴う落ち着きを感じさせられました。', null, '盛り上がり: 今の作品は気に入っているのか、終始機嫌よく、集中して取り組んでいました。'),
  ('295222c5-3b2f-5701-94e9-26d2886fca60', '53dc382f-637d-5a46-9b57-4204c79ee130', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-07-12', '17:30:00', null, '通常 / 教室に慣れる、基本的なスキルを学ぶ', '絵画？をやっているためか、スプライトの見た目の変化をかなり面白がってくれたため、「名前を動かそう」は順調に進みました。アルファベットを入れるのも、最終的にアレンジをして自分と弟くんの名前がアニメーションのようになるのも、とても楽しんでくれました。 ちょっと甘えたがりなところもあり、授業中もよくしゃべっていますが、雑談から課題に戻るときも基本的に素直なので、進行に問題はありません。 疲れたから休憩したい、水や飴をとりにいきたい、というのも素直に口に出します。無理強いせずに好きなようにさせてみましたが、休憩から授業に戻る切り替えもはやいので、特に問題はありませんでした。', 'ゲームというよりも、アート的な方に興味があるようなので、ファイルの1枚目をそのまま進めて、アニメーションを作ろう、といったようなノリの方が楽しめると思います。', 'タイピング: タイピングは苦手ではないようで、素直に取り組んでいました
盛り上がり: アルファベットの色が変わりながら動いたりするのを喜んで取り組めていました。'),
  ('da051f70-5fdf-5c5a-98f6-43fc10cbc156', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-19', '16:30:00', null, '通常 / コードの順番を意識しよう', '今回も自ら進んでやることを決めようとしていたので、コード探求の3つから選びました。スロットを選びました。そこで、見た感じから自ら作り始めていくが、押してもスロットが止まらない状態になってしまいました。前回までで、1度きりの判定に使うには何があったか思い出してもらったら、「まで待つ」が使えて止まるようになりました。次に、判定の方法に悩んでいました。そこで、どのタイミングで判定をすればいいか全体の流れを一緒に考えました。その流れで、メッセージを使うことを伝えましたが、本人的にはなじみが薄い感じでした。そのあとは一緒に考えていき完成できました。 今回からメッセージの使用用途の感覚が薄いと感じたので、物語などの祖の感覚を身に着けた方がいいです。', null, 'タイピング: 授業前いち早く取り組んでいました。
盛り上がり: アレンジで、前回試し下ビデオのことを試していてよかったです。'),
  ('58f4900e-07bd-5278-9016-81b7b35f5b1c', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-19', '17:30:00', null, '通常 / 自由製作', '今回も自由製作してくれました。来て早々作りたいものがあり、単純に言えば、当たったら死ぬゲームでした。初稿が試したが、ゲーム性を上げるべきとゆったら、修正してくれました。その後も、ゆづきくんやはるくんから遊んでその都度修正を入れて楽しんでいました。演出も面白いものとなっていたしよかったと思います。', null, null),
  ('a042ed9d-d640-5578-9ba4-a6e93e7c9c08', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-19', '17:30:00', null, '通常 / 親子大会作り', '最初に進捗状況を聞いてみると、かなりまだまだぽいです。普段はわからないことがあれば、声をかけてくれたが、今日はなかなか手が回らず申し訳ない。かなり大作を作っているので、状況を把握するのに時間がかかってしまいました。最終的には、時間オーバーでバグ対処できなかった。次回までにむりそうだったら個人的には作品の深堀ができているので、U16でもよさそう。イラストもオリジナルで書いているし。', null, null),
  ('56eac4eb-d7e0-50e6-a14c-3d411c48ebdc', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-19', '17:30:00', null, '通常 / 親子大会作品作り', '前回で一通りの流れができていたので、細かいバグを直していきました。ゲームクリア後の動作止めや変数の不具合などが治していきました。こちらからどのような状況でしたい動作をすべきか質問しながら明確にしていきました。しっかり受けごたえで来ていたので、身をもって把握できていると思います。クリア後に、じゃんけんを追加しました。「聞いて待つ」の質問ブロックを使いたいそうだったので使いました。使うブロックだけを提示させ、条件を佑月くん自身で整理しました。条件コードはできていたので、次回はそこを整理したら完成できると思います。', null, null),
  ('4dbf3555-51f9-5947-b8f3-876294b5a77e', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-19', '18:40:00', null, '振替 / 親子大会作品作り', 'ゲームスタートやオーバーの仕組みを作って1通りの流れは完成しました。ゴール条件で間違って「もし」を使っていたこと自ら気づき、「まで待つ」に修正できていました。クリアの演出もこだわって作っていました。そのあと、変数周りの細かなバグを直しました。 一通りはできたので、メモっていた自分のアイデアでまだ使えるものか照らし合わせたいそうです。 そこで、最後はイラスト追加していました。迎えが来ていても書き続けました。', null, null),
  ('e2f4a60b-ca7d-5b4f-a0b5-6f0155af2d80', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-19', '18:40:00', null, '通常 / 親子大会作品作り', 'パッと見作品がごたついていたので、とりあえず、次に進めたい聞きました。そしたら、もう一段階点数に応じて進化するそうです。そこで、今まであるやつをリサイクルできるので、その作業を一緒にやろうと思いましたが、スキルが置いておらず一方的でした。そのため、教室をふらついてお絵かきに走っている場面が何度も見られました。 そこで、帰りに親との話し合いで夏休みはスキルアップを目指すことを耳に挟みました。', 'ゆきさん、親との話した内容に補足事項があれば追加お願いします。 はい、親と本人と３人で話をしました。 作りたいアイデアが広がるも、できるスキルが少ないので実現が難しくなっている。 本人にも、ファイルをみせて。こんだけ課題をやれば、頭の中のイメージを形にできるようになると、やれるかな？と聞くと。非常に元気に「うん！」とやる気を出してくれました。 なので、次回からファイルの最初の方の基礎をやりましょう。 その際、最初にかならず「今日、これでこんなスキルが身に着く」という声がけをお願いします。', null),
  ('1c78427c-28f5-5d87-a802-4509b09bd5cc', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-19', '18:40:00', null, '通常 / U16大会作り', '今回は、U16大会に向けて書類審査の内容を説明しました。書類での説得力を持たせるためにストリーが必要だと説明をしました。戦いのゲームの技術は素晴らしいので、その状況に至るまでの背景を考えた方がいいと伝えてあげま知った。', null, null),
  ('9e3a4438-91df-5ff6-a022-65dc75930ea0', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-22', null, null, '通常 / 大会作品', 'やりたいことリストを作ってきてくれたようです。 ①上に止まってしまっているスクリプトをなくす②動く時間をランダムにする ③得点がマイナスにするスプライトを追加する④音を追加する の4つを主にしました。①はプログラムの内容を確認して「隠す」のブロックの追加、②は乱数の働きを確認して（怪しいかんじでした）取り入れました。③に関してはほぼ自力でできました。④で音を流すことができましたが、ゲームオーバーの時に音が重なってしまいました。「全てを止める」を使っても解決できなかったので、もし余裕があれば、エントリーシートの内容と伏せて確認をお願いしたいです。 楽しく取り組めました！！', 'エントリーシートの内容確認、ゲームオーバー前に音を止める（できれば）', '時間帯: その他'),
  ('a178c94f-3345-5daf-9801-8b6bac9ef7fe', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-22', null, null, '通常 / 検定2級応用問題3、ピンポンゲーム', '検定問題は40分で取り組んでもらいました。途中、見慣れないブロックがでてきて少し困ったことがあったようですが、答え合わせのときには全部完答できていました。 興味がありそうだったのでピンポンゲームに取り組んでもらいました。パドルの動かし方が少し難しかったようです。見本をみてもらいながら、少しヒントを出すとすぐにうまく動かせていました。まだ途中なので、次週続きです。', null, '時間帯: その他'),
  ('d2c73f78-ccf3-502a-b0d3-55f251e67a5e', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-22', null, null, '通常 / 大会用作品。締め切りを意識', '一通りゲームの内容はできていたので、ゲームオーバーの部分を作成しました。検証をするときに敵のHPがなかなか減らず大変だったので、検証用にパラメーターを調整しました。また、使っていないコードや送っているメッセージ名が間違っていたので修正できていました。ビームの見た目を変更しました。 中に使用していないスクリプトがいくつかあるので、整理する必要もありそうです。', null, '時間帯: その他
タイピング: 少し損をしていましたが、楽しそうでした。'),
  ('961051d5-cdc0-52a2-89e7-598e7caf175a', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-22', null, null, '振替 / オリジナル作品', 'カーソルに触れた玉をゲットし、ゲットした玉がカーソルの周囲をきれいにクルクル回るようなプログラムを作っていました。定義や演算のブロックがたくさん使われていて、かなり高度なプログラムになりそうです。途中、「カーソルの周囲を回っている玉が落ちてくる玉に触れたときに消せるようにしたい！」とのことで相談を受けました。定義ブロックを使っていたので変数を使うことを提案しました。その後、自分でも工夫してうまく作動させることができていました！', null, '時間帯: その他
盛り上がり: かなり熱中して取り組んでいました。楽しそうです。'),
  ('9a0d2c13-edfa-55e1-a43a-f6d69de16964', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-22', null, null, '通常 / 大会用作品', '間が空いてしまったので、現状の聞き取りをしました。キャラクターを増やし、上から落ちてくるものをキャッチするようなゲームの仕組みが出来上がっていました。スプライトを増やして工夫したそうです。 スコアのプログラムが動かなくなっていたので、プログラムを見ながら一緒に改善しました。またコンセプトとしてはネコが地球を守るような感じみたいです。 またその他の工夫として、コスチュームを変える、キャッチしたら隠すをプログラムしました。来週もし時間があれば、最後の得点によって「守れた！」などネコが話せるようにしたいです。', 'エントリーシートの確認、時間があれば最後の得点によって「守れた！」などネコが話せるようにしたい', '時間帯: その他'),
  ('2e902fd3-8ca8-5d3d-9bb3-e5a3aa615324', 'e2ac46d1-ae85-5d6d-b24f-86dc103d0170', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-22', '16:30:00', null, '振替 / 作品を作って遊ぼう', '作りたいものを軽く手伝おう程度に思っていたが、親子大会の話を聞くと、学校で見ていたから少し出したい気持ちがあるそうでした。そこで、作りたそうだったバレーボールの打ち合いのゲームを一通りの流れを作りました。学校での経験が少しあり、スクラッチの座標と向きの感覚はしっかりと身についてたので、スムーズに作れました。「もし」や跳ね返し方などはこちら側からアイデアを出しましたが、非常に楽しんで作れていました。一人で進めているときも、細かい修正などをして作品を整えていました。', null, '盛り上がり: 自慢のBMXで乗ってきてくれました'),
  ('331d584e-abb8-5a98-bf1f-04a25c31aca4', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-22', '16:30:00', null, '通常 / 親子大会作品作り', '今回は、ゲームの始まりと終わりの演出をしっかりと作り上げていました。おわりはかなり華やかしいものになりました。はじまりもゲームの仕方がうまく誘導で来ていてよかったです。そして、タイピングしてく途中で出来上がる布も作成していました。どんどんと布がおりあがっていくような演出がしたいそうです。前回自分が作ったものと組み合わせてゲーム途中の演出を仕上げれば、完成すると思います。', null, null),
  ('443858b1-3dab-523b-88d9-9bc8e265d8fe', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-07-22', '16:30:00', null, '通常 / 習ったブロックの復習をしながら新しい作品を作る', 'お母さんから、コンテストビギナーズ部門への参加IDが届いていたため説明をしましたが、本人が頑なに「参加しない」とのことだったので、勧めるのはやめました。 新しい作品が作りたい、と言いながら、自分でファイルをパラパラめくって【DKゲーム】02迷路 チーズをさがせ！②邪魔者ver、乱数のサイコロ、スロットマシーンなどをいろいろ試した結果、迷路のアレンジがしたい、となりました。 条件分岐と矢印キーでスプライトを動かす学習の復習として、スプライトの向きなどに注意しながらスプライトを前後左右に動かすコードを作成しました。できあがった途端、やっぱりマウスで動かしたい、となってコードを完全に書き換えましたが、復習にはなったかと思います。 マウスの方にスプライトが動くのは、以前もやったと言いながら楽しそうに作成していました。 この教材では、ファイルにスタンプを押すところがなかったせいか、細分化して一つずつ作成を勧めてはみましたが、スタンプ押すところがないなら俺がアレンジしたい！と聞かず、迷路の中で動くオリジナルゲーム作成になりそうです。それでもたくさんのスプライトを迷路に配置して大きさを調整し、次回は「スプライトに触れたら」を作るんだと張り切っていました。 最初に対応した先生に固執するのか、今日は私が他の子のところにいくと執拗に声をかけてくる様子が見られました。過去の月曜日、私が最初に他の子を見た時は、どちらかというとスルーされるので、先生に執着するというより、今日はこの人、と思った人に最後まで面倒を見てほしいタイプなのかもしれません…。', 'チーズを探せの続きから', '盛り上がり: こちらの示す教材にはなかなか集中できませんでしたが、やると決めたものはしっかりと取り組もうとしていました。 迷路の中に動物をたくさん配置して満足そうでした。
備考: コンテストをやってみないかと促したけど本人がやらないと言い切った、という話をお母さんにしたところ、少し残念そうでした。'),
  ('691d5890-45f0-57a9-afd8-b6833aaf6d38', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-22', '17:30:00', null, '通常 / 親子大会作品作り', '前回から家である程度は進めてきたそうです。そこで、やりたいアイデアはあふれてしまってなかなか手が付けられない様子でした。そこで、まずは目の前にあるバグを修正することを進めました。インクの太さなども調節してゲーム性を保ちました。ためダッシュみたいのも作りたいそうだったので、小技のため技も紹介して家でやってくるそうです。', null, null),
  ('e411ec12-e34f-5bb7-aea7-7fdb271d4b76', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-07-22', '16:30:00', null, '通常 / 親子大会ビギナーズ部門の作品にチャレンジする', '勇作君と一緒にコンテストの説明を軽くしたところ、乗り気になってきました。 勇作君がやらないとのことで、勇作君が教材を選んでいるときにかなり気をとられ、何度も脱線しかけましたが、最終的には「どうしてもコンテストをやる」と自分の教材にもどってきました。 最初からすべて作成するのは間に合わなかったため、カウントダウンのスプライトは飛ばし、風船のところから作成しました。風船をビームに変えて、いろいろなところから出るようにしたいとのことで、作品はかなり変わってしまいましたが、座標と向きのよい勉強にはなりました。 ビームが両脇と下からたくさん出てくるように作ることができて、とても喜んでいました。', 'ビームが当たったらの動きや得点などを作り込みたいとのこと', '盛り上がり: いろいろと脱線しそうにはなったものの、思うように作成を進められたようで、お母さんにも得意げに報告し、嬉しそうに帰っていきました。'),
  ('900df223-99b3-5d48-ab75-490708942fdc', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-07-22', '17:30:00', null, '通常 / オリジナル作品の作成をすすめる', '20分ほど遅刻して駆け込んできました。やる気はあったのか、自主的に15分ほど延長して作成を続けていました。 ずっと作成を続けている鉄道操作盤？を熱心に作り込んでいました。 質問するところは特にないそうで、一人で黙々と作業していましたが、終わりごろに声をかけると、操作の順序やボタンの見た目で工夫したところなどを教えてくれました。', null, '盛り上がり: 教室で作成が進んだ分を説明してくれるときは、わりと雄弁で、少し嬉しそうに語ってくれていました。'),
  ('c003f7d4-987b-513b-8c61-0604ac5ec311', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-07-22', '17:30:00', null, '通常 / 基本的なスキルを学ぶ', '体験やこれまでの授業の流れで学習したことはよく覚えていて、座標で動かす、背景を変える、音を加えるなど、どれも「やったことがある」と自分でコードを作成することができていました。このあたりのレベルなら一人でも進められそうですが、先生と話しながらやりたいタイプのようで、声をかけたり隣に座ったりするととても嬉しそうでした。 座標で動かす学習の際、ただ適当な場所に動かすのではなく、背景を変えたりしてストーリーがあるように動かすのを提案すると、とても面白がって取り組んでくれました。', null, '盛り上がり: スプライトの動きに意味やストーリーがある方が楽しいようで、アルくんが歩いてから場面転換するところなど、BGMを付けたりして熱心に作成していました。
備考: スプラトゥーンが好きだそうで、そうたくんと使用している武器などについておしゃべりしていました。'),
  ('bea32393-54d6-560b-95a4-ad1b894869f3', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-23', '16:30:00', null, '通常 / 大会作品', '前回やったステージ番号の仕組みはすぐに理解できた模様。ステージ番号が4になったときの動きを調整しました。「まで待つ」の使い方を詳しく紹介しました。 おばけを追いかける仕組みにしたかったそうですが、時間がないので、制限時間付きのゲームになりました。ゲームオーバーの画面を作成しました。メッセージが多く入り乱れいるプログラムでしたが、スクリプトを動かし始めるタイミングについては自分でよく考えて取り組めました。 まだ逆に成功したときのプログラムを作れていないので、次回30分ほどで作る必要がありそうです。', null, null),
  ('a0d9111a-5ef6-53a0-a01b-cc609281524f', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-23', '16:30:00', null, '通常 / 大会作品作成', '「アレンジとか作り込みをする！」とのことで、とくに前半は集中して取り組むことができました。本人の目的意識があってよかった。 正解数に応じて何かをゲットすることを提案しましたが、あまり乗り気ではありませんでした。いくつか提案しましたが、自分的にやりたいことがあるそうで、メッセージや喋ることばのタイピング、プログラムの整理などに取り組んでいました。内容のレベルを上げるよりも、楽しく取り組むほうが好きなようです。', null, '盛り上がり: 検定は来月から取り組むことは伝えました！'),
  ('7f4bdf8e-1c85-55f6-91f2-cde521d6ba71', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-23', '17:30:00', null, '振替 / トランプゲーム、その他情報の共有', '本人的にはExcelをやる予定だったそうですが、イヤホンがなかったので、Scratchに移りました。新しくトランプのスプライトが出ていたのでいろいろ考えてもらいました！作品として作るのは難しかったそうなので、前半でストップしました。 後半は診断系のScratchを紹介してもらいました！MBTI診断をScratchで作っているもので、ホームページにあったやつを見せてもらい、実際にプレイしました。あんまりScratchに診断系のゲームはないので、複数人で遊んで相性が測れるような仕組みがあったらおもしろいよねー！という話をしました。 オフィスアプリを使うときのAltキーの使い方、またChatGPTの使い方についても共有しました。ChatGPTに関しては、実際に使った様子を見せつつ、いいところ悪いところの両方を紹介しました。', null, null),
  ('89a48afd-dc7f-58a0-b5da-1866921af22c', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-07-23', '16:30:00', null, '通常 / 親子大会作成', 'ゲームの動き自体はだいたい作れていましたが、どういう状況なのかがあいまいだったので一緒に組み立てました。少し説明があったほうが分かりやすいよねと伝えると、ゲームの導入部分と終わった後の部分をつけることに決まりました。また、キャラクターがアクションするごとにセリフを出すことで内容をわかりやすくしました。条件によってノーマルクリアとスペシャルクリアを作り、両方完成させました。寝ている間に悪夢にうなされるというストーリーをはっきり示すことができました。', null, '盛り上がり: 最後までうまくいったときは達成感を感じた様子でした。'),
  ('8d84e995-a4c8-55fd-beb7-500e65b64982', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-07-23', '16:30:00', null, '振替 / 親子大会完成', 'HP回復ボタンを押したらずっと反応しているバグがあることを指摘すると、「1秒待つ」で対処することを思いついて直せました。シールドを壊したらシールドの変数を隠すなど見栄えも調整していました。前回少しふざけて作ったような背景があったのですが「これをゲームオーバーの背景にすれば雰囲気出るかも」とアドバイスすると作りこんで採用していました。そのあとクリア画面を作っている途中でやる気が落ちてきてしまったのですが、これだけ完成させて提出できるようにしようという今日の目標を再確認すると調子を取り戻しました。時間の最後の方で無事完成できました。', '提出', 'タイピング: ゲームクリアの壁を越えようと頑張っていました'),
  ('1f1d0519-6c05-5ab8-b5d2-0edc4b1dc447', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-07-20', null, null, '通常 / 親子大会作成', '最初は、画像を集めて配置する作業の続きをやっていました。それが終わったとき、クイズの動作確認をするように促すと後半の方で少しバグが見つかりました。ただ、該当のコードをよく見ると繰り返しの範囲が違っていただけだとすぐに気づき、直すことができました。無事に一通り完成し、少し時間が余ったのでアレンジをつけたすことにし、内容を考えてもらいました。しかしあまりアイデアが出てこないようなので会話して「終わったら置いてある食べ物を食べる」などのアイデアを提案しましたがしっくりこないようだったので、このまま完成とするのもありかもしれません。', null, '時間帯: その他'),
  ('81153164-44e9-5f68-befd-1ee4f769cb24', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-07-20', null, null, '通常 / 親子大会作成', 'ストーリーが多めのゲームなので、話の内容はしっかり決まっているか確認すると大丈夫とのことでした。その後、あまり手を止めることもなくキャラクターの会話と動きを作り続けていきました。ただ完成まではいけていないので次回ラストスパートをかける必要がありそうです。', null, '時間帯: その他
盛り上がり: 集中することはできていました。'),
  ('81bed655-a5a3-50f2-b9fa-3eb066df4e64', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-07-25', '16:30:00', null, '通常 / 大会作品制作', '前回の続きから作成していき、最終的な仕上げまで取り掛かっていきました。リストなどを使っての複雑なプログラムであるため何度かバグが発生してしまいましたが、コードを順番に読み解いていくことでデバッグ作業を終わらせていくことができました。時間の都合上入れたかった部分を削らざるを得なくなってしまいましたが、現在できているところまでで最大限頑張って作っていました。残りはクリア画面のみとなったため、その箇所を来週完成させていき、フォームに入力できればと思っています。', null, '盛り上がり: 残り少ない時間で最大限工夫して取り組んでいました。'),
  ('0a4903ca-b5c9-5235-9c94-8f6c4225215d', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-25', '16:30:00', null, '通常 / U16大会作品作り', '七ならべをリストを使って、作成していました。手札の分配をかぶりなしに行うには方法に苦戦していて、アイデアを与えてあげました。リスト付近のブロックはなじみがないものがまだあるので、うまく活用できていけたいいと思います。', null, null),
  ('e8067651-7714-5e5b-84d1-65a5f527e7c6', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-25', '17:30:00', null, '通常 / U16大会作品作り', '夏休みモードで始まる前からかなりゲームをしていました。テトリスについて、気持ちゆったり程度で全体の5割程度まで進めることができました。今日はゆったりしたかったのか遊び多めでも寛容にしてあげました', null, '盛り上がり: 中学1年1学期を終えて、期末テストの難しさに苦戦したそうです'),
  ('e46bd638-58d6-5c7e-8a74-14d4e97f4b2a', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-07-25', '16:30:00', null, '通常 / 大会作品制作', '今回は、作品の総仕上げに取り掛かっていきました。作品の完成イメージは既に出来上がっていたため、スムーズに制作をおこなっていくことができていました。アルバイトをしてお金を稼いでいくというコンセプトに沿って自分のアイデアを作品へと落とし込むことができていました。結果として、作品の完成には漕ぎ着けることができていました。残りの応募フォームへの入力は来週行っていく予定ですので、撮影したスクリーンショットをもとに行っていく予定です。', null, null),
  ('a08abeeb-2a27-5470-87c8-5bd47fab8f97', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-25', '17:30:00', null, '振替 / 親子大会作品作り', '振替でほかの習い事が重なり、終始お疲れのようでした。少しは休憩を取りつつも、制限時間や、インクの演出を変えていきました。また、スペシャル武器を使うために、インクの使用量を表す変数も使ってあげました。ある程度こちらから仕組みのヒントを教えてあげたら、自分で組み叩ていけるので、うまく進んでいきました。家で、ほかのスペシャル武器の演出を考えてやってくるそうです。', 'インクの変数の大小関係で勝敗判定を作ってあげてほしいです', null),
  ('c4cb2189-aba5-576c-b1a5-71e392f2b8da', '57f45872-1f3e-5540-b676-bf9023444e39', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-07-25', '16:30:00', null, '通常 / 大会作品制作', '今回が作品制作の最終回ということで、今まで作っていた大会作品制作のラストスパートをかけていきました。自身のやりたかったことができなかったようなので、一緒に考えていくことで実現していきました。ゲームの内容である野球のバットを振るモーションや、ボールを投げる位置などにこだわることで応募フォームのアピールポイントを彩っていました。今回で提出まで終えることができたため、とても嬉しそうにしていました。', null, null),
  ('b8531844-dc35-55a1-8702-c400327e9545', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-07-25', '17:30:00', null, '通常 / 大会作品制作', '今まであまり時間が取れていないようでしたが、大会に提出したいということでこの時間のみで作品制作に取り掛かっていきました。内容としては、プレイヤーのマウスカーソルでスイカを斬っていくというシンプルながらも面白いものでした。何よりこの短時間で作品を完成させていることから、かなり技術力が上がっていることを本人も実感できているようでした。応募フォームへの入力も完了したため、本人としても嬉しかったようです。', null, null),
  ('6f5a5a5b-7e69-55d4-a916-8cc86ece3186', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-26', '16:30:00', null, '通常 / 大会作品作成と提出', '使いたかった石の絵を忘れてしまいました。本人的には画像サイトからもってきたかったようですが、無料で使えるもので納得のいくものがなかったので他の物を使ってもらいました。2時間授業時間があったので、自分の納得のいくまでプログラムできたようです。アピールポイント、操作説明も自分で丁寧にタイピングして提出することができました。', null, null),
  ('73006d2e-caae-576f-8600-8e1ee18e05de', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-26', '16:30:00', null, '通常 / 大会作品作成と提出', '作品はもう完成していたので、あとは提出をするだけでしたが、提出をするのに2時間かかりました。アピールポイント、操作説明を書くように促しましたが、鉛筆がなかなか持てませんでした。アピールポイントについては一緒に作品をプレイしてこちらからいくつか提案しました。書くことが苦手なのかもしれません。', null, null),
  ('46adbf64-42c7-5b7f-9b0c-653da478b988', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-26', '16:30:00', null, '通常 / 追跡ゲームアレンジ・迷路チーズ（ねずみとチーズの動作）', '「ゲームのアレンジ」の想像が難しかったようなので、いくつか具体例を挙げて紹介しました。新しいスプライトを追加して、ゲームの難易度を上げることにしました。過去につくったプログラムを確認しつつ、自分でプログラムができていて素晴らしかったです。 また後半は迷路チーズをしました。「調べる」にあるキー操作のブロックでスプライトを動かすのは初めての経験だったので、角度の考え方と合わせて丁寧に説明しました。角度についてはよく理解できていました。また、ネズミが壁にぶつかったときの考え方を共有しました。チーズも「どこかへ行く」という考え方から、乱数につなげて紹介しました。乱数については「勉強したかも」くらいの理解度でした。最後に邪魔者が入ったプログラムで遊んでもらい、虫の動きについて一緒に考えました。', null, 'タイピング: あまり得意ではなさそうでしたが、しっかり真面目に取り組んでいました！！'),
  ('02c9adf0-1393-5dbe-8525-4849b3847e10', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-26', '16:30:00', null, '通常 / 作品提出＆メッセージっ確認', '最初は提出のために作品を確認していきました。すると、さっそくスコアのバグが発生したので、確認し甲斐がありました。ほかにも、細かな修正ができたので良かったです。アピールポイントは家で書けてきたので、すぐ提出することができました。 後半は、前回メッセージのやり取りに不安を感じたので、物語形式で確認していきました。メッセージのやり取りが名前変更を変えるタイミングを忘れることが何度かあったがよく理解して使えてました。', null, 'タイピング: 来て早々にやり始めました'),
  ('ef299cd8-1397-5d38-96e3-2f0d7f50f601', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-26', '16:30:00', null, '通常 / U16大会作品作り', '作る作品に悩んでいたので、依然作っていたコインのクリッカーゲームをブラッシュアップしていきました。ベルトの細かなデザインや動き方の変えてきていきました。このまま変えていければいいが、今のままだとただ単調すぎるので、何か追加してゲーム性を高めていければいいと思います。', null, '盛り上がり: 宿題をこの時点で半分以上終わらせているのはなんと計画的だ'),
  ('240d7b2d-24aa-57d8-bf7b-e04b41d03b8d', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-26', '17:30:00', null, '通常 / 親子大会作品作り', '前回終わりのじゃんけんの仕組みを作っていきました。仕組みの枠組みは作っていたので、中の条件を自分で埋めていけました。あとはかすかな、表示隠すの表示を修正して、アピールポイントを考えていきました。風船からなぜボールに変えたのか、ボールの違いに得点の違いはあるかなど、こちらから引き出せそうなところを質問しながら作っていきました。そして、提出することができました。', null, '盛り上がり: 毛糸君の新作ゲームに誘惑されながらも終わりました'),
  ('49a0ff62-5c44-5688-8211-c4303ae15ac5', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-26', '17:30:00', null, '通常 / オリジナルゲーム作品', '前半は、様々なゲームを途中まで作ってやめていました。（3回くらい繰り返していたかな？）最後までなかなかやりきれない様子だったので、声をかけて今日で1つのゲームを完成させることにしました。 考えてくれたゲームは敵がランダムに動いて、ポインターあるスプライトに触れたらゲームオーバーというシンプルなものでしたが、回数やスプライトの大きさを工夫して面白いゲームになっていました。本人もいろんな人にプレイしてもらって嬉しそうでした！プレイしてもらったことで、気づいたこと（スプライトが動ける範囲を限定するなど）があったようです。また確率についても考えられていました（すごい）！', null, '盛り上がり: 大会に出品する予定はなかったのですが、帰ったあとわざわざ一度戻ってきて、親子大会の締め切りを確認していました。'),
  ('743a4ad9-15b5-55df-a243-c5360f58401e', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-26', null, null, '通常 / U16作成', '少し疲れていて眠かったようですが（瞑想している時間があった）、いろいろ考えつつ手を動かすことができていました。スタートボタンを押した直後に勝敗を決めるスプライトが出てくることにかなりイライラしていたようです。話しつつ原因を考えていたのですが、自分のアイデアで問題を解決することができてかなり嬉しそうでした。審査員の視点についても考えられていて良いなと感じました。 ユニークなゾンビの動きを作成できていました！', null, '時間帯: その他'),
  ('d4e9eb24-b536-533c-8a18-994ec51ddf16', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-26', null, null, '通常 / 大会出品＆インベーダーゲーム（全体について想像しながら）', '大会作品を提出しました。プログラムのアピールポイントについて考えていたようです。話しながら、数量的な説明やストーリーを加えました。自分の名前などはタイピングしてもらったのですが、とてもスムーズに取り組めていました。 提出後はインベーダーゲームを作成しました。プレイした後に作品の特徴（動き方、攻撃方法、クリアやゲームオーバーの条件など）について話し合いました。手順書を見ながら作成してもらいました。青いスプライトの途中まで取り組めています！自由時間のタイミングでも自分で取り組めていて素晴らしかったです！', null, '時間帯: その他
タイピング: 集中して取り組めていました。'),
  ('424d07cd-28a4-5ec3-94ac-adb8d1cd19a0', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-26', '16:30:00', null, '振替 / いちごの反乱の続き', 'コスチュームのアレンジと、TheEndの画面が出てくるタイミングについて話しました。最後の画面が出てくるタイミングはよくプログラムできていたのですが、リストと変数で混ざって考えていたので、プログラムが機能していなかったようです。また不要なプログラムを落として（メッセージのやり取りも確認しつつ）整理させることができていました！そろそろ終わる様子なので、少なくともあと2週間以内には終わらせたいです。', null, 'タイピング: 授業前に終わらせていました！すごい！'),
  ('c2ba4c49-540f-52e7-86f7-dcbb3ecd3697', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-26', '17:30:00', null, '通常 / 月曜指導内容の確認', '月曜にあけてしまうので、進めてほしいポイントを確認しました。勇作君のチーズの探せは本人も作ったことがあったので、事前の把握はすんなりいくと思います。性格的には、勝手に突っ走ることがあるので、、その制御をするようお願いしました。 そうたくんについては、まだゲームの結ができていないので、それの作成を第1目標に進めメロウようにしました。部長自身にもアイデアがあるそうなので、リミックスして自分のと見比べて指導するよう伝えました。', null, '盛り上がり: 月曜お願いします'),
  ('8521c632-625d-53e0-91d6-0490e53726a0', '53dc382f-637d-5a46-9b57-4204c79ee130', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-26', '17:30:00', null, '通常 / 2回目。世界を創造（基礎の部分）', '前回やったことの復習をした後に、始めました。おしゃべりさせたり大きさを変えたり、座標を変えたりしました。 全体的によくできていた。座標の話も大枠はなんとなく呑み込めていて、プログラムの制御の部分について、「ずっと」の考え方を理解できていました。ただプログラムが始まるトリガーの部分についてまだあまり想像が及ばないようなので、なれる必要があるかな？と思いました。', null, 'タイピング: 集中して取り組めていました！嫌いではなさそうです。'),
  ('b050cbaf-7fa0-519a-b8c6-1aebb3ffd4c7', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-26', '18:40:00', null, '通常 / メッセージのやり取りと録音を学ぼう', '前半は、手にを得なくなった作品をいったん切りがいいところまで進めて、「この作品はお休みする」に伝えてら、快く了承してくれました。本人もちらかり具合もわかっていたそうです。 そこで、基本操作コース０６でせりふのやり取りを学びました。メッセージのやり取りを覚えると、次々にセリフの言い合いをするようになりました。そして、録音の機能をおしえてっら、奇抜な音声を取り込んで楽しくやっていました。 次回はその続きもやるって本人もやる気になっていました。', null, '盛り上がり: 帰りにお母さんに自慢するくらい音声に楽しんでいました。'),
  ('bfc4fe7c-68f4-55c2-98b7-556fdf2c8528', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-07-26', '18:40:00', null, '振替 / 作品提出', '昨日、ある程度までアピールポイントをかけていたので、よりよくしていきました。中なk府で進んでいなかったので、じぶんはりょうーやくん作品を触れてこなかったので、初見プレイで感想言ってあげました。音声で制つめいしているところがいいぽ院になったと思います。これで提出はできました。', null, null),
  ('a421f906-819d-52d4-8034-de315845e4f0', '0047fb11-a84a-5592-8c39-5a16c20eb10e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-07-20', null, null, '通常 / スロットゲーム ジャンプゲーム', '今回はスロットゲームを用いて~ではないと〜までまつの復習、そして新たにジャンプゲームの作成に取り掛かっていきました。前回の内容をしっかりと覚えていたようで、スロットゲームの作成において復習の部分をスラスラと作っていくことができていました。ジャンプゲームに関してもゲームの仕組みをしっかりと理解し、アレンジを加えながら作成していました。この調子で次回の内容もしっかりと作っていければと思います。', null, '時間帯: その他'),
  ('8371cfe8-9bb6-51d3-aaa5-30b61f846ee1', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-07-26', '17:30:00', null, '通常 / インベーダーゲーム作成', '前回の続きから作成を行っていきましたが、前回導入した素材が消えてしまっていたようなので、戻し作業から再開して行きました。自分で描いてきたキャラクターをゲームのボスとしていたので、そのボスキャラクターを再び作品に入れていくと同時に、ボスの攻撃方法や移動方法なども追加して行きました。約束の時間であった30分をしっかりと守って作品作りに取り組めていました。次回は、ボスのステージや体力について作成をしていく予定です。', null, null),
  ('70bdcc6c-b0dd-5b7d-a0dd-fd659f1afc05', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-07-26', '17:30:00', null, '通常 / U16大会作品制作', '今回からU16作品の制作に取り掛かっていきました。作品内容としては、pythonを用いて対象の端末内にappleのBluetoothがあるのかを検出するものということでした。PC内にターミナルなどがないことから、GoogleColabを使ってプログラムを書いていきました。参考としている資料に記載されている内容がMacを基準としたもののため、作成には苦労していましたが、少しづつエラー確認をしながら進めていくことができていました。本人のモチベーションもかなり高いようなので、次回以降もこの調子で進めていくことができれば良いともいます。', null, null),
  ('aba69d43-f3b9-5e5a-9b05-b6109add5dc6', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-07-26', '17:30:00', null, '通常 / 親子大会作品制作', '前回の続きである二分子や三分子の判定について作成していきました。内容としては、リストを使いそれぞれの原子の並びを総当たりで確認していくというもので、かなりの長さとなっているため作成をしている際にはかなり大変だといっていました。しかし、全体的にも終わりがかなり見えているため、本人も気合を入れて作成に取り掛かっていきました。結果として、三分子の基礎部分までは完成したため、来週最後の作業では残っている部分の仕上げをおこなって完成を目指していきたいです。', null, null),
  ('6c423090-98b9-5495-bad6-3819a977cd2b', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-27', null, null, '通常 / 大会提出・オリジナルゲーム', '得点に応じてねこちゃんが最後に秘密の言葉を話すようにアレンジを加えました。演算と変数の使い方について復習をしました。またその後、話しながら操作方法やアピールポイントを考えました。 その後、家で作っている作品を見せてもらいました。キーをクリックした速さに応じてボールが勝ち負けを離すプログラムでした。よく考えられていたので詳しく聞くと、家で家族と本を見ながらなにか作ったようです。スプライトや文章で英語が使われていました。字と球が同じスプライトだったので整理をしたり、ゲームの終わりを作ったりしました。もう作成は終わりだと思います。', null, '時間帯: その他'),
  ('5849c8bd-a125-5a59-b34a-1de22ec8903f', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-07-27', null, null, '通常 / 大会提出準備', '提出は家でやるとのことだったので、作品の修正やアピールポイントを考えました。修正はひとりでよくできていてこちらの助けもいらないくらいだったのですが、アピールポイントに頭を抱えていました。操作方法やストーリーを載せること、アピールとしてはプログラム的な工夫（メッセージ、条件分岐の使い方の工夫）もよいのでは？と提案したところ、少しずつ進み始めてよかったです。家で少しやるそうなので、家族にプレイしてもらって感想を聞くこともおすすめしました。', null, '時間帯: その他'),
  ('f7b3e211-1caf-5213-a6a9-70a6b2c90c62', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-07-27', null, null, '通常 / 大会提出', '提出する回でしたが、クリア演出だけ作ってから提出したいとのことだったのでやりました。全問正解のときにクリアにするために、「変数で正解数をカウントしよう」というヒントだけ出すとあとは自力でできていました。アピールポイントなども紙に書いてきてくれていたので、無事提出までできました。', null, '時間帯: その他
盛り上がり: 最後までこだわりたいという気持ちで頑張っていました。'),
  ('db1a2338-2f4c-584a-9158-7f031e480f9f', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-07-27', null, null, '通常 / 大会提出', '前回はこれで完成だと言っていましたが、改めてこれで出していいか問い直すともう少しアレンジを加えたいとのことでした。カウントダウンのあとに"GO"という文字を出すということで、いつ表示するのか問いかけると、旗を押して3秒待ってからだと答えてくれました。アピールポイントに操作方法の内容を付け加え、提出まですることができました。ゆっくりですがタイピングはできるので、部分的にやってもらいました。', null, '時間帯: その他'),
  ('e7575bf8-9de7-5449-a99c-50bf6e3151fc', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-07-27', null, null, '通常 / インベーダーゲームのアレンジ', '今日もインベーダーゲームのアレンジを進めました。まずは、欲しい雰囲気のフリー音源の戦闘用BGMをgoogle検索して追加しました。そのあと、「時間切れになったらビームが四方八方から中央に飛んできて爆発するようにしたい」とのことで、スプライトや背景を色々用意していました。完成系をある程度イメージして言語化することができていました。', null, '時間帯: その他
盛り上がり: 操作がうまくいかなかったときには少しイラッとしてしまうようですが、それ以外は集中を保って30分頑張ることができました。'),
  ('e02b2c45-7061-5f69-ba79-291b2614e903', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-07-27', null, null, '通常 / 検定練習', '時間より早く来た(今回は前倒しの必要もない)ので、始まるまでスクラッチのゲームとかをやってていいと伝えましたが、もう始めたいとのことだったのでそうしました。2級の問題は、途中でテストプレイしたときバグがあったものの時間内に自己解決して完璧に解けていました。時間が余ったので終わってもいいと伝えましたが、3級の問題を追加で解きたいと意欲的だったのでやりました。短時間しか取れませんでしたが、アレンジを除いて一通り解けたとのことでした。', null, '時間帯: その他
盛り上がり: 来たる検定に向けて気持ちが入っていました。'),
  ('cd6f7673-b931-5f1c-9645-dccc78c6428b', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-07-30', '16:30:00', null, '通常 / 親子大会作品の提出', '今日やることは自分でわかっていたようで、来室後すぐに取りかかっていました。 ステージクリア後にコードを付け足そうとして、どのメッセージがクリアを示しているのかわからずにしばらく悩んでいました。クリアメッセージがきちんとしたタイミングで出ているからメッセージがあるはず、と思い込んでいたようですが、そもそもメッセージが背景の1つのコスチュームとして作成してあり、スプライトが右端に行くたびにステージ番号の変数を1ずつかえ、ステージ番号とスプライトのコスチューム番号を対応させていたため、クリアのメッセージがなくても該当するコスチュームが表示されていてメッセージがみえていた、という解説を、2，3度して理解したようでした。 その後はオープニングを少し調整し、全体を見直したりして提出作業に入りました。 作品の説明をなんて書いたらいいのかわからない、とぼやいていましたが、こちらがさらちゃんの話を聞きながら2文くらい書いて見せたところ、それを参考にして自分できちんとフォームに文章を足しながら入力していました。', null, '盛り上がり: ひとまず考えていたところまでは完成できたようで、ほっとしたようでした。 自作の絵がかわいい作品に仕上がったので、満足そうでした。'),
  ('1b5d519b-6ac7-52e7-b752-a5eeb024b317', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-07-30', '16:30:00', null, '通常 / 親子大会作品の提出', '先にやらないと気になる、とのことで、提出フォームの入力から始めていました。打つのは速いせいか、特に苦も無くスラスラと入力を済ませ、作品の色などをチェックして、授業開始後15分くらいで提出を完了していました。 検定の勉強は8月からがいい、と主張しつつ、どんな問題が出るのか気になるようだったので、サーティファイの試験概要のサイトを開いて見せたところ、かなり熱心に見ていました。こういうのを見るのが好きなのかも？ 試験範囲のPDFファイルを丁寧に見ていて、とりあえず知らないブロックはなかった、と嬉しそうに言っていました。 8月は検定の準備をがんばる、とのことで、残り時間は自由に過ごしました。', '検定準備', '盛り上がり: 作品提出が完了したのと、試験範囲のブロックに見たことがないものがなさそう、というので、すっきりした様子で帰っていきました。'),
  ('ffe519a3-1376-5bad-9572-ef4f19f565ef', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-07-30', '17:30:00', null, '振替 / 親子大会完成', 'だいたいのコードは作れていたのですが、バグや不足がいくつかあったので直していきました。 ・レベルが切り替わったときに、元素を入れる枠も切り替える。また、以前のレベルの元素は全て消す ・「もしクリックされたら～」で実行するブロックの範囲が間違っていたので修正 ・説明を聞き終わる前に遊び始めるときちんと動かないので、説明役をクリックすると説明をスキップするようにした やりたいことがいくつも残っているようでしたが、とりあえず動くようにして提出することが第一なので、優先順位を示しつつサポートしていきました。状況を把握しやすくするために、余計なブロックなどがあると消していたのが良かったです。時間いっぱいまで作っていたので、自宅で提出するとのことです。', null, '盛り上がり: バグが残っているときは相当焦っていたのですが、頑張って全部直せたときはいい笑顔を見せてくれました。'),
  ('423205f3-59c7-5901-84f0-69bcc7d5dd86', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-07-30', '17:30:00', null, '振替 / 作品の提出目標を決める', '授業開始時に進捗を聞いたところ、完全に間に合わない、とのことだったので、U16大会の説明をしました。とても嬉しそうに話を聞いてくれて、ぜひそちらにエントリーしたいとのこと、今回の親子大会には提出しないでU16大会を目指すことで決定しました。 ゲーム上のインジゲーター？の点灯が思い通りにならないようで、メッセージを増やしたり、キー操作を追加して対応しようと努力していました。 途中でキャラクター追加などでうまく息抜きをしながら、黙々と取り組んでいました。 今後、作品がもっと長くなるようなら、変数によるステージ管理などを取り入れた方がいいかもしれません。', null, '盛り上がり: 今の作品は頑張って作っていたため、まだ作成期間をのばせるということが嬉しかったようでした。 来室してリュックを背負ったままなのにも気づかずに、集中して頑張っていました。'),
  ('48539fd7-ed32-5caf-bf66-72fb7404e13a', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-07-30', '16:30:00', null, '通常 / アレンジ作品の完成', '今日はゲームのステージを整理して完成させる、という目標が自分の中にあったようで、すぐに取りかかっていました。ビームの出方も自分なりに工夫したといい、ゲームのテンポ感や最後の方のビームなど、かなりおもしろいアレンジができたのではないかと思います。 途中でアレンジのネタがつきた、と言ってきたので、ビームが当たった時に体力変数が減るだけだと物足りないと話したら、ビームが当たったらアルくんが光るようにアレンジをし、クリア画面を付け足していました。 体力を付け加えたことで、元のゲームより難易度が下がったため、最後の2ステージのビームを難しいものに変えて難易度を調整し、ゲームのスリル感を損なわないようにしようと工夫していました。 それなりのアレンジができたので、公開してみるかと聞くとすぐにのってきて、自分でコメントを書いて公開していました。 こちらが話を聞く姿勢を見せると、自分が工夫したところや面白いと思ったところなどをかなり饒舌にしゃべってくれました。', null, 'タイピング: 声をかけたら、遊んでいたゲームをすぐに閉じてタイピングに切り替えていました
盛り上がり: 今回、数回にわたってアレンジしたイチゴの反乱は、かなり楽しかったようで、授業中に椅子から落ちたりすることもなく、ひたすら熱心にPCに向き合っていました。 自分でコードを見て、この動きはここで作っているというのがわかり、そこをアレンジすることもできたというのが自信になったのか、コードと実際のゲームの動きを合わせて見せてくれて、熱心に説明してくれました。（こんな長文をしゃべるのか！とびっくりするくらいでした）'),
  ('702365ee-ee07-585f-83d9-bfeaab104791', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-07-27', '16:30:00', null, '通常 / U16大会作品制作', '前回まで作成していた内容から今回は別のものへとシフトしていきました。作成しているものとしては、スケジュールアプリのように予定を入力し、規定の時間になった際にLINEなど連携しているアプリに通知がくるというものです。Monacaにてコードを組み実行してみたところ、エラー文が出ていましたが変数をnullのまま参照していることに気づくことができ、自分の力で修正もおこなうことができていました。次回もコードの続きから作成を行っていきたいと言っていました', null, null),
  ('c6b406fe-a81a-5489-a7d3-26aeaea838bb', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-08-01', null, null, '通常 / 親子大会作品制作', '今回で制作の総仕上げと提出フォームへの入力をしていきました。爆弾の挙動が不安定であったため、座標を変更することで修正をおこなっていき、効果音などもつけていきました。その後は、細かい部分の調整などを一緒におこなっていき付け加えていきたい部分を完成させていきました。提出フォームについては、事前にほとんど書いてもらったため見直しと少し付け足すだけで完成させることができました。完成した際には、ここ何回かで作り続けていたものが出来上がった達成感を感じている様子でした。', null, '時間帯: その他'),
  ('ce630d19-d5b2-57b3-b0ca-f8828b6ddc63', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-08-01', '16:30:00', null, '通常 / オリジナル作品制作', '前回からの続きでRPG風ゲームの制作を進めていきました。キャラクターの攻撃エフェクトや、SEなど様々な部分にこだわって素材の収集から始めていました。コマンド操作に関しても、ドラクエのようなデザインとなっており自分の入れたいものをどんどん取り入れることができているようです。作成中でもどんどんとアイディアが出てくるようで、取り入れたい内容を尽きることなく作成を続けていきました。次回以降もこの作品を作っていきたいと言っていました。', null, null),
  ('b248091e-7fd3-52c2-b140-76a5af447eb7', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-07-30', '16:30:00', null, '通常 / 親子大会提出', '最後に作っておきたいものはないか聞くと、ゲームが終わったあとのストーリーを軽く作りたいとのことでした。そのためのコードをどこに挟めばいいのか問いかけると、ゲームクリアしたタイミングにすればいいことを理解し、製作をしていきました。想定通りの時間と内容で作り終わり、無事提出することができました。時間が少し余ったので遊んでてもいいよと伝えましたが、何かプログラミングをやりたいと言ってくれました。製作するほどの時間はなかったものの、まゆねこを探せを遊んでもらい、このゲームに使われているクローンについての話をしました。', null, '盛り上がり: 提出作業中に使ったgoogle driveについて、「これ見たことある！」と少し興味を示していました。'),
  ('de67ad35-abc9-5f19-8d45-0cbbcd6dac25', '28d52d6e-7571-5090-a2d9-492c997b719e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-07-30', '17:30:00', null, '振替 / 親子大会提出', '前回ゲームオーバーの効果音がきちんと鳴らないというバグがあったため、そこの修正から取り組みました。ゲームの終了条件を満たしたらBGMを止めて効果音を鳴らすというコードは作れていたのですが、これだとBGMが1周鳴り終わらないと止まらないという話をしました。鳴らすのと止めるのを別々に分けようというヒントを出すと納得したようで直すことができました。また、ゲーム最初のルール説明を見る秒数を指定するのに「～秒待つ」をいくつも使っていて調整が大変そうだったため、待つ時間を変数で管理するようにするとすっきりしました。提出用紙も書いてきてくれていたので、ゲーム完成のあと時間内に提出することができました。ただ、一度提出した後さらに直したいところが出てきたようで、家でもう一度出すかもしれないとのことです。', null, '盛り上がり: 最後までクオリティーを追求していました。'),
  ('235e3147-5ec5-5613-9363-6a95470bcc75', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-01', '16:30:00', null, '通常 / 親子大会提出', '今日は親子大会の作品が未完成だったので取り組んで提出までしました。 クイズの問題・正解が正しく表示されないというバグに困っていたため、リストの中身を確認することを促したところ、中身がおかしいことに気付いて直すことができました。しかしそれでも出題がおかしかったためコードを見てみると、繰り返しの範囲が間違っていました。「問題の数だけ繰り返すのはどこからどこまで？」と問いかけると少し考えて理解したようでした。各ステージが終わった時に表示されるはずのボタンが隠れたままという問題については、メッセージを送って自力で対処できていました。全て作り終わったとき、ちゃんと動くかどうか客観的に知りたいという考えで、第三者である先生に最終テストをお願いしてくれました。作品アピールなどは事前に練っていたようで、無事に提出できました。', null, '盛り上がり: 最初計画していたものの時間が間に合わず断念したパートがあったそうで、次の機会にバージョンアップしたいと意欲的でした。'),
  ('35046e8d-176e-5368-a264-cd13b62562f6', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-01', '16:30:00', null, '通常 / 検定練習', '2級問題に初めて取り組みました。「リンゴとバナナ」ブロックや「～と聞いて待つ」ブロックの応用のしかたがよくわからなかったようで、これは知識がないと厳しそうなのでそこだけ教えると、途中までは順調にできていました。ただ、使うべきブロックが直接書かれていない「正解のとき以下を行う」のところで再び詰まっていました。そこで時間が終わってしまったのですが、これについては「正解とは何がどうであることか」を考えて言語化する必要があるので、次回続きをやる予定です。', null, 'タイピング: リラックスした様子で取り組んでいました。
盛り上がり: どうやって考えればいいのかわからない様子でしたが、冷静に取り組んでいました。'),
  ('e8249c30-707a-54fc-89aa-145c69971c2f', '57f45872-1f3e-5540-b676-bf9023444e39', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-01', '16:30:00', null, '通常 / 検定練習', '検定自体初めてなので、概要を説明した後取り組んでもらいました。上から順番に読んでいく作業などに慣れず苦戦したようだったので、途中まで一緒に流れを確認していきました。解いている途中で席を立つことなどがあったため、検定のときは学校のテストのように時間内は集中しようと促しました。1時間じっくり頑張って、なんとか一通り終わらせることには成功しました。やはり難しいという感想を持ったようだったので、最初からできる人はいないし練習すればだんだんできるようになると励ましました。', '答え合わせ(お手本ムービーと違う動きがあった)', '盛り上がり: 大変そうでしたが、嫌がっている様子ではありませんでした。'),
  ('2145a26c-4a57-50de-b641-971255cb88c9', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-01', '16:30:00', null, '通常 / 検定練習', '1級と2級のダブル受験を提案しましたがまだ決められないとのことで、今日はとりあえず2級に取り組みました。今まで2級は応用課題を2回くらい練習していたのですが、今回は特に苦手な問題傾向だったようでした。使い慣れていない「～と聞いて待つ」の用法だったり、文章に書かれているのと違う順番でブロックを置かないといけない部分に混乱していました。手が止まってしまうくらいだったので、作るべきコードの流れを一緒に整理したり、ヒントを出したりすると理解してきたようで、途中まではできました。今回は2級のみの受検にした方が無理がなさそうだと感じました。', '続きを解く(「コードの修正」問題から)', '盛り上がり: 難しくても諦めずに取り組んでいました。'),
  ('0772e908-fbce-5771-9e3b-f33cce7ba420', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-02', '16:30:00', null, '通常 / 検定3級1回目にやるもの', '前回、検定をやった記憶があまりないようです。紙の読み方から動画のポイントまで説明すると、なんとなく思い出したようです。 途中、困っていたところもあったようですが、動画と紙をよく確認して取り組めていました。移動量の変数がうまく動かず、悩んでいたようです。また項目だてている数字のとなりの文言を読み飛ばしてしまったようで、旗の設定を忘れていました。 「ずつかわる」と「～になる」をまちがえていたり、読み飛ばしたりしていましたが、一方で難しいブロック（～ではないまで待つなど）はしっかり使えていました。練習を積めば問題ないかな？と感じています。', null, 'タイピング: 集中して取り組めていました。'),
  ('16bf3ee7-037d-5ea5-ba29-56028cc4f75a', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-02', '17:30:00', null, '通常 / 検定3級1回目にやるもの', '前回やった記憶はうっすらあるようで、本番でアレンジができなかったことを少し残念そうにしていました。 見本と文章をしっかり読んで取り組むことができました。ただあまりつかったことのないブロック（～ではない）、独特の言い回し（～とき）に苦戦していましたが、何回か伝えると雰囲気をつかめたようで頑張っていました。分からないと言いつつ前向きに取り組めていました。 変数と動き、制御が組み合わさると難しいようなので、検定前にドリルでやったりたくさん問題をやったりして回数を積む必要がありそうです。自分の苦手なことを把握できていました。', null, 'タイピング: 集中して取り組めていました'),
  ('6d397b7a-347d-59a6-8803-a04ef218a328', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-02', null, null, '通常 / 前回の続き（物語）', 'やりたいことがあったようなので、メッセージと背景のチェンジ、滑るように動かすということをやりました。座標については少し理解が難しいように感じたので、動かしたい着地点にスプライトを置いてからブロックを使うように伝えました。ブロックを使ったときに動くのプログラムの順序が少し怪しい様子です。メッセージを使うと混乱してしまうようだったので、何回かしつこく説明しました。 話すことで自分がやりたいことを言語化してもらい、表現に繋げられました。本人とも話したのですが、ゲーム系の内容でファイルを埋めていくことになりました！次回は「サメからにげろ！」に挑戦したいです。', null, '時間帯: その他
盛り上がり: サメからにげろ！'),
  ('69047d06-6bb8-5b3c-9591-2bed7bd5f045', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-02', null, null, '通常 / 自由製作続き', '最初様子を見たかったのですが、ある程度の完成系を見せたかったようで断られました。とても集中して取り組めていました。 攻撃のときにコスチューム変化を加えたり、色を調整したり（？）していたようです。英検4級とったそうです。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('904e40e6-ca48-5d2a-86bb-1b2931cee8b0', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-02', null, null, '通常 / 検定4級の応用課題E016 余裕があれば3級に挑戦したい', '一度やったことのあるものを進めましたが、どうしても他の問題がやりたいということで、応用課題に挑戦することになりました。「①の後にプログラムする」と書いてあることが呑み込めなかったようなので、詳しく解説しました。（応用問題だからという事情があるからかもしれませんが。ずっとについての記述が少なく難しいように感じました）また、かなり疲れていたようで、集中力は低かったです。 プログラムの制御の部分（プログラムの動く順番）についてもう少し考えられるようになりたいです。', null, '時間帯: その他
タイピング: 集中して取り組めていました。'),
  ('30b8ce39-f567-57f5-9c9c-5b61e781185f', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-03', null, null, '通常 / 迷路チーズ（簡単Ver）（～まで待つ・乱数）', '乱数のプログラムについて復習しました。 コスチュームの変化にしか乱数が使えないと思っていた様子でした。 迷路チーズについては、チーズの動きが「どこかへ行く」ではなく、迷路の範囲内を動くということに気が付けていました。みみちゃんを歩かすプログラムは自分でつくることができました。座標の上限下限については詳しく解説しました。「～まで待つ」は使い方を自分で考えて作れていました。 めいろにぶつかったときのプログラムも、「～触れたら」まで自分で考えられていました。歩く量をキャンセルさせる考え方で説明すると、そのあと自分で考えてプログラムできていました。 おおよそ完成しました！（終わりでいいかな？と思います）', null, '時間帯: その他
タイピング: 少し補助をしながらでしたが、きちんと取り組めました。たくさん問題にツッコミをいれていて面白かったです。'),
  ('c12d2306-5d09-5064-9aa4-34f8c9ea33b7', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-03', null, null, '通常 / オリジナルゲーム（RPG）', '前半はスプライトの絵を探しつつ、中盤～後半はしっかりプログラムに取り組めていました。U16など、大会に作品を出品する予定はないようです。 演出にこだわりがありました。また、攻撃ターンを変数で管理するようなので、偶数奇数でプログラムを整理するようにアドバイスしました。 だらだらと作り続けるのもよくないと感じたので、残り2~3回ほどでゲームの中心となる部分（ボスを倒すなど）はプログラムを作り終える提案をしました。本人もそのつもりだったので、今後うまく声掛けをお願いします！！', null, '時間帯: その他'),
  ('dd1a33e0-5171-59a3-af03-ff4ba62a74e5', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-03', null, null, '通常 / ジャンプゲーム', '数と高さについての考え方がなかなか難しかったようです。〇秒で（座標）へ行くのプログラムは初めて使ったようなので、かなり丁寧に解説しました。ジャンプ力については初めは教材通りに作り、その後どうしても変えたいとのことで変更しました。 今回は「教材通りに作る」をイメージして、スプライトや背景の調整をしました。しぶしぶながらもしっかり作れたので、次回はアレンジをしていく予定です。', 'ジャンプゲームアレンジ', '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('2ff518eb-0060-5f68-8131-a01e2015e2f8', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-03', null, null, '通常 / 3級検定問題を使った変数の復習', '集中して取り組めました。間違えたポイントはプログラムの実行順序の部分でした。変数についてのプログラムはよくできていました。最後に時間があまったのでアレンジに挑戦してもらいました。考え方のポイントはかなり丁寧に伝えたのですが、なかなか考えるのが難しかったようです。プログラムせずに終わりました。', null, '時間帯: その他
タイピング: 集中して取り組めていました。'),
  ('524ebefc-cdf9-5eb6-bce8-d2b14e223182', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-03', null, null, '通常 / 3級検定問題を使った変数と演算の復習', '検定をやったことは覚えているようでした。途中、変数の値を自分自身の値からマイナス1倍にするプログラムに困っていました。伝えると仕組みは理解できたようです。また、最後にアレンジも考えてもらいました。プログラムまでは進めなかったようですが、話を聞くとよく考えることができていました。細かいところまで読んでよく取り組めていました。', null, '時間帯: その他
タイピング: 集中して取り組めました'),
  ('6a7a86b4-8dd7-5f05-a146-7ab89db2dbff', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-08-03', null, null, '通常 / 教室に慣れる', '最初にファイルを見せて、表のスキルを覚えていくといろいろなゲームができるようになる、と説明したところ、素直に「本当？！すごい！！」と喜んでいました。 最初の「色を変える」「回転させる」までは手順通りに進めましたが、そこでストーリーが湧き上がってきたようで、こんなステージにしたい、と積極的にやりたいことを説明して作成していきました。 やりたいことを実現する中で、コスチュームの変更、繰り返し、座標を使って動かす、最初の座標を指定する、もし○○に触れたら、回転方法を左右のみにする、などのスキルを覚えました。 ローマ字はまだ母音くらいしか覚えていないようでしたが、英文字自体は読めていて、ローマ字さえこちらが教えれば、すべての入力を自分でできていました。 スプライト名や背景、コスチューム名などにもしっかりとこだわりがあって、すべて丁寧に考えてしっかり変更していました。作品名もきちんと変更していました。 1時間集中して、一度もだれることなく楽しんでいました。', null, '時間帯: その他
タイピング: はじめようから最初のおさらいまで 学校ではできなかったGHとおさらいができたと喜んでいました
盛り上がり: とにかく一つ一つのことができるたびに素直に喜んで、ひたすら楽しそうに作成していました！
備考: ゲームはマイクラが好きとのことですが、アルスタジオのマリオvsルイージを楽しんでプレイしていました。'),
  ('65d03581-47f0-55ff-9c0b-a1a982a03020', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-03', null, null, '通常 / 基礎力を強化する', 'インベーダーゲームの方向性が定まらなくなりそうだったため、前半は検定の問題を頑張り、後半は自由時間(ゲームで遊ぶかインベーダーゲームの自由作成)にすることにしました。最初はインベーダーゲームを続けたいと渋っていたのですが、30分ならと始めてくれました。自力でやると問題文を読み落としそうな感じでしたが、このあとに何が書いてあるかなどを問いかけていくときちんと内容を把握してもらえました。「ブロックをどこから持ってきたらいいかわからない」と言うことも数回ありましたが、一度教えると二度目は覚えていました。「～まで待つ」「～または～」などのブロックをここで新しく学習し、問題の中盤まで進めることができました。', '続き', '時間帯: その他
盛り上がり: 文章をしっかり読もうとしてくれました。'),
  ('f8978ff4-6477-55eb-b61a-892049af225c', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-03', null, null, '通常 / U16大会作成', '技術的なことはゆき先生とも相談したりしながら進めました。自分のiPadからデータを転送して使うなど効率的に進めています。途中出てきたエラー文について、内容を調べてバグを自己解決するなど、ある程度自走することもできています。', null, '時間帯: その他'),
  ('4cca07a3-238a-579e-9de4-dd0c04fe1d1a', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-03', null, null, '通常 / 「ではないまで待つ」などの習得', '「ではないまで待つ」が今日の重要テーマでしたが、これは以前シューティングゲームを作った時に覚えていました。意味をわかっているか聞くと「キーが離されるまで待つ」としっかり理解していました。したがってほぼ順調に進みましたが、順位を表示するところでは困っていました。ここで「変数を使う」というヒントを出すと、各キャラについて歩数の変数を作って処理しようとしていました。「歩数じゃなくて順位を変数にしたほうが簡単かも」と伝えると、「一旦歩数の変数で完成させてみたい」と言い、ある程度見通しも立っていそうなのでそのままやってもらいました。メッセージ、「かつ」ブロック、等式と不等式など色々な要素を使い、試行錯誤を必要としたものの、1位と2位の判定と表示が最後の方でうまくいきました。そのうえで順位の変数を使った作り方を紹介すると、これは確かに簡単だと納得した様子でした。', null, '時間帯: その他
盛り上がり: 自分の方法でやりきったときは達成感があったようでした。'),
  ('03767668-c1a5-5dc3-89fe-0e538eaa45a6', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-08-05', '17:30:00', null, '通常 / 基本操作コース２,３', '今回がプログラミングコースに移行して初めての授業ということで、基本操作コースから始めていきました。内容としてもかなり基礎的な内容が書かれているもののため、本人としても簡単だと言っていました。次々と作り続けていき、最終的には基本操作コースの２と３を完成させることができました。時間配分としては、タイピングに多く時間を割いていた中でこのスピードでしたので、次回以降も順調に進められると思います。', null, 'タイピング: 桃太郎タイピングでは簡単すぎたようなので、プレイグラムへと移行しました。難易度としては難しいでも打つこと自体は簡単だった様子でした。そのため、次回からは速度も意識して行えると尚良いかもしれません。'),
  ('f59a610b-4d42-517e-8795-07440db08083', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-08-05', '16:30:00', null, '通常 / 乱数を覚えよう！', '今日は乱数について学習していきました。まずは、サイコロの目を使うことで乱数とはどう言ったものなのかを考えていきました。原理についてはすぐに理解することができており、面白そうにみていました。次に、迷路チーズを探せの①部分を作成していきました。キャラクターの移動方法から、乱数の理解についてはしっかりとできている様子でした。しかし、コードを作成していくことに消極的となっているため、作るまでに少し時間がかかってしまう部分は治していきたいところです。', null, 'タイピング: ゆっくりですが確実に打つことができていました。'),
  ('41301f8e-31dc-565c-8ac0-5011f34bf70a', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-05', '16:30:00', null, '通常 / 基礎を進める（ジャンプゲーム）', '先週作ったものは完成したとのことだったので、ジャンプゲームをしました（コード探求は時間を置いた方が思い出す＆定着すると思ったため）脱線せずに取り組むことがでいました。座標についての考え方を共有しました。（上下左右の矢印の向きを参考にするように伝えました）たまごのプログラムも、動く順序に気をつけながら取り組めました。楽しそうで良かったです。 ゲームオーバーまで作りました。あとはスコアのプログラムを設定する必要があります。すぐに「変数だ！」と考えられていて良かったです。また、ひとりでお願いしたいときに大まかな道筋を示して「～～まで作れたら教えて」と伝えると、比較的自分で考えてプログラムを作れました。', null, 'タイピング: 次回は違うものに挑戦してみたいとのことでした。'),
  ('7e952812-67da-5243-a712-b1368d79b37e', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-05', '16:30:00', null, '振替 / 2級検定最初にやるもの', '40分、集中して取り組めました。かなり悩んでいる様子のときは、いくつかアドバイスをしました。（プログラムの順番など） 間違えていた箇所は正答と誤答の処理の部分でした。演算と制御のブロックをいくつか組み合わせると混乱してしまうようです。また制御の部分で間違えると、その後の進行が把握しきれず、最後までプログラムしきれないことがあるようでした。 制御と演算が組み合わさったプログラムにいくつか挑戦する必要があるかもしれません。', null, null),
  ('b16e7e4c-ff2d-54a1-9ebc-8bd3f56d803d', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-05', '17:30:00', null, '通常 / 前回の続き・サメから逃げろ', '滑らかに動かすブロックとメッセージの確認しながらオリジナル作品の作成をしました。座標については縦横の把握は出来ているようです。また初期位置の設定も考え方は理解できていました。メッセージが一番よく理解できていました！！プログラムの実行順序について共有しました。 サメから逃げろは、スプライトの動かし方について2種類あることを説明しました。（角度と歩数）「触れたとき」のブロックは学校で友達と使っているようで、「もし」「ずっと」と組み合わせてうまくプログラムの終了を作ることができました。 スキルもあるしやりたいこともありますが、それらが結びつかないようです。ちょっと説明（足がかりをつくれば）すると、手が動く様子です。', null, 'タイピング: 集中して取り組めました。
盛り上がり: 夏休みは予定がたくさんで忙しいようです。'),
  ('b967d04b-aa59-549e-b1b4-c5f234fd9a3e', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-03', null, null, '通常 / 検定の問題に慣れる', '今日のテーマは「変数の特別な使い方」なので、そのことを最初に説明した後取り組んでもらいました。あおしくんは検定に難しいイメージを持っているのかモチベーションがあまりないので最初はスローペースでした。ただ、上から順に一行ずつ読んだり大事なところに印をつけたりすれば思ったより辛くないことを伝えていくと、次第にスイッチが入ってきました。40分間に収めるのには少し練習が要りそうですが、レッスンの最後の方で完成させられたので少し自信がついたと思います。', null, '時間帯: その他'),
  ('2c8c0ff1-0b22-523c-bde3-f9d9020cecbf', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-08-06', '16:30:00', null, '通常 / 検定問題２級①', '大会作品制作も終了したため、今回から検定に向けての対策を始めていきました。以前に挑戦した２級の応用問題1の答え合わせから２級の練習問題に取り組んでいきました。答え合わせに関しては、問題文の一部が抜けていたりよく読んでいなかったりと基本的なミスが連発していたため、少し落ち着いて取り組んでみても良いと思いました。練習問題へと取り組みとしては、分からない箇所があったらその部分で考え込んでしまう癖があるようなので、どんどん次の箇所へ進めていくようにしていくことで、さらに点数を稼ぐことができると思います。次回は練習問題の答え合わせから行っていく予定です。', null, '備考: 補足：大原）授業後に眞子ちゃんとお母さんと少し話しました。2級の問題が想像以上に難しくて、何がわからないのかわからなく、手ごたえがないとのこと、このまま受験する意味があるのか、少し悩んでいたようです。ただ、今日の問題は難しめだったこと、一緒に振り返りを丁寧にやってみて、それでもどうしても…という場合には、また延期について話し合おうと持ち掛けると、納得されたようでした。とりあえずもう少し頑張ってみるとのことです。 一度、問題をそのまま解かせるのではなく、どういう風に問題文を読んでいけばいいのか解説しながら、先生と一緒に取り組んでみて、感覚を体験させるのもよいかもしれません。'),
  ('5b8b9e82-0659-526c-a3d8-d2f49625fd9c', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-08-06', '17:30:00', null, '振替 / 検定問題３級①', '今回から検定に向けて問題を解き始めました。初回ということで、３級の最初の問題から取り組んでいきました。作業中も悩んで止まる箇所はほとんどなく解き進めていき、間違うことなく作り続けることができていました。時間が少し足りなかったようで、残りわずかな部分が手付かずの状態となっていましたが、それ以外の箇所は全て正解していたため、90点ほど獲得することができていたと思います。次回の挑戦では、スピードを少し意識して取り組みながら、アレンジ部分まで手をつけることができればと思っています。', null, '盛り上がり: 間違いをすることなく解けていたので喜んでいました。'),
  ('02ab5f1b-8833-502d-9a18-aefd88329c6f', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-08-05', '16:30:00', null, '通常 / U16大会に向けて', 'U16大会の話を持ち掛けると、家でも少し話した、と少し嬉しそうに話してくれました。声をかけられたことは嬉しかったようです。ポスターを見せたところ、賞金のところを見て、「これでお金がもらえたら、ここに通うお金になる！」と言っていました(^^;) 年齢的にU13大会を目指すことでひろとくんも納得しました。 親子大会に出した作品の方は、大人の目から見ると惜しい点も多かったですが、本人的にはだいぶ満足しているようで、やや得意げに作品を見せてくれました。 ゲームの部分はわりとやり切った感があったので、とりあえず、オープニングやエンディングをもっと面白いものにすることを目標としました。そのために、コードをもう少し整理することを勧め、メッセージの多用を減らして、場面転換を変数で管理することを勧めました。 説明すると、わりとすぐに「わかった！」と言って手を動かし始めるのですが、少し自走させて戻ってみると、微妙にずれたことをしていることがありました。 同じようなメッセージでスプライトの表示非表示を切り替えているところが多々あり、本人も、似たようなコードばかりという自覚はあるようだったので、変数をフラグとして使用してオンオフを切り替えるよう提案し、すぐに「なるほど！」となって、自分でやってみるというので少し離れて戻ってみたら、変数の規定値を0にしたあと、すべてのコードにおいて、条件を満たしたときに「変数を1ずつ変える」とやっていました。 上記の説明の後、自分で修正したいというので自走させたところ、メッセージの数だけ同じような変数を作成していたようでした。時間の関係でチェックがしきれませんでしたが、必要のない変数まで作っている可能性があるため、次回もう一度、何のための変数なのか、この変数で何を管理したいのか、確認する必要があると思われます。', '全体の構成をもう一度整理した方が良いかも…', 'タイピング: 今日はタイピングの気分ではないということで省略しました
盛り上がり: 上級の大会に挑戦できるのは嬉しそうでした。 今の作品にも愛着があるようなので、よりよくしていきたいというモチベーションもあるようでした。 体験の子がいたため、授業の前半はけいとくんと斜め向かいでやっていたのですが、けいとくんが積極的に話しかけてくるのを面白がっていました。（今まであまり会ったことのないタイプ、と言ってました）'),
  ('0eb191ba-52f7-582f-8dc9-df8287f477d3', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-06', null, null, '通常 / 検定に慣れる', '以前一回だけ問題を解いたことがあったものの、検定というものについてよく知らなかったので説明したあと解いてもらいました。手順書を見てゲームを作成する練習として位置付けるとやる気が出たようでした。最初の方だけ一緒に進めましたが、それ以降はコツをつかんで自走することができました。文章中の①や②という記号をきちんと把握して流れを追ったり、お手本ムービーと違う動きをしているからどこか間違っていると気づいたりもすることができました。答え合わせをしても、一か所ブロックが抜けてしまっていた程度でほとんど完璧でした。時間が少し余ったので、小技の中から気になるものを選んで作ってもらいました。残像の作り方を選び、クローンと幽霊効果などの仕組みを理解しながら一通り作ることができました。', null, '時間帯: その他'),
  ('5b81f4c6-48b7-5cc7-b43f-d1055af1c090', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-06', '16:30:00', null, '通常 / 検定練習', '腕試しとして検定をやってもいいという気分だったようだったのでやってもらいました。変数に文字列を入れてもいいことや「りんごとバナナ」ブロックの応用の仕方について困っていたのでそこだけ軽くヒントを出しましたが、基本的には自力でできたところが多かったです。答え合わせでも軽い入力ミス程度でほぼできていたので、自信を持っていいよと伝えました。', null, '盛り上がり: そうすけくんのポケットにギザ十が入っていてみんなで盛り上がりました'),
  ('a0af80b7-d7f5-5e07-b216-d5df466727bc', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-06', '17:30:00', null, '通常 / 検定練習', '前回の問題の続きからやりました。サンプル問題にもかかわらず難しいほうの問題なので、今できなくても大丈夫と安心させました。前回は算数的な要素が多くて苦戦したようでしたが、今日やった「修正する問題」の部分はさらっとできて完璧でした。 半分くらい時間が残ったので次の問題に途中まで進みました。「(変数a)を(変数b)にする」という動作が出てきてよくわからなかったようでしたが、「その変数と同じ数にする」と説明するとイメージがつかめたようでした。それ以外は前回の問題よりやりやすかった様子で、自信を取り戻してきていると思います。半端な時間から始めたので、できたのは途中まででした。', '続きから', '盛り上がり: 落ち着いて取り組んでいました。'),
  ('e1654cbb-5cd7-5bd3-86bf-75d5baa4eabf', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-08-07', '16:30:00', null, '通常 / 検定問題２級サンプル２', '前回挑戦したサンプル問題1の復習とサンプル問題２に取り組んでいきました。1の問題内容では、どこがどう分からないのかを明確に説明してくれて適切な箇所を教えていくことができました。自分がなぜ分からなかったのかを理解してもらうことができたため、しっかりと覚えることができている様子でした。２に関しては、じゃんけんの勝敗判定でつまづいていたため、どのようにして成立させているのかを教えたところ、自分で理解して全通りの条件を作ることができていました。次回は２の問題の答え合わせから行っていきたいです。', 'サンプル問題２の答え合わせ', null),
  ('161a5f44-a7e5-52a2-816c-abaef0a0edb7', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-08', '17:30:00', null, '通常 / 乱数復習 世界を創造しよう（やったいことないとのことでした', '迷路チーズではスコアのプログラムを作成しました。追跡ゲームの考え方の復習をしました。乱数ではコスチュームで使えること、座標にも使えることを説明しました。 世界を創造しようをやったことがなかったようなので、話す、矢印キーで動かす、コスチュームを変えるをプログラムしました。座標で動かすときに方向とプラスマイナスを確認しました。おおよそ理解できている様子です。', null, 'タイピング: 集中して取り組めました。苦手なようですが、あきらめずに取り組めました。'),
  ('89730208-be2f-5e85-a903-098fe3a4531a', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-08', '17:30:00', null, '通常 / 今月末、２級の検定受験なので、しっかりやる', '今月末に検定本番なことを伝えて取り組んでもらいました。また、始まる前に自分が苦手なところを振り返ってもらいました。（あまりないようでした）前回自分が途中だったところまで把握できていましたが、今回は本番を意識して初めからプログラムするように伝えました。 時間内に終えることができました。日本語が少し難しいところを読み間違えていたのが1箇所、「ずっと」をいれてプログラムしていたのが1箇所ありました。それ以外はよくできていました。アレンジを考えてもらいましたが、なかなか思いつかなかったようです。', null, null),
  ('ee63933e-2e3b-5f40-9ac5-aaa14ccbf5df', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-08-07', '17:30:00', null, '通常 / 検定問題２級サンプル１', '検定は受けませんが、問題理解力を深める目的で２級のサンプル問題に挑戦していきました。検定の方式である指示書を見て内容通りに作るという部分に少し難を感じていたようで、抜けている部分があったり指示されていないものが入っていたりと言った内容が見受けられました。そして、時間制限があるという状況にも慣れていないようで時間配分を誤ってしまった結果、最後まで到達することができていない様子でした。しかし、問題をよく読めばしっかりと完成をさせることができそうなため、今後も挑戦していくことで慣れていくことが重要になってくると思いました。', null, null),
  ('046349d6-d369-5160-aae4-76bf35fe25a3', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-08-09', '16:30:00', null, '通常 / U16作品の作成', '前回に引き続き、コインの作品をリメイクしていきました。判定状態について、脱出ゲームで使った幽霊効果の仕組みをうまく活用できていました。また、元から条件を複雑につくっていたので、新たに付け加えるときに、どのような条件を作ればいい迷う場面もありました。そこで、何を起点に動かしているか話し合いながら変数であることに気づけていました。その後も順調に作っていけました。', null, 'タイピング: 果敢に取り組んでいました'),
  ('64d8a75e-3094-5cb4-84eb-5ef547298e4f', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-08-09', '16:30:00', null, '通常 / 花火作品を作ろう', '以外にもペンツールのなじみがなかったので、花火大会の作品を作っていきました。コードは紙を見ればできるものだったので、作りながらなぜそのコードを必要なのかを問いかけながら作っていきました。試遊しながら答えることができたので、花火の向きやクローンの変数の役割を答えることができました。最後の方、つめつめでペンツールのところを作り終えましたが、本人的には、猫ちゃんの形をした花火を作ってみたいそうなので、続きをやるのありかと', null, 'タイピング: 久々に触れていきました
盛り上がり: たっちゃんは細部までこだわってやっていました'),
  ('5d1160eb-0616-5c4d-bfdd-3cc8d82932cf', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-08-09', '17:30:00', null, '通常 / ビデオモーションセンサーを活用しよう', 'ビデモーションを活用したものを作ってもらいました。最初はそのまま作って、どこをいじれば、感度がよくなるか自分で見つけ出していたので、楽しんでいました。アルスタッフのをたたいたら、黒線入れる面白いアレンジをしてくれました。雑談多めだったけど、にぎやかにできていました。', null, 'タイピング: いつもしぶしぶ断るがやってくれました
盛り上がり: ぶちょーとネットミームやボカロを話して、コアな話題まで盛り上がっていました。'),
  ('09d0ebae-ae61-504c-8233-f9ca59d8e92d', '53dc382f-637d-5a46-9b57-4204c79ee130', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-09', '17:30:00', null, '通常 / 世界を創造しよう・物語をつくろう', '背景を変える・音を加える（BGM）、おしゃべり、自分の声を録音、滑るように動かすをしました。世界を創造については、自分で作りたい作品がなかったようなので、物語を作ろうが終わったところで作品を作ることになりました。 「〇秒待つ」だったり座標の話をしたりしました。自分で進めるのは苦手なようですが、「終わったら教えてね！」というとしっかり声をかけてくれます。録音については方法と録音だけしてみました。（鼻歌を録音していましたかわいい）次回、続きと可能であれば作品作成に入ります。', null, 'タイピング: 集中して取り組めました。'),
  ('9858e2c2-0d07-5218-836e-c0c67655772e', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-09', '17:30:00', null, '通常 / U16大会用 作品', '素材がまだそろっていないとのことでしたが、できる範囲でプログラムを進めていました。今回は音を探していました。けいとくんと話して楽しく進められていたようです。またスプライトの表示について、矛盾しているところがあったので指摘したりしました。 今回はどちらかというと楽しく進める回だったので、残りの時間もぼちぼち意識しつつ頑張ってほしいです。', null, null),
  ('2bef3f43-457c-5dde-8ed7-dddd81f7f9ba', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-09', null, null, '振替 / 昨日の続き', '拡大縮小・滑らかに動かす・メッセージ・背景を変えるをやりました。こちらが声をかけてもなかなか動きだせないので残念です。逆に言うと、自分でかみ砕いて考える時間をしっかり確保した方がいいのかもしれません。どれも共通して「初めの設定」と「変更後の設定」が必要なことを強調して説明しました。 「やってみたいな～」という軽い気持ちで教室に通い始めてくれたそうです。アニメーションとゲームを見てもらいましたが、ゲームの方がやりたい様子です。最後の方はかなり楽しげに帰っていきました。今後のイメージがもてたかな？？', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('130f8cd5-e9d4-5f70-abcb-18337ce20f35', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-09', '16:30:00', null, '通常 / ⇒和ちゃんの「物語を作ろう」', '物語を作ろうの作品例2を見せました。使っている技（背景を変える、メッセージ、滑らかに動かす、話すなど）を一通り説明した後、オリジナル作品を作ってもらおうと思いましたが、作品例2の見本通りに作ってくれました。「～まで繰り返す」を使うときの注意点、滑らかに動かす方法をアドバイスしましたが、その他はよくできていました。録音は実際にしませんでしたが、方法について共有しました。 メッセージの使い方も良かったです。少し時間が余ったので、アクションゲームでジャンプの考え方を共有しました。条件分岐をよく確認して、ある程度理解することができたので良かったです。', null, 'タイピング: 集中して取り組めました。'),
  ('562410ee-5152-5dbd-b294-a987ebe8d52f', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-08-09', '17:30:00', null, '通常 / ビデオセンサーを活用しよう', 'けいと君と同様に、ビデオセンサーを使うものを作り上げていきました。最初からリンゴだけで物足りず、爆弾やダイヤなども追加していきました。けいと君の作品もうながされて、録音も使っていきました。いろんな動きを試しながら楽しくできていました。', null, '盛り上がり: 猫ミームの動きが一番切れやすかったそうですｗ'),
  ('5a87f828-13b2-5c6a-8ee9-bfd5e4853c4b', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-09', null, null, '通常 / 案外、自分の好きに作ることが多かったので。一旦、教材通りのをつくってもらおう 【Prg】10 レースゲームを作ろう！ ⇒「スピード」を変数にして、「スピード歩動かす」と「スピード＋乱数歩動かす」をマスター', 'ゲームを遊んでもらい、内容を簡単に説明してもらいました。プログラムを最初に示しつつ、スピードの変数部分を確認してもらいました。変数の値の変化を追って確認することができました。その後、見本をみつつプログラムを作ってもらいました。敵の車の動きについても変数と乱数に注目して確認しました。終盤はかなり眠かったようですが、ステージも作って最後まで頑張れました。敵の車のプログラムがひとつ終わっていないので、未完成です。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('55924e2f-d02e-5f2f-9a55-a4e5e844917c', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-08-09', '18:40:00', null, '通常 / さめからにげろから動きを覚えよう', '今回はゲーム系のサメのゲームを作っていきました。最初の試遊から、ざっくりと動きを確認して、答えらていました。今回は、どこの動きを作ろうからそれでどのコードを注目するすればいいかの作る際の着想の流れをしっかりさせて作っていきました。まだ知らないコードなどもあるので、ほぼ紹介形式やっていったが、ざひょうやむきの理解は少しずつできてきました。最後の方に、メッセージの復習として、自力でやらせそうとしたが、あまり覚えてなくて、使うブロックを提示させたら、少し自分で動かせるようにはできました。 本人はまだアレンジはしたいと考えているぽいので進めていければいいと思う。', null, null),
  ('8efc5823-acb2-5700-8fe6-54eb9f5d85df', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-08-10', null, null, '通常 / 変数の使い方を広げよう', '先週の検定練習の変数の使い道を広げるために、レースゲームを作りました。ゲームを細分化しながらを作っていくのは久しぶりだったので、最初は手の付け所がわからず、もたついてましたが、一度進めれば、うまく進められました。最後のゴール判定のメッセージの仕組みが、わからず時間をかかっていました。途中の変数の切り替えは、質問しながらしっかり応じることができ、理解してました。', null, '時間帯: その他
タイピング: スコアが伸びていました'),
  ('9eb29ddc-9abe-5e60-84e0-cd52c4df1aff', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-08-10', '16:30:00', null, '通常 / アルスタジオ', '前回作ったジャンプゲームに躍動感をつけ買ったので、横スクロールのアレンジが死体のことでした。条件の演算式のところの理解はのあくんにはまだ早いと思ったので、そこは支えながら、メッセージのやり取りの関係を中心に教えていきました。かなりパターン化している部分が多いので、最後の方は自分で複製したものをどこを直せばいいか気づけていました。', null, '盛り上がり: 作った作品は母親にも見せられて喜んでいました。'),
  ('afc2e88b-a334-5b12-be70-8f9c49ca2186', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-08-10', '16:30:00', null, '通常 / U16作品作り', '今回の課題は、プレイヤー場を中心に回っている玉と同じ色の球が衝突した際に、2つとも消滅するようにしたい、とのことでした。クローン同士の区別をスクラッチ上では、難しいため、こちらからも有益なアドバイスをすることに苦戦しました。座標との取得などから考えてくれて時間延長で取り組んでいくれました。', null, null),
  ('009f4ad7-e7fa-57a6-a580-79a14e1fd3ae', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-08-10', '17:30:00', null, '通常 / リスト学習', 'リスト自体の存在を知らなかったので、この度はよい機会でした。最初の概念的な説明の段階では、あまりピンときてなかったが、実際にブロックを触れながら、説明を聞いていたことで、理解を吸収していました。その後の、練習のクイズ作成では、一通り流れの中で、みうちゃんは「リストの長さ」と「変数併用の●番目の繰り返し」の利用のところが難しく感じたそうです。特に、変数併用の●番目の繰り返し」はこれだけだと使いこなせるほど、理解はできていないので、ほかのゲームとかで意識させた方がよさそう。', null, null),
  ('913fde95-f3b6-5a5f-9e99-78678b47de74', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-10', null, null, '通常 / 変数の特別な使い方', '前回からやっている「変数の特別な使い方」をテーマにレースゲームを作っていきました。手順書を用意しましたが最初はヒントだけを見せて考えてもらいました。レースのコースを何回も変更するなど脱線することもありましたが、「(変数)歩動かす」という重要ポイントは理解してくれたようでした。途中、車が別のコースに移ってしまうというバグが出てきたのですが、いつそうなっているのか問いかけると、コースの感覚が近づきすぎていることに気付いて修正することができました。終盤は集中して完成までもっていけました。', null, '時間帯: その他'),
  ('7fd79ff3-793b-5e39-9b02-dfc4cdca466f', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-10', null, null, '通常 / 変数の特別な使い方', 'まずヒントだけを見せて考えてもらい、最初の方はできましたが自力で完成までもっていくのは大変そうだったので手順書を参考にしながら進めました。変数、あるいはそれに乱数を足したものを動く歩数として使うというのが今回のポイントでしたが、理解して作れたようでした。最終的にバグなどなく完成させることができました。', null, '時間帯: その他
盛り上がり: やや難しい所も理解しようとしていました。'),
  ('bee5a9f0-6336-5191-9071-20e532327966', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-08-10', '17:30:00', null, '通常 / U16作品の作り', 'U16の作品作りのことでしたが、この大会のことをあまり把握してなかったので、どうゆうコンセプトの大会なのか一通り説明しました。発表形式に合わせた、ゲームの背景設定を考えるように意識させました。前々から作りこんでした作品が、かなりRPGに近い感じで、作りこまれていてゲーム性はかなり高くなっていました。今後もこの調子鉄く上げてもらいたい', null, null),
  ('06c00b5f-5bdd-50f0-ac98-ab2ac0e3e96b', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-10', null, null, '通常 / U16作成', '今日もU16の製作を続けました。アプリの見た目や機能もしっかり作れてきていて、ゆき先生によく進捗を見せ、アドバイスをもらっていました。コードの部分に加えて、canvaでデザイン面の作成も行っていました。', null, '時間帯: その他
盛り上がり: 生き生きと作成できていました。'),
  ('8d540446-7d98-5aa5-918d-e73c67ecfb5a', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-10', null, null, '通常 / 基礎の定着', 'まずは前回の復習をして内容を思い出して続きに入りました。今日は集中力が切れることが少し多めでしたが、モードに入っているときは文章をしっかり読もうとする姿勢が感じられました。やっている途中で、「まで繰り返す」などのブロックを新しく習得しました。 30分頑張って自由時間になると、アルスタジオの「いちごの反乱」を遊んでいたのですが、「ゲームオーバーにならないように変えてみたい」と言い、ゲームオーバーになる部分のコードを探してアレンジしていました。', null, '時間帯: その他'),
  ('53eca8c8-cc7c-5a3a-acdf-d40b2ea2eaa6', '28d52d6e-7571-5090-a2d9-492c997b719e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-10', null, null, '通常 / 検定練習', '検定というものの概要を話してからやってもらいました。最初こそ形式に戸惑ったものの、次第に「読めば答え書いてあるじゃん」と簡単に感じてきたようでした。お手本ムービーと自分の作ったものが一致することを確認し、最後のアレンジまでできました。検定というものには慣れることができたようでした。', null, '時間帯: その他
盛り上がり: 完成させられたことに対して自信ありげでした。'),
  ('4cabb766-5faa-52f7-8e7b-6d06950fa0c5', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-08-10', '17:30:00', null, '通常 / 検定問題になれよう', '文章からコードを作れる練習として、3級の練習問題をやりました。1文1文しかっり読み込んで、チェックもでき、その通りで来ていたので、読解力とコードの作成能力は問題はないです。しかし、初回もあって、1つ1つ箇所を作り上げることに、喜びすぎたり、未完成のままであるので、バグの違和感に突っ込みを入れたりと、長時間集中して解くことは、まだまだかかりそうです。能力は十分あるので、検定を受けるのであれば、そこは回数こなして集中力を高める必要があると思います。', null, 'タイピング: かなり長く30分弱やっていました。
盛り上がり: タイピングの良さはすごく伝わった。'),
  ('0e19a1b8-5ed5-59de-b53f-d71e58d89219', '82396ac6-71bd-59d4-a372-57212866fd5d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-10', null, null, '通常 / 基本操作コースを進める', 'スタンプをコンプリートするという目標を示してから始めるとやる気が出たようでした。スタンプが埋まっていないところから順にアルスタジオで動きを見せ、自分で作ってもらいました。「10歩(-10歩)動く」「大きさを～にする」など新しいブロックは教えましたが、すでに習ったブロックはほぼマスターできていました。「旗が押されたとき」と「スプライトが押されたとき」の動きをしっかり分けて考えることができていました。「キャラクターをクリックすると何か起こることを説明したい」と言ったので、セリフのブロックを紹介し、後ろの方の内容に飛んだりもしました。', '続き', '時間帯: その他
タイピング: クリアしたときは達成感を感じた様子でした
盛り上がり: スタンプを押すたびに喜んでくれました。'),
  ('48f89334-69f2-551c-b88b-311aaead2d1a', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-19', '17:30:00', null, '通常 / オリジナル作品続き', '作品を教室の中で公開することを提案してみましたが、どうしてもしたくないようです。プログラムで作った作品に限らず自分が作った作品を他の人に見てもらうことに少し抵抗感もあるようです。人に見てもらうメリットも伝えつつ（自分の気づかない改善案、新しい観点）、「そのうちね～」ということで伝えました。 最後に今日やったことを教えてもらいました。音を「止める」のではなく音量を0にすることで音を止めているような工夫を加えていて、とても参考になりました。', null, null)
on conflict (lesson_record_id) do update set lesson_date = excluded.lesson_date, start_time = excluded.start_time, end_time = excluded.end_time, title = excluded.title, content = excluded.content, homework = excluded.homework, memo = excluded.memo;

insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('d68fbc14-ea33-5556-bff6-2b703d6d9840', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-19', '17:30:00', null, '通常 / 追跡ゲーム', 'サメから逃げろを復習した後、追跡ゲームに取り組みました。見本を遊んだ感じ、「簡単」とのことでした。また追いかけるというゲーム性に疑問を少し感じたようでした。 座標を使った移動の復習、「どこかへ行く」の使い方、音を鳴らす、変数を作るなどをやりました。「～まで待つ」の使い方も詳しく説明しました。背景チェンジは自分でプログラムすることができました。スコアのリセットも少しヒントを出すと自分でしっかりプログラムできました。', null, 'タイピング: 集中して取り組めていました。
盛り上がり: 楽しく取り組めました！絵を描くのが上手です！！'),
  ('c5b42ba2-f159-5d70-a5ea-66d9abb45a8f', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-19', '17:30:00', null, '通常 / 検定2級の実際の過去問', 'やった記憶があるとのことだったので、大まかにやり方を説明をしましたが、「紙を見ながらやる」ことに抵抗感があったようです。 諦めることなく取り組めました。最後の修正・加筆の部分は文章が難しい（変だと言っていました）ようで、スキップしました。つまずいた点としては、①読み飛ばし②次どこの続きにプログラムを書くのか③より小さい・大きいのプログラムの仕方 でした。本人が「文章が変！！」といっていましたが、初めて取り組んだにしてはよくできていたと思います！', null, null),
  ('2628e02a-4fa5-5302-ba6c-337c2cb8ef17', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-19', '16:30:00', null, '通常 / 物語を作ろう', 'ひととおり内容はやっていたので、内容を取り入れつつアレンジ作品を作りながら復習をすることになりました。 恐竜のスプライトで作った作品を見本として確認してもらいました。スプライトをいくつか準備をしてお話をさせ、物語を進める方針になりました。大きさを数字の設定で変えようとしていたので、復習としてプログラムで設定してもらいました。 かなりスプライトの見た目にこだわってしまい、あまり進められませんでしたが、会話をする部分は作れました。交互に会話をするために時間を細かく調整できていたので良かったです。一方で、表示非表示のプログラムを緑の旗ではなくスペースキーを押してコントロールしていたので、見本作品を例にしながら一貫性の大切さを強調しつつ、ひとつのスクリプトにまとめてもらいました。 次回は物語の続きです。あと何回で終わるのかを決めた方がいいかもしれません。', null, 'タイピング: 集中して取り組めました。'),
  ('e58d49c1-8d37-56ae-8916-7cd63f3b042a', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-19', '16:30:00', null, '振替 / 検定4級最初の問題', '最後まで投げだすことなく集中して取り組めました。時間はちょうど30分くらいで最後まで取り組めたようでした。 間違えたポイントとしては、①読み飛ばし②書いてないことをプログラムする ということが何か所かありました。ただ、一緒に紙を見直して少し指摘すると自分で直せたり、気が付けたりしました。最後に感想を聞いたところ「たのしい」とのことです。何回か練習して慣れればいけるかもしれません。', null, 'タイピング: 集中して取り組めました'),
  ('7328b62c-6f34-5b7c-9bff-a919ae0e7b09', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-19', '16:30:00', null, '通常 / U16大会作品', 'ひとりでしっかり進められていました。作品のしくみの大枠も説明してくれました。変数の使い方もよく理解できていました。変数の初期化のタイミングがうまくいかず困っている様子だったので、うまくいっている箇所とそうでない箇所を並べながら少し解説をしました。', null, 'タイピング: 集中して取り組めました。'),
  ('f77d3569-62fe-5de0-9439-32190b2b8aa3', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-08-22', '16:30:00', null, '通常', '3級の練習問題を解いていきました。途中の、「「移動量」だけ動かす」の表現の仕方に悩んでいました。そこで、今まで、変数をどのように使ってきたか思い出してもらい、ヒントを少しずつ与え使えそうな方法を長考していました。その結果、正解の形を自力に導きました。動きのブロックに変数を組み合わせるのは初めてで、変な感じだと言っていました。そのせいなのかあって、ほかのところの読み飛ばしが数か所ありました。その辺の注意力も練習で重ねていければいいと思います。', null, null),
  ('7ea533c4-9929-5f01-9e93-90d4ab8dca3e', '57f45872-1f3e-5540-b676-bf9023444e39', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-22', '16:30:00', null, '通常 / 検定に慣れる', '前回やったサンプル問題について忘れていた様子で、なおかつバグも残っていたようだったので答え合わせから始めました。しばしば読み飛ばしがあり、特に「～のときの動き。」という文を飛ばしがちだったので一緒に整理しました。上から順番にやっていく意識や、問題文と自分のコードを対応させる意識を持ってもらいました。そうしてサンプル問題のコードが完成したあと、次は自分でこれをやってみようと次の問題を促しました。やる気をもって初めてくれて、問題文を音読しながら注意深く理解しようとしていました。途中まで終わりました。', '続き', '盛り上がり: 無事にすべてのバグが直ったときは自信を持った様子でした。'),
  ('55922ba6-a74d-5f51-b277-0e32440653c9', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-22', '16:30:00', null, '通常 / 検定2級の問題（じゃんけんのやつ） 時間があればレースゲーム', '前回、フルで時間を使いつつも最後まで終わっていないとのことで、全部で30分ほど時間を渡して最後まで取り組んでもらいました。難しかった場所は、判定をつくる箇所だそうです。内容を確認しましたが、勝ちの判定の部分を2重でプログラムしていました。文章も見つつ、制御のブロックに注目しながら仕組みを解説しました。また「～キーがおされたとき」が旗のブロックを使ったプログラムになっていたので、文章の求めるところを説明しつつ改善しました。本人的にはかなり難しかったようです。 レースゲームでは見本をみつつ、ゲームの仕組みについていくつか質問をし、答えてもらいました。また道を外さないようになっている部分のプログラムについて、少し解説しました。変数に気を付けて取り組んでもらいたいことを伝えました。途中です。', 'レースゲーム途中', 'タイピング: 集中して取り組めました'),
  ('fcc551c3-7114-5413-8d55-c0acb0b793a1', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-22', '16:30:00', null, '通常 / 2コマ 4級検定問題2回目に取り組むもの', '2コマかけてようやく完成しました。 こちらが声をかけないと手が進まず、完成に時間がかかりました。スプライトを自分なりに工夫しようとして時間を駆けたりもしていました。 文章を読むように促したり、お願いしたところまで終わったら声をかけるように伝えたりしましたが、どれもうまくいきませんでした。また話しているときも「ちゃんと考えているのかな？」と心配になることが多々ありました。 完成するとかなり嬉しそうだったので良かったです。', null, 'タイピング: 取り組めました。'),
  ('ff00104a-af95-5364-8b02-723908c83c5e', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-22', '16:30:00', null, '通常 / 2コマ 3級検定問題1回目に取り組むもの 3級応用課題1', '【1回目】大枠はできていました。ただ独特の言い回しに慣れず、「ずっと繰り返し」を「10回繰り返す」と一緒に使うものだと思い込んでいたようです。また思い込みとして、移動量の変化のプログラムの結果だけを解釈し、文章通りにプログラムできていない箇所もありました。 【応用課題1】前回の反省を最初に確認（思い込み、プログラムの仕方など）し、取り組んでもらいました。制御のプログラムと座標変化のプログラムが入り組んだときに、混乱してしまう様子でした。文章を確認しながら一度整理しました。 次回は答え合わせからです。', '3級応用課題1の答え合わせ', 'タイピング: 集中して取り組めました。'),
  ('a0522db3-04e9-5f0c-adbd-755f81ad557f', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-22', '17:30:00', null, '通常 / 検定練習', '本番前最後ということで予行演習的な意識でやってもらいました。ただこの問題は難しいのでいくつか引っかかったポイントがありました。「～と聞いて待つ」の答えが「変数『答え』」と書かれていたことで、自分でその変数を作ってしまうというミスがありました。また、座標の値がいくつもの演算ブロックを複雑な入れ子にしたものだったので作成に時間がかかったようでした。ただ、そのような事態が起こりつつも、できるところは手を動かして時間内にある程度の完成度は生むことができました。そのうえで、難しかったところは先生と一緒に整理すると、最後で全て修正することができました。「これが難しかった分、本番の問題は簡単に見えると思う」とフォローすると、納得した様子で終わることができました。', null, '盛り上がり: 冷静に進められていました。'),
  ('d9d6afeb-7ba9-553f-b2ab-66b52aec98cf', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-20', '17:30:00', null, '振替 / U16作成', '大会に出すうえではゲームに何かしらのストーリー要素をつけたほうがいいという話をしたところ納得してくれたのですが、とりあえずはバグっている場所を直してしまいたいとのことでした。着地するキャラクターが床をすり抜けてしまうバグで困っていましたが、着地のコードを見て原因を探るように促すと、床が薄いせいで触れずに通り抜けてしまっていることを発見できました。床の部分を広くすることを提案するとそれで直すことができました。そのほかにも、発射される技がうまく消えないため、消える条件を整理して修正していました。', null, null),
  ('9e456f7a-3d71-5dfb-a685-2b08191dd10d', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-08-23', '16:30:00', null, '通常 / 花火作品のアレンジをしよう', '前回猫の形をつくりたいのことだったので、アレンジをやっていきました。最初は点々で猫との形を描こうと思ったが、形するには難しく感じたそうなので、スプライトの猫のやつからやっていきました。花火の広がりを大きさの変化で表現で来ていてよかったです。途中保存しきれてなくて、最初に戻ってしまうことがあったが、すぐに修正はできました。', null, 'タイピング: よく見ていました'),
  ('8946ef04-53e5-585a-a718-ad574a8a2ea7', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-08-23', '17:30:00', null, '通常 / U16作品作り', '作品を事前によく見たら、表示されないとか、一部通れるはずのところが通れない細かな場バグ見つかりました。それを最初に、伝えたところ、「これは治らないからそのままでいい」とバグの存在を隠そうとしていたので、しっかりと修正法を教えてあげました。その都度、バグを直していかないと複雑に絡み合ってしまうことになる可能性があるので、次々と新しいのも作っていくのもいいが注意しました。 そこで、コンセプトのために、作品の全体像を聞くと、黒いねこから逃げていくゲームだそうです。逃げていく中で、各ステージごとにギミックがいろいろあるそうです。あと2，3部屋を作るらしいので、終わりのポイントはしっかりと考えていました。 次々と新しいスプラとがあるので、ちょくちょくバグを見ていった方がいいおもいます', null, null),
  ('dc81ea83-35ac-54d0-b8b7-9a44a505c165', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-08-23', '17:30:00', null, '通常 / プラットフォーマーゲーム作りに目指そう', 'プラットフォーマーのゲームを見せたら、この重力のあるジャンプに惹かれていました。けど、ゆづきくんはジャンプ系のものを作ってこなかったので、まずは、党則ジャンプでどうゆう仕組みか考えてもらいました。変数で表す際に、ジャンプの下りの表現を表す際は、悩みましたが、四則計算のヒントを出すと、自力で導きました。次に、放物ジャンプ移るときに、ジャンプを違いを聞いてみたら、最初から上がる幅が小さくなることに気づけていました。ただ、それを一からコードを考えるには難しかったので、コードを見せながら作りました。何回か説明をしたがあまりピンときていなかったので、次回も復讐させた方がいいと思う。 次回は、段差を上る方法を作るように告知をしたので、アル君の冒険の段差のジャンプを法没ジャンプで作れるようにしたいです。', null, null),
  ('693a6380-109d-53de-bf46-f14112f882c1', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-23', null, null, '通常 / 3級検定問題1回目にやるもの', '制限時間を過ぎていましたが、5~10分ほど延長して進めました。詰まった部分はあったようですが、ヒントをみて解決できたようです。 制御のブロックがどこまで続くのかの把握ミス、変数の間違いなどがありました。制御については考え方のヒントを出し、再度自分で取り組んでもらいました。また、自分で4級との違い（制御・演算のブロックなど）を把握できていました。3級は初めてですが、よくできていたと思います。', null, '時間帯: その他'),
  ('81d10213-42fe-5820-b8b5-82ea8ae1e470', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-23', null, null, '振替 / サメから逃げろ！', '最初にあさひくんのサメの作品で遊んでもらいました。音がかなり気に入ったようで楽しそうでした。最初にサメのプログラムを作りました。見本を遊んで気づいたコメント（ずっと動かす、跳ね返る）から少し手助けをしましたが、ほぼ自分で作れていました。またあるくんのプログラムで動かすときに、動かす方向と歩数の順番に気を付けるように伝えました。また「ずっと」「もし」「触れた」のブロックの使い方も説明しました。おおよそ理解できたようです。最後にアレンジとして、サメが喋るようになったり、効果音を設定したりしました。どれも自力でできていました！', null, '時間帯: その他
タイピング: ふつうとかんたんの2種類に取り組めていました！
盛り上がり: ずっと楽しそうでした！'),
  ('4ade5248-47a9-5696-b0ce-9f8900205370', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-08-23', '17:30:00', null, '通常 / U16作品', '前回まで作っていた的後のゲームがカタチになりました。的が内向かれた際に、穴が開く演出はきれいにできていました。また、的の出現で、縦回転して現る演出はうまくコスチュームで組み合わさっていました。銃撃のの音もあり、リアルティーあるものに仕上がりました。', null, null),
  ('d1adbe14-0c24-59d2-be9f-986c6cbb6f0b', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-23', '17:30:00', null, '通常 / 4級検定問題初めにやる演習 ー文章を読んでプログラムする', '文章は目で追えるようですが、読んでプログラムするということはできませんでした。文章をイチ行ずつこちらで示して読んでもらう→プログラムするというのを促すと、大きさや位置などは自分で取り組めていました。制御の「まで繰り返す」というブロックはあまり見たことがなかったようなので解説しました。文章が長くなると理解するのが難しいようでした。 今後もトレーニングとして検定問題に取り組んでいくようです。', null, 'タイピング: 集中して取り組めました。'),
  ('45a3127c-7653-5208-a824-e6e9280c5554', '53dc382f-637d-5a46-9b57-4204c79ee130', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-23', '17:30:00', null, '通常 / 物語を作ろうのオリジナル作品', '前回の続きとして、どのような物語を作るかを最初に考えてもらいました。会話文が中心のプログラムになってしまいましたが、途中で背景変化を提案したり、初めてメッセージを使ったりしました。 メッセージの仕組みはなんとなく理解できたようでした。また会話文なので交互にプログラムする必要がありましたが。混乱せず丁寧に取り組めていました。 自分的にはかなり作品に満足しているようでしたが、個人的にはもう少し動きを付け加えてほしかったです。次回の話をしてみましたが、あまり音楽には興味がないようです。またプログラムで作りたいものを今後探していきたいようです。', null, 'タイピング: 誤タイプが多かったですが、集中して取り組んでいました。'),
  ('ba7a83af-57b4-5265-abe6-febf8998a0fe', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-23', '16:30:00', null, '通常 / プラットフォーマーゲーム（ジャンプ系）', '前回やったことの復習をしつつ、プラットフォーマーゲームの完成版を見てもらい、ゲームの仕組みを確認しました。背景スクロールとジャンプの要素からなることを説明し、ジャンプのプログラムに入りました。 等速ジャンプ①②は、数値的にはスムーズに取り組めました。一方で移動する量として変数を使うのは初めてだったので驚いていました。初期化も説明すると理解できていました。その後、自分がやりたいジャンプのプログラムに脱線しそうになりましたが、根本的なスタートの考えが違うことを説明し、また別の機会に取り組むように促しました。 放物ジャンプは基本的な考え方は理解できていましたが、変数を使うことが難しかったようです。解説するとプログラムできていました。 次回は放物ジャンプ②かなと思います。', null, 'タイピング: 集中して取り組めました。'),
  ('5a00a98e-992e-536a-8d78-9baec62bde9b', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-08-22', '17:30:00', null, '通常 / U16作品つくり', '前回は床のすり抜けのバグがあったが、今回は足場の横方向のすり抜けバグに立ち向かいました。これが、スプライト同士で、同じコードを持っているので、片方だけうまくいかないので、ほかのコードも見比べていましたが、なかなか見つからなかったそうです。ストーリーについては、創友系は苦手らしいので、そっちにまだ着手できていないです。', null, null),
  ('984e1b28-b0b7-50af-9d38-81cf64882364', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '694bc25a-68e7-599d-9514-5e7539918db8', '2024-08-23', '16:30:00', null, '振替 / U16大会作品', 'ストーリーについて深掘りして聞いてみましたが、理由なくいろいろと物事がおきる治安の悪い（？）世界のようなので、もう少し詳しく考えてくれると良いかなと思いました。また、先週まではきちんと動いていたようなのですが、クローンしたコインがうまく見えない問題が起きていました。しもさんが確認してくれたところ、クローンはできているのですが、煙突(?)の中にあるだけで下に落ちてきていないようです。次回見直す必要があるかもしれません。難しいバグがあると他の人に任せてしまうような傾向があるので、自分でも頑張ってほしいです！', null, null),
  ('224bde44-99aa-5cd6-b97f-3aebba8efd52', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-08-23', '18:40:00', null, '通常 / サメの作品をアレンジしよう', '今回は、逃げ切れた時の演出作っていきました。その際に、メッセージの存在を伝えましたが、まだ、自分で使いこなせるほど、理解は定着していないです。逃げて帰る演出は、井戸系のブロックは自ら動かせるようになってきました。最後にアレンジとして、食べられた魚が骨になるのもよかったです。途中は、作ったものをみずき君も見せて楽しんでいました。', null, '盛り上がり: 録音は、本人的には、楽しんでいるが、多少騒ぎすぎなところもあります。'),
  ('bec4d6b9-3b20-5713-a393-07df4f8472e6', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2024-08-19', '17:30:00', null, '通常 / 変数のいろいろな使い方', '土曜日にやった「変数のいろいろな使い方」の次のステップ【Prg】10 レースゲームを作ろう！⇒手順書あり。 最初に全体を細分化して考えてもらってから、作れるイメージができるか？●色が〇色に触れたらの主語が違っていて上手く動作せず。ふてくされていた。 最後は「プレイヤー」でコードを書く時に、自分が持っていない色を指定している、と説明して理解した様子。 上手く動かないと、自分で考えない、説明をちゃんと理解しようという根気が若干すくないのが少し気になる、、、、。もしかしたら、考え尽くして分からないから、嫌になっているのか？', '「変数のいろいろな使い方」のスィッチとして、バレーボールにチャレンジか？', '盛り上がり: 色の解決ができて、上手く動いたのは満足度が高そうだった。'),
  ('35f37427-a22a-50d4-84a5-59cd74676c63', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, null, '2024-08-20', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('25a74b3c-49f8-5968-9bea-6b5942499d69', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-20', '17:30:00', null, '振替 / 検定練習', '集中して解いていましたが、途中わからない場所があるようだったので、その箇所に印をつけて一旦飛ばすという方法を促しました。とりあえずできるところまで進めるのに良いと納得してくれたようで実践してくれました。一通り進めた後その場所に戻り、おてほんムービーを見ながら該当の動きをイメージしていて、しっかり思考することもできていました。答え合わせすると、「～を鳴らす」と「終わるまで～を鳴らす」の間違いや繰り返しの範囲のミスがありましたが、このまま慣れればマスターできそうな感じでした。', null, '盛り上がり: お休みのまこちゃんに会いたそうでした'),
  ('f5743467-f3b4-5083-b0c2-953a251a7fc9', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, null, '2024-08-20', '16:30:00', null, '休み（未対象）', null, null, null),
  ('ffc56eb5-c88a-5ed3-ab5b-021397b4f8b0', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, null, '2024-08-20', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('f6b19408-a826-5fc5-b224-527024accca8', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-20', '16:30:00', null, '通常 / 興味のある作品を作る', 'prgや弾幕などいくつか提示したところ、今日はシンプルで作りやすそうなお散歩ゲームを選びました。最初はだらけ気味だったものの、時間に対してメリハリを持とうという話をした結果集中モードに入ってくれました。それぞれのスプライトについて問いかけをし、一緒に細分化しながら進めました。岩を落としてくるにはクローンを作って動かせばいいことを理解し、スプライト本体の動きとクローンの動きを分離しながら作ることができました。スコアが変わる条件について整理させたところ、加点と減点に分けて言語化することができ、そのコードまで作れました。背景については、下向きに動いていることはわかったようですが実際のコードを作るには至りませんでした。', '続き', '盛り上がり: 後半はよく集中してくれました。'),
  ('6bb0eb22-2fea-5c78-84cc-ce11ead8e9ee', '57f45872-1f3e-5540-b676-bf9023444e39', null, null, '2024-08-20', null, null, '休み（未対象）', null, null, '時間帯: その他'),
  ('f869490c-61a3-5968-92a6-3f8f1e5c680e', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, null, '2024-08-27', '17:30:00', null, '休み（未対象）', null, null, null),
  ('515fef07-d3dd-5da8-b1d5-9ba57f216a7c', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-27', '16:30:00', null, '振替 / 変数の特別な使い方', 'まずは手順書の表紙だけ見せてスタート、レース、ゴールの3つに分割して考えてもらったところ、メッセージ送信を含めたスタート部分は自分でできました。レース部分は自力では厳しそうだったので、今回のテーマである「変数の特別な使い方」を意識して、「(変数)歩動かす」という使い方を理解してもらいました。そのうえで手順書を参考にしながら作っていくときちんと車が動かせました。途中、マウスを長押しするとズルできてしまうことに気付いたので、次回ゴール部分の作成が終わったら「～ではないまで待つ」の学習もかねて修正させてもいいかもしれません。', '続き', '盛り上がり: いつもと違う環境で人が少なかったですが普段通りの様子でした'),
  ('830ef1d8-bddc-5245-8fff-3e649d15b4f0', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-27', '16:30:00', null, '通常 / ゲームの完成を目指す', 'ステージの縦スクロールからやる予定でしたが、エサの挙動がおかしかったのでそこの修正から取り組みました。まずは一度エサを食べると大量にライフが回復してしまうことについて、完成版のゲームと動きを見比べてもらうと、食べたときに隠すのを忘れていたことに気づけました。また、エサが取れずに下まで落ちたときにも回復してしまうので、「食べたとき」と「食べられなかったとき」の両方について流れを言語化してもらうと、場合分けしながらコードを組みなおすことができました。 後半はスクロールの作成に入り、難しく感じたようでしたが、岩やエサと似たような動きをしているというヒントを出すと手を動かせていました。ただどのタイミングでステージを一番上に戻すかなどの考察が難しく、持ち越しになりました。', null, 'タイピング: 頑張って数回取り組んでいました
盛り上がり: わからないとところを自分から口に出してくれたりと、モチベーションはやや高かったです。'),
  ('c3714e1f-df00-5e02-84c9-a4dba2c2ca7b', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-24', null, null, '通常 / 変数の特別な使い方', '今回も変数の特別な使い方というテーマで、バレーボールに取り組みました。ボールをランダムな場所に落とす部分についてはキャッチゲームなどの復習ですが、どうやるのか忘れてしまったようでした。それについては、何座標がどう変わるのか、いつまで変わるのかなどを問いかけると自分の手で作ることができました。現在の姿勢に合わせて変数「向き」を設定するところまではできましたが、それをどう使うのかは次回の続きになりました。', null, '時間帯: その他'),
  ('5d452550-5ee1-537f-9b4e-d6be68fe36c4', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-24', null, null, '通常 / 変数の特別な使い方', '今回も変数の特別な使い方というテーマで、バレーボールに取り組みました。左右に合わせて変わる「向き」という変数によってボールの動きを変えようというヒントを聞くと、その変数が0と1のときで場合分けして動きを考えることができていました。ただ、その変数の値自体の設定がまだできていないので、それができれば完成しそうです。', null, '時間帯: その他
タイピング: 集中していました'),
  ('a7145401-622b-5e5b-b116-4c5170f2b96b', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-24', null, null, '通常 / 検定をやってみる', '検定問題が初めてなのでどういうものか軽く説明してから始めました。序盤は一緒に読み合わせながら進め、それなりにできたので後半は基本的に自力でやってもらいました。「～まで繰り返す」や「スプライトの他のスクリプトを止める」など知らないブロックについて質問されたのでそこで勉強してもらいました。答え合わせすると少し読み飛ばしがあったのですが、その箇所をもう一度読ませると納得したようでした。', null, '時間帯: その他
盛り上がり: 検定本番については乗り気ではないようでしたがレッスンで解く分には大丈夫そうでした。'),
  ('a79a2c75-b341-5c2a-be84-991576cd499c', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-24', null, null, '通常 / 自由作成', 'どれくらい進んでいるのか質問すると、「主人公の動きは作り終わったけど敵の動きは今やり始めたところ」と進捗を伝えてくれて、計画もイメージできているようでした。先生に見せてくれるのは時々でそれ以外は断られるのですが、作業は進んでいるようです。', null, '時間帯: その他'),
  ('8d2d14e9-4e7f-560d-a2bb-ab6aa0f23bfc', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-24', null, null, '通常 / U16作成', '大会に出すにあたってはストーリー要素を入れたほうがいいかもという話をすると、「自分のゲームは何も考えずにできる作業ゲーというコンセプトで作っているし、過去のゲーム系の入賞作品にはストーリーはついてないものが多かったので、特に必要だと思わない」という返答でした。入賞作品が実際そうなのかは確認できなかったのですが、とりあえずはデバッグに取り組みました。ボールのクローン同士がぶつかったときに両方消えてほしいものの片方しか消えないと困っていたので、両者のクローン番号を記録してから順番に消すことを提案するとその方法でやりましたが、それでもうまくいかず難しいようでした。', null, '時間帯: その他'),
  ('a19d833a-0a6d-5ee9-8ab4-9d9e08e52673', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-24', null, null, '通常 / 検定に慣れる', '前回に引き続き検定3級に取り組んでもらいました。自分の作ったものとお手本ムービーの違うところを見つけるなど頑張っていましたが、まだ引っかかる場所が多かったです。プログラミングのスキル自体は身についていますが、文章を読みながら分岐や繰り返しなどの構造を読み取るのは難しかったようです。', null, '時間帯: その他'),
  ('be7acd94-74ce-505d-b2ce-e8aae527c02e', '28d52d6e-7571-5090-a2d9-492c997b719e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-24', null, null, '通常 / 検定練習', '一通り最後まで解き終わった後、テストプレイをすると動きがおかしいと気付きました。「どこかしら間違えてるってことだからそれを探してみて」と見直しを促すも分からなかったようなので答え合わせをしました。繰り返しの範囲や、3種類ある「止める」ブロックの選択を間違えていたので一緒に確認しました。これらは、使うブロックが直接文中に書かれているわけではなく自分で判断する必要がある内容でした。やっている途中「読んだ通りにやるだけだから余裕」という発言もしていたのですが、読んだうえで自分で考える必要もあることを理解してもらいたいところです。', null, '時間帯: その他'),
  ('b8280da1-407c-55a0-93fc-9b859d9fe2d9', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-30', null, null, '通常 / リストの練習', '前回扱ったリストの応用ということで、比較的シンプルなおばけのゲームに取り組みました。素材のみについているヒントだけでは厳しそうでしたが、x座標というリストの中身を見せると、乱数と「リストの～番め」などを組み合わせてうまく作れ、完成までできました。リストの基礎については理解している様子でした。', null, '時間帯: その他'),
  ('c3b97508-22f1-5d2e-9ef8-1b2af6f920f5', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-24', null, null, '通常 / U16作成', 'U16作品として、ヴァンパイアサバイバー風のゲームの作成を進めました。これまでの進み具合や今後の計画について聞くと、現状大きなバグは無く、アイデアやキャラクター、ストーリーもイメージできているようで、ほぼ自走できています。数多くのスプライトを使っていますが使いこなせています。', null, '時間帯: その他'),
  ('ae0c1231-a360-5560-ab6c-b2caea18a4c7', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-31', '16:30:00', null, '通常 / ジャンプゲーム続き', '前回の復習をした後、変数の作成と卵を増やしました。 変数については使い方を忘れかけていたので再度紹介と、プログラムするブロックをどこに置くべきなのかについて考えてもらいました。初期化もなんとなく理解できていました。 卵の動きも復習し、特定のスコアで卵が増えるようにしました。座標についての理解がまだ少し浅かったので、詳しく説明しました。表示非表示などは順を追って考えられるようになったかな？と思います。', null, 'タイピング: 集中して取り組めました。'),
  ('a968aff1-417d-57b1-96c0-0b5baa3fbe56', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-31', '16:30:00', null, '通常 / オリジナル作品', '別の大会に作品を提出するために少し内容を変更する必要があること、国旗ができていく様子が全体が滑らかにつながれば見栄えがよくなることを伝えました。とくに前者についてはよく納得してくれたようで、時間中にメッセージの整理だけではなく新しくスプライトを足すなど工夫をしていました。後者については今後検討していくようです。', null, null),
  ('c594d195-1f3b-5783-b0d0-04fdd6b699d3', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-31', '16:30:00', null, '振替 / オリジナル作品', 'Prg41の「あっち向いてほい」を参考に、カタカナのへとひらがなのへを仕分けるゲームを作りました。ポイントは「聞いて待つ」を使わず、プレイヤーがクリック操作のみでプレイできる点かな？と感じました。 変数とコスチューム番号を使って仕分けるという発想は良かったのですが、文字が出現されるタイミング、プレイヤーがボタンを押すタイミング、判定を行うタイミングを同時並行で考えてしまい混乱している様子でした。いくつかアドバイスをしておおよそ完成しましたが、本人的にはかなり疲れている様子でした。', null, 'タイピング: 集中して取り組めました。'),
  ('2e59daa7-faf3-5021-9c2f-497befbba5f3', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-31', '17:30:00', null, '通常 / オリジナル作品', '今日は新しくドアの開閉部分のプログラムを作成していたようです。画像の変更のほうにもかなりこだわっている様子でした。まだ完成はしていないそうですが、シンプルなプログラムを作れそうです。集中して取り組めました。', null, null),
  ('34713b7e-9840-50cf-b50a-5ea3ba54e44c', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-31', '17:30:00', null, '通常 / バレーボールキャッチ', 'ボールが落ちてくる、むらっちが動くなどの基本的な部分は自分でプログラムを作成することができました。また「向き」の変数にも気が付け、考え方（フラグとしての変数）を大ざっぱに説明すると、スムーズにプログラムを作成することができました。検定で少し慣れたのかな？一方で、途中で「疲れた～」とすぐに別のことを初めてしまうのが残念です。', null, 'タイピング: 集中して取り組めました。'),
  ('a1c14644-d52a-5482-8970-15e7fb385c83', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-31', '17:30:00', null, '通常 / 5秒で止めろ', 'けいとくんが作った「5秒で止めろ」を気に入った様子だったので、まずはオリジナルの見本通りに作ることにしました。見本のプログラムを見ながら作ってもらい、その後プログラムの意味を考えました。四捨五入の部分が少し難しかったようですが、その他はおおよそ理解できていました。定義を使ったプログラムも見慣れてきたようです。', null, 'タイピング: 集中して取り組めました。'),
  ('a1a4c7ac-7c48-52cb-a7e0-5713a5b6fef6', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-31', null, null, '通常 / バレーボールでスイッチの復習。タコで変数の使い方の確認', '前回までにかなりバレーボールのプログラムを進めていたので、変数のスイッチのプログラムを作りました。見本を使って思い出してもらい、プログラムを進めました。また変数の使い方のバリエーションを増やすために、タコの作品を遊んでもらいました。変数を使っているポイントを考えてもらい、紙を見ながらプログラムしてもらいました。「上級」はプレイの難易度が高いそうです。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('3bd81b55-06c4-5c43-9144-fde3cd98547e', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-31', null, null, '通常 / 検定3級復習・検定4級問題初回', '検定3級の復習をしましたが、自分でスクリプトを分けてしまっていた部分以外はおおよそできていました。本人に検定になれるため＆感覚をつかむために、4級の問題に取り組みました。15分くらいでおおよそできました。一か所、読み間違いでプログラムを書く場所を間違えていましたが、他はよくできていました。その後、アレンジについて説明し、プログラムを作ってもらいました。最後に内容を口頭で説明してもらいました。楽しそうで良かったです。', null, '時間帯: その他
タイピング: 「むずかしい」でもかなり余裕なようです。'),
  ('ebe21d0a-4f52-52ee-8160-b14f14d81a4f', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-31', null, null, '通常 / 「とめる」方法の復習。検定の意味をもう一度説明した方がいいかも。単元別のファイルでいろいろやるのもいいかも。ひとつの時間で作品が仕上がるのでよい', '検定の方は少し疲れている様子だったので、今日は基本操作コースのピンポンゲームを作成することにしました。パドルのプログラムで苦戦していましたが、座標に注目してもらい、共通している部分を考えてもらいました。言葉で説明できていたので良かったです。赤い線に止まったときにプログラムを止めるのも、前回の復習としてよくできていました。パドルでのボールの跳ね返りは角度についてあまり想像が及ばないようで、少し時間がかかりました。回転の仕組みを想像してプログラムにつなげるのが苦手なようです。変数については復習をしながら、スプライトの出現では「～まで待つ」の使い方を詳しく説明しながらプログラムしました。楽しそうで良かったです。次回アレンジです。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('7aed576a-a4ec-54d8-ba15-50a64e90858c', '0047fb11-a84a-5592-8c39-5a16c20eb10e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-08-31', null, null, '通常 / 検定3級問題・初回に取り組む問題', 'ほぼ時間内にスムーズに取り組めていました。一か所問題文を読んでも分からない部分があったそうですが、文章を一緒に読み進めて意味ごとにスラッシュを引くと、自分でもプログラムすることができました。また「まで繰り返す」ブロックはあまり使ったことがなかったそうです。文章読み返して内容を確認すると、なんとなく使い方が分かったようすでした。他に分けてプログラムを作ってしまった箇所がありました。 大枠はとてもよくできていました。次回以降、自分のしらないプログラム方法やブロックを知るために検定問題をすることがあるかもしれないことを伝えました。', null, '時間帯: その他
タイピング: 少し苦手なようです。'),
  ('04abd5a4-6878-5bc6-a346-5a51c31e16cf', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2024-08-26', '17:30:00', null, '通常 / 追跡ゲームとメッセージの応用「星とり」でストーリー性のある流れ', '追跡の基本とメッセージをしっかり理解しているので。5年生ということと、ストーリー性の高い作品つくりが好みそうだったので「星とり」をみせたところ、「かわい～～」と言って気に入っていたので。こちらに。 キャッチのしくみはまだ習っていなかったです、簡単に説明しながら、なんとかやっていた状態。', 'キャッチの仕組みを軽くしかやっていないので。次回、しっかり復習すると定着すると思う。（座標と繰り返し）あと、意外とコスチュームを変化させることで動いている風になることを知らなかったので。犬のコスチュームを追加して、食べたり、立ったりさせて動きのある画面を提案すると楽しんでくれるかも？', '盛り上がり: 数回前の物語を作ろうの時もそうですが、ストーリーを作るのが好きそうで。'),
  ('5998834c-07fb-5a4d-97dc-e18a76ba6958', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2024-08-26', '17:30:00', null, '通常 / 追跡ゲームの進化', '先生少ないので、PC横にもう1台置いて横で番号順に細分化した動きをみせて。「この動き、できる？」というなるべく自走パターンで実施、「この動きをどうやって動いてる？」という問いかけに、一生懸命考える様子がみえて頼もしいです。とはいえ、まだスキルがないので。勝手に進んでいくのが行き過ぎると戻れなくなりそうだったので、早めにパーツごとに完成をみせて簡単に説明しながら進めました。内容、ちゃんと理解できてるね！', '追跡を復習して、次のステップ（乱数と迷路かな？）', 'タイピング: きちんと取り組めていますが。お母さんから、目が悪いので、姿勢と正しいホームポジションをと言われています。なので、この2点は気づいたら声かけてください。
盛り上がり: 最後に、クリア画面を手描きでつくり、スコアが機能した時は嬉しそうで。お母さんにも誇らしげに見せていました(^^)v'),
  ('41a9b74d-2181-5e3e-8027-d46733cbbcc6', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-02', '16:30:00', null, '通常 / 向上に向けた見直しポイントを洗い出そう', '最初に、ゆき先生の方から9月末までの退会までの流れを説明してもらいました。そこまでには作品を仕上げて提出する認識を共有できました。今回は、親子大会で入賞に至らなかった点を入賞作品と比較しながら。探っていきました。ひろとくんはゲームの仕組みのコードはよくできていましたが、比較した際に、なぜ機織りのゲームをすることになったのか導入の部分が不足していました。また、肝心の機織りの工程を表す部分では一目ではわかりずらいことも指摘しました。前者の改善は、すぐにはできそうになかったので、後者の機織りの工程を見やすくしていきました。やることがはっきりしていたので、自分で治すところが自力で治せることができました。ただ、どちらにせよ、ストーリー的なことを考えるのは苦手っぽい感じです。 あと、終わり方が不安定だったので、そこもキレイに直していけたら', '導入のところを考えてくるようにしたので、そこ進めてもらえれば、 悩ましいそうだったらイラストの細かい祖語を直してもらって', null),
  ('86631cdb-5119-5e8c-b186-cb0a46355ccd', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-02', '17:30:00', null, '通常 / 星取ゲーム続き', '爆弾が下に降りた後に上に戻るようにするため、前回の復習をしました。星の座標のプログラムに注目して、プログラムの意味を確認しました。演算のブロックの意味が少しあやふやなのかもしれないので、単元別などで一度確認をしておいた方がいいかもしれません。 スコアのプログラムの後に、星と犬がぶつかる回数をカウントしてプログラムが終わりになるようにしました。変数を使うことはこちらから提案しましたが、スコアとおおよそ同じように考えてある程度自分でプログラムをつくることができました。 作品はこれで完成です。', null, 'タイピング: 集中して取り組めました。
盛り上がり: くびが痛くて学校をお休みしたそうですが、教室には来てくれたようです！！'),
  ('eeccfd7c-74c0-5916-b854-80e4665dabcd', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-02', '16:30:00', null, '通常 / 単元別にさらい直す ---ドリルで動きを確認', 'ドリル1・2はかなり余裕でした。ただ3・4になって角度が加わると難しかったようです。「～度にする」と「～度まわる」の違いがあまりよく理解できていないようでした。実際のものを例えていくつか説明をしましたが、理解できたか微妙です。また右回りと左回りがあることを説明したのですが、あまりよく分かっていない様子でした。 右→左→右の順番に動かすなど、いくつかの動作が組み合わさると順番にプログラムできないようです。簡単なブロックをいくつか組み合わせて長いスクリプトを作る練習をした方がいいかも？', 'ドリルの続き（と復習）がよいかな？と感じています', 'タイピング: 集中して取り組むことができました。'),
  ('fef4b9df-bccb-5e8f-8cb5-7871a8131a07', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-02', '17:30:00', null, '通常 / 追跡ゲームのクリアの演出、乱数（サイコロ）、迷路チーズ', '追跡ゲームのクリアがうまく表示できていなかったので、プログラムの実行順序について解説して修正しました。アレンジはあまりやる気がないようだったので、乱数についてやりました。内容についてはおおよそ理解できたようです。 その後、迷路チーズを作成しました。時間の都合でネズミのプログラムのみ作成しました。迷路に当たった時に止まるプログラムを「0歩」を考えて作りました。こちらから誘導して質問し整理するとうまくプログラムを作成できました。次回、乱数を使ったチーズのプログラムを作ります。', null, 'タイピング: 集中して取り組めました。'),
  ('d5588f12-55c3-54b5-8d74-2ea99526fa1d', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-02', '17:30:00', null, '通常 / 変数の使い方を広げよう', '変数の使い方のパターンとして、野球ゲームの変数で動きと大きさを変えることの理解を進めました。意外にも「まで繰り返す」の使い方が定着してなくて、今一度教えてあげました。検定ではよく出ていたので、不自由なく使えると勝手に思っていたが、文章に出てきたらわかるが、自らは使えないそうです。変数のところは、まず動きは単純な動きを作り、変数に変化していくような作り方でヒントを与えたので、うまく作れました。 ほかのところは、集中切れもあった画家たちにはなりました。', null, '盛り上がり: 夏休みはばいくらんにつぎこんだそうです。'),
  ('49c09408-d5ae-5b34-8dae-6138848fb35e', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-02', '17:30:00', null, '通常 / U16作品作り', '今回は、ドアの開閉をできるようになりました。変数を組み込んでいて、スムーズに開けるようになっていました。着々と進んでいるので、このまま自力に進んでいけそうです。', null, null),
  ('14adfcd9-2cae-5b7a-850a-d6ee481c9c8b', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-09-03', '17:30:00', null, '振替 / ジャンプゲーム完成', '軽く復習してから始めました。すでにお手本通りには作れていて、「スコアが5点と10点になったときに新しい卵を出現させる」というアレンジに取り組んでいたようだったので、その続きをやりました。「スコア=5まで待つ」を作る時に、等号は今日初めて使ったようでしたが「まで待つ」は習得済みで自分で使えました。表示する・隠すブロックが必要なこともわかったようでしたが、どこに入れるか迷っていたので、「プログラムは上から順番に動くから、流れを確認してからブロックを入れよう」と順次処理の概念を伝えました。それできちんと動いたのですが、ゲームとして難しすぎたので難易度調整に入りました。卵を遅く動かすには「～秒で～に行く」ブロックで時間を変えればいいことを確認すると、クリアできそうな難易度に変えられていました。', null, 'タイピング: 片手でやっていたので、「かっこいいし早く打てる」と両手打ちを勧めました
盛り上がり: 自分の作ったゲームが気に入った様子でした。'),
  ('32e019ed-eba5-5dd0-a6d1-11d9098ed290', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-09-03', '16:30:00', null, '通常 / 夏休み明けのウォーミングアップをする', '久しぶりのレッスンだったため、軽くスキルチェックしながらのウォーミングアップと位置付けて検定問題に取り組みました。ある程度はできていましたが、抜けているところも多かったです。不等式とは何かを忘れていたり、繰り返しの範囲が間違っていたりしたため復習しました。「(スプライト)の(向き)」など、今日初めて知ったブロックもあったようで新しく学習しました。 答え合わせを半分くらいやったところで終わりました。', '答え合わせの続き(問題2ページ目から)', 'タイピング: 集中していました。
盛り上がり: 夏休みは満喫できたようでした'),
  ('6b472f2c-bcc7-553f-a1ac-c0a7d92f061a', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-09-03', '16:30:00', null, '通常 / 作品作り', '検定練習が続いていたので切り替えて作品作りに取り組みました。まずは今回作るお散歩ゲームを、息抜きも兼ねてやりこんでもらいました。作成時は、変数について「～にする」と「～ずつ変える」を間違えがちだったので、出てくるたびに確認しました。1ずつ変わるはずのライフが一気に変わってしまうと困っていたので、「変えるときに少し待ってあげると一気に増えない」とヒントを出すとできました。', '続き', 'タイピング: お得ラインに到達していました'),
  ('c3b7fc3e-05c6-5b68-b7e9-c6c03a8d6f94', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-09-03', '16:30:00', null, '通常 / お散歩ゲーム完成', 'スクロールの作成の続きからやりました。背景が一番下に来たら一番上に戻すというイメージはつかめていたのですが、具体的な座標を計算するのは難しそうだったので、y座標360と-360を上下の基準にするというヒントを出すと無事に動きました。 一通りできたので残りの時間はアレンジをしました。お気に入りのリスのスプライトを使い、食べ物をどんぐりに変えるなどして楽しいゲームが完成しました。', null, '盛り上がり: あまりだらけたりせずに取り組めました'),
  ('db76e57c-3ee5-57a3-8100-2b326e758b9b', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, null, '2024-08-24', null, null, '休み（振替対象）', null, null, '時間帯: その他'),
  ('3cba4d6f-2aae-5fd4-8671-968881129820', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-31', null, null, '通常 / 変数の特別な使い方', '先週お休みだったので今日からバレーボールに取り組みました。ボールを落ちる動きを作るのに少し苦戦したようだったので、キャッチゲームを復習して、細分化をすると乱数やy座標の変化を使ってできました。本題である「向き」の変数については、むらっちの向きと変数の値をきちんと対応させて理解することができていました。レシーブ作成の直前までできました。', null, '時間帯: その他'),
  ('2d21ba55-cf82-5099-b7ec-f1e75c0d4387', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2024-08-31', null, null, '通常 / U16作成', '作品の完成度を上げてきているようで、ゆき先生にアプリの出来栄えを見せてフィードバックをもらうなどしていました。アプリ内容を修正するためjavascriptやHTMLのコードを書き足すなどしていました。', null, '時間帯: その他'),
  ('5a89a33b-0f41-558b-af49-b2423ff91f92', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-31', null, null, '通常 / 変数の特別な使い方', '変数について前回のテーマを復習してから、続きに取り組みました。お手本のゲームを再び見せて「むらっちの今の向きに合わせてボールが違う動きをする」ということに気付かせると、今回やるべきことの流れがつかめたようでモチベーションが上がっていました。変数の使い方自体はすぐわかったようで、それに合わせてボールを飛ばす方法をじっくり考えていました。ただ、「□座標を〇ずつ変える」というブロックを何回も使うので、プラスマイナスを間違えて、数字をあてずっぽうに変えたりしていました。そこで左右の向きごとに動きを書いて整理すると、きちんと考えたうえで完成できました。', null, '時間帯: その他'),
  ('82dfeda1-1bda-5bf3-84d9-9007300d4869', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-31', null, null, '通常 / 検定問題完成', '検定問題の続きを一緒に進めました。今からやる部分の問題文を読むように促すと音読してくれたのですが、一気にたくさん読んでいたので、①,②,...などの〇ごとに区切って把握してもらうようにしました。そうすることで細分化と集中力維持ができました。不等号や「止める」ブロックなど基礎知識はすでに頭に入っているようでした。ブロックをどこに入れるかなどの組み立て方についてヒントを出すことで、構造を考えて作成を進められました。ちょうど約束の30分が経ったところで完成しました。', null, '時間帯: その他
盛り上がり: 今回作ったゲームの内容がお気に入りだっただけに、完成したことに達成感を感じて喜んでいました。'),
  ('fc15aaf2-aff2-5042-aa26-be56bd949d3f', '28d52d6e-7571-5090-a2d9-492c997b719e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-31', null, null, '通常 / 検定練習', '今回も検定4級の練習を行いました。「以下の動作を行う」という形式の文が初めてで「以下」が何かわからなかったようですが、下に書いてある箇条書きのことだと伝えるとすぐに理解しました。その部分以外はほとんど自走できて、答え合わせしても完璧でした。時間が余ったので次の問題をやってもらおうとしましたが、前半でよく集中していただけに「これ以上はやる気が出ない」という反応だったため、途中で取りやめて自由時間にしました。', null, '時間帯: その他'),
  ('24d904ec-dfae-5ca7-af9c-f7101fe220eb', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-08-31', null, null, '通常 / リストの応用', '前回まで扱ってきたリストをもっと実用的な場面で活用する練習のため、スコアの履歴をリストで残すゲームの作成に取り組みました。リスト内容の追加や消去の部分をはじめ、ボタンが押されたかどうかを保持する変数など、重要なポイントは理解を確認しながら進めました。動画のとおりにコードを作成しましたが、途中でテストプレイして動きがおかしい所があったためデバッグを一緒に行いました。バグの内容から怪しいコードを絞り込むことや、繰り返しの範囲が間違っていないか確かめることなどを勧めると、無事に正しく動作するようになりました。動画の中盤まで終わりました。', null, '時間帯: その他
盛り上がり: prgの動画を別のパソコンで見ながらの作成でしたが、2つのパソコンを両手で器用に操作していました。'),
  ('edea263f-d411-56de-9828-2c1aaf7538d7', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-06', '16:30:00', null, '通常 / 背景スクロール会得しよう', '最初に、復習として、放物ジャンプを見直しました。前回では、変数の繰り返す条件が定まっていなかったので、その条件について説明していきました。演算的な概念は難しいものの最初に決めた値のマイナスの時であると理解できていました。 次に、背景スクロールを作っていきました。ざっと最初に、仕組み説明すると、自分の手で動かして、メッセージのやり取りをできていたので、スムーズに完成できました。 その流れの中で、足場に乗れるジャンプを作りたいのことでした。即興ではうまく対応できずに、次回にやろうとその場では流してしまいました。その間は、自由に他に作れていたので、止まるということはなかったです。', '足場に乗るジャンプ ゆづきくんの作品のコードを参考にしてください', 'タイピング: よくやっていました'),
  ('6836a789-e5a1-59f7-804b-0866f67667fd', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-06', '17:30:00', null, '通常 / 足場に乗るジャンプを作ろう', '足場に乗るジャンプをともに作っていきました。手元に実例がなく、なるべく形を変えないようにその場で考えていきました。その合間に、放物ジャンプの復習をしたが、いまいちどこまで変数を減らしていけばいいか理解はできていませんでした。そこに、足場に乗るためのジャンプを組み合わせるコードはとりあえず作ったが、ゆづきくん自身にもかなり難色な顔をしていました。算数が苦手だと、変数の段階的に減っていくことの理解が中結びつかない感じが出ていました。次回もかなり福州から入った方がいいと思います。', null, '備考: コードは出来上がっているので、りょうまくんのときには参考にしてください'),
  ('f1b963ac-31e4-5196-bceb-7fd5e03be39b', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-06', null, null, '通常 / バレーボールで変数の使い方を確認', '前回の復習をした後、変数の使い方をいくつか紹介してバレーボールに取り組みました。まずボールを落とすところからつまずき、座標の大小と乱数について確認しました。乱数についてはほぼ覚えていない様子だったので、次回確認した方がいいかもしれません。またキャッチゲームの進行度を確認したのですが、途中で終わっていたようです。 その後、むらっちを左右に動かすところは自分でプログラムできました。レシーブは時間の都合でまだです。 変数よりも、座標と乱数の復習をした方がいいかもしれません。', null, '時間帯: その他
タイピング: 集中して取り組めました。
盛り上がり: 日曜日にお母さんと2人で遊びにいくようです。そわそわしていました。'),
  ('84a7ee83-e444-5af3-b6b7-83e8a254b67c', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-06', null, null, '通常 / オリジナル作品（U16大会） ストーリー作成など。深める。', '敵に攻撃が当たったときのエフェクトを作成していました。プログラム的にも難しいところがあったようですが、最終的にはうまく作成できたようです。ステージの大きさを変えることにしたようです。 ストーリー設定について前半何度か声をかけたのですが、プログラムの方に夢中で伝わったかどうかが不安です。', null, '時間帯: その他'),
  ('39f15590-053d-533f-8167-a74f1ebfebae', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-06', '17:30:00', null, '通常 / オリジナル作品', '自分なりに取り組めました。作品の完成度と付け加えた方がよい要素（スプライトの説明、ストーリー）についてアドバイスをしました。バッテリーがあるそうなのですが、どのように減るのか説明がなかったり、いまどのような場面なのかが分からないので説明が必要かなと感じました。 またストーリーについては終わりがないので、目指す先を意識してもらう必要がありそうです。（書類提出の期日までに考えないと！！）', null, 'タイピング: 集中して取り組めました。'),
  ('d1a920af-be63-50e1-a84e-52fa47c10106', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-06', '17:30:00', null, '通常 / Prg/まゆげネコ', '「くそゲーにはクローンが必要！！」とのことで、クローンの使い方をまゆげネコで作成しました 自分のオリジナルで、クローンを作成できうまくプログラムができていましたが、親分→子分の考え方が薄く、クローンしたものが自分で動けないような状態だったので、再度説明しました。「クローンが作られたとき」のブロックの使い方を確認しました。その後、プログラムの大枠は自分で作成することができました。制限時間のプログラムで少し困っていたので、プログラムの実行順序に気を付けるようにアドバイスをしながら取り組むように伝えました。 楽しいプログラムを作れたようです！最後に公開しました！', null, 'タイピング: 集中して取り組めました。'),
  ('48b33d34-52e1-518c-bfca-18b83011072d', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2024-09-06', '17:30:00', null, '通常 / 検定もう一度集中してやろう', 'ゆき先生と話して、景帝のやる意味を今一度確認しました。そのあとは、かなり集中して取り組めていました。気になるところも、答えになるところあったが聞けていて、うまく進めていました。時間が終わった時には、少しはバグはありつつも8割くらいできていました。', null, 'タイピング: いろんな機能を見つけていました'),
  ('6d03616e-b552-534c-8d63-6711c59acdc3', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-06', '16:30:00', null, '通常 / 変数の使い方ハコ編~Prgタコ~', '前回作っていた花火のプログラムで変数を使っていたので、さらに他の作品でも振り返りながら変数の使い方を確認しました。 授業中他のことに意識が飛んでいる時間もあったのですが、タコの作り方の説明の紙を見ながら、変数のリセット、使い方について解説しました。プログラムを遊んだときに、変数を使っていそうなポイントはある程度絞り込めていたので良かったです。最初、レベルを選ぶボタンのプログラムも「同じように」の言葉に注意するように伝えましたが、自分なりに考えて完成できました。 まだ作成途中なので次回続きです。', null, 'タイピング: 集中して取り組めました。
盛り上がり: タコ続き'),
  ('123cac72-4bc0-5ce6-905c-35025ed5e2f3', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-06', '18:40:00', null, '通常 / 座標と触れる判定の感覚をつかもう', '最初に遊んでもらい、ここでアレンジしたいアイデアがあふれていました。今回は抑えてもらって、まずは基本の上下左右の動きを作いきました。座標の感覚は、まだすぐには出てきてないので、じっくり考ってえれば出てくる程度なので、ここはできるまで確認はした方がよさそうです。星に触れる判定は、前回で触れるの判定を使っていたから、覚えているかと思ったが、全く覚えていませんでした。そこで、前回の作品に戻って、どのコードが使われていたか確認して、こちら側は直接的なコードの指示はせずに作れました。 少し眠たい様子があったので、ゆっくり進みはんぶんくらいまではつくれました', '追跡ゲームの「スコアをつけよう」から', 'タイピング: まだ、キーがわからずも必死に取り組んでいました。'),
  ('4b46dc01-61fe-582c-809a-0aadae290d3e', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-08', '16:30:00', null, '通常 / 検定問題答え合わせ 【Prg】10 レースゲームを作ろう', '前回挑戦した検定問題に関しては、問題文をよく読んでいなくて抜けている箇所が目立っていたため、もったいない点数の落とし方をしていました。そして、制限時間内に解き終えることができていなかったようで、1つのスプライトが手付かずの状態で終わっていました。なので、問題をしっかりと読むことで点数を落とさないように気をつけて挑戦していくことが必要だと感じました。レースゲームでは、手順通りに作成を行なっていき、車のデザイン変更や背景の変更など、自分のやりたいことを随時取り入れていきたい様子でした。', null, '盛り上がり: レースゲームにて自分のやりたいこともできていたようで喜んでいました。'),
  ('3d54efe5-c165-5b1d-bf2f-c9d3c92af5b0', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-08', '16:30:00', null, '通常 / ドリル２', '今回は小さな問題が複数あるドリルに挑戦していきました。今までに取り扱ったことのある問題も多く出ており、難易度としてはそれほど高いものではありませんでしたが、本人の集中力が切れてしまうことが多く思っていたほど進めることができませんでした。原因として、自分のやりたいことができていないことや一度躓くと思考を放棄してしまう癖があるようなので、本人のやりたいことの中に新たな技術を取り入れてくことでさらに集中することができると感じました。', null, 'タイピング: 順調に進めていくことができていました。'),
  ('d79e040f-cb4b-5756-9f9d-90dd1e6b0ebd', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-08', '17:30:00', null, '通常 / 【Prg】10 レースゲームを作ろうの続き', '前回の続きから取り組んでいきました。クリックを押し続けるとずっと車が加速してしまう状態だったので、ではないまで待つのブロックを使って解決していきました。これを使ったところ本人はかなり興味を示していたので、今後のオリジナル作品やアレンジで使ってくれると思います。それ以外の部分としては、車のルートがUターンをするようなっていたためゴールを近づけることで解決していました。自分自身で解決をすることができたため、喜んでいました。', null, 'タイピング: 集中して取り組むことができていました。'),
  ('4fff82a5-cf5c-595b-963e-28ec79b6765a', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-08', '17:30:00', null, '通常 / 単元F「条件分岐」', '条件分岐について復習を行なっていきました。内容自体は覚えているようでしたが、細かい箇所に曖昧な部分が多く見られたため、何となく覚えているというものが多い様子でした。そして、イマイチ集中することができていないのか反応があまりなかったり何処か上の空である様子も見受けられました。なので、本人のやりたいことを一度やらせてから再度復習などに入っていくと良い結果を出せるようになるかもしれません。', null, 'タイピング: 真剣に取り組むことができていました。'),
  ('6de9cafc-b554-53ee-a85a-978b01afbc95', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '694bc25a-68e7-599d-9514-5e7539918db8', '2024-08-22', '17:30:00', null, '通常 / 教室に慣れる', 'スクラッチは、家で、たまうちゲームみたいのを作っていたので、座標の感覚はしっかりしていました。何も言わなくても、旗を押したら、初期位置のコードを作れていました。名前を動かすの範囲で、開店と顔と、色、大きさの表現を使いみて、あまり使った来ていなかったので、興味をひかれていました。見本を見せたら、その通り作るしっかりまじめなタイプです。 続いて、ジャンプを使ったゲームを今後作ってみたいのことだったので、重力のあるジャンプを見せてあげました。すごいと、驚いてくれました。その流れ、追跡ゲームを作りました。その最中は、自分で考える指示を与えても、しっかりといやにならず、考えてくれました。よくありがちな「もし」に図っとをつけ忘れるミスはあったものの、スムーズに進められら増した。ただ、変数や演算は今まで使ってこなかったので、一緒に教えてあげました。この辺は、今は知らないだけなので、身につけば、自由に使えそうになると思います。', null, '盛り上がり: 終わった後はかなり満足気でした。普段は、スイッチで弟妹と舞倉をやっているそうです。冒険より、楽しんでいるそうです。'),
  ('2ac8ced7-75b3-52f7-a37f-03dd412edf6e', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-09', '16:30:00', null, '通常 / ドリル１', '前回ドリルの問題５まで完成させていたので、続きから取り組んでいきました。問題に対しての理解が高く、途中で止まることなくスラスラと解き続けていくことができました。さらに、前の問題で学習したことの応用についても自分自身で気づくことができており、時間に余裕を持って終わらせることができました。残りの時間で追加するコスチュームの作成を行なっていき、本人の作りたいものを作り上げることができたようです。', null, 'タイピング: 集中して取り組めていました。'),
  ('db3881df-c5f4-57e2-b27f-4132d110c869', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-09', '17:30:00', null, '通常 / 追跡ゲーム（チーズ）の続き', '前回までに作っていた追跡ゲームの続きから作成をしていきました。乱数部分について曖昧な部分が多かったようなので、復習も兼ねて一緒に作っていきました。サイコロの乱数を見せながらどういった意図で使われているのかを理解しながら作っていくことで、作品ではどのような働きをするのかをしっかりと理解しながら完成まで持っていくことができていました。アレンジでは、キャラクターの大きさや速さを変えていくことでより面白いものへと作り替えることに成功していました。', null, 'タイピング: しっかりと取り組むことができていました。'),
  ('6730da8c-c81a-5e6f-8a55-6b9278f9f3b2', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-09', '16:30:00', null, '通常 / オリジナル作品続き', '大会に出すコメントは自分で考えたいそうです。教室ではプログラミングをしたい様子。次回、大会に出すコメントを考えるポイントをいくつか共有するだけで大丈夫かな？と思います。 プログラムもほぼ仕上がってきました！くまさんのイラストがきれいに作成できるようになっています！！すごい！！一方で見えてほしくない矢印が表示されてしまう不具合がありました。作品の流れで説明がつくミスですが、本人的にも修正したいそうです。変数の不具合だと思うので次回確認します。', null, 'タイピング: 集中して取り組めました。'),
  ('0db53cfc-ebe9-533b-83c7-6e4708cbd29e', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-09', '17:30:00', null, '通常 / 【Prg】32 タコから逃げろゲームを作ろう！', '今回はプレイグラムのタコを作成していきました。指示書があったため、作成は非常にスムーズに行なっていくことができていました。難易度の変更方法や、スピードアップの際の値についてもしっかりと理解することができ、作品に対しての理解は高く終えることができました。しかし、バイクランをやりたいからなのかアレンジについてはかなり消極的になっており、あくまで課題をやるのみにとどまってしまっていたため、やる気の面において課題が残っているかもしれません。', null, 'タイピング: 間違わないように慎重に取り組んでいました。'),
  ('d4a06e14-08bf-5a9b-9b81-0d80a428adc0', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-09', '16:30:00', null, '振替 / 追跡ゲームアレンジ。乱数の紹介', '前回の復習（プログラムを説明してもらいました）のあと、追跡ゲームアレンジを進めました。「アレンジ」についても説明しました。本人の希望でBGMを付け加えました。他に思い浮かばない様子だったので、障害物の提案をしました。色判定を使ってプログラムを自分で作成できました。障害物やネコのサイズ、色判定の仕組みを使ってひっかけを作ることで、かなり高難易度のゲームができました。楽しそうで良かったです。 乱数を紹介しました（なんとなく知っている様子でした）。次回、さいころのレッスンからです。', null, 'タイピング: 集中して取り組めました。うでだめしは長くて大変そうでした。'),
  ('eec085a7-4b00-5f54-a4c8-4ae29dd66c12', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-09', '17:30:00', null, '通常 / Prg 51 ネコのたてスクロール作品', '本人が「やりたい！！」と言っていたのですが、いざ始めてみると難しかったようです。学校も始まりかなり眠い様子でした。たてスクロールの仕組みだけ、変数とメッセージを追いながら一緒に確認しました。内容的にも重かった様子なので、次回やるのは難しそうです。 まゆねこを進めてみると少し興味をもったようでした。来週作りたいなと思っています（クローンいろんなことに使えるので）', null, 'タイピング: 集中して取り組めました。'),
  ('86edc3ae-123e-559c-b9b2-e698c1fef9e6', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-09', '17:30:00', null, '通常 / さあ踊ろう（メッセージ）', 'コスチュームを変えるのは全く問題なく取り組めました。初期位置の設定も、こちらが言わずとも自分で最初からできていました。すごい！！メッセージの使い方は丁寧に伝えました。また制御のブロックが増えたときに、ブロックを置く場所に注意するように助言しました。その後、色や幽霊の効果のブロックでアレンジを加えました。いろいろ試せて楽しかったようです。 最後にイラストの話もできてうれしそうでした！！', null, 'タイピング: 集中して取り組めました。'),
  ('2043277b-c606-5c0e-95c9-65dc982ec59a', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-09', '17:30:00', null, '通常 / オリジナル作品制作', 'しばらく作成している電車の運転席部分などの続きを作っていきました。本人としては、運転席がしっかりと動くようになれば完成のようなので、Scratchにある見本などを見て着実に完成へと近づいているようです。今回は音の部分を調整していたようで、さまざまな部分にこだわりを見せています。そして、そういった細部までこだわっていることを褒めたところ、嬉しそうにしていました。', null, 'タイピング: 完璧にやり遂げていました。'),
  ('f9a965f8-6941-581c-b64c-a23552fe1c57', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2024-09-10', '16:30:00', null, '通常', '２回目の検定。文章読むのは慣れた様子。「このスクリプト以外をとめる」の個所でつまったこと以外は手が止まることなく進めていました。 終わったと言ったあとに、動画をもう一回見てみると、スプライトが最後に消えていることに気づき、修正。テスト本番の時は、少し早く終わったら動画をもう一度う見直そうねと伝えました。音を加えるアレンジも加えました。', '１１月の検定があることを伝えた。隔週なので、検定までに残り４回しかないので、毎回類問やるのもいいね、という様子でした。', 'タイピング: っつ、った、など小さい「つ」の練習。
盛り上がり: 止めるブロックに３種類あること、「このスクリプト以外」にした時だけブロックをつなげられることを形の違いで確認すると、「これだと、間に入れられるんだ～～！」とものすごい納得していました。'),
  ('989e3f49-5cb0-53b3-a00e-6c2b46483dae', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2024-09-10', '16:30:00', null, '通常 / 基礎コードの復習', '基礎を振り替えるために、久しぶりに「エラーで学ぶ」を使いました。条件分岐の34～37まで。シンプルな問題ながら、基礎的なコードの使い方を問われるので、なかなな苦戦しました。 逆に、ちょっとした条件分岐や演算の使い方の確認になってよかったです。 最後、ペンツールの42は全くお手上げ？ペンツールを使ったことがなかったようです。', null, 'タイピング: タイピングコンテストがあると言うと、結構ノリ気の雰囲気でした。
盛り上がり: 最初に「今日は、クイズ系やるよ～～～」というと、めっちゃ最初は喜んでいました。１問完結なので、集中して取り組めていました。'),
  ('d0e0f26a-d4bf-56c8-b9c0-e9fe1fca12ae', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-10', '16:30:00', null, '通常 / 【Prg】51 どこまでいける？ネコのお散歩ゲーム続き', '前回少し始めていたお散歩ゲームの続きを作成していきました。縦スクロールについてを中心に学んでいきましたが、以前に学習した横スクロールの応用だということに気づいたため、すぐに内容を理解することができていました。猫などのコードについても、説明した内容をしっかりと理解できていたようで、どういった動きをしていくのかをしっかりと説明することができていました。岩とエサのコードが未完成のため、次回で完成させていきたいです。', null, 'タイピング: 集中して取り組むことができていました。'),
  ('c0b7797b-430d-5b19-9ecb-0c3b935a5c7a', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-10', '16:30:00', null, '通常 / シューティングゲーム「火星防衛軍Nodack」', '今回は、シューティングゲームの作成に挑戦していきました。自分の動かすキャラクターや敵キャラクターが、それぞれどのような動き方をしているのかを確認しながら作成していきました。動き方については、座標やクローンなどやったことのあるものが多いためサクサクと作っていくことができました。しかし、長いコードを見るとやる気をなくしてしまうようなので、そういったコードを作る前に内容がどのようなものかをしっかりと説明すると良いと感じました。', null, 'タイピング: かなり速くタイピングを行うことができていました。'),
  ('3e6140eb-5a0c-50eb-8730-87f9bf3d8843', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-11', null, null, '通常 / 【Prg】32 タコから逃げろゲームを作ろう！', '今回は手順書を見ながらタコから逃げろゲームを作成していきました。難易度の変更を変数で指定していることをしっかりと把握して作ることができていました。使用しているブロックが少し多いため、イマイチ気が進まないようでしたが指示書を見ながら一つずつ理解していくことで、作品の動きを把握してからはスラスラと作っていました。今回で難易度部分は完成することができたため、次回でダイバーとタコのコードを完成させていきたいです。', null, '時間帯: その他'),
  ('28d87379-ec19-5c4e-be96-0eefbcaec102', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-11', null, null, '通常 / 【Prg】32 タコから逃げろゲームを作ろう！', '前回少し始めていたタコの続きを作っていきました。ダイバーとタコの変数で水上に上がるためのボタン操作にて変化する変数をしっかりと把握して作ることができていました。さらに、スラスラと進めていけたことで少し時間が余ったためアレンジも行っていきました。この作品でどのような動き方をするのかをしっかりと確認できていたようです。', null, '時間帯: その他'),
  ('54817103-e609-5e68-a250-40673ac63439', '57f45872-1f3e-5540-b676-bf9023444e39', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-09-05', '16:30:00', null, '通常 / 検定練習', '前回戸惑った検定に慣れるべく今回も練習しました。文を読むこと自体はできていますが、繰り返しなどやや複雑な構造を必要とする部分になるとどうすればいいかわからず詰まっていました。そこで、「なんのブロックが必要か」と「それらをどう組み合わせるか」を分割して問いかけることで、考え方がだんだんわかってきたようでした。じっくり考えて進め、全体の7割くらい終わりました。', null, '盛り上がり: できた部分については「俺天才じゃね！？」などと言って楽しんで取り組んでいました。'),
  ('3edbd20b-57d5-501d-83f6-53389dc34736', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-09-05', '16:30:00', null, '通常 / 変数の使い方', '手順書を見ながらレースゲームに取り組みました。入力したセリフが適当だったりとモチベーションはそこまで高くないようにも見えましたが、スピード変数の使い方をポイントとして確認するとそれは理解したようでした。スピードアップの処理にバグがあるので、コードを見なおさせたうえで、まだやっていないゴール判定に着手したいところです。', null, null),
  ('a3beb0fe-6f7f-55dd-aad1-eb9f9af15a44', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-09-05', '17:30:00', null, '通常 / U16作成など', '検定が無事に終わったので、U16のテトリスでも気楽に作っていこうと伝えると序盤はそうしていました。ただ、自分のファイルを眺めていて、過去に検定2級の練習問題を解いたときに間違い直しが終わっていない問題があることに気付くと、自主的にその直しに取り組み始めました。もう本番には関係ないので、ある意味これも気楽にできたのだと思います。以前の自分にはわからなかったことがわかるようになっていて嬉しそうな様子でした。', null, 'タイピング: 99点で悔しがっていました'),
  ('684f3082-fb14-517e-801d-0b1c7243e1dc', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-09-05', '17:30:00', null, '通常 / 追跡ゲーム完成', '追跡ゲームの続きに取り組みました。クリアの判定が未作成だったので最初にやりました。等号のブロックは初めて使うようなので説明しましたが、「もしスコアが〇点なら」というコードを作れればいいことは理解できていたのでほぼ自力でできました。余裕がありそうだったので影武者を紹介して作ってもらいました。「隠す」と「ゆうれい」の違いだけ説明すると仕組みを素早く飲み込めていました。背景の青色部分に触れたらゲームオーバーにするなど、自分で考えて応用の効いたアレンジもできていました。', null, 'タイピング: 慣れない文字も頑張って打っていました'),
  ('c0402d95-a48c-54c5-8300-9c314aacfe7b', '28d52d6e-7571-5090-a2d9-492c997b719e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-09-07', null, null, '通常 / ドリル', '検定の延長でドリルに取り組みました。「～度に向ける」と「～度回す」を一度間違えていましたがその後はきちんと意識して使い分けできていました。指示があまり直接的でない部分も、自分で考えながらやることができるようになってきてきました。問題数が多いことを逆手にとって「3問解くごとにアメ1個を食べる」と決めることでモチベーションも保って進められました。', null, '時間帯: その他'),
  ('65b7937c-f427-5d87-a7fc-c36ae9761a19', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-09-07', null, null, '通常 / ドリル', '文章を読んで一人で作る練習を、検定とは違うアプローチで行うためドリルに取り組みました。問題が細かく分割されているのと、最初の方はあまり難しいブロックも登場しなかったので集中して作ることができました。少し難しくなってくるとブロックを配置する順番を間違えたりしたので、本人の作ったものがお手本の動きと違うことを確認してもらいました。そして、「プログラミングは順番が大事だから番号順に見て作ろう」と伝えると、きちんと修正できました。「ここまで終わったらいったん休憩していい？」と申し出て、集中力の管理もできていました。', null, '時間帯: その他'),
  ('07111a48-7288-5d06-aa90-b512a20330b1', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-09-07', null, null, '通常 / ドリル', '自分で文章を読んで作る練習のためドリルに取り組みました。最初の方はお手本の動きも見ずにできました。途中、ネコの向きを毎回手動で戻さないといけない状態で完成だと言い張っていましたが、ブロックをきちんと使う練習でもあると説得するとわかってくれたようでした。ブロックを置く順番などの基礎はしっかり理解していました。30分間頑張ることができました。', null, '時間帯: その他'),
  ('28c99347-41d2-5157-9549-4b814d3cbcfc', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-09-07', null, null, '通常 / U16作成', '今回もU16の作成を進めました。全体像は十分見えているので、個々の部分の作成を進めていました。何種類も用意された武器のそれぞれに説明をつけたり、ガチャを引くときの映像的な演出をつけたりと丁寧に作りこんでいました。テストプレイを定期的に行ってバグもつぶしながら作成を進めました。', null, '時間帯: その他'),
  ('551df5c3-141f-51a2-bc58-81d2a14fcf8c', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-07', null, null, '通常 / ファイルを埋めるーー世界を創造しよう、物語をつくろう', '座標についての理解が浅いように感じたので、数字の大小も含めて丁寧に説明しました。過去に使っているブロック（～という、など）をいくつか忘れているようだったので、よい復習の機会になったと思います。また座標についての理解は浅いのですが、初期位置の設定の仕方はパターンとして覚えているようで、毎回自分から進んでプログラムできていました。すごい！！', null, '時間帯: その他
タイピング: 集中して取り組めていました。'),
  ('4efdc4fa-36de-51e7-bc0a-c58ed470098a', '0047fb11-a84a-5592-8c39-5a16c20eb10e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-07', null, null, '通常 / プラットフォーム ージャンプ（等速、放物）', '等速ジャンプについては全て自分で取り組めました。変数の使い方も、少し解説するとすんなり理解できたようでした。 放物ジャンプについては方眼紙を使って解説したあと、実際にプログラムを考えてもらって見本と見比べました。かなり惜しい線までできていました。「何回ジャンプする必要があるのか」を考えて設定するところが難しかったようです。最後に自分が過去に作った作品を見せてもらいました。とてもよくできているので、教室で共有したいなと思っています。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('05604644-8370-5733-aea3-f65ff9380971', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-12', '16:30:00', null, '通常 / 大会作品制作', 'アプリケーションとしての内容はほとんど完成したため、AndroidやiOSで動作が異なってしまう部分を修正していきました。OSの違いで動作が異なっているため、修正の方向ではなく作品提出としては片方のOSで動かすものとしての提出をすることに決めました。機能としても、見直していきたい部分がいくつかあるようなので9月末の提出までに資料作成と並行して進めていく予定です。', null, null),
  ('5831f25e-bd16-5321-8717-93b7d510077e', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-12', '17:30:00', null, '通常 / ドリル２', 'ドリルの問題では、今までにやったことのあるスキルが多く記載されていたため、順調に進めていくことができていました。しかし、ペンツールに関しては初めて触るようで新しい技術に驚いていました。特に丸を描く問題では、どのようにして描くことができるのかを悩んでいました。内容を解説したところ、しっかりと納得してもらい発展問題である二重丸を各問題では自力で解き切ることができていました。今回で問題を全て終えることができたため、とても喜んでいました。', null, 'タイピング: 集中して取り組めていました。'),
  ('6eb84358-35ef-5e6b-8613-39a13848f71b', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-12', '17:30:00', null, '通常 / 【Prg】49 ジャンプゲーム＿演算＿リスト機能で記録を残す', '今回はリスト機能を活用した作品を作っていきました。リストの仕組みや使い方については把握することができていたため、順調に進めていくことができました。リストをどのようにして活用していくのかもこの作品を通して確認できた様子でした。前回からの続きであったため作品をしっかりと完成させることでき、本人も達成感を感じていました。', null, null),
  ('ef0de2f0-adaa-57a7-9c06-120bc981017c', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-12', '16:30:00', null, '通常 / 【Prg】10 レースゲームを作ろう！続き', '前回からの続きでゴール部分や判定についてを修正していきました。自分と敵キャラクターのゴール判定がうまくいっていなかったようなので、コースのルートやゴール地点の位置などを見直していました。その他にもキャラクターが線を踏んだかどうかの判定が間違っていたようなので、一緒に修正をしていきました。完成してからはアレンジを行っていきました。エラーで学ぶについては来週から取り掛かっていく予定です。', 'エラーで学ぶ', null),
  ('29fca462-9991-56b9-989d-289e64f22252', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-12', '16:30:00', null, '通常 / ドリル２続き', '前回ドリルの問題16で終わっていたため、その続きから作っていきました。キャラクターをどのような動きをしているのかを重点的に見ながら作っていき、一つ一つ進めていくことができていました。時々集中力が切れてしまうことがあるものの、注意すれば再び作成に取り掛かっていたため以前よりは良くなっていると感じました。最終的には図形以外の部分を全て完成させることができたため、とても喜んでいました。', null, 'タイピング: 完璧にできていましたが、少し簡単すぎるため次回からはプレイグラムに移行していきたいです。'),
  ('efecc95c-a7a9-5b77-bb8c-3cdc5f4b3e92', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-12', '16:30:00', null, '振替 / ドリル1', '回転と動きの復習をしました。見本のプログラムが用意されていないこともあり、後半は特に文章を読んで挑戦しました。「～歩うごく」のプログラムは問題なくできていますが、角度の概念が少し難しいようです。設定の仕方も忘れかけていたので、丁寧に確認しながら進めました。 楽しく取り組めたようです。', null, 'タイピング: 集中して取り組めました。'),
  ('9f41b2e4-ba18-5846-8c8e-fd68e44e98ab', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-12', '17:30:00', null, '通常 / U16大会オリジナル作品', '逆転裁判のような作品を作るようです。今日は最初のニュースの場面（オープニング）を作成しました。文字を1つずつ出すようなプログラム（定義）を作って進めていました。スクリーンを背景とするか、スプライトとして作るのかの判断が難しかったようです。締め切り日を確認して、意外と時間がないことに気が付いてもらいました。間に合わせてほしいです。', null, 'タイピング: 集中して取り組めました。'),
  ('b5003061-44be-5062-8be3-0bd602f45a4e', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-12', '17:30:00', null, '通常 / レベル2問題13~18', '円の形に動かす：回転はできたのですが、回転させながら動かすということが思いつかなかったようです。初期位置や初期のコスチュームの設定をこちらが言わずともできていたので素晴らしかったです。キー入力、クリックでスプライトを動かすのもスムーズにできました。「動きながら大きさを変える」のが思いつかず難しかったようですが、一度理解した後は数字をかえたりして工夫していました。', null, 'タイピング: 集中して取り組めました。'),
  ('bcc1d28e-464a-5666-9f8c-c1ddc5515eb7', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-12', '16:30:00', null, '通常 / レースゲーム続き', '前回まだ途中だったようで、最後まで作りたい様子だったので続きをしました。敵の動きのプログラムを中心に作成していました。ゴールの判定がきちんと動かず困っていたので、作り方を見直しました。制御のプログラムミスだったので、スムーズに発見できました。 最後に変数の使い方の解説をしました。バレーボールのゲームで遊んでもらったのですが、少しプレイが難しかったようです。', null, 'タイピング: 集中して取り組めました。'),
  ('4927968c-7b06-5107-b96b-696f966c4d01', '57f45872-1f3e-5540-b676-bf9023444e39', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-09-12', '16:30:00', null, '通常 / 基礎力をつける', '検定の途中だったので、軽く振り返ってから続きをやりました。よく知っているブロックを先に配置してしまう癖があったので、「プログラミングは順番が大事だから上から一つずつ作ろう」と声を掛けました。やっぱり検定は難しいという印象はあるようですが頑張って最後までたどり着きました。検定が完成して動作確認したあとドリルに移行しました。他の子との兼ね合いで高めのレベル3に取り組みましたが、難しすぎるほどでもなく頑張れました。「端に触れたら跳ね返る」ブロックは最初の方に扱ってから間が空いたので忘れていましたが、ヒントを出すとすぐに思い出しました。「操作できるゲームの方が作りたかった」と言いつつも最終的にはきちんと取り組めました。', null, '盛り上がり: 最近りょうやくんやるいくんと仲がいいです'),
  ('d009a739-fd9b-597d-a6e6-536afe4a6853', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-09-12', '17:30:00', null, '通常 / 基礎力を身に着ける', '基礎力を定着させるためとしてドリルに取り組みました。ブロックの順番が前後することがあってそこは直してもらいましたが、基本的には自力で文を読んで作成できていました。角度ブロックの「向ける」と「回す」を使い分けることができていました。最初に6問を目標にしようと伝えたのがよかったのか、集中力を保ってちょうど6問解き切りました。', null, 'タイピング: タイピングにも慣れてきた様子です'),
  ('483d6b4f-8f6b-5920-abc0-085e6dde5ba6', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-09-12', '17:30:00', null, '通常 / 乱数を学ぶ', '最初はレッスンでサイコロをやりましたが、乱数の概念はすぐに理解できたようでした。この乱数を応用するゲームとしてチーズを探せに入りました。座標ではなく「〇歩動かす」でネズミの位置を変えるということだけ伝えると、壁に当たった時に-10歩動かすことも自分で思いつけていました。今まで「□座標を〇ずつ変える」は使ってきたようでしたが、x座標とy座標で位置を指定するのは初めてだったので教えました。x座標とy座標の違いはすでに覚えていたので納得してくれて、それぞれの座標を乱数にすればいいことも理解しました。ゆうれいや虫の動きやスコアも作れて、今までやった内容の応用が効いていました。', null, 'タイピング: 楽しくやっていました
盛り上がり: しっかり考えようとしてくれています'),
  ('5909ddcb-ce8a-5386-a3e0-a2a051aa31db', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-13', '16:30:00', null, '通常 / 【Prg】32 タコから逃げろゲームを作ろう！続き', '前回作成していたタコのゲームの続きを作成していきました。残りはタコの部分のみだったためサクサクと作り終えたところで、バグ直しの作業に入っていきました。難易度設定にて変数を使うということがイマイチ理解できていなかった様子なので、変数部分について説明しながらデバッグを行なっていきました。時間が余ったため、この作品のアレンジも行っていきました。難易度はどの変数が管理しているのか、どこを変えればゲームとして面白くなるのかを考えながらアレンジを行なっていました。', null, 'タイピング: 素早く打つことができていました。'),
  ('a5ed946b-2136-5ac9-bbe6-a9193816d139', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-13', '17:30:00', null, '通常 / オリジナルゲーム作成', '今回はゲームを作りたいとのことだったので、オリジナルゲームの作成を行なっていきました。火星防衛軍については、イマイチ刺さらなかったのかプレイはしていましたが作りたくはないとのことでした。オリジナルゲームでは対戦型のシューティングゲームを作っていくようで、キャラクター同時を向き合わせて互いに弾を発射していくものでした。弾ごとに特徴を持たせたいようで、どんな動きをするのが面白いかを模索しながら作成をしていました。', null, 'タイピング: 集中して取り組めていました。'),
  ('ac75da5d-6bc1-5b35-8321-779d7458e1b5', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-13', '17:30:00', null, '通常 / U16大会作品制作', '今回の大会作品制作では、キャラクターがギミックを解いていく際にどのような謎や仕掛けが作動するのかを考え、実装していきました。会話やアイテムの名前が英語のため、翻訳などを駆使しながらどういう配置がいいのかを相談しながら作品の品質を高めていました。難易度調整もそのうちしていきたいとのことだったので、さらにこだわっていく部分も出てきそうです。イメージが曖昧な状態で作成している箇所もあるため、そういった部分をどう修正していくのかが課題になってくるかもしれません。', null, null),
  ('ea5fed7c-0bde-5de4-8fd6-7696b38bf7f5', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-13', '18:40:00', null, '通常 / 【Prg】ボールキャッチ続き 【達人01】ゲームの基本 座標マスター', '前回の続きでボールキャッチの完成していない部分を作っていきました。ボールがなぜこのような跳ね方をするのかがイマイチ理解することができていない様子だったので、作品を完成させてから座標マスターを作っていきました。座標マスターはスラスラと完成させることができたため、ここにアレンジを加えて座標をいじってどのような動きをするのかを確認していきました。キャラクターや新たに加えたスプライトの規則性について実際に数値を見ながら理解することができていました。', null, 'タイピング: 集中して取り組んでいました。'),
  ('73801997-ee11-5897-8661-e7a1591551b3', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-13', '18:40:00', null, '通常 / U16大会作品制作', '今回は、作品にはどのようなコンセプトがあるのかを考えながら制作を行なっていきました。本人としてはスマブラをオマージュしたような作品であるとのことなので、格闘ゲームやアクションゲームの要素を取り入れたみんなが楽しめる作品を作ることを目標としているようです。なので、今後デザインなどに派手な演出や音などを用いることで、より楽しめるような仕掛けを入れていきたいといっていました。次回からもみんなが楽しめる作品というコンセプトを忘れずに作って行けたらいいと思います。', null, null),
  ('397e72f4-6710-5470-abab-e485bb390684', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-13', '17:30:00', null, '通常 / プラットフォーマーゲーム ジャンプ復習', '前回作成した放物ジャンプの変数の部分を見直そうと思ったのですが、顔がかなり渋かったので、簡単なジャンプと台に乗るということを掛け合わせて考えてもらうために、レッスンのあるくんの冒険2に取り組んでもらいました。途中出てきたクイズもよく考えられていました！丁寧に取り組み、無事完成できていたので、再度考え方（地面orNot, 上にあがるという考え方）を共有しました。 その後前回自分が作成したサイコロのプログラムの方に戻り、今回やったことを使っていました。また足が地面に触れているときにのみジャンプができるような工夫も伝えました。楽しく取り組めました！', null, 'タイピング: 集中して取り組めていました。'),
  ('b35b87d9-941a-57a7-a754-4770e1997334', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-13', '17:30:00', null, '通常 / ドリル続き・集中力', '最初の問題10まで進めることを約束しました。 問題6の四角形に動かすところでかなり時間がかかりました（20分くらい）ただ、一人で考えていろいろ試せている時間が長く、頑張っていました！最後は問題を見ながら一緒に取り組みました。どうしても複製を使いたくなってしまい混乱している＆「～度にする」「～度回転する」の違いが分かっていない状態でした。後者については、「回転するときにはどちらかしか使わない」ということでひとまず統一し、ネコの一つの挙動を追いながらプログラムを進めました。 その後のアニメーションのような問題については、とてもスムーズに取り組めました。目標には届きませんでしたが、途中休憩は6分だけで頑張れていました！！！', null, 'タイピング: プログラミング中に「ドリル～～」と打ってもらいました。
盛り上がり: 最後にスタンプも自分で押せて満足そうでした！
備考: 本人が気が付かないときにキーを押して意図せず拡大と縮小が起きてしまうときに、感情が高ぶってパニック（？）になりそうになるので、早めに対応する必要がありそうです。'),
  ('38e60f67-a9da-55d2-a13f-95d6c7b517c3', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-13', '18:40:00', null, '通常 / U16大会作品制作', '今回は、用事や渋滞によって遅れてしまったため18時半の枠で行なっていきました。ガサガサ探検隊の写真や動画を受け取っていなかったようなので、資料として使う救命胴衣の写真をトレースしてきました。今回初めてフォトショップを使ったようで、時々操作に戸惑っていましたが、自身で調べたり聞いたりして問題を解決していました。作品のものは写真や動画以外は基本的に手書きにこだわっているようで、より高得点を狙うために手書きを用いているとのことでした。次回はガサガサ探検隊のデータを使って資料作成を行なっていく予定です。', null, null),
  ('446581f8-73ef-5fd7-8bd0-f2ce9e2c955a', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-13', '16:30:00', null, '通常 / プラットフォーマーゲーム・ジャンプ', '前回の復習した後、台に乗るプログラムの考え方を把握するために取り組みました。大まかなジャンプの種類や方法は把握できていました。 解説動画に出てくるクイズの部分は自分で考えてもらいました。「～でなければ」を使って地面とそうでない部分を区別することを確認しました。途中プログラムミスでうまくいかない部分もありましたが、修正できました（下に落ちるのを10回繰り返していた）。 最後に自分のオリジナル作品の方にプログラムを作って実践していました。背景スクロールが止まらないように、自分でメッセージを作って考えてしっかり実装していました！すごい！！楽しそうで良かったです。', null, 'タイピング: 授業前に集中して取り組めました。'),
  ('b627c8cd-6843-5da5-ada0-c41e16defdd2', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-13', null, null, '通常 / 追跡ゲーム完成＆アレンジ', '変数を使うのは初めてだったようなので、加点の仕方と0にリセットする方法を共有しました。おおよそ理解できていました！またクリアのスプライトも自分で作成し、表示非表示が必要なことも把握できていました。「～まで待つ」を紹介しましたが、どれくらい心に残ったかは分かりません。 アレンジとして触れたらスコアが減ってしまう邪魔者を作りました。（アレンジも初めてだったかな？）マイナスについて簡単に紹介し、加点のプログラムを参考にしながら自分でプログラムを作成できていました！ここで追跡ゲームを追えることは説明しましたが、後日どうしても本人がやりたければアレンジ続きをやってもいいかもしれません。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('e0f60080-27ca-59d0-a003-dfdf2dcc5cc5', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-13', null, null, '通常 / Excel', '動画を見ながら自分で進められていました。桁整理や色を付ける部分を確認したそうです。10月末に向けて3級に挑戦できるか聞いてみましたが、「少し難しいかも？けど頑張ってみる！」とのことでした。イヤホンを忘れて教室のを借りていましたが、片耳が聞こえないと教えてくれました。', null, '時間帯: その他'),
  ('b26dea00-2277-5088-9d8b-ce142e2a7d8c', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-14', null, null, '通常 / エラースクラッチ', '前回のバレーの変数の仕組みを復習をまずしました。コードをすぐ完成できたので、変数の役割の説明をお願いしましたが、上手に答えらていました。 次に、エラースクラッチをしました。セリフの有無ものは少しかみ砕いてヒントを与えらあらできました。スタンプの問題では、あまりスタンプのコードになじみがなかったので、動かしの順序が困惑していました。特に、繰り返しの範囲の区別がうまくできておらず、横の動きの繰り返しと縦移動の1回のコードの組み立てがうまくできていなかったです。ほかの、変数を使ったものはすぐに作ることができました。ここで、コードの順序が少し弱いと感じました。', null, '時間帯: その他'),
  ('e7e3ed4f-ac34-55fb-9b8c-3889c17579ec', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-14', null, null, '通常 / エラー', 'ほぼ自力で取り組めましたが、クリックの度に止まると動くを繰り返すプログラムが難しい様子でした。考え方に気が付けなかったので、変数に注目してもらいながらブロックの言葉で挙動を説明し、その後自分で考えてもらいました。制御と演算のブロックを組み合わせてうまくプログラムできました。34番については紹介して終わりました。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('356e03a1-48df-5884-903b-d3976d41d673', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-14', null, null, '通常 / ドリル1問題5~8', 'ファイルの方の記録がなかったので、おそらく復習も兼ねて問題5~8に取り組んでもらいました。角度についてはバッチリでしたが、繰り返すときに角度に混乱してしまうようです。ジグザグ、四角形に丁寧に取り組めました！！ その後、アニメーションに取り組みました。とくに斜めに歩かせるときは見本のプログラムをみて取り組んだほうが、かなり分かりやすいようでした。 お昼にたくさんお菓子を食べてしまったようです。', null, '時間帯: その他
タイピング: 時間をかけて「むずかしい」に取り組みました。'),
  ('4489bc6e-091c-5fba-a9ad-09651d126416', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-14', null, null, '通常 / パワポ作成', null, null, '時間帯: その他
タイピング: パワポ作成/Canva'),
  ('fba8b887-cd02-5f74-9d58-62eb4c816020', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-14', null, null, '通常 / オリジナルプログラム', 'オリジナル作品の続きをプログラムしました。攻撃の部分をプログラムしたいとのことでしたが、HPのプログラムを忘れていたことに気が付き、体力バーのプログラムを追加しました。小技にあるプログラムで内容を一緒に確認し、その後オリジナルの作品に反映させたようです。また挙動の確認をしていたようですが、メッセージとずっとを同時に使っていたので、「～まで待つ」を使うアドバイスをしました（伝わったかどうかは分かりません。）', null, '時間帯: その他'),
  ('8ec1ba4e-dbbf-59e0-9722-656db16a050d', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-14', null, null, '通常 / ピンポンのアレンジ', '前回ほぼ完成していたので、最後の仕上げとアレンジをしていきました。アレンジする際に、「最後にミニオンが出るようにしたい」とのことだったので、「まで待つ」の復習しました。スコアの条件を振り返って、自分だけでコードの説明をすることができました。そこから、ほかのスプライトも「までまつ」の活用できていて、反復使用ができていました。 その際に、先生とともに不等号の条件に変更で来て、自分が望むものが完成できていました。', null, '時間帯: その他
タイピング: ミスが少なくできました
盛り上がり: 後半はこーしろうー君とともにソニックで盛り上がっていました'),
  ('10bf207c-ce0e-5eb5-bed5-ab41ea173fdf', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-09-14', null, null, '通常 / エラー解決', '前回タコのゲームにバグが残っていたので、改めて考えてもらいました。座標の符号を間違えているという予想をして、確認すると実際にそうでした。タコのゲームが終わるとエラーで学ぶスクラッチに移行しました。不等号が出てくる問題で、大小関係を考えるのはあまり得意ではなさそうでしたが、1から10までの数を視覚的に並べてみるとイメージがわいたようでした。「ではないまで待つ」が出てくる問題では、さっきのタコのゲームと同じスキルを使うというヒントを出すと頑張って思い出すことができました。', null, '時間帯: その他
盛り上がり: エラーで学ぶスクラッチについて、「プログラミングの間違い探し」という導入をするとゲーム感覚で興味をもって始めてくれました'),
  ('6e51444b-3fa0-5a79-bbe0-05efa4a390df', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-14', null, null, '通常 / ドリル演習', '前回に続いてドリル演習をしました。最初の方は、簡単と言い張るものが多かったdの絵、少しずつ飛ばしながらもスムーズに解いていきました。少し立ち止まったものは、回転のブロックを使ったものです。ぴょんぴょんするジャンプやドミノ倒しが思うままに形にするのに時間がかかっていました。まだ「何度に向ける」と「何度回転」が混同している感じでした。ドミノ倒しは最後まで終わらなかったので、続きをやってください。', null, '時間帯: その他
タイピング: お得まで、あと少しでした'),
  ('6ccef133-d417-5ff9-8844-db2a1a27f310', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-09-14', null, null, '通常 / ドリルを進める', '今日はドリルに高い集中力で取り組めました。ただ、プログラミングだけにひたすら集中していたため、「問題ごとに新しい作品を作ってね」などのお願いは聞いてもらえませんでした。しかしプログラミングの内容としては良く、一度動かしてみた結果、向きを設定し忘れたことに気付いて直すなどもできていました。また、「音を鳴らす」と「終わるまで音を鳴らす」を意識して使い分けていました。前回と今回を合わせて、時間ちょうどでレベル1が完了しました。', null, '時間帯: その他'),
  ('ed7101b3-967b-5710-8a6c-aa97cca433c7', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-09-14', null, null, '通常 / エラー解決', 'ジャンプゲームがあと少しだったので完成させてしまい、リストの事項を復習して終わりました。残りの時間はエラーで学ぶスクラッチに取り組みました。前回ジャンプゲームでデバッグをしたのに関連して、それと似た修正の練習と位置付けて導入しました。最後のカーリング以外は全体的にスピーディーに片づけていきました。カーリングについては、セリフを言わないバグがなかなか直らなかったのですが、「セリフは言われているけれど一瞬すぎて見えない」というヒントで納得したようでした。1時間のうちに全て解き終わり、実力を身に着けてきている様子でした。', null, '時間帯: その他'),
  ('592f1e74-ed90-5a3b-bf42-0220bd9b703a', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-14', null, null, '通常 / U16大会作品作り', '続いて、作品を作っています。武器へのコメントなど細かいとこまで隙間なく作れていて、濃密な仕上がりとなっています。ほとんど完成に近づいてきたので、次回からはスライドづくりに移っていく方面がよさそうです。', null, '時間帯: その他'),
  ('ddd19e24-f5f8-5569-9a90-998787507aff', '82396ac6-71bd-59d4-a372-57212866fd5d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-09-14', null, null, '通常 / 基本操作コース', 'ストーリーを作るのは好きなようで楽しく進めていきました。「～秒待つ」を使ったキャラ同士の会話や、背景の変化はさらっとこなせていました。セリフのタイピングは自力で頑張っていました。座標についてはまだ難しく感じる部分もあるようで、「～秒で座標を～にする」というブロックを新しく扱ったときはイメージしづらそうでした。ただ、実際にキャラクターを動かしてみた結果、今までと同じように座標を変えると場所も変わるということは理解してくれたようでした。', null, '時間帯: その他
タイピング: だんだん打つのに慣れてきている様子です'),
  ('b8dbd96f-8c2d-51ad-9f6e-905cab9aa504', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-09-17', '16:30:00', null, '通常 / 花火を作ろう', '資料に載っていたコードのお手本を入力させた後、一段ずつ「なぜこのコードを置くのか」という解説をしました。 身振り手振りや身近な具体例を用いて説明すると「こういうことですよね？」とよく聞き返してくれるので、とても反応が良かったです。 一連の動作の解説は15分程度で終わりましたが、ペイントツールに関して私がよく理解出来ていなかったため、 残り時間を中島先生にも手伝っていただいてツールを解説する時間に当てました。また、ペイントツールで描いた線を落下させたような動きを書く際になぜタイマーを使うのか、タイマーを使った際になぜ小数点表記なのか…という説明までしましたがイマイチ理解出来ているかが怪しいです。本人も「一度では理解は難しい」と言っていたので、次回軽くおさらいしてみた方が良さそうです。', '今回よりもっと簡単な例を使ってペイントツールの使い方を学ぶ', 'タイピング: 集中されていました。
盛り上がり: 実際に花火が動いたりする様子を見て「すごい！」と感心された様子でした。'),
  ('34899bc7-703a-5551-ad43-f21a9da2f894', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-09-17', '16:30:00', null, '通常 / お散歩ゲームを進める', '最初に、遊び始めた瞬間にゲームオーバーになってしまうバグがあったので直していきました。変数やメッセージの名前を間違えて入力しているところが複数あったので、自分で確認と修正をしてもらいました。岩の動きを作るのにはクローンを使いますが、クローン自体ほとんど使ったことがないようだったので基本から説明しました。クローンは自分の分身で、その動きは「クローンされたとき」ブロックで表現することを理解してもらいましたが、まだ使い慣れない様子でした。岩の動きの中盤まで終わりました。', null, null),
  ('81697241-59e8-553f-ac95-d34376e51577', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-09-17', '16:30:00', null, '通常 / ゲーム完成を目指す', 'まず前回どこまで進んだかを確認しました。キャラクター数が多いため、「今日はこのキャラクターまで終わらせることを目標にしよう」と伝えてから始めました。敵の種類が多かったですが、動きの似ている敵を理解しながら作成できていました。最後に、銃弾の出てくる場所がおかしくなるバグがあったので修正に取り組みました。「挙動からしてこの変数が間違って設定されてるね」ということを一緒に確認し、それを設定しているコードはどこかと問いかけると、本人の手で修正に取り組めました。', null, '盛り上がり: 今日の目標を決めたことである程度モチベーションが保てたようでした。'),
  ('a91fa312-006b-5cdb-b177-1e1936cb6c76', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, null, '2024-09-19', '17:30:00', null, '休み（未対象）', null, null, null),
  ('b29cb7b1-4574-5f88-9ef2-2f40e2f438f1', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, null, '2024-09-19', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('f37c5661-fa59-5b1f-a083-3b0d810a8259', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-09-19', '16:30:00', null, '通常 / 【Prg】ボールキャッチ 完成＿変数のリミックス', 'バレーボールのゲームでプログラムというより、コスチュームの見た目にこだわっている時間が多かったです。人物を左右に動かしたりするのはほとんど何も見ずに自力で出来ていました。途中、ボールを動かす部分だけ難しかったようで、アドバイスをしながら進めさせましたが時間が足りなくて途中で終わってしまいました。 時間内に終わらせるのであれば、コスチュームへこだわる時間は少なくさせた方が良さそうです。', null, 'タイピング: 集中して取り組めました。'),
  ('235eca32-a8b8-53d1-960a-eb6ac3635810', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-19', '16:30:00', null, '通常 / プラットフォームを作ってみよう', '雨の影響で大幅に遅れました今回からプラットフォームの流れを作っていきます。ジャンプ系の製作は1年前にやった形跡はありましたが、本人は曰全く覚えていません。遅れてきたので、ジャンプの内容に取り掛かることはできませんでしたが、次回からかなりゆっくり復習してやっていった方がいいと思います。', null, null),
  ('104e89de-da69-57d0-b275-27e27912354e', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-19', '17:30:00', null, '通常 / 変数の「スイッチ」の使い方を覚えよう', '前回までレースゲームで変数を使ったため、その使い道を広げるために今回はバレーゲームをしました。最初の試遊で、腕やボールの打ち上げる条件を細かく見れていて、変数による状態の違いも自分の言葉で説明できていました。作り始めると、基本的な動きが多かったので、スムーズに作り上げることができました。打ち上げ条件も「かつ」もしっかり使えていてました。元ゲームのままだと打ち上げ高さが低かったので、そこを自由に変えて小太郎君と遊んで楽しんでいました。', null, 'タイピング: 連打芸すごいです'),
  ('d8ffccd8-e0e2-5bc8-a5fc-284bae3bc300', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-09-19', '16:30:00', null, '通常 / 集中してドリルを進める', 'ドリルの続きをやっていきました。最初は「やる気が出ない」と始めてくれませんでしたが、今日の目標を低めに設定することでなんとか取り組むことができました。自動で動かす作品なのに矢印キーを使ったりと、最初は問題の把握がきちんとできていませんでしたが、一緒にキャラクターごとに動きを把握していくと理解することができました。いったん自分で作ってみて、音が一瞬でたくさん鳴りすぎるなどのバグが出てきたときは、「1秒待つ」といった解決策を考えることができていてよかったです。', null, null),
  ('de87c3f3-44a5-5ad1-a8ee-f2c5f895dc56', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-19', '17:30:00', null, '通常 / ピンポンゲームを作ろう回転やもしの使い方を学ぼう', 'ピンポンゲームを作て行きました。最初の試遊の時点で、どこがどんな働きをしているか答えることができていたので、全体的に、スムーズに作れていきました。マウスのx座標を使う仕組みも自分で選んで持ってくることができていたので、理解力は高いです。跳ね返りの部分では、まず、ノーヒントで考えてもらいましたが、なかなかうまくいきませんでした。そこで、跳ね返すの動きは質問形式で細分化しながらやっていくと、使えそうなブロックを自分持ってこれることが多かったです。最後の変数の仕組みも、慣れた手つきで作れ神瀬できました。', 'アレンジ？', 'タイピング: 1つ1つ打てていました
盛り上がり: 最後父親や妹ちゃんにも見せてやり切った満足気な表情でした。'),
  ('9747595c-af28-5d87-9576-ae1deeaae4da', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-09-19', '17:30:00', null, '通常 / ドリルを進める', '前回でドリルのレベル1の半分が終わったという振り返りをして、残りの半分を埋めることを今日の目標にして始めました。問題を解くたびにファイルに記録することで、ゲーム感覚で楽しく進めることができたようでした。ファイルに使うブロック自体はわかっていたのですが、旗を押した瞬間だけ行うのか「ずっと」の中に入れるのかを間違えることが多かったです。途中で向きが変わる時は「～度に向ける」はずっとではなく最初だけということを確認すると、一応は理解したようでしたがもう少し振り返りをしたほうがよいかもしれません。', null, 'タイピング: 集中していました。'),
  ('034b7254-e3fb-5468-9c8b-fbb67df5fc49', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-19', '17:30:00', null, '通常 / 大会作品作り', '前回に続いて作品作りをしました。承太郎君の想定では終わりの形まで見えているが、その量がかなり膨大なため、時間管理が必要です。内容的にはかなり会話劇を占める部分が多いので、セリフなど内容は授業外でも考えて、USBなどでコピペして持ってくることも提案しました。現時点では、セリフなども考えながら作っているので、コードの作成部分を少しでも長くしてあげたいのがこちらの考えです。', null, null),
  ('a63d8625-a67b-5396-8d5b-5688e9320ee1', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-09-20', '17:30:00', null, '通常 / プラットフォーマーゲームを自分なりにアレンジ', 'ジャンプと足場作成、ゴールの設定はすでにできていたので、ゴールに辿り着くまでにいろんな障害を自分なりにアレンジして追加する事を提案。動く敵を複数設置して、触れるとスタート地点からやり直し、鍵を取るとゴールまでの近道の足場が現れるギミック作成等。やるべきことの指針を示すと、サクサクとさほど迷わずに作成できていました。基本的なスクリプトの作成は問題なくスムーズにできていると感じました', null, null),
  ('5d81a101-daf9-540d-ab8f-70ff4fc2a6a2', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-20', '16:30:00', null, '通常 / 変数による状況区別をしよう', 'ある程度いろんなことを積んできたので、変数の使い方として、バレーボールを作りました。この変数の状態の区別はしっかりと認識で来ていたので、初めからノーヒントで作るようにしていきました。むらっちの動きに関してスムーズに作れましたが、ボールの落下に関しては「何秒で座標異動」を使おうとしていたので、ほかのやり方をやるよう提案しましたが、そこでなかなかうまくいきませんでした。忘れていたそうだったので、基本操作コースのカードを見せながらなら、やったらできたので、初期の動きの忘れがたびたび見受けられます。変数の条件に関しては、自ら立てられていたので、基本的な動きの種類が向けているような気がします。たっちゃんには簡単かもしれないが、基本動作の復習としてドリルのレベル3でもやっていいかも', null, 'タイピング: だんだん早くなっていきます'),
  ('fc31f382-b7d7-5dc3-ae27-926ed4325410', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-20', '16:30:00', null, '通常 / 作品作り', '退会低州についてあいまいなところがあったので、今一度大会作品の過去のものを見て考えてもらいと、かなり難色示した顔をしました。出さない気持ちが80％くらい傾いていました。ただ、出さないとしても今作っているものをバグ残りでは終わらせてほしくなかったので、デバッグをやりました。前から残っていたクローンの複製がうまく行かなったところが確認して、ただ、クローン状態時の表示ができていなかっただけのそうでした。それに付随していたバグも解消できて確認作業もできていました。', null, 'タイピング: 寿司だもやっていろいろ長々となっていました。'),
  ('f8b93c2f-f759-526a-8367-34ad0869ac09', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-20', '17:30:00', null, '通常 / 大会作品作り', '前回から続いていた監視カメラの映像の製作に取り組んでいました。それぞれ個々のメッセージを使ってコード作っていたので、作り終えた後も何か所も作り忘れが見受けれてました。何度も名前をわかりやすくした方がいいと頼んでいるが、なかなか変えないです。本人曰く山場だった監視カメラのシーンを作り終えたので、気持ち的にはかなり楽になっていました。ある程度は終わる兆しが見えてきたそうです。', null, null),
  ('99f608df-7696-5190-a893-f3386562b92c', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-20', '17:30:00', null, '通常 / ドリル10~14', '実際には6問進める予定だったのですが、途中5分ほどの休憩をはさんで5問に取り組むことができました。コスチュームの追加をしたのですが、他のスプライトの見た目をコスチュームとして追加できることは知らなかったようです！共有したのですが、理解してくれているかは分かりません。またレベル1のドリルを終えられたことを伝えると嬉しそうでした！ 円のように動かすのは、ヒントをかりながらうまくプログラムをできました！また角度を変化させることで、動く円の軌跡が変化することも共有しました。矢印キーで動かすプログラムは、動かしたい方向もプログラムする必要があることを強調しました！', null, 'タイピング: 頑張って取り組めました！'),
  ('48748c1a-8d71-5d4a-baab-63f2257cec1e', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-20', '16:30:00', null, '通常 / 前回のプラットフォーマーゲームアレンジ', '前回作った作品にゲーム要素を足しました。画面の右端についたら左に動くようなプログラムは座標でコントロールすることを提案し、一緒にプログラムを進めました。また溶岩ゾーンを作り、ぶつかったら初期位置に戻ったり、体力を作ったりしました。背景と背景スクロールの両方を使って、本当の意味でのアスレチックゲームを作っていたように感じました。', null, 'タイピング: ミス率を下げていきたいです！'),
  ('d49afe45-e4cf-598b-9515-e08ed041f75f', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-20', null, null, '通常 / 大会オリジナル作品続き', 'シナリオの部分はあまり進められませんでしたが、プログラムの方は集中してよく取り組めました。衝撃を受けたときに沈んだとき上に戻るようなプログラムを作っていましたが、それが自然に見えるように工夫していました。また、前回作っていた、キャラが端によってしまったときに使うスプライトもうまくプログラムして表示できていました。新しい登場人物が追加されるそうで、表情をよく作れていました！', null, '時間帯: その他'),
  ('ca4a6131-87df-563f-a539-978a0adc4d34', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-20', null, null, '通常 / 乱数と迷路チーズ', '乱数について、レッスンを用いて説明しました。サイコロはイメージしやすかったようで、見た目だけでなく動きの部分を変えられることも併せて説明しました。 迷路チーズでは、みみちゃんの動きのみを作りました。もし～～を使った矢印操作がほぼなかったようなので、説明しながら取り組みました。「ずっと」と「もし」はセットで使うことを強調しました。また、歩くプログラムは座標ではよくやっていたけど、歩数と向きは記憶が薄かったようです。再度説明してイメージしてもらいました。 壁にぶつかったときに跳ね返るプログラムも作成しました。止まる＝0歩あるく から考えるのは難しかったようですが、最後は自分で答えを見つけられていて良かったです！ 次回チーズの部分から作成です！', '次回チーズの部分から作成です！', '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('de32908f-b79a-5f1d-ad93-1a98f6888273', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-20', '17:30:00', null, '通常 / 自由製作', '前回から作っていた、作品インついて進めていたが、有効的な攻撃パターンが思いつい杖おらず、悩んでいました、そこで、こちらからアイデアを渡すと、意気揚々に取り組めて、コードで形にできていたので、コードの具現化はよくできてきたと思います。いったんできたとしても、ゲームバランスの調整も適宜行って、程よいゲーム性のある対戦型のゲームができてました。', null, 'タイピング: よく進めらていられていました
盛り上がり: 他人に遊ばせたい欲が原動力になってコード作成がここ最近続いていてよいです。'),
  ('38a65e14-93b8-5011-93cd-b959757b39f3', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-20', '18:40:00', null, '通常 / 変数の使い道を広げよう', '今回は場面転換を対応するタコから逃げろを作成しました。ここでの変数の使い道を予想してもらうと、変数の作成の流れもあってか答えることができていました。だが、変数での区別分けで変数と値をテキトーに最初設定したこともあって、後半の動きの確認の際に、より難しくなってしまいました。今回の場合、変数の値にも意味を持っていたので、そこのところで困惑していました。最終的には、元の値通りに戻して完成できていました。アレンジはできていないので、次回はそれをやってもいいかも', null, null),
  ('ca6737ef-bcf6-5aef-a658-04633732d076', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-09-21', null, null, '通常 / 学んだスキルを活かしてゲームを作成する', '全体を見るとスプライトやコードが多くて何から手を付けてよいかわからない、といった感じでしたが、知っている動きから作ろうと声をかけ、戦闘機の動きから作成に入りました。「かつ」の後の座標指定でとまどっていましたが、どうしてこの不等号の式が入っているのか、不等号の向きの意味などを一緒に確認していくと、納得できたようでした。 ただ、座標のプラスマイナスと不等号の向きを自力で設定するのはまだ難しそうという印象でした。 弾のスプライトのコードでクローンの復習をしました。このあたりは覚えていたようで、あまり迷うこともなくスムーズにできていました。', '敵のコードの続きから', '時間帯: その他
タイピング: 何度も繰り返して熱心に練習していました。1回目は9級相当だったのが、最後に5級相当の記録が出て嬉しそうでした。
盛り上がり: 本格的なゲーム作成に、自分が学習してきたスキルでチャレンジできるのが嬉しそうに見えました。タイピングも含め、とても熱心に学習していました。'),
  ('bd4ed03b-1c7e-532e-aed2-c9738a5aca42', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-09-21', null, null, '通常 / ドリルでスキルの定着を図る', '今日は授業開始前に遊ぶ時間がなかったので、単元別演習Aの5問ができたら自由時間、というと、俄然やる気になってくれました。 A1のタイマーは初めて見ると言いながらもすぐに覚えられたようでした。 A2以降はほぼ自力でできていて、条件分岐と〇色に触れたらを組み合わせることなどもきちんとわかっていて、口頭でスラスラと答えていましたが、実際にコードを組む前に正解かどうかを確認したがる傾向がありました。', null, '時間帯: その他
盛り上がり: 各課題をしっかりと楽しみながら取り組めていて、保存した作品をすべて、お母さんに得意そうに見せていました。 演習をすべて終えた後、残り10分の自由時間も満喫していました。Scratchで見つけたというソニックゲームで盛り上がっていました。'),
  ('4fa81794-9090-5a33-a428-e00bf63da352', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-09-26', '16:30:00', null, '通常 / 【Prg】ボールキャッチ 完成＿変数のリミックス', '前回の左右に人を動かす動作からボールの跳ね返りの動作まではプログラム出来ていましたが、腕がずれてしまう動きになっていたためアドバイスをしました。最終的に見本通りのコードではなく、本人の考えたコードで満足したため一旦は完成させました。 完成したのが授業終了20分前だったので、ペイントツールを使って人物にアレンジを加えたらどうかという提案をしました。', null, 'タイピング: 頑張ってました（やればやるほどできなくなってまうようで、悔しそうでした(和)）'),
  ('5da90a3c-5bfb-537c-82fc-5280a34e2a41', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-26', '16:30:00', null, '通常 / 集中してドリルを進めよう', '最初に6問やったら、あとは自由時間と約束してから始めましたが、3問くらいから集中力が切れて、かなりいやいや期になってしまいました。ドリルは作る順番を文章で書いてあるので、1番目のことが終わったら次に文章に読むように誘導したら、しっかりと次に行動のコードを作り始められます。だが、こちらが次に文を読むことを誘導させなかったら、自由に考えてしまうことが何度かありました。それでうまくいかなくて、いやいやになったと思います。読んだ見たものを自分を作るまでの集中の維持がとても短いです。そのことがうまくいったときは、スムーズにコードが作れれるが、、、とくに最後の問題を解くときががそうでした。', null, null),
  ('e9fabe0f-6568-511d-9696-e4cb0d52f630', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-26', '17:30:00', null, '通常 / 検定練習', '今回で2球が合格できたので、11月末に1級にチャレンジするために、練習をしました汰。50分フルに使ったとりあえず解き終わりましたが、途中わからない難しかったところもあったそうです。特に(4)の①です。答え合わせができなかったので、次回お願いします。', null, null),
  ('7bf657d0-4f3d-5d92-bed6-a16744e6dd4d', '57f45872-1f3e-5540-b676-bf9023444e39', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-26', '16:30:00', null, '通常 / プラットフォーマーゲーム 等速ジャンプと放物ジャンプ少し', '前回の予告の確認の後、等速ジャンプをしました。ジャンプゲームを思い出しつつできていました！ただy座標の符号については何回か試した後に決定していました。変数で置き換えるということがあまり理解できなかったようです。降りるときに高さの変数にマイナス1かけるのも、本人とかなり話してようやくたどり着けました。 また参考プログラムとしてカエルに取り組んでもらいましたが、あまり面白くなかったようです。背景スクロールと画面上でのカエルの見え方について確認しました。 放物ジャンプと等速ジャンプを比べて違いを話したあと、考え方を簡単に図に示しました。そのままプログラムを進めてもらったのですが、変数の変化がうまくできていないものの、変数と動きが組み合わさる大枠の部分はできました。次回、変数部分のプログラムを修正する予定です。', null, 'タイピング: 集中して取り組めました。'),
  ('9636a793-0405-5ea0-b441-59cdb7d5001c', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-26', '17:30:00', null, '通常 / ドリル13~18', '矢印キーで動かすところでかなり悩んでいました。角度の概念を忘れてしまっていたようで、少し声をかけると自分で気が付いて修正できていました！！大きさや見た目のプログラムはよくできていましたが、制御のブロックが入ってくると（ずっとなど）、何をずっと繰り返すのかについて、意識が薄くなってしまうので、何回か挑戦していく必要があるかなと感じました。 ドリルは結構気に入っている（？）ようです。今日も1時間ちょうどかけて集中して取り組めました。次回は24まで終わらすと意気込んでいました。', null, 'タイピング: 集中して取り組めていました。'),
  ('4eea40cd-1894-5dae-b2c6-23ca876bc307', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-26', '17:30:00', null, '通常 / ドリル6~12', '前回はレベル2に入っていたのですが、ファイルを確認するとレベル1がもれていた（本人も覚えがなかった）ので、復習を兼ねて取り組みました。どれもスムーズに取り組むことができ、場合によっては初期位置など＋1の工夫もできていました。ただドリル11のコスチューム選択の部分で、他のスクリプトのコスチュームを選べるということを知らなかったようで、とても驚いていました。レベル1とはいえ、かなりボリュームがあったのですが集中して取り組めていました！', null, 'タイピング: 集中して取り組めました。
盛り上がり: 好きなポケモンはブラッキー。'),
  ('c096d1c7-b6d9-534c-a5b9-f2977fda57f7', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-26', '16:30:00', null, '通常 / 検定の問題に始めてやってみよう', '今までの習熟度から検定の問題をやってみてもいいかと思い、4級を取り組みました。ゆき先生からやる目的を聞き、取り組みましたが、やって途中で様子をうかがうと、読み飛ばしで困惑してしまっている場面が見えました。ほかにも、検定特有の「「①のあとに」の文章が正しく解釈ができていなかったので、一緒に前半は文章を読んでいきました。そのあと進んでいくと、バグが発生してしまい、自由に作り変えてしまうことがあったので、今一度迷ったら問題文と動画を見ていくやり方の説明は必要です。あと読み飛ばしも多かったので、1文ずつチェックしていくもいいと思います。文章の読み方の苦戦していたので、スクるは問題ないです。今日はお父さんは車待機だったので、成果内容は離せませんでした。', null, 'タイピング: だんだんと早くなっていきました。'),
  ('7566534d-9e50-5f80-8613-50f42df339df', '0047fb11-a84a-5592-8c39-5a16c20eb10e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-21', null, null, '通常 / エラーで学ぶ続き', '前回の続きからデバッグ問題を解いていきました。問題の核となる部分に毎回引っかかることができており、一緒に考えていくと答えまで辿り着くことができていました。特に問題37では、移動と停止の仕組みについてかなり悩んでいましたが、停止をどのようにさせるのかをはっきりとさせてからは納得してスラスラと解くことができており、とても嬉しそうでした。', null, '時間帯: その他
タイピング: 集中して取り組めていました。'),
  ('7ae46e70-aeaf-5ffd-aaad-c7c615b31152', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-21', '16:30:00', null, '通常 / U16大会作品制作', '以前から問題視していたOS部分については解決したため、今回はUI面を改修していきました。タッチするボタンが小さい、文字が見えにくいなど大きさ部分に関しての問題が多かったため、どこで文字やボタンを管理しているのかを探すのに苦労している様子でした。しかし、修正を全て1人で行うことができており、文字のデザインも変更するなど自前のスキルの高さで解決していました。', null, 'タイピング: 素早く正確に打つことができていました。'),
  ('a4900373-e0e7-5059-8b0c-aadda8d8eba0', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-09-21', '16:30:00', null, '通常 / オリジナルゲーム作成続き', '前回から、キャラクターの攻撃ごとに経過するターンの変数について問題があったようなので、その部分を中心に修正していきました。自分と敵のターンがうまく噛み合っていないようなので、コードを確認したところ変数が１つのスプライトにのみ適用されていたようです。この状態になったのは初めてのようで困惑していましたが、原理を説明したところ納得して修正することができていました。', null, 'タイピング: ２級を目指して集中して取り組めていました。'),
  ('28fbde6f-5a31-5dbe-a70b-ac0c560105c4', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-21', null, null, '通常 / 追跡ゲームへ向けて、サメから逃げろ', '座標は理解が浅いようですが、自分で試して最後にきちんと答えを出せます。分からないときはスペースキーを使って（簡略化して）実験できていたのが良かった！！ちょっとヒントだすと自分で考えてプログラムできました。 角度の話はまだ苦手そうです。見本と同じようにあちこち動くプログラムにしようと思いましたが、左右に動かすのみで終わりました。（本人的にはかなり満足）あとスコアを足せばほぼ追跡ゲームです... 長いスクリプトを作るのはまだ苦手なようです。', null, '時間帯: その他
タイピング: いろいろな難易度に挑戦しています'),
  ('07f74007-1e48-572b-8de2-06b468f8060e', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-21', null, null, '通常 / クローン（検定に向けて）', '検定に臨むにあたり、クローンを知らないようだったので取り組みました。 初めてだったようですが、まゆねこ、宇宙クローン（クローンに置き換える部分）、変数を渡して変数ごとに違う位置に置くプログラムをしました！！ まゆねこで、クローンの基本的な考え方（親と子）を紹介しました。表示非表示やコスチュームの変更もスムーズに取り組めました。宇宙クローンではスペースキーでコントロールされている部分をクローンを使ったプログラムに変更し、連射ができるようにしました。少し悩んだようだったので一緒に整理して続けました。また変数を「このスプライトのみ」と設定して使うことで、それぞれのクローンを違う位置にする（動かし方をする）プログラムも紹介しました。よく理解できていました！', null, '時間帯: その他
タイピング: 何度か挑戦していました。'),
  ('5cede12f-b896-559b-9023-43588a214ea6', '0047fb11-a84a-5592-8c39-5a16c20eb10e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-21', null, null, '通常 / エラーで学ぶ', '42番は少し考えてもらった後に、種明かしをしました。原因も理解できて驚いてくれてよいリアクションでした。 唯一つまづいたのは、クリックであるくんのスタートストップを切り替えるプログラムです。変数を使っていることは分かっていましたが、変数の切り替えるポイントを言語化した後にプログラムにつなげることができませんでした。3回くらい確認してから、正解にたどり着けました！もしかすると、変数と制御が複雑なプログラムが、実際にどのような動きになるのかについて、コードを見ただけで想像するのが難しいのかもしれません。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('87e5c0d8-bdf2-585b-b2c8-fd32f23a30df', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-21', null, null, '通常 / 火星防衛軍（変数意識で）', '戦闘機のプログラムと弾がでるプログラムを作成しました。戦闘機の動きの基本的な部分はよくできていたのですが、画面外に出ないようにするプログラムが少し難しかったようです。詳しく説明しました。また、戦闘機が弾のクローンを作れる（自分自身以外のクローンも作成可能）ことを強調し、弾のクローンを作成しました。 最初のスタート画面にかなり興味をもった（自分の作品に応用したい感じ）ようなので、中身確認しするのも良いかもです。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('823c6db2-7853-5f83-b31e-9e0056b8904b', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-09-27', '18:40:00', null, '通常 / Excel検定3級のための学習', '来室時は買ってもらったというヘッドフォンを嬉しそうに見せてくれたりして動画をきちんと視聴していたようでしたが、30分を過ぎたころからかなりの勢いで舟をこぎ始めました(^^;) はじめのうちはさりげなく、そのうち露骨に声掛けをしましたが、半分寝ぼけていて、変なキーを押し続けたりしている状態で、一度席を立って水を飲んだりする提案にも首をふっていたので、実際の演習に切り替えることにしました。 教室の問題集に載っているURLからはデータのダウンロードができなかったので、急遽用意したデータを使い、フォントやセルの書式設定、罫線の設定を問題集通りにやってもらいました。このあたりから目が覚めてきて、きちんと会話をしながら取り組むことができました。 列の幅や高さの設定の場所を覚えていなくてヒントを出した以外は、すべて自力で設定ができました。', '関数の習得の方が時間がかかるため、次回からはそちらを中心に学習しようと声掛けをしました。', '盛り上がり: 途中は眠くてつらそうにしていましたが、問題演習にうつってからは一生懸命取り組めていました。書式設定の範囲は大丈夫と声掛けをしたら、少し安心したようでした。
備考: 試験日を教えてほしいとのことでした。 あと、はるちゃんのPCにExcelが入っていないようなのですが…'),
  ('d0548111-34ce-5da1-9820-1d1d15ceba03', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-09-27', '17:30:00', null, '通常 / プラットフォームゲームの完成系を目指す', '先週作ったゲームに対して、敵の数を増やしたり、足場を変更したり、難易度を上げたりとブラッシュアップをはかり、ほぼほぼ完成系になったと感じているようです。けいと君に挑戦してもらってクリアができなくてクソゲー呼ばわりされていましたが、楽しそうでした。来週は、特に追加したいことがなければ、新しい事を始めても良さそうかなと感じました。', null, null),
  ('29463fbf-668e-5e07-93e6-08b486eaaa09', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-09-27', '17:30:00', null, '通常 / 約束した範囲の学習に集中する。「マウスのクリックでスプライトを動かす」「キーでスプライトを操作する」ことを覚える。', '最初に今日の目的をファイルの表を見せながら説明して、そうすけくんが納得した状態で始めました。最初の目標の4問ができたらゲームタイムを入れるというと、熱心に課題に取り組んでくれました。 最初にドリルの問題にぱっと目を通して、適当にわかる箇所から始めようとする癖があったので、まずは問題の1から順にやっていくことを勧めました。後半はきちんと①から進められるようになりました。 今日の目的の範囲は、本人がきちんとブロックを覚えていて、得意そうに完成させ、名前をつけて保存してファイルにスタンプを押す、というサイクルをきちんとこなすことができていました。 ゲームタイムの後の後半は、最初に問題3つ分をめくってみて、後半は難しいから1問だけにしたい、とのことで、18のみ取り組みました。 大きさの既定値を設定したあと、どこまでを繰り返しの中に入れるかで迷いが見られましたが、実際に実行した動きを見て修正ができました。', null, 'タイピング: 今日はタイピングはとばしてすぐにプログラミングに入りたいと主張したため省略
盛り上がり: 目標をこなせたらほめられてゲームもできる、というのを覚えているようで、課題に取り組んでいる間はきちんとこちらの話も聞き、頑張る事ができていました。 授業後にScratchのゲームで遊んだ際は、ずっとあさひくんと一緒に盛り上がっていました。'),
  ('be2bf59b-a8ec-549e-9365-201b1e6bb705', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-27', '17:30:00', null, '通常 / 作品概要 プレゼンの内容づくり', '大会用作品のギミックを追加していました。音にかなりこだわっている様子です。プレゼンに盛り込む内容をキーワードだけでも書いてもらいました（誰に遊んでもらいたいか、どういう気もちになってほしいか）作品概要は、ネタバレになってしまうことが気になるようです。ストーリーはあるようですが、あまりしっかり書きたくないのかもしれません。 聞き取り調査した内容を貼っておくので、ぜひご確認ください。', null, 'タイピング: 集中して取り組んでいました'),
  ('61ca7550-b3c5-5259-9d65-0eb5282aed11', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-09-27', '18:40:00', null, '通常 / 大会オリジナル作品続', '私が軽く動かしてみて、攻撃を受けた後のキャラクターの動きが、何点かおかしい（地面にめり込む等）時があったのでそれを指摘。その動き修正と、ゲーム終了時の背景切り替えの処理をブラッシュアップしていました。今では、バグ等もほぼ見つからず、だいぶ完成に近いのかなと思います。来週は、特にバグ修正等がなければ、パワポ作成に取り掛かっても良いのではと思います。', null, null),
  ('9f4083e5-1845-5e24-94ef-0098200e6a00', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-27', null, null, '通常 / 迷路チーズ続き', 'ねずみの動きを確認した後、チーズの動きを作成しました。「ミミに触れたとき」を自力で作れなかったのが少し残念です。制御の「もし」「～に触れたら」を忘れてしまっていたようなので、これからも複数回取り組む必要があるかな？と思いました。また前回やった乱数も記憶が浅かったのでもう一度説明し直し、プログラムに加えました。座標も伏せて復習をしました。 最後に、とうきくんのグラデーションにかなり興味をもっていたので、ミミのコスチュームを使ってグラデーションを説明しました。作品はこれで完成です！', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('7c0eff0c-56d4-5be5-bb22-c91d87f49b19', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-27', '17:30:00', null, '通常 / エラーで学ぶ34~37, 42', '前回の復習をした後、エラーで学ぶに取り掛かりました。思ったよりも興味を持ち、サクサク進められました。変数をクリックして切り替えるところが難しかったようで、言語化の部分はかなり手助けをしました（変数の切り替えの詳細が気づきにくい）。50で止める問題は、あるくんを使うとスムーズにできることを伝えると他のスプライトを一生懸命探していました（矢印スプライトだと可能だそうです）。楽しそうでした。 後半はへとかのゲームを作っていました。まだ途中のようなので、次回少し取り組みたいそうです。またゆづきくんが作ったプログラムをプレイしていました。クソゲーと言っていましたが、かなり楽しい様子でした。', null, 'タイピング: 集中して取り組めました。'),
  ('3d42575c-f8ac-5d23-872d-18f465841e73', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-27', null, null, '通常 / Prgタコ', '見本と確認しつつ丁寧に取り組むことができました。しっかり完成させることができました！最後にコスチュームのアレンジを加えていました。自分で書いたり、グラデーションを作ったりして海の中にうまくなじませていました。また応援隊のようだったのでリクエストして、プレイ中にも応援してくれるキャラになりました！楽しそうで良かったです。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('35398eb9-9b1f-5d10-8400-04dc90fd67cd', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-09-27', '16:30:00', null, '通常 / エラーで学ぶ35~37', '話さないブロックとして空白を使うことは知っていた！ 「まで待つブロック」はあまり使いなれないようでしたが、少し会話をすると自分でしっかり作れました！ブロックを置く箇所も良かったです。「1秒待つ」を使いたかったようです。 変数が1→0に、0→1に切り替わることは言葉で理解できていましたが、前の問題で知った「押されたではないまで待つ」にとらわれてしまっていたようです。一度正解に近づきそうであったものの、また離れてしまうこともありました。また長いスプライトが苦手かもしれないです。 変数の切り替えについて、正解と同じプログラムを作成したのですが、バグで動かなかったようです（モヤモヤしたまま終わってしまいました） よければ次回始める前に確認お願いします。', null, 'タイピング: 集中して取り組めました。'),
  ('e3032148-4e16-5aa3-91ed-4f4a21d084f4', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-30', '16:30:00', null, '通常 / 検定練習', '最後だったので、やりたい検定問題を取り組みました。2級は少し難易度上げたつもりだったが、挑戦したいのことでした。じゃんけんゲームの問題だったので、案の定勝ち負けの条件の演算式がわからなったそうです。とても、変数との対応の説明していると、途中で組み合わせ方がわかり、あともう少しの考えが必要でした。ほかにも、修正のところでは文章とどのように対応していけばいいかわからず、悩んでいました。時間がなく、解説はすべてできなかったが、じゃんけんの勝敗以外の変数のやり取りはうまく作れていました・', null, 'タイピング: 集中してできていました'),
  ('02da6367-3138-5d66-920e-e6d1ca86677f', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-09-30', '16:30:00', null, '通常 / ドリル１', '前回習った角度をつける方法について、都度気にしながら作っていましたが、逆に今度は「〜歩動く」を入れ忘れてしまっている場面があったので、指を使って今出来ている動きと何が足りて無いかの具体的な説明をして納得してもらいました。 途中休憩したり友達と話す時間も少しありましたが、タイピング時から授業終了ギリギリまでPCに向かえていました。今回は8まで作ることができました。', null, 'タイピング: 少しアドバイスを教えてあげたらスコアが伸びました。'),
  ('5ed60c8b-07a7-5e27-ad13-af6d51563f5e', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-30', '16:30:00', null, '通常 / ドリル演習 レベル2', '前回から祝日でかなり空いたので、復習からしました。以外にも作ったものを覚えていて、紹介してくれました。今回は、まず円形に動くことをやっていきました。回転や向きを変えることはできていたが、肝心の動くブロックが抜けていたので、自分で気づくように誘導してあげました。次に、矢印キーで動くでしたが、最初はこれなら簡単と豪語していたが、いざ作ると、左右上下の増減の方向に悩んでいました。そこで、自らマウスで動かして座標の位置について確認して、気づいていました。やはり、座標系は定着するまで、増減含め必要そうです。', null, 'タイピング: はじめて記録を取るようにしていきました。
盛り上がり: 1つ1つ完成したらゆうさくくんに見せて言って自慢していたのが、いとおしかったです。'),
  ('e3b584dc-f363-5d92-9bf6-273a5760fc3c', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-30', '17:30:00', null, '通常 / 自由製作', '今回は、電車と打って変わって、別の作品を自由に作っていました。内容的には、キャラクターの選択画面をクオリティ高めで作っていました。文字やスプライトがフェードアウトのように消えていて、演出が凝っていました。隣のしゅうくんもできたものを見て楽しそうにしていました。', null, '盛り上がり: エクセルの話を持ち掛けると、学校でもやってないそうで、かなり興味津々でした。進めていくやる気はあるみたいです。'),
  ('91398284-6105-559a-a411-f0b5b8ac1b26', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-30', '17:30:00', null, '通常 / 縦スクロール猫ゲーム', '最初は自分の進捗を見て、全然すすでなくて、めんどくさがっていましたが、黙々に進め、半分ちょいの時間で、作り上げることができました。定義などありましたが、特に気にすることなく作れていました。完成品をちゃんと見れてなかったのが、少し心のこりです。残りの時間はバイクランで費やしていました。', null, '盛り上がり: 壮太君と競い合っていました。'),
  ('e988a135-f8cc-5a8e-83a2-fd02a42bf829', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-09-30', '17:30:00', null, '通常 / 乱数の使い道を知ろう', '踊ろうを作り終えていたので、チーズを探せに向けて、乱数を扱いました。スクラッチでの乱数の存在はスクラッチ好きの友達によって知っていたが、使い道は知らなかったです。そこで、さいころで、利便性を確かめていきました。 次に、チーズを探せでは、まずはミミの動きで、最初は向きを動きをついていなかったが、お手本を見比べてたら、自分で修正はできました。後半は跳ね返りの仕組みを作りましたが、かなり眠たそうだったので、次回復習をしてあげてください。', null, 'タイピング: たくさん取り組んでいました。'),
  ('e80072a1-a336-5b5e-9dc7-566723a2751a', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-09-20', '16:30:00', null, '【体験】', '自分のScratchアカウントでいろいろなゲームを作っているそうで、たくさん見せてくれました。信長無双？ような戦国時代のシミュレーションゲームを作成中で、今は近畿地方だけなのを、画面をスクロールして他の地方も出せるようにしたいそうです。大作になりそうなので、じっくり作って来年のU16大会を目指すのも良いかもしれません。戦国武将の話を振ると、とても嬉しそうでした。', null, null),
  ('89a389a9-e524-578e-b9ea-78c4959b99a6', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-10-07', '17:30:00', null, '通常 / 湾岸afternoon作成', '前回残っていたプレイグラムのゲームを完成させてから、今回の湾岸afternoonへと入っていきました。縦スクロールの復習部分では、前回の内容をしっかりと把握できているようで止まることなく作ることができていました。しかし、作品の内容がかなり長いと感じていたようで、湊太君が遊ぼうと誘ったところやりたくない様子を見せていました。最終的に、ある程度の区切りをつけて終えることができていたため、今後は１つの作品をいくつかに分割して進めていくと良いと思いました。', null, null),
  ('9959065e-44b5-5d0d-83b3-eb33040d4656', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-10-07', '17:30:00', null, '通常 / 物語を作ろう', '「〜秒待つ」「喋らせる」といったコードを、ほぼお手本を確認するまでもなく自発的に作っていたので、私からはストーリーをどうするかや動作に不備があった場合のアドバイスについてのみサポートをしていました。 「キャラをここまで移動させる」「歩くスチルに切り替える」なども私が提案しただけで自分で作れていたので、理解度が高いように見えました。', null, 'タイピング: なし
盛り上がり: 自分の好きな電車を物語に取り入れられて楽しそうでした。'),
  ('cf528269-33e7-5f27-8ef6-57c8c604c8a4', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-10-07', '17:30:00', null, '通常 / 【Prg】29 カミナリをよけろゲームを作ろう！', '今回は主に、クローン部分の復習を兼ねて【Prg】29 カミナリをよけろゲームを作ろう！を作っていきました。クローンのスプライトは1から作成していき、残りのコード部分に関しては本人に説明をしてもらう形で進めていきました。自分の中で、どのような動きが行われているのかをしっかりと把握することができていたため、スムーズに進めていくことができていました。しかし、面倒くさがりな性格のためか自分で考えるよりも、写してすぐに終わらせたい気持ちが出てきているようでした。知識やスキルは十分に持っているため、自分のアイデアを作品へと出すことができるきっかけがあればさらに成長できると思いました。', null, null),
  ('ad05ff43-d3a5-59e5-9ad1-036401dc9428', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-10-07', '16:30:00', null, '通常 / バナナを探せゲームだよ♪（タッチ操作可能）」 単元別演習B', '今回は、座標を使う際にx座標とy座標の方向、座標をどのようにして使っていくのかを学んでいきました。バナナを探せゲームでは、x座標とy座標の書かれた画面からバナナを見つけていく際に、座標のプラスマイナスと縦軸横軸について覚えられていました。次に、単元別演習Bにてスプライトがどのように動いているのかを視覚的に確認するとともに、座標がどのように変化しているのかを確認していきました。どちらも教えたことを素直に吸収し、座標における位置と使い方をしっかりとマスターしていました。ドリルの続きもやりたかったようで、時間がなくできなかった際には少し残念そうにしていました。本人の性格的にも向上心はかなりあるようなので、次々に新しい知識を吸収させた方が伸びていくと感じました。', null, null),
  ('2a62e579-d4bb-5481-ac5e-e4663042fd4f', '0cc61de6-7c24-5ecb-8a1f-b37027e03647', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-10-07', '17:30:00', null, '通常 / 基本的なスキルを学ぶ', '前回の乱数は理解できていたようなので、ピンポンゲームに進みました。教室でお友達が作っていたことがある、と嬉しそうでした。 スプライトのx座標をマウスのx座標にするというのはまったく思いつかなかったようで、難しい！という表情になったので、「マウスのx座標」ブロックはこういう使い方ができるということを、今回の学習で納得できればOKとフォローを入れました。 ボールがレッドラインに触れたらゲームが止まるということは見本をプレイしたときに気付いたらしく、ボールの動きのコードに続けてスラスラと条件分岐を作成していました。ただ、その後に続けて跳ね返るための条件分岐を作成したため、跳ね返るときのボールが一瞬カクカクするようになっていました。そこで、異なる処理を無理に一つのコードに続けて書くのではなく、処理によってコードをわけて個々のコードはなるべくシンプルにすることを伝えました。実際に自分で作成して動かしてみて、とても納得できたようでした。 ボールがパドルから跳ね返るコードについても、実際にボールが跳ね返るときの動きを想像してもらい、どういう動きを組み合わせるかとの発問に、向きを変えて動かすと答えて作成することができたので、細分化しながらの作成をどんどん進めて慣れさせていきたいところです。 スコアを変数で作成し、ゲームクリアを作成するのもほぼ自力でできました。 おまけの課題でクリア時に音楽を鳴らすところで、音が一瞬しか鳴らないことに困っていたので、「音を鳴らす」と「終わるまで鳴らす」の違いを説明しました。', null, 'タイピング: 熱心にチャレンジしていました。
盛り上がり: 今日は先生の人数に余裕があり、話したり質問したりできる時間が余裕を持ってとれたせいか、とても楽しそうに最後まで集中できていました。えにしくんとそうたくんの会話を聞きながら、えにしくんが聖くんに似ていて面白いなどと感想を言ったりもしていました。 ピンポンゲームがちょうど完成できたためか、スッキリした感じで帰っていきました。'),
  ('3be5f9fb-d603-5a89-a82d-957eb29de8c8', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, null, '2024-10-07', '17:30:00', null, '休み（未対象）', null, null, null),
  ('c9fe584e-30a4-55a0-99bd-882548b0d351', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-08', '16:30:00', null, '通常 / Prg51 ネコのお散歩ゲーム', '一度プログラムを見本と見比べて変数部分を修正したとに、すぐにプログラムが終わってしまう問題を直しました。送られているメッセージから見直して解決するように促したのですが、あまり自分で進められなかったのでかなり手助けをしました。「～まで繰り返す」のブロックがある箇所ではプログラムの実行順序について話しました。原因の変数が見つかって改善できたので良かったです。 岩のプログラムはほぼ終わりました。エサのプログラムに取り掛かったのですが、途中です。画面下にエサがたまって消えないので改善したいです。', null, 'タイピング: 集中して取り組めました。'),
  ('fc7e740d-4b42-546f-bb24-a792a4343aee', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-08', '16:30:00', null, '通常 / ペンツールの使い方をマスターする 図形を描く', 'ペンの使い方を前回の作品を使って思い出し、三角形と〇を描きました・（ペンの使い方であれば、点線とかをやった方がよかったかもしれないです...すみません） 直線はうまく書けましたが、その後の三角形は座標を指定してプログラムしていました。斬新な方法でしたが、「～歩うごく」と「回転する」ブロックを使うようにリクエストしました。自分でイメージをするのは難しかったので、図説した紙を見せてプログラムを書いてもらいました。角度の考え方はバッチリでした。 次に円を考えてもらいました。プログラムに困っていたので、「200角形」をイメージしてプログラムを考えてもらいました。紙面で考えてイメージすしてもらうと、自分でプログラムに落とし込むことができました。 最後に円の大きさを変えたり、直線部分を作ったりして楽しんでいました。', null, 'タイピング: 集中して取り組めました。'),
  ('5510c27e-e58d-5d7d-9952-bf5e61e032c4', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-10-07', '16:30:00', null, '通常 / 未履修のタイプの検定問題に挑戦する', '検定問題は25分くらいで解き終えていました。問題の⑧をとめる、という記載について、そもそも他のコードの動きは既にこの時点で止まっているから、すべてを止めるじゃなくて他のスクリプトを止めるにしてみた、などと、よく内容を考えているようでした。 迷ったのはそこだけで、あとは面白くできた、との感想でした。 終了前に動画も何度も見直して、自分が作ったものと動きが合っているか確認もできていました。 時間が25分ほど余ったので、5秒で止めろを見せたらとてもハマっていました。四捨五入がわからない学年のため、ボタンのコードのみ自力で作成しましたが、四捨五入にも興味を持ったので、タイマーをそのまま使うコードと比べさせてみました。四捨五入がどんなものか、おぼろげながら理解したようで、これを使わないとゲームが難しくなるんだね！と感心していました。', null, '盛り上がり: 検定も5秒で止めろも、とても楽しんで取り組めていました。以前よりも知的好奇心が旺盛になってきていて、一生懸命に質問して理解しようとする姿勢が見られました。'),
  ('62440b3d-a669-574c-b52f-5a255c44f242', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-10-10', '16:30:00', null, '通常 / 放物ジャンプをりかいしよう', '前回の復習からやっていきました。1週も空いて、？の割合が増えてしまったので、過去の自分が作ったものを説明してもらいました。前回悩んでいた下がるところのー１の掛け算は最初は忘れていたので、つけない場合と比較して思い出させました。 そのあと、放物ジャンプに移ろうとしましたが、おそらくあめの食べ過ぎで眠気が襲っていましたので、休み時間が多かったです。残り10分で落ち着いてきたので、放物ジャンプを作りましたが、変数がどうなるとかの説明があると頭に入らなそうだったので、本質の等速ジャンプと比べて、繰り返しの中でジャンプ幅画家減少することだけで滑らかジャンプになることを覚えることができました。次回、等速ジャンプとの違いを聞いてください', null, 'タイピング: 久しぶりに戻ってやっていました'),
  ('9c9d6eb6-f7a4-524a-9318-8d287fd51c79', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-10-10', '16:30:00', null, '通常 / 【Prg】ボールキャッチ 完成＿変数のリミックス', '前回自己流の方法でボールの落下と腕の動かし方のコードを入力していたため、今回は別解を教えることにしました。 ボールの落下については「もし（y座標）＞（数字）なら」を使った考え方、腕の動かし方については「もし＜右向き/左向きキーが押された＞なら」を使った考え方について、それぞれヒントを教えた上で自分で組み立てるよう指示しました。 ただ、自分の説明力不足と、授業序盤の段階から前と同じカリキュラムが続いていることに飽きている様子(これで出来ているならよくないか）だったため、教えた内容がよく伝わっていない可能性が高いです。 授業終了前に「【Prg】19 100m走」で遊ばせてみたところ興味を持ってくれたので、次回からは新しいカリキュラムに挑戦してみて、今回教えた内容と似たコードがあればその都度考え方を提示出来たら良さそうです。', null, 'タイピング: タイピング大会があると聞いて、なるべくミスタイプしないよう集中して取り組んでいました。'),
  ('2ec11315-cf52-5f51-a41f-cbc3d864e713', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-10', '17:30:00', null, '通常 / U16書類作成', '今日は書類審査のスライド作成を進めました。全体的に時間が足りなそうで焦っていましたが、スライドとゲーム自体についてそれぞれ締め切りを確認したうえで、「最低限急いで一通り完成させたうえで、余った時間でできるところまで作りこむ」という方針でやってもらうことにしました。スライドの文章はある程度すらすらと書けて、既定の量の半分くらいは埋まりました。家でも作成してくるそうです。', null, '盛り上がり: 夜更かしして眠かったようですが頑張って進めていました。'),
  ('dfa84844-bd11-523c-9ed5-03539e669ed9', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-10-10', '16:30:00', null, '通常 / 検定練習', '変数多めの問題で、最初はいやだと言っていましたが、しぶしぶ進めてくれました。今回の問題には、変数の中に数字以外の言葉が入る活用をする問題だったので、まず入れていいのか戸惑う場面がありました。変数の概念的に言葉を使うことがなかったので、そこのところを広げてもらいたいです。そのご、手をかけながら進んでいったが、修正するところがわからんそうでした。答え合わせができていないので、復習から進めてもらうといいです。', null, '盛り上がり: こたろう君のジャンプの復習にしっかりと教えられていてジャンプの理解はある程度残っていました。'),
  ('e731fcff-0cc6-51e4-9556-3cb5417f5f5b', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-10', '17:30:00', null, '通常 / 検定練習', '検定3級の練習を進めました。集中して取り組み、大きくつまずく所はなく最後まで終えられたようでした。アレンジに熱が入って長いことやっていましたが、手順書のパートは時間内にできていました。答え合わせすると「もし～なら」に入れるブロックの範囲を間違えていましたが、指摘するとすぐ自分で直せていたので理解はしているようでした。', null, null),
  ('67753b99-68e8-52cc-9c20-59b4e6c7fa11', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-10-10', '17:30:00', null, '通常 / 検定連取', '前回のものは不安要素あったと本人は言っていたが、もんだいはすべてできてました。今回のハンバーガーの問題は、機能名と変数やリストの名前が混同して物が多く、2，3か所わからずじまいになっていたところがありました。しゅうくんも、わかりずらさにもどかしくなっていました。その程度のミスだったら合格はできるが、機能名か名前かの区別がするのは、冷静に読む力は必要だと思いました。', null, null),
  ('ede75008-a555-5c41-9540-766dd678c85a', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-10-10', '17:30:00', null, '通常 / ドリル19~24', 'ほとんど一人で黙々とこなしていました。19~20の途中、どうしてもコードがわからなかった部分は答えをチラッと見たと言っていましたが、コードの順番が違っていたぐらいで「〜秒待つ」や「〜度に向ける」「ずっと〜」など以前ドリルでやったことを活かして自分で問題解決出来ている様子でした。 ただ、21の内容が少し難しかったのかやや停滞気味でした。 次回も21に取り組んでみて、やはり時間がかかるようであればアルスパーク内の見本や回答を使い、解説してから自分で作らせてみても良いのかなと思いました。', null, 'タイピング: 集中して取り組めていました。'),
  ('043542e5-9648-5e38-8d90-22c7834ead5a', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-10-10', '17:30:00', null, '通常 / 検定練習', '前回は、読み方がわからず、うまく溶けていなかったので、最初に前回の問題で、読み方のコツを教えていきました。「旗が押されたら」なら旗のブロックを持って来る、「①のあと」ならそのコードの続けて書く、わからない文章があったら、コードが名から似た文章を探す、わからなくなったら動画に戻るなど、１からすべて教えていきました。その際、本人もわからなったところが納得できた感じになっていたので、今回の問題を解きました。すると、ものの20分で解き終わり、アレンジも十分にめいいっぱいできました。間違えもなく完璧にできていました。さらに時間も余っていたので、さらにアレンジを進めて、満足気でした。', null, 'タイピング: そっこそこよくなっています
盛り上がり: アレンジで、サメが親子ずれになっているのがかわいかった。'),
  ('014dc664-beb0-5e60-8a54-06049c0eb271', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-10', '16:30:00', null, '通常 / ゲーム作成', '前回のドリルの復習を軽くして今日作るゲームに入りました。各キャラクターの動きを観察してもらい、動きについて問いかけをすると、口頭で細分化ができました。「マウスのポインターに行く」「端についたら跳ね返る」など大事なブロックは自力でうまく使えていました。途中で違う動きも作りたいと言って脱線しかけましたが、アレンジは完成したあとでやろうと伝えました。中盤まで進みました。', null, null),
  ('51b892bd-bb44-5252-afcd-4dcdb4ea5d25', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-10-11', '16:30:00', null, '通常 / 基本操作のレッスン', '先週までのオリジナル作品は完成とのことで、基本操作コースIで少し難しめのコードをレッスンした。一つ目、「コード探求【ではないまで待つ】レース順位ゲーム」は変数を使って順位を決めるロジックの作成がすぐ思い浮かばなかったことを除いて、スムーズに完了させることができました。二つ目、「コード探求【もし●●なら】だるまさんがころんだ」の、アルゴンがプレイヤーを見ている時に、動いていると負けになる仕組みを細分化して説明、「負け」になる仕組みは理解したが、コードに間違いがあり上手く動かない状態です。来週はこの部分を上手く動かす事からかと思います。', null, null),
  ('fdf6a045-7271-5e63-b206-87637786b061', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-10-11', '17:30:00', null, '通常 / プレゼン用資料の検討・作成', 'プレゼン資料のテンプレートに沿って、書き込みを行なっていきましたが、なかなか考えがまとまらず、完成まではまだ時間がかかりそうだなという雰囲気。このゲームでできること、楽しんでもらいたいことが、細々といっぱいあるようです。が、それら全てを盛り込むのは大変なので、ある程度アピールしたい事柄を絞り込んで、それを上手くアピールするようにしたほうが良いのではとは言いましたが、アピールポイントの絞り込み、まとめ方がなかなか進まない状態で、時間切れとなりました。来週も、この続きとなると思います。', null, null),
  ('64553046-77cd-583c-a9da-19b484c2b453', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-10-11', '18:40:00', null, '通常 / 大会作品プレゼン資料検討・作成', 'そもそもプレゼン資料をどのように作って行ったら良いかを、過去の入賞作品のプレゼンを例に説明。プレゼン資料をテンプレートに沿って記述し始めた。スマブラに似たゲームだけど、実際スマブラと比べてどんな違いがあるか、何かこのゲームならではのもの、何かうりになるアピールポイントを考えて、記載はし始めたものの、まだ納得できるようなものはできていない印象。また、このゲームのストーリーも頭の中で少しはイメージはできてきたけど、まだそれをプレゼンで文章化できていない状態のようです。来週はこの続きと思いますが、アピールポイントの表現の仕方、ストーリーを上手くプレゼンで表現してまとめられたらと思います。', null, null),
  ('6018588a-265d-576c-8d30-9f4c759934af', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-10-12', null, null, '通常 / 検定練習', '8,9月の変数を扱ってきたことから3級の問題を取り組んでいきました。やっていくと、変数の使ったところができていませんでした。ほかの動きや条件は2ミス程度でした。そこで、まずはレースゲームなどを振り返ってもらうと、「あああそうだった」動きのところに変数のぶっろくを入れれることを思い出したので、答え合わせした後に残りを作ってもらいました。その時は先生の助けをもらわずに、最後まで作れていたので、授業が空いてしまったことが原因で、何回か積み重ねていけば、変数の使い方もなれると思います。', null, '時間帯: その他'),
  ('9d8e9fc9-a6c3-5c78-8e07-a33c1c309934', '0047fb11-a84a-5592-8c39-5a16c20eb10e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-10-12', null, null, '通常 / 【Prg】32 タコから逃げろゲームを作ろう！', '前回挑戦したエラーで学ぶの復習から行っていきました。なぜこの作品でこのようなエラーが起こるのか、なぜこのデバッグで直せているのかをしっかりと説明することができていました。続いてタコから逃げろゲームの制作に入っていきました。資料を見ながらサクサクと進めていき、セリフなどでアレンジを加えながら最後まで作っていくことができました。しかし、難易度変更の部分がいまいち理解できていないようなので、次回その部分の説明をすることから始めていきたいです。', null, '時間帯: その他
タイピング: 集中して取り組めていました。'),
  ('d91e7f59-20ba-5f83-a8a7-8fe5d8b6510a', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-10-12', null, null, '通常 / 検定練習になれる', '検定の問題をやっていましたが、終わるまでずっと集中してできていました。しかし、スキル不足か文章の読み飛ばしがあってなかなかうまくいかないことがありました。2つの文章が混合してコード作られていることが多くありました。一緒に読んでいくと、自分で動かしてコードを持ってこられていたので、ゆっくり冷静になれば、作れて行けそうです。ただ、時間も終わるのに1時間かかっていしまったので、コードを素早く思いつく能力も必要だと感じました。', null, '時間帯: その他
タイピング: 何回も取り組んでいました
盛り上がり: 問題を渡したときも嫌な顔せずに、やる気ありげに取り組んでいました。'),
  ('13ebccba-e4dd-568b-8f8e-718d5064c4e0', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-10-12', null, null, '通常 / 検定練習', '久しぶりの検定練習でしたが、ほぼミスをすることなく時間内に終えることができました。ミスといえば、不等号の向きが逆になっていたことくらいで、変数を含めた複雑な演算式は迷うことなく作れていました。本人も不等号以外は難しく感じるところ華立ったそうです。', null, '時間帯: その他'),
  ('dd138573-f36d-5a7d-b4da-e5ebbb7fa6b8', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-10-12', '16:30:00', null, '通常 / 乱数をマスターしよう_サイコロ 【DKゲーム】02迷路 チーズをさがせ！', '今回は乱数と〜まで待つについて学習していきました。乱数は、サイコロのコードを使ってくじ引きと同じようなものだと説明したら、しっかりと理解できたようでした。〜まで待つでは、迷路ゲームのキャラクターがなぜ壁にめり込まないのか、チーズがどのようにして動いているのかを一緒に確認しながら作っていきました。キャラクターが壁で跳ね返るのが面白かったようで、数字をいじるとどのように動きが変化するのか試していました。次回の制作で作品の完成を目指していきたいです。', null, 'タイピング: 真剣に取り組めていました。'),
  ('90f53bfc-5612-5323-83e0-e9d688b91790', 'f8f1a0b4-dffb-5132-98c0-d851a7cc2e5b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-10-12', null, null, '通常 / 検定練習', '時間は10分ほど余らせて、一通りは終えましたが、１かっしょバグが残ってしまいました。探してみていたが、時間内に見つけることができませんでした。敵の球が、うまく作動していないのことだったので、バグ探しの手順を考えながら、教えていきました。それ以外はミスはなく、クローン系の問題が大丈夫そうです。', null, '時間帯: その他
タイピング: 検定に向けて頑張っていました'),
  ('2f22faf9-7117-5e34-a763-17aa9d9696f6', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-10-12', '16:30:00', null, '通常 / オリジナル作品制作', '今回もRPG風ゲームの制作をしていきました。キャラクターの攻撃モーションとエフェクトについては完成したようなので、今回はキャラクターの体力について作成していきました。体力についてはこだわっていきたいようで、どんなものがいいか相談しながら作成をしていき、デザインなども試行錯誤していました。しかし、作品に対する熱も薄れてきているのかいまいち集中していないと感じられる部分も見られました。なので、本人の入れたいものをどんどん取り入れていき、作品に対しての熱を取り戻すことも必要かもしれません。', null, 'タイピング: 集中して取り組むことができていました。'),
  ('4f8b3ad3-2d98-5b36-b4e1-1da484dc5e77', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-10-12', '16:30:00', null, '通常 / 大会書類作り', '提出に向けた、資料つくりをしていきました。機能や誰向けとかの要素は最初から作れていましたが、アピールポイントが不足していたので、深堀していきました。その際、普段のプリケーションと違ってどのようなところがほかと違うか考えてもらい、こちら側の提案としては、なぜ、多目的トイレのマップ要素を入れたか？なぜアプリのアイコンの大きさがでかいか？などしました。その提案で、力になれたような気がします。', null, null),
  ('881215b3-484f-5653-abde-72a1f4a066a7', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-10-12', '16:30:00', null, '通常 / 大会提出資料作成', '大会提出まであと2週間ということで、書類選考用の資料を作成していきました。作品自体はまだ完成していないようですが、どんな作品となるかは決まっているようなので完成した際のイメージを書いていきました。以前の大会入賞者作品を見て、自分の作品においてアピールしていく箇所はどこなのか、どんな説明がいい評価をもらえるのか悩みながら作っていました。今回で半分ほどはできていたので、残りの部分を家と来週来た際に完成させていく予定です。', null, null),
  ('880ae6b5-d7ae-5cb1-925f-b36c8b660a5d', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-10-12', '17:30:00', null, '通常 / 検定３級最初の問題', 'コンテストの話を切り出したりしつつ最初にタイピングを促しても、やりたくない、コンテストに興味ないとの事でタイピングはスキップ。最初の10分くらいは、自分で何か作りたいとか、以前作ってたインベーダーゲームをやりたい等々、検定問題に取り掛かってくれない雰囲気。何かのゲームをプレイしていたので、雑談して雰囲気を和ませつつ、なんとか検定３級問題（最初の問題）を開いてもらい、始めることができました。文章通りに、一発で、きちんとプログラムを組むことはあまりできていませんでした（例えば、「ずっと」を入れ忘れる、「もし」を入れない、使うブロックを正しく判断できない等、こちらのアドバイスがまだ結構必要な状態）。なんとか、この検定問題のプログラムは完成させて終わることはできましたが、わからない部分があって、（ヒントを出しても）その状態が続くとイライラしがちで、そうなると、なかなかコミュニケーションが取りづらくなることが多く、対応に苦慮しました。（結局こちらが答えを教えることも多く、どんな対応をすべきか悩みました）', null, null),
  ('1427b7fa-8428-509f-8bed-c48d537978fa', '6bf53ba4-9ba1-58d0-a1b0-ac00d8cdce67', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-10-12', '17:30:00', null, '通常 / 大会提出資料作成', '知弘くんと同様に、提出まであと2週間ということで資料作成に着手していきました。こちらも作品が完成していないようなので、完成した際のイメージをもとに作成していきました。ゲームで使用されているキャラクターやアイテムのスクリーンショットを使い、ゲームに登場するものを画像付きで紹介するページを作成していました。その他にも、アピールぽいんとでは、自分が推していきたいゲームの特徴をしっかりと書き出すことができており、順調に作成を進めていました。今回である程度完成まで持っていくことができていたので、残り部分は家で仕上げてくるようです。', null, null),
  ('e69311c9-dac3-5c87-bf06-99141163714a', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-10-12', null, null, '通常 / 乱数と「～まで待つ」を使えるようになる', 'サイコロのプログラムは、見せた瞬間に「ランダムに出るやつだ！」と発言したので、「ランダム」を知っていることを褒めると、「ランダム」について一生懸命に説明しようとしてくれました。おかげで導入はスムーズで、コスチュームの乱数もすぐに1～6にすると気づけていました。「○○に触れた」と「スプライトが押されたとき」を少し混同しているところはありましたが、作業をしながら思い出すことができました。 チーズを探せはなるべく丁寧に、口頭での細分化をして紙に書きだしてから始めました。口頭での説明はわりと的確で、プレイヤーのネズミが「向きをかえて」から「動く」というのも自分から言えたため、条件分岐後のコード作成もスムーズでした。 条件分岐の際に「ずっと」を使うことをなかなか思い出せないなど、過去の学習内容が定着していない面もありますが、細分化して見せた動きをコードに置きかえるのはわりと良くできていました。壁のスプライトにぶつかったときの動きを「もし触れたら後ろに下がる」と言語化ができたり、チーズがランダムな場所に出てくるのを「乱数と座標を使えばできそう」と言ったりと、センスを見せるときもあるのですが、過去の作品を覚えていないこともあるので、今後の課題は口頭での細分化をしてからの方が記憶に残るかもしれません。', 'チーズを探せの虫の動きとスコア作成、ゆうれいの効果を考える', '時間帯: その他
タイピング: こだまの森で2回ともランクAを出していました。QやPなど端の方のキーを小指で打とうとする姿勢が良かったです。
盛り上がり: 今日は全体的に納得して進めることができたせいか、最後までしっかり集中して頑張る事ができていました！'),
  ('e4608880-59a0-543d-b66d-22c0c8612075', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-10-12', null, null, '通常 / ドリル１問題９〜１２', 'ドリルの問題をスムーズに解いていました。また、プログラムを作っていく中で、もっとこうしたいああしたいと色々発言していて、発想力があると感じましたし、ドリル１は余裕にできるくらいの力はあると思いました。残り２０分で、ドリル２に挑戦してもらおうとしたら、今日はもうドリルは終わりにしたいということで、残り時間は、オリジナルのゲームというか、スクラッチでのちょっとしたアニメーション作成をして終了となりました。ドラゴンボールにハマっているみたいで、悟空やベジータを使って何か動きを表現するもの（猿に化ける、カメハメは出す等）を作ろうとしていました。', null, '時間帯: その他'),
  ('cece8ee7-78ea-5071-a601-610d3057db5b', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-10-12', null, null, '通常 / 検定練習', '2級の1回目のロケットの問題をやっていきました。計算問題を正誤判定のところが悩みこんでしまい、時間が過ぎてしまいました。文章の構造的に、変数の乱数指定が計算式を訊くことより後の文章だったので、答えが合わず困惑していたそうです。また、変数の和が答えになるような条件式の組み立てもうまくできてなかったので、次回問題の復習から始めた方がいいです。後半のコードを修正していくところも手を付けられていないので', null, '時間帯: その他
タイピング: 集中してやっていました'),
  ('906b30d4-148a-5833-a3e1-6c837f739ee0', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-10-08', '16:30:00', null, '通常 / バグを探して修正し、作品を完成させる', '前回の時点で、どこがおかしいかということを自分で把握しているようだったので、説明をさせてみました。どのスプライトのどこの動きがおかしくて、このコードは自分で確認してみた、というところまで、自分の言葉で話すことができていました。 戦闘機のスプライトが左右の端にいくと動かなくなってしまうというのは、端にいったときのx座標と演算式で使用しているx座標に注目させると、自分で直すことができました。 途中で敵が出なくなるというのは、単にプログラムがきちんと動いていなかったのか、一度停止ボタンできちんと止めてから再度実行すると解決しました。 アレンジについては初めは面倒そうな反応でしたが、前にやったカミナリをよけろのアレンジが良かったと声をかけると、コスチュームを変えてファンタジーっぽいゲームにするアレンジを一生懸命に始めました。一通り見た目を変えて満足したのか、残り10分くらいで「今日はここまででいい？」と聞いてきたので、次回から新しいことをやろうと声掛けをしてフリータイムに切り替えました。', null, '盛り上がり: スプライトの見た目を変えてゲームの雰囲気を変えるのは好きなようで、楽しそうに取り組んでいました。以前のように、手書きでごちゃごちゃさせることもなくなったようです。'),
  ('4936bb3e-ffab-5ceb-a207-967c2006ec70', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-15', '16:30:00', null, '通常 / 検定2級2回目にやる問題', '時間より早く終わったようですが、読み飛ばしの部分があり残念でした。判定の部分でよい考え方ができていましたが、「かつ」と「または」の使い方を置忘れてしまっていたので、詳しく復習しました。また検定の独特の記述に慣れ切れていない様子です。進めるときにこちらから促す部分も多かったのですが、数をこなせば慣れるかな？というイメージです。', null, null),
  ('84278cb1-c452-5fe3-96e1-e4be8594298e', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-15', '17:30:00', null, '振替 / 大会に向けたスライド作成', 'AIが推してくれたポイントとして「バッテリー残量の管理」があったので、話しながら深めてスライドにしました。あまり書きたくない様子だったのですが、バッテリーの使い方や存在について作品中でほぼ言及されていなかったため、私がかなり説得して記載してもらいました。文章が多かったのですが、しっかり記載することができました。 スクリーンショットの仕方はほぼ知っているようだったので、詳しく説明しませんでした。次回、アピールポイントを1つ増やし（推し場面集でもいいかも?）スライドを整理するようです。', null, 'タイピング: 集中して取り組めました。'),
  ('7e176d08-01ac-56dd-80d4-29e5f0763d4b', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-15', '17:30:00', null, '振替 / Prg51 ネコのお散歩ゲーム 過去の作品のアレンジ', 'ネコのお散歩ゲーム：ドーナツが消えないバグ、距離が加算されない問題を、動画を見ながら解決しました。メッセージのミスや表示・非表示を忘れていたようです。諦めることなく自分で解決できていて良かったです。満足そうでした。 過去作品アレンジ：Scratchで作品を公開させることを説明し、迷路の作品の道幅を調整したり終わりの画面を作ったりしました。作品のアピール文はまだなので、次回取り組む予定です。', null, 'タイピング: 集中して取り組めました。'),
  ('ee4bc54e-a58c-512c-9fae-7a69a3cdf4f9', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-15', '16:30:00', null, '通常 / 検定2級1回目にやる問題', '最初は比較的根気強く取り組んでいましたが、判定の部分で集中力が減ってしまったので、話しながら一緒に進めました。プログラムについては十分できている（大きさの判定を逆にしてしまったくらい）のですが、制御のブロックを通したプログラムの実行順序の整理が苦手なようです。また文章を根気強く読めていないので、集中力の向上も兼ねて何度か練習が必要そうです。', null, 'タイピング: 一度間違えてしまうと少しイライラする傾向があるようです。'),
  ('1acd31b3-47b6-5254-a50e-e1d9d47d3439', '7aa558fb-4f40-54f9-9e0c-ab1effa97eba', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-17', '16:30:00', null, '通常 / 初回。レベルチェックと基礎を進める。', '角度の概念の共有。座標はある程度理解して自分でも使ってきた様子。普段自分が使わないブロックがあるので、今後いろんなものに触れてなれていく必要がありそうです。メッセージの存在はもう知っていました。すごい！！ アニメーションよりゲーム派だそうです。人のプログラムをいろいろ見るのも好きな様子です。けいとくんと仲良くなっていました。', null, 'タイピング: あまり得意ではないようですが、頑張っていました！'),
  ('dfd1093f-5414-5641-a9c9-3b1b8df631d7', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-17', null, null, '通常 / 検定準備', 'あまり集中力が続かないようでした。 答え合わせをすると読み飛ばし多く、こちらが指摘すると気づいて修正することはできていました。また1箇所だけプログラムの順番ミスがありました。 制御のブロックを使った少し複雑なプログラムや、文章を読むことになれる必要があるかな？と思います。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('8d0cc347-284e-52da-9314-101262563eda', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-17', '17:30:00', null, '通常 / へのゲームの修正 5秒で止めろの作品公開準備', '前半は今までに作った作品の修正をしました。ゲーム性を高めたかったようです。プログラム的には短いスクリプトが多いので、もう少し長いものになれてもいいかな？と思うのですが、本人が満足そうで良かったです。 後半は作品公開の準備をしました。億劫そうでしたが、隣のゆづきくんと一緒に頑張って記入できました。作品のチョイスも丁寧に行っていました。 今のところ選んでいる作品は一つですが、他にも公開したいものがあれば増やしてもいいかもしれないです。', null, 'タイピング: 集中して取り組めました。'),
  ('f8937ac7-9fc7-5ff7-9246-69df2b91a2f6', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-11', null, null, '通常 / 基本操作コースピンポンゲーム', 'ボールが壁で跳ね返ってあちこちに動かすプログラムがパッと作れませんでした。制御のブロックまで考え方が追いつかない様子です。また「跳ね返る」という物理現象を説明するときに角度のワードがなかなか出てこなかったので、今後少しずつ慣れていく必要がありそうです。 一方で、初期位置の設定をよく覚えていて、ボールの初期位置を自分で考えてプログラムできました！！次回はスコアからですが、変数を使うことは覚えているようです！', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('52dd4d69-45f0-563f-b4a1-da4a26084468', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-11', '17:30:00', null, '通常 / サイコロくんの冒険の作品公開準備', null, null, 'タイピング: 集中して取り組めました。Scratchでの作品公開準備/アルスパーク'),
  ('82ffbe3a-b056-58b4-aba6-caf52fd6f1ab', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-10-17', '17:30:00', null, '通常 / ドリル19-24', '前回は初対面だったのであまり質問されないまま集中していたようでしたが、今回はすぐに「わからない」と聞いてきてくれて、前回の目標だった24まで無事終わらせることが出来ました！ わからないと言われたものに関しては、前回プログラミングした動きと似ている箇所があり、ある程度は自分で完成させていたため、考え方の方向性だけ教えてあげました。 まだ本人に確認していませんが、おそらく次回もドリルに取り組みそうです。 25~29の動き自体は前回作ったものと似ているので、次回もこの調子で進めればいいなと思います。', null, 'タイピング: 集中して取り組めてました'),
  ('56f2a6ae-59ee-5914-a070-66388d69e34d', '57f45872-1f3e-5540-b676-bf9023444e39', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-17', '16:30:00', null, '通常 / ⇒今日は、息抜きしながら放物線できるといいのだが ⇒バイクランのコンテストが再開しているので、それを遊びつつ ⇒バイクランの手順書みながら作成するか？ （ジャンプも出てくるので、作品作りながらだと理解が進むかも）', '近くにいたりょうやくんとよく話してしまい、集中して進めることができませんでした。バイクランも遊ぶ方に夢中になってしまい、なかなか作成を始めることができませんでした。 スタート画面のプログラムも何度か声をかけたにも関わらず、自転車の方にプログラムをしてしまいました。自転車の動きのプログラムもかなり億劫そうでしたが、なんとか取り組めました。距離のプログラムと地面にいるかの判定については、質問に答えてもらいながらプログラムの仕組みを確認しました。あまり理解できていなかったです。次回続きです。 もう少し落ち着いてほしいです。', null, 'タイピング: 比較的集中して取り組めました。'),
  ('4aff16b1-dffa-5f7d-b357-5690e4f1de8a', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-17', '17:30:00', null, '通常 / ⇒検定の息抜きするか？1級の「リスト」をマスターするか？ ⇒「リスト」のマスターの場合、アルスタジオのレッスン、 「問題の多いクイズ屋さん」超基礎で自信つけるか？ https://app.arstudio.fun/contents/3362', '動画を見ながらリストの使い方をやったあとに、変数を出題番号として扱い「～回繰り返す」を使うことで、少ない手数で繰り返し出題できることをおさらいしました。ヒントを少し出すと、自分で考えてしっかり取り組めました。またいくつかのリスト系のブロックについて、使い方を紹介しました。 その後、問題数を増やしてもらって乱数番目に出題されるようなプログラムを考えてもらいました。 リストから削除するブロックやリストの「長さ」を紹介しながら乱数ブロックと組み合わせてうまくプログラムできました。大枠については自分でよく考えられていました。', null, 'タイピング: 集中して取り組めました。'),
  ('28cc5aab-bbb2-58b9-8239-c86d191fd6a8', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-17', '17:30:00', null, '通常 / 3級が慣れてきて、問題はなさそう ⇒先週と連続になるが、検定をやるか、あるいはゲーム制作と並行するか？', '本人の希望で検定問題に取り組みました。嫌いではないそうです。 途中ひとりごとが多かったですが、自力で取り組めました。「より小さい」の不号の向きが分からなかったようですが、その他にスキル的なミスはありませんでした。一方で、問題の読み飛ばしや数値の読取りミスでいくつか間違いがありました。もったいないことを本人にも伝えましたが、分かってくれているかどうか。。。', null, 'タイピング: 集中して取り組めました。
盛り上がり: 検定中も楽しそうに取り組んでいます。'),
  ('95caf262-f9d3-5dbb-af16-d9712323df38', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-17', '16:30:00', null, '通常 / ⇒前回検定「2級 S011」見直しがまだのようなので、復習かねて見直しからでよいかな？ ⇒検定が嫌そうかな？ 様子みて ①「ガサガサ探検隊」のゲーム制作してもいいよと声かけてみて。 ②バイクランコンテスト再開してるので、遊んでから手順書みて作成', '検定の見直しがどうしてもいやそうだったので、バイクランを作成しました。遊ぶ方に夢中になり、作成までにはかなり時間がかかりました。 みちの色をグラデーションにアレンジしていましたが、手順書を見てプログラムに支障がでることに気づき、修正していました。うごいた距離のプログラムの仕組みはよく理解できていました。地面にいるorいないの判定は、理解できたか微妙です。着地の定義まで作成しました。', null, 'タイピング: 集中して取り組めました。'),
  ('b9988b97-3711-565c-8b29-f6f23ddb7ee6', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-10-18', '17:30:00', null, '通常 / 約束したドリルを終わらせる', '途中少し脱線しながらも、ドリルを３つ終わらせることができました。途中ドリルで指定された以外の動作をしたいらしくて色々と脱線したりしていましたが、「きちんと今のドリルを終わらせてからしよっか」の言葉を素直に聞き入れて集中して、後半一気に２つのドリル(19,20)を終わらせて、約束していたゲームタイムとなりました。後半は、頑張って楽しく取り組んで言いたと思います。', null, 'タイピング: 集中して取り組んでいました'),
  ('dd9d26cc-bbb6-5ba5-bc94-fca11f7d462c', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-10-18', '18:40:00', null, '通常 / 基本操作コースピンポンゲーム続き', '前回の続きで、基本操作ピンポンゲームの”5.スコアをつけよう”から。スコアのために変数を使うことはきちんと理解している様子。スコア用の変数を作る際に、「スコア」という普通の名前をつけるのではなく、適当にタイピングして意味不明な名前をつけては消したりして、変数名を決めて使えるようにするまで結構時間を要しました。「スコアを１ずつ変える」のブロックを使えばよいことと、それを適切な場所に配置するのも、結構ヒントを出して時間がかかりました。また、スコアが一定数に達したら(5に設定)ゲームを終了させる処理で、ゲーム終了時の文字表示が、またしても、適当タイピングで意味不明な文字を使うとのことで、そのまま使わせました。「スコア=5まで待つのブロック」を使うことまではヒントを出してできたのですが、５の入力が日本語入力だったため、期待通りに動かず、私が焦りましたが、英数字の5で入力し直しすことできちんと動作しました。これをきっかけに、日本語の数字入力だと、コンピュータは理解できないから、数字の入力の時は英数字を使うようにしようとは伝えました。ピンポンゲームを完了させて終了です。今回初めてあさひ君を担当しましたが、全体的に、脱線がする事が多くて、予想より時間がかかってしまったなと感じました。', null, 'タイピング: 使う指、ホームポジションを意識しながらかなり集中していました。'),
  ('62aaf8c1-5f46-52f9-9753-0f03b358cbcf', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-10-19', null, null, '通常 / 検定２級②', '何個か上手く行かないところがあったようで、検定の４０分内に終了させることはできませんでした。特にジャンケンでの勝ち判定処理の部分が作成できなかったようで（（グーの時とき、かつ、相手がチョキの時）、または、（チョキの時、かつ、相手がパーの時））といった条件文が入れ子になる複雑なケースなので、初見でこれは確かに難しいと個人的にも感じました。これに時間をだいぶ費やしていたので、「６０％正解できれば合格するから、わからないところは後回しにして全体をまず終わらせみては」と、時間配分についてのアドバイスもしました。上記の処理部分が作成できなかったことにより、デバッグもきちんとできておらず、正しい動作がまだ出来ておらず、答え合わせもできていません。', '今回の続きで、正しい動きになるよう修正と、答え合わせからすれば良いかなと思います。', '時間帯: その他'),
  ('05cb3392-06e8-5c84-b5ea-ef3beed0b84b', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-19', null, null, '通常 / 検定練習、変数の使い方', '検定の練習としてではなく、ゲーム作成として導入することで楽しく始めてくれました。途中で「ける向き」という変数が出てきたときに、同じく向きの変数を使ったバレーボールを振り返りました。スプライトの向きと変数の値が対応することを覚えていました。「まで待つ」「まで繰り返す」といった複数の制御ブロックも使い分けることができていました。レッスンの最後の方で完成し、きちんと動くことを確認できました。', null, '時間帯: その他
タイピング: いつもよりも集中していました。'),
  ('3954d4ac-bb13-5722-89f3-3fa88d9476d5', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-10-19', null, null, '通常 / 演算式への苦手意識をなくす', '前回が少々挫折気味だったようなので、演算式への苦手意識を少しでもなくすことを目的に、ゆっくりと復習をしていきました。「聞いて待つ」の「答え」と、変数を使用した演算式をイコールでつなげることが思いつかなかったようで、ヒントを出しながら少しずつ考えていくよう誘導しました。「答え」の使い方がよくわかっていなかったこと（過去にやったはずですが、忘れていたようです）と、数値を使った演算式はScratch上できちんと計算してくれることがイマイチぴんときていなかったようで、一度演算式ができあがると、納得できたようでした。 演算式を使って、座標が○○になるまで繰り返す、などのブロックは、しっかりと自力でできていました。 同様の問題になれるため、九九のゲームで数値を乱数で入力するところと、正解を出すための演算式のところだけ自力でやらせてみましたが、こちらはすぐにできて、少し自信もついたようでした。 残り20分は息抜きとして小技をやりましたが、検定問題で扱ったばかりのスプライトの配置が関係していたため、興味を持って楽しそうに取り組むことができました。', null, '時間帯: その他
タイピング: 淡々と取り組んでいました
盛り上がり: 前回の作品を見せてと声掛けをしたときはテンションが低くて心配しましたが、悩んでいたところの整理ができるとスッキリしたのか、他の箇所は熱心に解いていました。 後半の九九と小技ではだいぶ笑顔も戻ってきて、小技の作品のアレンジを楽しそうにしていました。'),
  ('fc20ffe7-0d1d-58f9-8bdd-f32c7b4bc1f3', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-19', null, null, '通常 / U16書類作成', '締め切り間近のスライドの作成を進めました。表紙にはレギュレーションがあることを伝えて差し替えてもらいましたが、それ以外は自分のやり方で凝ったスライドを作っていきました。一通りできたところで色々な先生が見てフィードバックをしました。スペースが空いたところに画像を足したり、文字が多すぎるところはページを分けて見やすくしたりというアドバイスをしたところ、納得してくれました。締め切りまでにもう一回自主的に教室に来て、ゆき先生と話して作業したいとのことで意欲的でした。', null, '時間帯: その他'),
  ('8ffb6787-7f9d-5636-8dfb-9ac53f320011', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-19', null, null, '通常 / 検定練習', '久しぶりのレッスンでしたが、作るPKゲームが楽しそうなこともありすぐにスイッチが入っていました。3級に挑戦するにあたって、プログラミングのスキルは十分あるので、問題文を読むということに慣れていこうと話しました。途中、細かい数値を読み間違えたり、複雑な文だと内容を誤解したりということがありました。しかし、読み返すよう促すとすぐに理解することができ、モチベーションも下がらずに保てていました。無事完成させられました。', null, '時間帯: その他
タイピング: ココアタイピング内のタイピング試験を頑張っていました。
盛り上がり: 親子大会で優秀作品に選ばれたことをお祝いすると、改めて喜んでいました。'),
  ('8624538a-3380-5c69-aa55-ed92f38f7d08', '82396ac6-71bd-59d4-a372-57212866fd5d', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-10-19', null, null, '通常 / DKゲーム02迷路チーズを探せ', '前回の続き、迷路の壁を通り抜けできてしまったり等、修正必要な部分を修正。壁に触れた時に後退する移動量より、前に進む移動量が大きかったためでした。なぜ壁を突き進んでしまうのかの状況をきちんと理解した上で修正できました。その後、邪魔者を表示させて触れたらゲーム終了させる処理を作成。さらに、思いつきで音を追加したり、敵と邪魔者のクローンを追加したりしていました。次回は、新しいことをしても良いのかもしれません。', null, '時間帯: その他'),
  ('32d27d66-804b-5b19-890b-5384cbb16492', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-10-19', null, null, '通常 / 乱数と「～まで待つ」を使えるようになる 続き', '前回「チーズがランダムな場所に出現る」と言うところまでは理解していたので、お手本のゲームを別タブで開かせて適宜見返すようにアドバイスしました。 おばけがチーズのようにすぐ出現しないでバラバラである理由を考えてもらうと、すぐに理解したのか作成できていました。 また、当たるとゲームオーバーになる虫のランダムな動かし方が難しそうで、頭を悩ませていました。近くにいた真美先生から「どう動かせたらいいのか」という具体的なヒントをもらうと、理解して自分で組み立てていた様子でした。', null, '時間帯: その他
タイピング: 集中して取り組んでいました。'),
  ('2bd661b5-989d-5d8c-a165-bda8537a34d7', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-10-19', '16:30:00', null, '通常 / ドリル', '元々13~16まで進める予定でしたが、かなり順調で授業が始まって30分以内に目標の16まで達成していました。 18まで一旦進めたあとは少し休憩をし、その後は一気に21まで集中して取り組めていました。本人にどのくらい難しいか聞いたところ、「中級ぐらい」で楽勝とまではいかない難易度だったレベルらしいです。 ここままのレベルだったら正直もっとやれそうだなと思い、「次回もドリルがやりたいか、ゲームがしたいのか」を一応聞いて見たのですが「ドリルは好きでも嫌いでもないからどっちでもいい」とのことでした。難易度的に21以降も簡単そうであれば、もう少し難しい内容のものを考えてみてもいいのかなと思いました。', null, null),
  ('f6f99d03-86a6-5fff-ab9e-be96c1352a6c', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-10-19', '17:30:00', null, '通常 / 基本操作コース_07_06ピンポンゲーム【ゲームに勝ったとき】', '作るゲーム内容を紹介した時点から、ドラゴンボールに絡めたアイデアをしたい！と言うことを伝えてきました。本人の難易度的に見たらすぐ再現できるレベルとのことでした。 ただボールの跳ね返りがちょっと難しかったのか詰まっており、近くにいた真美先生から具体的な説明をしてもらって完成させていました。 選ぶスプライトもただの棒ではなくドラゴンボール由来の如意棒に、筋斗雲のようなスプライトは無かったので雲と月が見える景色を選んで工夫していました。 跳ね返るボールの色差分をいくつか作っており、点数が５点増えるごとに速さが変わるようなプログラミングを自分で組んでいました。途中、「ボールをただのグレーじゃなくてシルバーのものにしたい」と悩んでおり、横に見本でグラデーションを使ったシルバー感のあるボールをお手本で作ってあげたところ、スポイトを利用してすぐ似たものを作れていたので応用力があるなと感じました。', null, null),
  ('55c09732-4d06-5c89-8696-6df8b8556dd5', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-17', '16:30:00', null, '通常 / ダイヤを探せ完成', '完成させることを目標として示してから始めました。prgの動画を参考にして進めましたが、見た目の演出の部分は難しそうだったので、重要な動作に絞って見てもらいました。座標を決めるのに乱数を使いましたが、あまりピンときていないようだったので軽く復習しました。「誰が何したらどうなる？」という問いかけは何回かしましたが、それにはきちんと答えられていました。いつものように集中が途切れてしまうことはありましたが、その都度戻ってきて再開することができました。一通り完成させることができ、「アレンジは完成したあとで」という約束通りアレンジを加えていました。', null, null),
  ('4b1e8f82-8f0a-510f-827b-efb23b763a18', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-17', '17:30:00', null, '通常 / U16書類作成', '今日もU16の書類作成を進めました。スライドに書かれたゆき先生のフィードバックをもとにして、内容を修正・追加していきました。今日で最低限提出はできるくらいの完成度にもっていくことができました。スライドに画像も入れていたのですが、スペースが空いた場所にもう少し画像を増やしたほうがよりよいなどとアドバイスしました。書類提出までに振替分が残っているので、できればそこを修正するとのことでした。', null, '盛り上がり: 冷静に作業を進められていました。'),
  ('20a8bc6d-3fbc-5273-9691-6813787f6368', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-17', '17:30:00', null, '通常 / 基本操作を進める、ピンポンゲームの応用', '検定から基本操作コースに戻り、スロットに取り組みました。スロットを回すときに「まで待つ」と「まで繰り返す」を両方使おうとして混乱していたので、使うのは片方だけでいいというヒントを出すと、「このスクリプトを止める」も組み合わせてうまく作れていました。数字の切り替わりが速すぎることに気付いたときは、ピンポンでもやったように「〇秒待つ」を使って処理のスピードを抑えることができていました。当たりの判定を作る時に、初めて使うコスチューム番号のブロックを説明したところ、番号自体については理解していました。しかし、「何と何が等しかったら当たりなのか」を考えるのが難しかったようでした。ゲームの形として完成させることはできました。', null, 'タイピング: 文字入力に慣れてきています'),
  ('c707d181-0d76-5e53-9ac0-d274dd9daa70', '726bac59-fe00-5b0b-a344-344f40441b6d', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-10-21', '17:30:00', null, '通常 / 物語を作ろうのアレンジ', '新しい学習より、前回作った物語のアレンジをやりたそうだったためそのまま続きをやらせました。 ただ、授業内での目的が無い状態でスプライトの調整に夢中だったので、 前回迷路で習ったことを活かせるように、 「キャラクターにランダムなセリフを言ってもらったら面白くない？」 「旗が押された時にランダムにいろんな乗り物になったら面白いよね」 「家に帰っていく人物家の中に入って消えたら、電車が右から左に動くようにしたら？」 といった提案をしました（あまり前向きに聞き入れてはくれませんでした）。 次回もアレンジの続きをやるつもりだったので、「今まで悩んだプログラミングを駆使して考えていこうね」とは伝えました。 次回は管理画面を見ながら今まで習ったことが活かせるような組み方をもっと提案していきたいです。', null, 'タイピング: 集中して取り組めました。'),
  ('b64f2d47-39e7-5735-bfc5-ff3315b732bb', '1bbe2a0f-f9eb-54c9-a13c-84a2165814c4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-10-21', '16:30:00', null, '通常 / ドリル練習', '前回やりたがっていたドリルの続きをやっていきました。最初の問題が、いろんなキーで動かすものだったので、前回までやっていた動きを復習させてみました。動きに関して、コスチューム変化などはよくできていましたが、やはり「向き」と「回転」のブロックの区別がついていませんでした。向きをいじることが「何度に向ける」だけに結びついているようです。その辺は、普段の学校での学習まちかもしれない。右側の画面で動かして終わってしまう問題は、低学年から入ってきた子の共通して、位置確認の際に動かした名残があるかもしれないです。動きと大きさを組み合わせたものは、並列になることなく、順番通り組み替えていたので、コードで作る初期化の意味を大切にした方がいいかも', null, 'タイピング: うでだめしを必死に取り組んでいました。'),
  ('c385ad20-8f6a-55de-99a4-d1f2c38b301f', '96e2b5ff-ee56-5c41-8402-2c136f7287e3', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-10-21', '16:30:00', null, '通常 / ドリル１', 'レベル１の最後まで今日中に終わるだろうと思い提案しましたが、途中別の部分に凝り始めたので、一旦終わらせることより本人のやりたいことを尊重してみました（大体授業終了15分前ぐらいのことです）。 11の「複数のスプライトをそれぞれ交互に変える」を取り組む際、 アルくんのスプライトがダサい！とのことで、好きなものを選ばせると、 ドラゴンとパンサーのスプライトを使い、2つのスプライトを変えることで4コマ漫画のようなドラマを作ろうとしており、課題にユニークに取組もうとしていました。', null, 'タイピング: 画面がバグってしまったようであまり集中できていない様子'),
  ('83663adb-bded-5c8b-b0b6-c21676b91055', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-10-21', '16:30:00', null, '通常 / 敵の球を弾幕上に変えよう', '前回作っていた野茂を弾幕上に変えていくことをしていきました。ただのコード写しだけじゃ、できないことを本人はわかっていたので、修正点を作ること集中できていました。だが、できなそうな雰囲気が見えてきてしまうと、やる気が急に下がって別のゲームに移ってしまいそうになりました。こちら側から、見直せる点を指摘していたが、バグは残り続けていた増した。ただ、以前よりかは先が見えないことに関しても集中力は興味がついた気がします', '検定練習', '盛り上がり: えにしくんがやっていたロボロックスにかなり興味を示していたので、検定2級にやる気が出ていました。'),
  ('7ef0e2e6-e42a-5a0c-afe0-e3b18bc94385', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2024-10-21', '17:30:00', null, '通常 / ロボロックスに触れよう', '今回、ロボロックスの話を振りかけると、かなり興味を示して取り組んでくれました。導入は難しいものの、ずっと集中していて内容にはまっていました。', null, null),
  ('d14b2a67-0465-539e-9225-8b5ff0ea2487', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, null, '2024-10-22', '16:30:00', null, '休み（未対象）', null, null, null),
  ('09760c66-58a9-50b0-8c87-356ae85b2714', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-22', '16:30:00', null, '通常 / 検定練習', 'コスチューム名が一致するかどうかの判定など、コードが長くなる部分でかなり苦戦していたので、注目すべきポイントを示すなどして一緒に進めました。ただ、最初に苦戦したことによって簡単な部分でもモチベーションが下がってしまっていた様子でした。今日進んだのは全体の半分未満で、長い問題文への耐性をまだつける必要があるようでした。', null, null),
  ('ae345c10-3182-5858-bd57-41b80d877c38', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-22', '16:30:00', null, '通常 / 最後の作品づくり', '教室に来るのが残り2回ということで、prg50付近の難易度の高いゲームに挑戦して終わろうということになりました。いくつか遊んだ中でシューティングゲームに興味を持ったのでそれを作ることにしました。画面のスクロールなど難しい部分もありましたが、今までの内容を思い出してあまり詰まらずに理解できていました。自分で好きなゲームを選んだのもあり、全体的に集中して進めることができました。', null, 'タイピング: 集中していました。'),
  ('252c3da3-3d33-5d4a-8f6c-179f3e9a0c96', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-22', '16:30:00', null, '通常 / 検定練習', '検定について合格条件など細かいところが気になったようなので改めて説明したあと、4級の問題に取り組んでもらいました。時間に余裕を持って解き切ることができ、アレンジもたくさんやっていました。その後答え合わせをしましたが、「止める」ブロックの使い分けや、使うブロックが直接書かれていない部分を含めて完璧で、それらを自分で説明することもできていました。', null, '盛り上がり: コンテストのバイクランを初めてやって楽しそうでした。'),
  ('8f06f961-a446-506a-a824-fca99f223feb', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-22', '17:30:00', null, '振替 / U16作成', '最初はゲーム本編の作成に乗り気だったのですが、書類締め切り直前のためスライドの作成をやってもらいました。本人としてはスライドにあまりこだわらず先週までで完成したつもりだったようですが、「せっかく面白いゲームを作ってるからスライドでも審査員の人に興味を持ってもらわないと」と伝えました。体裁をなしていない場所もあったので一緒に修正していきました。今週金曜日にまた教室に来るのでそこで提出できそうです。', null, null),
  ('cc954b13-421f-54c9-95b7-803aca075f21', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-22', '17:30:00', null, '振替 / U16作成', '書類作成のラストスパートを進めました。内容に加えてデザインにも気を配りながら作成していきました。ゆき先生からもアドバイスをもらい、情報を詰め込みすぎず言いたいことが伝わりやすいスライドができました。細かい表記ミスなどもいくつか直し、完成版を出すことができました。', null, null),
  ('76003477-ba64-567e-ab1f-caf182ef5fa9', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-10-18', '16:30:00', null, '通常 / 検定2級応用課題1', 'Scratchに出したい作品は前回出すことができていたため、今回は検定問題に挑戦していきました。問題文を読んで理解するのに苦戦していたようで、引っかかる箇所があるとその部分でそのまま時間を使ってしまう癖があるようでした。特に、最後の修正問題に関しては簡単な内容が多いため、点数を稼ぐためにも問題の取捨選択をすることを意識させて取り組むのがいいと思いました。次回の答え合わせと一緒に、問題の選び方や優先度の確認などもしていきたいです。', null, 'タイピング: 2級を目指して真剣に取り組んでいました。'),
  ('df155997-83dc-5bb3-8396-f58330a1f78c', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-24', '16:30:00', null, '通常 / 検定問題3級②', '過去に検定問題をやった記憶はあり、動画と試料を見ながらスムーズに取り組めました。25分ほど一通りできました。答え合わせをしましたが、非常によくできていました。アレンジのときの注意事項も伝えました。見た目を変えたいようでしたが、プログラムの方で積極的にアレンジをするように伝えました。楽しく取り組めていたようで良かったです！', null, 'タイピング: 集中して取り組めました。'),
  ('af724805-623c-5f2f-b3de-5fce7599be14', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-24', '17:30:00', null, '通常 / 不等号の復習 検定3級応用課題2', '最初にこちらから問題を出して不等号の復習をしました。段階を上げて問題を難しくしていくとキチンと答えることができました。一方で、問題の中にもでてきたのですが、逆にしてしまい正答できませんでした。本人もかなり悔しがっていました。 問題は、時間が足りなかったようですが集中して取り組めました。制御の部分はよくできていましたが、半角全角と前述した不等号のミスがありました。他の部分はしっかりできていました。', null, 'タイピング: 集中して取り組めました。'),
  ('7402a1b1-e739-5c9b-ac39-7b2878ce65a0', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-10-24', '16:30:00', null, '通常 / 4級 エントリー第15回 応用課題1', '「文字が読めない」と集中できなさそうだったので、一度深呼吸させて落ち着いて取り組むように誘導しました。解答用紙にある日本語のどこを見ればいいかを鉛筆で強調しながら教えてあげると、ちゃんと解く姿勢に慣れていて良かったです。 私も初めて取り組んだ内容だったため、一緒に見本の動画を何度も見ながらどうしたらいいか？を考えていました。 ただ、最終的に問題の表面は作ることができましたが、他の友達と離席したり、こちらの不手際で解答からヒントを出す準備をするまで待たせてしまったりで、裏面の問題まで取り組むことができませんでした。', null, 'タイピング: 取り組めていました。前回プレイグラムへの以降を検討されていたので次回は誘導します。'),
  ('316ed9a4-bdaa-57e2-a934-cd78a5a04fd9', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-10-24', '16:30:00', null, '通常 / バイクランの中で今までの復習しよう', '最初に、検定の話をしましたが、本人的にはやる気はないそうです。 なので、バイクランの続きをやっていきました。ジャンプのところは、前までやっていた放物ジャンプと同じ仕組みなため、バイクランの中でどのようにコードに組み込まれているか確認していきました。の前に、変数を使ってy座標を動かしているブロックを見つけられたが、変数の下げ幅(重力)のところはコードが離れていたため、いまいちピンときていませんでした。ほかにも、2段ジャンプを制御している変数や、ゲームオーバー条件などはよく遊んでいたため、しっかりと把握できていました。残りは道の製作途中だったので、来週があれば、終わると思います。', null, '盛り上がり: 良哉君と机を離してみたが、最初の十数分はなかなか始められませんでした'),
  ('bc90f561-4b11-53ed-a44f-43a22f16a7bb', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-10-24', '17:30:00', null, '通常 / 検定練習', '今回も1級の練習をやっていきました。今回は、定義を使うジャンプアクションだったので、定義の引数の使い方の苦戦していました。修くん自身も定義自体になじみがなかったので、途中定義の使い方のヒントを入れましたが、ギブアップでした。答え合わせで、活用法を一緒見ると、できていたので、何回か積めば、何とかなると思います。けど、今日の問題で、本人的には、定義系の問題は矢田のことでした。', null, null),
  ('8495cfaa-034c-518a-b747-629d8d3ae56e', 'd6678a4f-7486-58ac-b706-f233df0e20c5', null, '5bfa9797-92f1-50bd-a647-b0576746c223', '2024-10-24', '17:30:00', null, '通常 / 基本操作コース07_ピンポンゲーム', '久しぶりのゲーム作成だったらしく、「ボールの動き〜赤い線を超えたら止める」が出来るまではしばらく一緒に考えながら作成していました。 途中、組みたいコードの場所について「どっかでみたことある」と思い出しながら作成出来そうだったので、変数の箇所は10分程度自力で考えさせるようにしていましたが、 やはり難しかったのか、詰まっている様子だったので再度隣で一緒に考えるやり方に戻しました。 乱数によるボールの跳ね返り関して、私も完全な理解が出来ておらず一緒に悩んでしまったところを和先生に助けてもらい、何とか時間内に完成させることが出来ました。 最後、指示には無かったのですが「（YOU WON）は作ったけどGAME OVER 作ってない」と言っていたので、次回ゲーム作成で余裕があればアレンジも提案できたらいいなと思います。', null, 'タイピング: 集中して取り組めてました'),
  ('7ad654b7-b823-5926-b581-e2fc968c199e', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2024-10-24', '16:30:00', null, '通常 / バイクランゲームの作成', '授業前半は、席を立ち歩いたり、こたろうくんと遊んだり、ウォーターサーバーの交換をやりたがったりと、とにかくパソコンに落ち着いて向かうことがダルそうな感じでした。 先生達が声をかけても「めんどうくさい」「やらなくていい」という返答が多かったです。ただ、面倒と言いつつも、バイクランの手順書は受け取っていました。 「テスト」というのがあまり好きではなくて、検定の話をされるのから逃げているようにも見えました(^^; 最近、行き詰まる経験が多くて逃げたくなっているようにも見えたので、後半は「困っていることを一緒に解決しよう」と声掛けをすると、「道が縦に動いてしまう」「自転車が空中に浮いたまま止まる」などのバグを報告してくれたので、「どのスプライトのコードが怪しいと思うか」「そのコードの何があやしいか」などと順を追って問いかけていくと、「道のスプライトの座標設定がyになっているかもしれない」「自転車スプライトのジャンプや着地の定義があやしい」などと自分で考えられるようになりました。 その後は俄然やる気になって、積極的にあやしいと思われるコードを自分で探してバグを見つけ、ジャンプの回数などをアレンジして記録が出やすいようにしたり、道2のスプライトを編集して楽しみながら、授業時間10分過ぎくらいまで熱中して、一気に完成させていました。アレンジには自分でも満足したようで、やり切った感を出して帰っていきました。', null, '盛り上がり: 前半と後半の態度が180度変わり、後半は楽しそうに、自分でアレンジした効果などを説明しながら作成に励んでいました。
備考: ●検定についてはお母さんとも話しましたが、「テスト」に対するプレッシャーが相当大きいとのこと。テストに対する拒否感がモチベーションの低下につながっている可能性もあるので、検定は無理しなくても良いかと思われます。お母さんも、本人の意向を聞いてみるとのことでした。今日はテストのことを敢えて言わなかった結果、自発的な学習につながりました。 ●Scratchを家でもいじりたい、とのことで、IDとパスワードを教え、ログイン練習をしました。'),
  ('40d19ea0-1e35-5c4b-aa86-619fd8138f6a', '39671405-aae1-5c6e-8530-efdb7e3b3432', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2024-10-24', '17:30:00', null, '通常 / 検定問題に挑戦する、新しいコードの使い方を学ぶ', '検定4級の応用課題は問題なく解けていました。コードの方のアレンジにはまだ慣れていないようですが、問題部分だけで十分合格点が取れそうです。 だるまさんがころんだでは、完成形をプレイした上で口頭で細分化をしてから作成に入りました。必要なスプライトや背景を完成形から読み取って作成するのはとても素早く、スムーズでした。 細分化された動きをコードにするのはとても速いのですが、思いついたそばからどんどんブロックを入れていく傾向がありました。そのため、アルゴンの方に「右向き矢印が押されたなら負けメッセージを送る」というブロックを早急に入れていたため、一度落ち着かせて、アルゴンの動きだけを作らせて、一度動作確認をするよう促しました。 上記までは完成できた、と本人が納得したため、次に必要なコードを細分化した文章を見せながら考えさせ、そのコードはどのスプライトが主体となるべきかと発問したところ、「これはアルくんに書くんだ！」と気づいてくれました。 そこでまた少し先走って、「右向き矢印が押されたなら負けメッセージ」と作成したので、このままだと右に進んだだけで負けになることを確認させ、もう一つ、負けになる条件を細分化した文章から思い出させたところで、条件分岐を重ねることができました。 往々にして先走ることも多いですが、こちらの発問にはしっかり答えようとしてくれるので、そこで一旦落ち着いて考えさせるとしっかり軌道修正ができるようでした。', '本人もお父さんも検定に前向きだったので、準備をしていきましょう。', '盛り上がり: だるまさんがころんだを、正解を見ながらではなく自分で完成できるとは思わなかったようで、最後に動作確認をしたときはとても嬉しそうでした。 こんな風にできるんだ～、と、しきりに感心していました。'),
  ('9f722295-3aa3-5b3b-90e0-0818b4c906db', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-10-18', '18:40:00', null, '通常 / 大会提出資料作成', '前回までで、ゲームの操作説明やタイトル部分については作成していたので、今回は作品のアピールポイントや動作環境などを埋めていくとともに、写真などを挿入していきました。作品の中でも、プレイするキャラクターによって出せる技が違う部分があり、そこをとても気に入っていたのでキャラクターごとの特徴や動きについてアピールしていきました。ポイントを大きく書き、実際に技などを使用している写真を貼ることで、審査員に対しても視覚的に分かりやすく伝えることができるようにしたと言っていました。次回で最終日のため、残りの部分を一気に作り上げていく予定です。', null, null),
  ('3750bdd4-0bc4-5e46-b5b2-3343bc5466a1', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-10-18', '16:30:00', null, '通常 / 3級応用課題2', '前回挑戦していた3級②の答え合わせをした後に応用課題へ取り組んでいきました。前回の問題では、ドラゴンの動きで少し問題があったようなので、問題文を見返して１つづつ確認する事で、自分自身で間違いを発見できていました。応用課題では、つまづく事なくスラスラと作成していき、間違う事なく最後まで完成させることができていました。残りの時間は、応用課題のアレンジを行っていき、キーパーやボールの変数を変えることで難易度調整を行なっていました。今回の応用課題はタイマーを計測しないで行いましたが、アレンジ以外を３０分ほどで終わらせていたため、時間配分も問題ないようでした。', null, 'タイピング: 集中して取り組めていました。'),
  ('18be125f-c98e-5e89-9abc-650c9e4538aa', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-10-25', '18:40:00', null, '通常 / 検定1級問題①', 'U16大会には参加しないとのことで、検定問題１級に挑戦していきました。問題内容に対しての理解はそれなりにできていたようで、正答率としてゃ合格点には到達することができていそうでした。しかし、問題と解いている際に集中がいまいち続かない場面も見られたため、問題文が長いと取り組むのに少し抵抗があるようでした。それでも理解はできていたため、１つの文を区切って考えていくことで集中力を継続することができそうです。', null, 'タイピング: 集中して取り組めていました。'),
  ('f90aeb1a-9868-5200-93bc-31573e3ce858', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-25', null, null, '振替 / 検定3級応用課題5', '一通り最後まで見ても完成しなかったので、一緒に確認しました。「～まで繰り返す」の範囲や、使う演算子の種類にミスがありました。とくに前者に関しては、読み飛ばしているところもあったので残念です。演算子については、いつもはスプライトの動きがプログラムに結びついているようで、言葉とプログラムを結び付けるのが少し難しいようでした。 時間いっぱいまで頑張って修正し、動作するようにできました！', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('0ae9d9ed-0769-55bf-b4e3-2739154f2b47', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-25', null, null, '通常 / 【Prg】29 カミナリをよけろゲームを作ろう！', '動画を見てやるとダラダラしてしまうかな？と思ったので、ドリル49, 50を参考にしながら一緒に話して考えながら進めました。 カミナリを落とすプログラムでは、一度にいろんなことを考えてしまうので、自分でプログラムを整理しきるのが難しかったようです。y座標についての考え方はとても良かったのですが、最初の場所に戻るとき、「画面の下にいった時」のプログラムでは、かなりこちらの助言が必要でした（座標、制御のブロック）（本人は使った記憶はある様子） その後は自分でアレンジをしつつ進めてくれました。カミナリに当たったときの恐竜のモーションや、スコアを追加しました。一応完成だそうです。楽しく取り組めたと思います。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('bf537910-70f3-5c39-b59b-7f35fca600d7', '53dc382f-637d-5a46-9b57-4204c79ee130', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-25', '17:30:00', null, '通常 / 検定4級①と応用課題①', '検定の形式につまずいたので、4級①は一緒に読みながら取り組みました。前半でかなり慣れたようなので、後半は少しずつ区切りながら取り組んでもらいました。ブロックを置くところを間違えているときもありましたが、自分で確認するように促すと修正できていました。 検定は嫌いではない様子だったので、応用課題①にも取り組んでもらいました。時間内に終わりました。とくに前半は紙に✓を付けながら、取り組めていました。アレンジはやっていないです。 もう少し検定の練習が必要かな？と思います。', null, 'タイピング: 集中して取り組めました。'),
  ('62643f92-c530-5e32-b2c1-ee01f645e8ad', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-25', '17:30:00', null, '通常 / 検定3級応用課題③', '今までにない問題のタイプで少し苦戦していました。変数のミスや、「～まで繰り返す」のブロックがどこまで有効なのか、について少し理解が浅かったりしました。また集中力があまり持たず、プログラムは続けられるのですがよくしゃべっています。 演算の使い方や見たいことのないブロックの使い方に困ったこともあったそうですが、自分なりに考えてしっかり解決できていたので良かったです！', null, 'タイピング: 集中して取り組めました。'),
  ('a7371612-fc85-57fa-a691-e6f7b903ea2c', 'f35236b7-5f13-5da1-b922-1d9211737d7d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-10-25', '16:30:00', null, '通常 / 基本操作コース「コード探求【もし●●なら】だるまさんがころんだ」', '前回、素材を取り込んだ後のリミックスを忘れてしまったそうで、データが飛んでしまったようです。今日はイチからプログラムをしました。 本人が大枠の概要を理解できていたので思い出しながらのプログラムになりました。細分化をしつつ進めましたが、コスチュームを右左に切り替えられていましたが、元のコスチュームに戻すという考え方があまり馴染まないようで、すこし時間がかかっていました。 かちの条件や負けの条件は前回を思い出しながらプログラムできました。余談として、コスチュームの見た目と番号でプログラムを分けられることを説明しました。また、タイムや背景のアレンジを加えて公開できました。', null, 'タイピング: 集中して取り組めました。'),
  ('842728ab-f566-5bed-8cdf-3ac5b4917339', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-10-25', '17:30:00', null, '通常 / 検定4級応用課題１', '最初の３０％位まで進んだところで、集中力がなくなって、やるべき事から脱線してばかりになったので、一度休憩時間でゲームを少しさせました。その後復活して、後半はかなりの集中力で残りの７０％くらいを一気に完了させることができました。きちんと終わらせることができて本人も喜んでいました。ほとんどは、ちょっとしたヒントを与えることで自力で作成できましたが、最後らへんの「スプライトの他のスプライトを止める」というブロックがあまりよくわからないままの終了となってしまいました。', null, 'タイピング: 集中して取り組んでいました'),
  ('0dcdd35c-bc16-5c29-9a6b-ec9cec78b272', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '27073d5b-1846-57b7-997a-9609d31edd74', '2024-10-25', '18:40:00', null, '通常 / 基本操作の続き', 'まず作ったピンボールの振り返りをしたのですが、そこでピンボールのプログラムをいじったりしてかなり脱線して時間を使ってしまった気がします。脱線を極力少なくして今日やりたいことにスムーズに入れる方法を勉強したいです。だるまさんが転んだを始めましたが、これも、一つ一つのブロック作成に時間がかかってしまいました。「だるまさんが転んだ」の音声を自分の声で作り始める等。。。「左キーを押したらキャラを左に動かす」のような基本的なプログラムについても、どうすれば良いのと聞いてきたりするので、まだ少し基本操作部分が弱いのかもしれませんね。だるまさんがころんだは、勝ち負けの判定処理が作成できず今日は終了となりました。ただ、もっと敵を作ったりしてとか、だるまさんがころんだをもっと面白くするような、いろんなオリジナルのアイデアを色々出してくれて、そういう話の時はとても楽しそうでした。', null, null),
  ('fd27d752-b438-51ff-b264-ffd786893970', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-10-26', null, null, '通常 / バイクランを完成させよう', '今週は、半年前ほどに作りかけになっていたバイクランを直していきました。足場が流れてこず、無限ジャンプするなど様々なバグがありました。設計書のコードを比較しながら、最初はただ見比べていましたが、本人ではそう簡単には見つけられず、飽きそうになっていました。そこで、何がおかしいかバグの内容を答えさせていきました。聞かれたらどこがおかしいか動きを見分けることができたので、そのうえで探してもらうと、細かい凡ミスを見つけることができました。内容を知ったうえで探すときは集中力は高かったです。作り途中だったものを直せました。', '検定練習？', '時間帯: その他
タイピング: 練習するよりミスタイプを増やす遊びの方にいってます'),
  ('4cc98d8b-f4d3-5015-a18a-03a0a9b02c36', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-10-26', null, null, '通常 / 大会作品制作', '今回は、主に定義を使った作成したコードを整理していました。ちひろくん自身も定義をいまま振れたことがなく、使ってみたい気持ちがあったので、意気揚々に取り組んでいました。ほかにも、クリック判定のしにくさなど改善点もあるそうなので、そこを整理して提出するそうです。', null, '時間帯: その他
盛り上がり: 初めて見たけど、三角形が浮かび上がるのすごい'),
  ('f12e41cd-e27e-5de6-ad89-e01a12c3d6a1', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-10-26', null, null, '通常 / 検定問題で復習をしよう', 'しばらく間が空いてしまったので、検定問題で復習しながら取り組んでいました。問題文の読みにくさで迷うことがあったが、コードの能力的に迷うことがほぼなかったです。「または」の活用も迷わずできていたので良かったです。そのため、間違うことなく作成できて、のびのびとアレンジをできていました。', null, '時間帯: その他
タイピング: よく集中していました
盛り上がり: さねゆきくんとアレンジ候補案をたくさん考えてい楽しんでいました。'),
  ('117ee86f-ca6f-5130-ba8c-f543dd7670eb', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-10-26', null, null, '通常 / 検定練習', '今回も検定問題にやりました。この問題は、「まで繰り返す」が多い問題で、優斗君が一折解き終わって確認してみるとうまく作動していませんでした。「まで繰り返す」の繰り返す内容がごちゃごちゃになっていたのが原因です。それと最後まで1文を読み切れていないことが多くありました。最初の触れるまでの条件にだけに目が行って、読み切れていませんでした。そのため、落ち着いて最後まで1文を見ることが大切にしてほしいです', '文章を最後もまで読むこと', '時間帯: その他
タイピング: ノーだめで進んでいました。'),
  ('73657ebc-4755-5e08-8c1b-83138a0fe224', '0047fb11-a84a-5592-8c39-5a16c20eb10e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-26', null, null, '通常 / ゲーム完成', '前回の続きで、難易度変更の部分だけ未作成だったので取り組みました。ゲームのむずかしさに変数の値を対応させるという概念はすぐに理解できたようでした。それについては作成できましたが、バグが残ったので原因を探りました。「この動作を行っているということは、このメッセージが誤って送られている」という推理が自分でできていました。ただ、原因まではたどりつけなかったので一緒に見てみると、x座標とy座標の取り違えや全角数字などの基本的なミスがあったことがわかりました。今後は基礎の抜けがないように身に着けていこうという気持ちになったようでした。', null, '時間帯: その他'),
  ('209ad6bd-9807-52c2-a286-987170e89370', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-26', null, null, '通常 / リストの復習', 'そろそろMonacaで配列を扱うため、スクラッチでリストの復習をしました。そこまで乗り気ではなく不満を言いながらではありましたが、しっかり手を動かしてくれました。リストの部分もそれ以外の部分も楽々とこなし完璧だったので、成長がうかがえました。', null, '時間帯: その他
盛り上がり: 来週ロブロックスをやると伝えるととても喜んでいました。'),
  ('db9d8a63-00af-51ce-9ea8-399a5793458f', '82396ac6-71bd-59d4-a372-57212866fd5d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-10-26', null, null, '通常 / チーズを探せ完成', 'ピンポンゲームに移る予定でしたが、チーズを探せの細かい部分が未完成とのことで進めました。クリアやゲームオーバーになったときの動きを作るために、メッセージを送ったり受け取ったりすることができていました。メッセージを受け取ったときの動きが終わる前にすべてが止まってしまい困っていたときに「メッセージを送って待つ」の使い方を教えると、納得した様子で活用できていました。アレンジを含めて無事に完成しました。', null, '時間帯: その他
盛り上がり: 作りたい動きを再現するためにどんなコードが必要なのか自分で考える姿勢がありました。')
on conflict (lesson_record_id) do update set lesson_date = excluded.lesson_date, start_time = excluded.start_time, end_time = excluded.end_time, title = excluded.title, content = excluded.content, homework = excluded.homework, memo = excluded.memo;

commit;
